-- Данные учебника Петерсон 3 класс, часть 2
-- PostgreSQL compatible

VALUES ('matematika', 3, 'Петерсон Л.Г.', 'Математика 3 класс', 2, 2022, 'Просвещение', 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik')
ON CONFLICT (subject, grade, authors, part) DO UPDATE SET year = EXCLUDED.year;

-- Задачи
DO $$
DECLARE
    v_textbook_id BIGINT;
    v_task_id BIGINT;
BEGIN
    SELECT id INTO v_textbook_id FROM textbooks WHERE subject = 'matematika' AND grade = 3 AND authors = 'Петерсон Л.Г.' AND part = 2;

    VALUES (v_textbook_id, 3, '1', 0, 'А) Объясни по рисунку, как умножить сумму на число, и выполни умножение: (а + в + с) ⋅ в = а ⋅ d + b ⋅ d + c ⋅ d 576 ⋅ 9 = (500 + 70 + 6) ⋅ 9 = … Что ты замечаешь? Сделай вывод. Б) Используя рисунок, объясни, как получен способ записи умножения 576 ⋅ 9 в столбик. Сделай вывод. 6 ⋅ 9 = 54; 70 ⋅ 9 = 630; 500 ⋅ 9 = 4500; 54 + 630 + 4500 = 5184; 576 ⋅ 9 = 5184.', '</p>\n\n<p class="text">А) Объясни по рисунку, как умножить сумму на число, и выполни умножение:<br/>\n(а + в + с) ⋅ в = а ⋅ d + b ⋅ d + c ⋅ d<br/>\n576 ⋅ 9 = (500 + 70 + 6) ⋅ 9 = …<br/>\nЧто ты замечаешь? Сделай вывод.<br/>\n<br/>\nБ) Используя рисунок, объясни, как получен способ записи умножения 576 ⋅ 9 в столбик. Сделай вывод.<br/>\n6 ⋅ 9 = 54;<br/>\n70 ⋅ 9 = 630;<br/>\n500 ⋅ 9 = 4500;<br/>\n54 + 630 + 4500 = 5184;<br/>	\n<br/>\n576 ⋅ 9 = 5184.\n</p>', 'А) Умножить сумму на число можно, если каждое из слагаемых умножить на это число, а полученные значения сложить. Я заметила, что выражение подтверждает мое предположение. Б) Число 570 сначала мысленно представляют в виде суммы разрядных слагаемых. Затем каждое из слагаемых умножают на второй множитель, а полученные значения складывают. Запись можно оформить иначе, если первым множителем записать то число, в котором знаков больше. Вторым множителем – число, в котором меньше множителей. А затем каждую цифру первого множителя умножают на второй множитель.', '<p>\nА) Умножить сумму на число можно, если каждое из слагаемых умножить на это число, а полученные значения сложить.<br/>\nЯ заметила, что выражение подтверждает мое предположение. <br/>\nБ) Число 570 сначала мысленно представляют в виде суммы разрядных слагаемых.<br/>\nЗатем каждое из слагаемых умножают на второй множитель, а полученные значения складывают.<br/>\nЗапись можно оформить иначе, если первым множителем записать то число, в котором знаков больше. Вторым множителем – число, в котором меньше множителей. А затем каждую цифру первого множителя умножают на второй множитель.\n</p>', 'Алгоритм умножения многозначного числа на однозначное в столбик 1.Записать однозначное число под разрядов единиц многозначного числа. 2.Умножить единицы. 3.Записать единицы под единицами, а десятки (если они есть) запомнить. 4.Умножить десятки; к результату прибавить десятки, которые запоминали. 5.Записать десятки под десятками, а сотни (если они есть) запомнить. 6.Аналогично умножить все разряды многозначного числа. 7.Назвать ответ.', '<div class="recomended-block">\n<span class="title">Алгоритм умножения многозначного числа на однозначное в столбик</span>\n<p>\n1.Записать однозначное число под разрядов единиц многозначного числа.<br/>\n2.Умножить единицы.<br/>\n3.Записать единицы под единицами, а десятки (если они есть) запомнить.<br/>\n4.Умножить десятки; к результату прибавить десятки, которые запоминали.<br/>\n5.Записать десятки под десятками, а сотни (если они есть) запомнить.<br/>\n6.Аналогично умножить все разряды многозначного числа.<br/>\n7.Назвать ответ.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-3/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '717133f400629defa7478179de7a417b3c3f7af7d4aee4bc2455a23ecac8f4e8', '6,9,54,70,500,576,630,4500,5184', '["столбик"]'::jsonb, 'а) объясни по рисунку, как умножить сумму на число, и выполни умножение:(а+в+с) ⋅ в=а ⋅ d+b ⋅ d+c ⋅ d 576 ⋅ 9=(500+70+6) ⋅ 9=... что ты замечаешь? сделай вывод. б) используя рисунок, объясни, как получен способ записи умножения 576 ⋅ 9 в столбик. сделай вывод. 6 ⋅ 9=54; 70 ⋅ 9=630; 500 ⋅ 9=4500; 54+630+4500=5184; 576 ⋅ 9=5184');

    VALUES (v_textbook_id, 3, '2', 1, 'Выполни умножение в столбик: А) 329 ⋅ 5; Б) 8 ⋅ 824; В) 4 ⋅ 906; Г) 407 ⋅ 7; Д) 5706 ⋅ 5; Е) 6 ⋅ 3087; Ж) 3 ⋅ 90 802; З) 280 019 ⋅ 9.', '</p>\n\n<p class="text">Выполни умножение в столбик:<br/>\nА) 329 ⋅ 5;<br/>\nБ) 8 ⋅ 824;<br/>\nВ) 4 ⋅ 906;<br/>\nГ) 407 ⋅ 7;<br/>\nД) 5706 ⋅ 5;<br/>\nЕ) 6 ⋅ 3087;<br/>\nЖ) 3 ⋅ 90 802;<br/>\nЗ) 280 019 ⋅ 9.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica3-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 3, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 3, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-3/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica3-nomer2.jpg', 'peterson/3/part2/page3/task2_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '87d45f5e7fd8af72510ce7ba6b9ab4743965baeac2868fa05464866941a5d6bb', '3,4,5,6,7,8,9,019,90,280', '["столбик"]'::jsonb, 'выполни умножение в столбик:а) 329 ⋅ 5; б) 8 ⋅ 824; в) 4 ⋅ 906; г) 407 ⋅ 7; д) 5706 ⋅ 5; е) 6 ⋅ 3087; ж) 3 ⋅ 90 802; з) 280 019 ⋅ 9');

    VALUES (v_textbook_id, 3, '3', 2, 'Реши уравнения с комментированием и сделай проверку: х : 9 = 809; 540 : х = 20; 3 ⋅ х = 810.', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:<br/>\nх : 9 = 809;<br/>\n540 : х = 20;<br/>\n3 ⋅ х = 810.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica3-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 3, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 3, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-3/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica3-nomer3.jpg', 'peterson/3/part2/page3/task3_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'f6b5acb8cbe751cdd3e8e693260356275bb358578bbd578432066c5a71de4f8a', '3,9,20,540,809,810', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:х:9=809; 540:х=20; 3 ⋅ х=810');

    VALUES (v_textbook_id, 4, '4', 0, 'А) Компьютер стоит 9356 р. Сколько надо заплатить за три таких компьютеров? Б) на экскурсию в город Суздаль купили 4 детских билета по цене 835 р. и 5 взрослых билетов по цене 1216 р. Сколько сдачи даст кассир, если в кассу заплатили 10 000 р.?', '</p>\n\n<p class="text">\nА) Компьютер стоит 9356 р. Сколько надо заплатить за три таких компьютеров?<br/>\nБ) на экскурсию в город Суздаль купили 4 детских билета по цене 835 р. и 5 взрослых билетов по цене 1216 р. Сколько сдачи даст кассир, если в кассу заплатили 10 000 р.?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica4-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 4, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-4/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica4-nomer4.jpg', 'peterson/3/part2/page4/task4_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '449dc5977c3c744cac93a4fcf252cd908a564774f2ea5f96a6331e1215184c1a', '000,4,5,10,835,1216,9356', NULL, 'а) компьютер стоит 9356 р. сколько надо заплатить за три таких компьютеров? б) на экскурсию в город суздаль купили 4 детских билета по цене 835 р. и 5 взрослых билетов по цене 1216 р. сколько сдачи даст кассир, если в кассу заплатили 10 000 р');

    VALUES (v_textbook_id, 4, '5', 1, 'В первой школе к учеников, во второй – в 2 раза больше, чем в первой, а в третьей – столько, сколько в первых двух школах вместе. Сколько всего учеников в трех этих школах? Составь выражение и найди его значение при к = 309.', '</p>\n\n<p class="text">В первой школе к учеников, во второй – в 2 раза больше, чем в первой, а в третьей – столько, сколько в первых двух школах вместе. Сколько всего учеников в трех этих школах? Составь выражение и найди его значение при к = 309.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica4-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 5, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 5, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-4/')
    RETURNING id INTO v_task_id;

