    VALUES (v_task_id, v_textbook_id, 3, 'a711fe06f3a1c46901f362b453020e420e421d6fff744214b972b2ca0259da03', '2,309', '["найди","больше","раз","раза"]'::jsonb, 'в первой школе к учеников, во второй-в 2 раза больше, чем в первой, а в третьей-столько, сколько в первых двух школах вместе. сколько всего учеников в трех этих школах? составь выражение и найди его значение при к=309');

    VALUES (v_textbook_id, 4, '6', 2, 'Из 1 кг макулатуры можно изготовить 25 тетрадей. Сколько таких тетрадей можно изготовить из 1 ц макулатуры, из 1 т макулатуры?', '</p>\n\n<p class="text">Из 1 кг макулатуры можно изготовить 25 тетрадей. Сколько таких тетрадей можно изготовить из 1 ц макулатуры, из 1 т макулатуры? \n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica4-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-4/')
