    VALUES (v_task_id, v_textbook_id, 3, '4a43e3fde778b74d4cee3ae96572941376f031719a01279f2ae959bf316c04bf', '1,25', NULL, 'из 1 кг макулатуры можно изготовить 25 тетрадей. сколько таких тетрадей можно изготовить из 1 ц макулатуры, из 1 т макулатуры');

    VALUES (v_textbook_id, 4, '7', 3, 'Выполни действия: А) 8 дм 2 см + 74 мм + 1 дм 6 мм; Б) 16 км 7 м + 915 м + 4 км 38 м; В) 7 т 7 кг + 95 кг + 29 ц 8 кг; Г) 15 кг 26 г + 4 кг 470 г + 6 кг 4 г.', '</p>\n\n<p class="text">Выполни действия:<br/>\nА) 8 дм 2 см + 74 мм + 1 дм 6 мм;<br/>\nБ) 16 км 7 м + 915 м + 4 км 38 м;<br/>\nВ) 7 т 7 кг + 95 кг  + 29 ц 8 кг;<br/>\nГ) 15 кг 26 г + 4 кг 470 г + 6 кг 4 г.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica4-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-4/')
