    VALUES (v_textbook_id, 4, '8', 4, 'Артем сделал за день 12 361 шаг, а Лена – 9 457 шагов. На сколько шагов больше сделал Артем, чем Лена?', '</p>\n\n<p class="text">Артем сделал за день 12 361 шаг, а Лена – 9 457 шагов. На сколько шагов больше сделал Артем, чем Лена?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica4-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-4/')
