    VALUES (v_textbook_id, 4, '9', 5, 'Составь программу действий и вычисли: А) (24 + 18) : 7 – 0 ⋅ (82 – 58) + 16 ⋅ 3; Б) 21 : (96 – 89) + (7 ⋅ 4 + 6) ⋅ 2 – 56 : 56.', '</p>\n\n<p class="text">Составь программу действий и вычисли:<br/>\nА) (24 + 18) : 7 – 0 ⋅ (82 – 58) + 16 ⋅ 3;<br/>\nБ) 21 : (96 – 89) + (7 ⋅ 4 + 6) ⋅ 2 – 56 : 56.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica4-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-4/')
