    VALUES (v_task_id, v_textbook_id, 3, '835115d0a7f82e54fe1c80b912172bbf46a336fc1d89a09cab82ef18afb6dec7', '0,2,3,4,6,7,16,18,21,24', '["вычисли"]'::jsonb, 'составь программу действий и вычисли:а) (24+18):7-0 ⋅ (82-58)+16 ⋅ 3; б) 21:(96-89)+(7 ⋅ 4+6) ⋅ 2-56:56');

    VALUES (v_textbook_id, 4, '10', 6, 'Нарисуй треугольник и четырехугольник, пересечением которых являются: а) точка; б) отрезок; в) треугольник; г) четырехугольник. Закрась синим цветом объединение этих фигур.', '</p>\n\n<p class="text">Нарисуй треугольник и четырехугольник, пересечением которых являются: а) точка; б) отрезок; в) треугольник; г) четырехугольник. Закрась синим цветом объединение этих фигур.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica4-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-4/')
    RETURNING id INTO v_task_id;

