    VALUES (v_task_id, v_textbook_id, 3, 'f22d8782ae94cda3e08791ce49144dfe65166d7d434c5ce8287fe1e505acd2e1', NULL, NULL, 'нарисуй треугольник и четырехугольник, пересечением которых являются:а) точка; б) отрезок; в) треугольник; г) четырехугольник. закрась синим цветом объединение этих фигур');

    VALUES (v_textbook_id, 4, '11', 7, 'Запиши с помощью фигурных скобок множество букв в слове «МИР». Перечисли все возможные способы записи этого множества.', '</p>\n\n<p class="text">Запиши с помощью фигурных скобок множество букв в слове «МИР». Перечисли все возможные способы записи этого множества.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica4-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 4, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-4/')
