    VALUES (v_task_id, v_textbook_id, 3, '737471c8b66d8a1369685b728c2ba650fb9fcc47c13be5e360e993a1de1a0313', NULL, NULL, 'запиши с помощью фигурных скобок множество букв в слове "мир". перечисли все возможные способы записи этого множества');

    VALUES (v_textbook_id, 4, '12', 8, 'В семье 3 сестры: Таня, Света и Марина. Их дни рождения соответственно летом, зимой и весной. Таня не старше Марины, а Света не старше Тани. Кто из сестёр старше всех? Кто младше всех?', '</p>\n\n<p class="text">В семье 3 сестры: Таня, Света и Марина. Их дни рождения соответственно летом, зимой и весной. Таня не старше Марины, а Света не старше Тани. Кто из сестёр старше всех? Кто младше всех?\n</p>', 'Перечислим все условия: 1) Таня не старше Марина, значит, Таня младше Марины; 2) Света не старше Тани, значит, Света младше Тани; Получается, возраст девочки расположен так: Света – Таня – Марина; Ответ: старше всех сестёр – Марина; младше всех сестёр – Света.', '<p>\nПеречислим все условия:<br/>\n1) Таня не старше Марина, значит, Таня младше Марины;<br/>\n2) Света не старше Тани, значит, Света младше Тани;<br/>\nПолучается, возраст девочки расположен так: Света – Таня – Марина;<br/>\nОтвет: старше всех сестёр – Марина; младше всех сестёр – Света.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-4/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '779f51dcdc1a3c656c47600f3aa3f9caf027fa4477ba04bcaa7b213aa7e05539', '3', NULL, 'в семье 3 сестры:таня, света и марина. их дни рождения соответственно летом, зимой и весной. таня не старше марины, а света не старше тани. кто из сестёр старше всех? кто младше всех');

    VALUES (v_textbook_id, 5, '1', 0, 'Найди правильную запись и решение примера 9052 ⋅ 6. В чем причины ошибок в остальных случаях? Как умножить многозначное число на однозначное?', '</p>\n\n<p class="text">Найди правильную запись и решение примера 9052 ⋅ 6. В чем причины ошибок в остальных случаях?<br/>\nКак умножить многозначное число на однозначное?\n</p>', 'Верная запись номер 3. В первом номере в неправильном месте записан второй множитель, потому что единицы нужно писать под единицами. Во втором номере пропущен один знак, и вместо пятизначного числа получилось четырехзначное. Вывод: чтобы умножить многозначное число на однозначное, нужно записать втором множитель так, чтобы разряд стоял под разрядом, а затем каждую цифру первого множителя умножить на второй множитель.', '<p>\nВерная запись номер 3.<br/>\nВ первом номере в неправильном месте записан второй множитель, потому что единицы нужно писать под единицами.<br/>\nВо втором номере пропущен один знак, и вместо пятизначного числа получилось четырехзначное.<br/>\nВывод: чтобы умножить многозначное число на однозначное, нужно записать втором множитель так, чтобы разряд стоял под разрядом, а затем каждую цифру первого множителя умножить на второй множитель.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-5/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd05b17592377a566c15ddc292e4f2b09814c631a5c30230916da850a6a43b933', '6,9052', '["найди"]'::jsonb, 'найди правильную запись и решение примера 9052 ⋅ 6. в чем причины ошибок в остальных случаях? как умножить многозначное число на однозначное');

    VALUES (v_textbook_id, 5, '2', 1, 'А) Объясни прием умножения круглых чисел. Какие свойства умножения здесь используются? 29 000 ⋅ 30 = (29 ⋅ 1000) ⋅ (3 ⋅ 10) = (29 ⋅ 3) ⋅ (1000 ⋅ 10) = 87 ⋅ 10 000 = 870 000; Б) Найди правильную запись умножения круглых чисел в столбик. Чем она удобна? 29 000 ⋅ 30 = 870 000.', '</p>\n\n<p class="text">\nА) Объясни прием умножения круглых чисел. Какие свойства умножения здесь используются?<br/>\n29 000 ⋅ 30 = (29 ⋅ 1000) ⋅ (3 ⋅ 10) = (29 ⋅ 3) ⋅ (1000 ⋅ 10) = 87 ⋅ 10 000 = 870 000;<br/>\nБ) Найди правильную запись умножения круглых чисел в столбик. Чем она удобна?<br/>\n29 000 ⋅ 30 = 870 000.\n\n</p>', 'А) Для того, чтобы умножить круглые числа, используют переместительное и сочетательное свойства умножения. По переместительному свойству множители переставляют местами, а по сочетательному – множители перемножают в разном порядке. Б) Правильная запись умножения – третья, потому что нули отдельно можно будет перенести в значение множителя, отдельно перемножив числа 29 и 3.', '<p>\nА) Для того, чтобы умножить круглые числа, используют переместительное и сочетательное свойства умножения.<br/>\nПо переместительному свойству множители переставляют местами, а по сочетательному – множители перемножают в разном порядке.<br/>\nБ) Правильная запись умножения – третья, потому что нули отдельно можно будет перенести в значение множителя, отдельно перемножив числа 29 и 3.\n</p>', 'Умножение круглых чисел в столбик При умножении круглых чисел в столбик числа записывают и умножают, не глядя на нули. Затем к результату приписывают справа столько нулей, сколько в обоих множителях вместе.', '<div class="recomended-block">\n<span class="title">Умножение круглых чисел в столбик</span>\n<p>\nПри умножении круглых чисел в столбик числа записывают и умножают, не глядя на нули. Затем к результату приписывают справа столько нулей, сколько в обоих множителях вместе.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-5/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '83d4ef2dc291ae5bb1cf3acd6fbae59eda664ee82e2423592e18bb1e2b008641', '000,3,10,29,30,87,870,1000', '["найди","столбик"]'::jsonb, 'а) объясни прием умножения круглых чисел. какие свойства умножения здесь используются? 29 000 ⋅ 30=(29 ⋅ 1000) ⋅ (3 ⋅ 10)=(29 ⋅ 3) ⋅ (1000 ⋅ 10)=87 ⋅ 10 000=870 000; б) найди правильную запись умножения круглых чисел в столбик. чем она удобна? 29 000 ⋅ 30=870 000');

    VALUES (v_textbook_id, 5, '3', 2, 'Объясни способ записи умножении и вычисли: А) 7 200 ⋅ 8; Б) 530 ⋅ 900; В) 83 056 ⋅ 800; Г) 90 200 ⋅ 50.', '</p>\n\n<p class="text">\nОбъясни способ записи умножении и вычисли:<br/>\nА) 7 200 ⋅ 8;<br/>\nБ) 530 ⋅ 900;<br/>\nВ) 83 056 ⋅ 800;<br/>\nГ) 90 200 ⋅ 50.\n</p>', 'Умножают круглые числа. Для этого нули отбрасывают, а умножают оставшиеся множители. Затем нули приписывают в значению произведения.', '<p>\nУмножают круглые числа. Для этого нули отбрасывают, а умножают оставшиеся множители. Затем нули приписывают в значению произведения.\n</p>\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica5-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 5, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 5, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-5/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica5-nomer3.jpg', 'peterson/3/part2/page5/task3_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'd041501bbd0f54b6d1ca6b11954103ba7e91d833dbe0e0499e6def672b441bff', '7,8,50,056,83,90,200,530,800,900', '["вычисли"]'::jsonb, 'объясни способ записи умножении и вычисли:а) 7 200 ⋅ 8; б) 530 ⋅ 900; в) 83 056 ⋅ 800; г) 90 200 ⋅ 50');

    VALUES (v_textbook_id, 5, '4', 3, 'Выполни умножение и прочитай полученные числа: А) 75 014 ⋅ 8; Б) 10 043 ⋅ 5; В) 5 030 ⋅ 70; Г) 23 860 ⋅ 800; Д) 269 507 ⋅ 6; Е) 9 056 ⋅ 3 000.', '</p>\n\n<p class="text">\nВыполни умножение и прочитай полученные числа:\nА) 75 014 ⋅ 8;\nБ) 10 043 ⋅ 5;\nВ) 5 030 ⋅ 70;\nГ) 23 860 ⋅ 800;\nД) 269 507 ⋅ 6;\nЕ) 9 056 ⋅ 3 000.\n</p>', 'А) шестьсот тысяч сто двенадцать; Б) пятьдесят тысяч двести пятнадцать; В) триста пятьдесят две тысячи сто; Г) девятнадцать миллионов восемьдесят восемь тысяч; Д) один миллион шестьсот семнадцать сорок два; Е) двадцать семь миллионов сто шестьдесят восемь тысяч.', '<p>\nА) шестьсот тысяч сто двенадцать;<br/>\nБ) пятьдесят тысяч двести пятнадцать;<br/>\nВ) триста пятьдесят две тысячи сто;<br/>\nГ) девятнадцать миллионов восемьдесят восемь тысяч;<br/>\nД) один миллион шестьсот семнадцать сорок два;<br/>\nЕ) двадцать семь миллионов сто шестьдесят восемь тысяч.\n</p>\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica5-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 5, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 5, номер 4, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-5/')
    RETURNING id INTO v_task_id;

