    VALUES (v_task_id, v_textbook_id, 3, 'dea3d3bed1a9c7ac1a65e8c3689716e2aa2e2c4ab0a55ccdab201fbd1467446c', '000,3,5,6,8,9,10,014,23,030', NULL, 'выполни умножение и прочитай полученные числа:а) 75 014 ⋅ 8; б) 10 043 ⋅ 5; в) 5 030 ⋅ 70; г) 23 860 ⋅ 800; д) 269 507 ⋅ 6; е) 9 056 ⋅ 3 000');

