    VALUES (v_task_id, v_textbook_id, 3, '6d111211a0a2654248d14e50d5ca142741ad6e5f2057d40d5be5c01aae845dd2', '3', '["реши","столбик"]'::jsonb, 'придумай и реши 3 своих примера на умножение круглых чисел в столбик');

    VALUES (v_textbook_id, 6, '6', 1, 'Расположи числа в порядке возрастания: 20 769 015; 2 076 901; 2 076; 20 780; 2 078 000; 258 999. Найди самое большое число. Сколько единиц в разряде десятков тысяч этого числа? Сколько в нем всего десятков тысяч? Единицы каких разрядов отсутствуют в его записи?', '</p>\n\n<p class="text">Расположи числа в порядке возрастания:<br/>\n20 769 015;<br/>\n2 076 901;<br/>\n2 076;<br/>\n20 780;<br/>\n2 078 000;<br/>\n258 999.<br/>\nНайди самое большое число. Сколько единиц в разряде десятков тысяч этого числа? Сколько в нем всего десятков тысяч? Единицы каких разрядов отсутствуют в его записи?\n</p>', '2 076; 20 780; 258 999; 2 076 901; 2 078 000; 20 769 015; Самое большое число – 20 769 015; В разряде десятков тысяч – 6 единиц; Десятков тысяч – 60 000; Отсутствуют сотни класса единиц и единицы класса миллионов.', '<p>\n2 076;<br/>\n20 780;<br/>\n258 999;<br/>\n2 076 901;<br/>\n2 078 000;<br/>\n20 769 015;<br/>\nСамое большое число – 20 769 015;<br/>\nВ разряде десятков тысяч – 6 единиц;<br/>\nДесятков тысяч – 60 000;<br/>\nОтсутствуют сотни класса единиц  и единицы класса миллионов.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-6/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd9c2215dd6ead368eeb620dda44da9f55d67dfd8dd950fc58b2b4788cc714ed2', '000,2,015,20,076,078,258,769,780,901', '["найди","раз"]'::jsonb, 'расположи числа в порядке возрастания:20 769 015; 2 076 901; 2 076; 20 780; 2 078 000; 258 999. найди самое большое число. сколько единиц в разряде десятков тысяч этого числа? сколько в нем всего десятков тысяч? единицы каких разрядов отсутствуют в его записи');

    VALUES (v_textbook_id, 6, '7', 2, 'Вычисли устно наиболее удобным способом: 2 608 + 529 + 392 + 271; 1 016 + 704 + 250 + 884 + 296.', '</p>\n\n<p class="text">\nВычисли устно наиболее удобным способом:<br/>\n2 608 + 529 + 392 + 271;<br/>\n1 016 + 704 + 250 + 884 + 296.\n</p>', '2 608 + 529 + 392 + 271 = (2608 + 392) + (529 + 271) = 3000 + 800 = 3 800; 1 016 + 704 + 250 + 884 + 296 = (1016 + 884) + (704 + 296) + 250 = 1900 + 1000 + 250 = 3 150.', '<p>\n2 608 + 529 + 392 + 271	= (2608 + 392) + (529 + 271) = 3000 + 800 = 3 800;<br/>\n1 016 + 704 + 250 + 884 + 296 = (1016 + 884) + (704 + 296) + 250 = 1900 + 1000 + 250 = 3 150.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-6/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ef109a2f352d65606da5b9b47c2e412e0a01d16b168eb895561646dfb69ad533', '1,2,016,250,271,296,392,529,608,704', '["вычисли"]'::jsonb, 'вычисли устно наиболее удобным способом:2 608+529+392+271; 1 016+704+250+884+296');

    VALUES (v_textbook_id, 6, '8', 3, 'Вырази в указанных единицах измерения: А) 3 м 8 см = … см; 12 км 25 м = … м; Б) 4 т 56 кг = … кг; 7 кг 42 г = … г.', '</p>\n\n<p class="text">\nВырази в указанных единицах измерения:<br/>\nА) 3 м 8 см = … см;<br/>\n12 км 25 м = … м;<br/>\nБ) 4 т 56 кг = … кг;<br/>\n7 кг 42 г = … г.\n</p>', 'А) 3 м 8 см = 300 см + 8 см = 308 см; 12 км 25 м = 12 000 м + 25 м = 12 025 м; Б) 4 т 56 кг = 4 000 кг + 56 кг = 4 056 кг; 7 кг 42 г = 7 000 г + 42 г = 7 042 г.', '<p>\nА) 3 м 8 см = 300 см + 8 см = 308 см;<br/>\n12 км 25 м = 12 000 м + 25 м = 12 025 м;<br/>\n<br/>\nБ) 4 т 56 кг = 4 000 кг + 56 кг = 4 056 кг;<br/>\n7 кг 42 г = 7 000 г + 42 г = 7 042 г.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-6/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '5fa9648e29b7f7ebcb72eb177d21461498d819adff6f743613e0634e2515912f', '3,4,7,8,12,25,42,56', '["раз"]'::jsonb, 'вырази в указанных единицах измерения:а) 3 м 8 см=... см; 12 км 25 м=... м; б) 4 т 56 кг=... кг; 7 кг 42 г=... г');

