    VALUES (v_textbook_id, 6, '11', 6, 'Реши уравнения с комментированием и сделай проверку: А) х ⋅ 6 = 720; Б) х : 380 = 400; в) 850 : х = 50; г) 900 ⋅ х = 3600; д) 964 + х = 1020; е) х – 2871 = 629.', '</p>\n\n<p class="text">\nРеши уравнения с комментированием и сделай проверку:<br/>\nА) х ⋅ 6 = 720;<br/>\nБ) х : 380 = 400;<br/>\nв) 850 : х = 50;<br/>\nг) 900 ⋅ х = 3600;<br/>\nд) 964 + х = 1020;<br/>\nе) х – 2871 = 629.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica6-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 6, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 6, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-6/')
