    VALUES (v_textbook_id, 6, '12', 7, 'Выполни деление с остатком и сделай проверку: 28 : 6; 47 : 8; 56 : 11; 70 : 15.', '</p>\n\n<p class="text">\nВыполни деление с остатком и сделай проверку:<br/>\n28 : 6;<br/>\n47 : 8;<br/>\n56 : 11;<br/>\n70 : 15.\n</p>', '28 : 6 = 4 (ост. 4); 47 : 8 = 5 (ост. 7); 56 : 11 = 5 (ост. 1); 70 : 15 = 4 (ост. 10).', '<p>\n28 : 6 = 4 (ост. 4);<br/>\n47 : 8 = 5 (ост. 7);<br/>\n56 : 11 = 5 (ост. 1);<br/>\n70 : 15 = 4 (ост. 10).\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-6/')
    RETURNING id INTO v_task_id;

