    VALUES (v_textbook_id, 6, '13', 8, 'Найди число, которое: А) при делении на 4 даёт частное 7 и остаток 2; Б) при делении на 5 даёт частное 0 и остаток 3.', '</p>\n\n<p class="text">\nНайди число, которое:<br/>\nА) при делении на 4 даёт частное 7 и остаток 2;<br/>\nБ) при делении на 5 даёт частное 0 и остаток 3.\n</p>', 'А) х : 4 = 7 (ост .2); Х = 4 ⋅ 7 + 2; Х = 30; Ответ: число 30; Б) х : 5 = 0 (ост. 3); Х = 5 ⋅ 0 + 3; Х = 3; Ответ: число 3.', '<p>\nА) х : 4 = 7 (ост .2);<br/>\nХ = 4 ⋅ 7 + 2;<br/>\nХ = 30;<br/>\nОтвет: число 30;<br/>\n<br/>\nБ) х : 5 = 0 (ост. 3);<br/>\nХ = 5 ⋅ 0 + 3;<br/>\nХ = 3;<br/>\nОтвет: число 3.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-6/')
    RETURNING id INTO v_task_id;

