    VALUES (v_textbook_id, 7, '4', 3, 'Реши уравнения. Сделай проверку с помощью калькулятора. х + 23 915 = 70 000; 820 315 – х = 96 325; х – 75 489 = 967.', '</p>\n\n<p class="text">\nРеши уравнения. Сделай проверку с помощью калькулятора.<br/>\nх + 23 915 = 70 000;<br/>\n820 315 – х = 96 325;<br/>\nх – 75 489 = 967.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica7-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 7, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 7, номер 4, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-7/')
