    VALUES (v_textbook_id, 7, '5', 4, 'Вырази число 540 807 в десятках и единицах; сотнях и единицах; тысячах и единицах. Единицы каких разрядов в нем отсутствуют? Представь это число в виде суммы разрядных слагаемых.', '</p>\n\n<p class="text">\nВырази число 540 807 в десятках и единицах; сотнях и единицах; тысячах и единицах. Единицы каких разрядов в нем отсутствуют?  Представь это число в виде суммы разрядных слагаемых.\n</p>', '54080 дес. 7 ед. 5408 сот. 7 ед. 540 тыс. 807 ед. Отсутствуют единицы разряда десятков и единиц тысяч 540 807 = 500 000 + 40 000 + 800 + 7.', '<p>\n54080 дес. 7 ед.<br/>\n5408 сот. 7 ед.<br/>\n540 тыс. 807 ед.<br/>\nОтсутствуют единицы разряда десятков и единиц тысяч<br/>\n540 807 = 500 000 + 40 000 + 800 + 7.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-7/')
    RETURNING id INTO v_task_id;

