    VALUES (v_textbook_id, 7, '6', 5, 'Дано число 32 068. Запиши новое число теми же цифрами, но в обратном порядке. На сколько полученное число больше данного?', '</p>\n\n<p class="text">\nДано число 32 068. Запиши новое число теми же цифрами, но в обратном порядке. На сколько полученное число больше данного?\n</p>', '32 068 – искомое число; 86 023 – новое число.', '<p>\n32 068 – искомое число;<br/>\n86 023 – новое число.\n</p>\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica7-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 7, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 7, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-7/')
