    VALUES (v_textbook_id, 7, '7', 6, 'За 3 месяца летних каникул Вася ходил на рыбалку 16 раз. В июне он рыбачил 3 раза, а в июле – в 2 раза больше, чем в июне. Сколько раз ходил Вася на рыбалку в августе?', '</p>\n\n<p class="text">\nЗа 3 месяца летних каникул Вася ходил на рыбалку 16 раз. В июне он рыбачил 3 раза, а в июле – в 2 раза больше, чем в июне. Сколько раз ходил Вася на рыбалку в августе?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica7-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 7, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 7, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-7/')
