    VALUES (v_task_id, v_textbook_id, 3, '849f720b1e534978793af9084c6cccdc0243666363aabd444b4ca7445e946b50', '2,3,16', '["больше","раз","раза"]'::jsonb, 'за 3 месяца летних каникул вася ходил на рыбалку 16 раз. в июне он рыбачил 3 раза, а в июле-в 2 раза больше, чем в июне. сколько раз ходил вася на рыбалку в августе');

    VALUES (v_textbook_id, 7, '8', 7, 'БЛИЦтурнир* А) В одной группе а туристов, а в другой – на 5 туристов больше. Сколько туристов в этих двух группах? Б) В куске b метров ткани. Одному покупателю отрезали с метров, а другому – d метров. Сколько метров ткани осталось после этого в куске? В) Сорвали m красных гвоздик, n розовых и k белых. Их всех этих гвоздик сделали букеты по 7 цветков в каждом. Сколько получилось букетов?', '</p>\n\n<p class="text">\nБЛИЦтурнир*<br/>\nА) В одной группе а туристов, а в другой – на 5 туристов больше. Сколько туристов в этих двух группах?<br/>\nБ) В куске b метров ткани. Одному покупателю отрезали с метров, а другому – d метров. Сколько метров ткани осталось после этого в куске?<br/>\nВ) Сорвали m красных гвоздик, n розовых и k белых. Их всех этих гвоздик сделали букеты по 7 цветков в каждом. Сколько получилось букетов?\n</p>', 'а + (а + 5) (чел.) – туристов в двух группах; b – (с + d) (м) – ткани осталось в куске; (m + n + k) : 7 (шт.) – букетов по 7 цветов получилось.', '<p>\nа + (а + 5) (чел.) – туристов в двух группах;<br/>\nb – (с + d) (м) – ткани осталось в куске;<br/>\n(m + n + k) : 7 (шт.) – букетов по 7 цветов получилось.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-7/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '81079f2e2691a6cc5ef7f878cdd2b7c21c2a1c1f006c0f1ee5f473cfa7c5c556', '5,7', '["больше"]'::jsonb, 'блицтурнир*а) в одной группе а туристов, а в другой-на 5 туристов больше. сколько туристов в этих двух группах? б) в куске b метров ткани. одному покупателю отрезали с метров, а другому-d метров. сколько метров ткани осталось после этого в куске? в) сорвали m красных гвоздик, n розовых и k белых. их всех этих гвоздик сделали букеты по 7 цветков в каждом. сколько получилось букетов');

    VALUES (v_textbook_id, 8, '9', 0, 'На рисунке изображен план земельного участка и указаны некоторые его размеры. Найди площадь этого участка и его периметр.', '</p>\n\n<p class="text">На рисунке изображен план земельного участка и указаны некоторые его размеры. Найди площадь этого участка и его периметр.</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica8-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 8, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 8, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-8/')
