    VALUES (v_task_id, v_textbook_id, 3, 'a062338ebee9a9f08e1bde700b6f6a5e2343d34be059dea981aa8b4f536b96d4', NULL, '["найди","периметр","площадь","раз"]'::jsonb, 'на рисунке изображен план земельного участка и указаны некоторые его размеры. найди площадь этого участка и его периметр');

    VALUES (v_textbook_id, 8, '10', 1, 'Длина садового участка прямоугольной формы 40 м, а площадь – 8 соток (1 сотка = 100 м 2 ). Чему равна длина изгороди, расположенной по периметру этого участка?', '</p>\n\n<p class="text">Длина садового участка прямоугольной формы 40 м, а площадь – 8 соток (1 сотка = 100 м<sub>2</sub>). Чему равна длина изгороди, расположенной по периметру этого участка?</p>', '1) 100 м 2 ⋅ 8 = 800 м 2 – площадь участка; 2) 800 : 40 = 20 (м) – длина изгороди; 3) (20 + 40) ⋅ 2 = 120 (м) – длина изгороди у этого участка; Ответ: 120 метров.', '<p>\n1) 100 м<sub>2</sub> ⋅ 8 = 800 м<sub>2</sub> – площадь участка;<br/>\n2) 800 : 40 = 20 (м) – длина изгороди;<br/>\n3) (20 + 40) ⋅ 2 = 120 (м) – длина изгороди у этого участка;<br/>\nОтвет: 120 метров.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-8/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '564d4ca3124c532f5f6782dd619cd9f42605a0ac45c3af7ffd9f77e2a7bac600', '1,2,8,40,100', '["периметр","площадь"]'::jsonb, 'длина садового участка прямоугольной формы 40 м, а площадь-8 соток (1 сотка=100 м 2 ). чему равна длина изгороди, расположенной по периметру этого участка');

    VALUES (v_textbook_id, 8, '11', 2, 'Вычисли: А) 2 м 7 см – 9 дм 8 см + 710 мм; Б) 5 м 2 дм – 64 см + 1 м 4 см; В) 3 т 15 кг + 4 ц 8 кг – 23 кг; Г) 46 кг 32 г – 2 кг 800 г + 768 г.', '</p>\n\n<p class="text">Вычисли:<br/>\nА) 2 м 7 см – 9 дм 8 см + 710 мм;<br/>\nБ) 5 м 2 дм – 64 см + 1 м 4 см;<br/>\nВ) 3 т 15 кг + 4 ц 8 кг – 23 кг;<br/>\nГ) 46 кг 32 г – 2 кг 800 г + 768 г.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica8-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 8, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 8, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-8/')
    RETURNING id INTO v_task_id;

