    VALUES (v_task_id, v_textbook_id, 3, 'f6c62e4d20a991484607cf01947e4f7e00518cb63164d5e9418cf9ed311f8177', '1,2,3,4,5,7,8,9,15,23', '["вычисли"]'::jsonb, 'вычисли:а) 2 м 7 см-9 дм 8 см+710 мм; б) 5 м 2 дм-64 см+1 м 4 см; в) 3 т 15 кг+4 ц 8 кг-23 кг; г) 46 кг 32 г-2 кг 800 г+768 г');

    VALUES (v_textbook_id, 8, '12', 3, 'Реши примеры. Расшифруй и отгадай загадку. Р. 250 + 700; О. 482 – 60; Г . 649 – 40 – 9; В. 40 ⋅ 80 : 100; Н. 3 ⋅ 26 – 18; Е. 880 : 44 ⋅ 9; И. 4 + 96 : 2; Т. 200 ⋅ 7 : 10; Д. 80 : 16 ⋅ 9.', '</p>\n\n<p class="text">Реши примеры. Расшифруй и отгадай загадку.<br/>\nР. 250 + 700;<br/>\nО. 482 – 60;<br/>\nГ . 649 – 40 – 9;<br/>\nВ. 40 ⋅ 80 : 100;<br/>\nН. 3 ⋅ 26 – 18;<br/>\nЕ. 880 : 44 ⋅ 9;<br/>\nИ. 4 + 96 : 2;<br/>\nТ. 200 ⋅ 7 : 10;<br/>\nД. 80 : 16 ⋅ 9.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica8-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 8, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 8, номер 12, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-8/')
    RETURNING id INTO v_task_id;

