    VALUES (v_task_id, v_textbook_id, 3, 'e4b9718d417ce61c63976242fb2a153f143dcb0b7c2968b78462c1d87fcc44f3', '2,3,4,7,9,10,16,18,26,40', '["реши"]'::jsonb, 'реши примеры. расшифруй и отгадай загадку. р. 250+700; о. 482-60; г . 649-40-9; в. 40 ⋅ 80:100; н. 3 ⋅ 26-18; е. 880:44 ⋅ 9; и. 4+96:2; т. 200 ⋅ 7:10; д. 80:16 ⋅ 9');

    VALUES (v_textbook_id, 8, '13', 4, 'А) Через 2 ч 40 мин наступит полночь. Который сейчас час? Б) сколько месяцев имеют в названии 4 буквы, 7 букв?', '</p>\n\n<p class="text">\nА) Через 2 ч 40 мин наступит полночь. Который сейчас час?<br/>\nБ) сколько месяцев имеют в названии 4 буквы, 7 букв?\n\n</p>', 'А) через 2 ч 40 мин наступит полночь, т.е. 00 : 00 и стрелка минутная и часовая будет на 12. Получается, что сейчас 9 ч мин; Б) 4 буквы – март, июнь, июль; 7 букв – декабрь, февраль, октябрь.', '<p>\nА) через 2 ч 40 мин наступит полночь, т.е. 00 : 00 и стрелка минутная и часовая будет на 12.\nПолучается, что сейчас 9 ч мин;<br/>\nБ) 4 буквы – март, июнь, июль; 7 букв – декабрь, февраль, октябрь.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-8/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd91de7464ed76d968d695a6d16bf2738cf08853d98055b9563458bb08f9ccb3c', '2,4,7,40', NULL, 'а) через 2 ч 40 мин наступит полночь. который сейчас час? б) сколько месяцев имеют в названии 4 буквы, 7 букв');

    VALUES (v_textbook_id, 8, '14', 5, 'На календаре 2014 год. Сумма цифр этого числа равна 7. Через сколько лет повторится такая же сумма?', '</p>\n\n<p class="text">На календаре 2014 год. Сумма цифр этого числа равна 7. Через сколько лет повторится такая же сумма?\n</p>', '2014 = 2 + 1 + 4 = 7; 2015 = 2 + 1 + 5 = 8; 2016 = 2 + 1 + 6 = 9; 2017 = 2 + 1 + 7 = 10; 2018 = 2 + 1 + 8 = 11; 2019 = 2 + 1 + 9 = 12; 2020 = 2 + 2 = 4; 2021 = 2 + 2 + 1 = 5; 2022 = 2 + 2 + 2 = 6; 2023 = 2 + 2 + 3 = 7. Значит, такая же сумма повторится через 9 лет. Ответ: через 9 лет.', '<p>\n2014 = 2 + 1 + 4 = 7;<br/>\n2015 = 2 + 1 + 5 = 8;<br/>\n2016 = 2 + 1 + 6 = 9;<br/>\n2017 = 2 + 1 + 7 = 10;<br/>\n2018 = 2 + 1 + 8 = 11;<br/>\n2019 = 2 + 1 + 9 = 12;<br/>\n2020 = 2 + 2 = 4;<br/>\n2021 = 2 + 2 + 1 = 5;<br/>\n2022 = 2 + 2 + 2 = 6;<br/>\n2023 = 2 + 2 + 3 = 7.<br/>\nЗначит, такая же сумма повторится через 9 лет.<br/>\nОтвет: через 9 лет.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-8/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4835fd125c15f01321955c476a1cde0cd6daa29db9048c43675f044301ed1194', '7,2014', '["сумма"]'::jsonb, 'на календаре 2014 год. сумма цифр этого числа равна 7. через сколько лет повторится такая же сумма');

    VALUES (v_textbook_id, 9, '1', 0, 'Практическая работа. Вырежи из бумаги две полоски разной длины. Покажи, как найти их сумму, их разность? Что получится, если из суммы полосок вычесть их разность? А если к сумме прибавить разность?', '</p>\n\n<p class="text">Практическая работа.<br/>\nВырежи из бумаги две полоски разной длины. Покажи, как найти их сумму, их разность?<br/>\nЧто получится, если из суммы полосок вычесть их разность? А если к сумме прибавить разность?\n</p>', 'Чтобы найти их сумму, нужно сопоставить начало и конец отрезков.. Чтобы найти разность отрезков, нужно сопоставить их начала. Если из суммы полосок вычесть их разность, то получится удвоенная длина меньшего отрезка. Если сложить сумму полосок и их разность, то получится удвоенная длина большего отрезка.', '<p>\nЧтобы найти их сумму, нужно сопоставить начало и конец отрезков..<br/>\nЧтобы найти разность отрезков, нужно сопоставить их начала.<br/>\nЕсли из суммы полосок вычесть их разность, то получится удвоенная длина меньшего отрезка.<br/>\nЕсли сложить сумму полосок и их разность, то получится удвоенная длина большего отрезка.\n</p>', 'Нахождение чисел по их сумме и разности При сложении суммы и разности двух чисел получается удвоенное больше число, а при вычитании – удвоенное меньшее число. (б – большее число, м – меньшее число, с – сумма, р – разность) Алгоритм нахождения чисел по их сумме и разности. 1 способ: 1.Сложить сумму и разность. 2.Разделить на 2 (б). 3.Вычесть разность (м). б = (с + р) : 2. м = б – р. 2 способ: 1.Из суммы вычесть разность. 2.Разделить на 2 (м). 3.Прибавить разность (б). м = (с – р) : 2. б = м + р.', '<div class="recomended-block">\n<span class="title">Нахождение чисел по их сумме и разности</span>\n<p>\nПри сложении суммы и разности двух чисел получается удвоенное больше число, а при вычитании – удвоенное меньшее число.<br/>\n(б – большее число, м – меньшее число, с – сумма, р – разность)<br/>\n<br/>\n<b class="black">Алгоритм нахождения чисел по их сумме и разности.</b><br/>\n1 способ:<br/>\n1.Сложить сумму и разность.<br/>\n2.Разделить на 2 (б).<br/>\n3.Вычесть разность (м).<br/>\nб = (с + р) : 2.<br/>\nм = б – р.<br/>\n<br/>\n2 способ:<br/>\n1.Из суммы вычесть разность.<br/>\n2.Разделить на 2 (м).<br/>\n3.Прибавить разность (б).<br/>\nм = (с – р) : 2.<br/>\nб = м + р.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-9/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '5899afe09e8d8ea11e63de4400ca34cb33ae67234013813e8384360343ce243f', NULL, '["разность","раз"]'::jsonb, 'практическая работа. вырежи из бумаги две полоски разной длины. покажи, как найти их сумму, их разность? что получится, если из суммы полосок вычесть их разность? а если к сумме прибавить разность');

    VALUES (v_textbook_id, 9, '2', 1, 'В двух классах 56 человек, причем в первом классе на 2 человека больше, чем во втором. Сколько человек в каждом классе?', '</p>\n\n<p class="text">В двух классах 56 человек, причем в первом классе на 2 человека больше, чем во втором. Сколько человек в каждом классе?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica9-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 9, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 9, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-9/')
    RETURNING id INTO v_task_id;

