    VALUES (v_textbook_id, 9, '3', 2, 'В двух сумках 18 кг продуктов, причем в первой сумке на 4 кг меньше, чем во второй. Сколько килограммов продуктов в каждой сумке?', '</p>\n\n<p class="text">В двух сумках 18 кг продуктов, причем в первой сумке на 4 кг меньше, чем во второй. Сколько килограммов продуктов в каждой сумке?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica9-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 9, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 9, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-9/')
