    VALUES (v_task_id, v_textbook_id, 3, '1dce52ec0346222224eb1a4e08d70308da1a0d9d99920c685b015fe0d8b0599d', '4,18', '["меньше"]'::jsonb, 'в двух сумках 18 кг продуктов, причем в первой сумке на 4 кг меньше, чем во второй. сколько килограммов продуктов в каждой сумке');

    VALUES (v_textbook_id, 10, '4', 0, 'Найди два числа, если: А) их сумма равна 15, а разность – 3; Б) разность этих чисел равна 48, а сумма – 132; В) сумма чисел равна с, а разность – d; Г) разность чисел равна х, а сумма – у.', '</p>\n\n<p class="text">Найди два числа, если:<br/>\nА) их сумма равна 15, а разность – 3;<br/>\nБ) разность этих чисел равна 48, а сумма – 132;<br/>\nВ) сумма чисел равна с, а разность – d;<br/>\nГ) разность чисел равна х, а сумма – у.\n</p>', 'А) Это числа 6 и 9; 15 – 3 = 12 – сумма, если бы числа были одинаковыми; 12 : 2 = 6 – первое число; 6 + 3 = 9 – второе число; Б) Это числа 42 и 90; 132 – 48 = 84 – сумма , если бы числа были одинаковыми; 84 : 2 = 42 – первое число; 42 + 48 = 90 – второе число; В) С – d – сумма, если бы числа были одинаковыми; (с – d) : 2 – первое число; (с – d) : 2 + d – второе число; Г) (у – х) – сумма, если вы бы числа были одинаковыми; (у – х) : 2 – первое число; (у – х) : 2 + х – второе число.', '<p>\nА) Это числа 6 и 9;<br/>\n15 – 3 = 12 – сумма, если бы числа были одинаковыми;<br/>\n12 : 2 = 6 – первое число;<br/>\n6 + 3 = 9 – второе число;<br/>\n<br/>\nБ) Это числа 42 и 90;<br/>\n132 – 48 = 84 – сумма , если бы числа были одинаковыми;<br/>\n84 : 2 = 42 – первое число;<br/>\n42 + 48 = 90 – второе число;<br/>\n<br/>\nВ)<br/>\nС – d – сумма, если бы числа были одинаковыми;<br/>\n(с – d) : 2 – первое число;<br/>\n(с – d) : 2 + d – второе число;<br/>\n<br/>\nГ)<br/>\n(у – х) – сумма, если вы бы числа были одинаковыми;<br/>\n(у – х) : 2 – первое число;<br/>\n(у – х) : 2 + х – второе число.\n\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-10/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '8702903c2feb8ca803e0d58bd9a330d1166a858a2775444bd3bc5033f23f83b3', '3,15,48,132', '["найди","сумма","разность","раз"]'::jsonb, 'найди два числа, если:а) их сумма равна 15, а разность-3; б) разность этих чисел равна 48, а сумма-132; в) сумма чисел равна с, а разность-d; г) разность чисел равна х, а сумма-у');

    VALUES (v_textbook_id, 10, '5', 1, 'А) У Пети и Мити вместе 248 марок, причем у Пети на 8 марок меньше, чем у Мити. Сколько марок у каждого из ребят? Б) У Ани и Даши вместе 372 открытки, причем у Ани на 12 открыток больше, чем у Даши. Сколько открыток у каждой из девочек?', '</p>\n\n<p class="text">\nА) У Пети и Мити вместе 248 марок, причем у Пети на 8 марок меньше, чем у Мити. Сколько марок у каждого из ребят?<br/>\nБ) У Ани и Даши вместе 372 открытки, причем у Ани на 12 открыток больше, чем у Даши. Сколько открыток у каждой из девочек?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica10-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 10, номер 5, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 10, номер 5, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-10/')
    RETURNING id INTO v_task_id;

