    VALUES (v_task_id, v_textbook_id, 3, 'f8fa36f751fb1eb4b59cf6d048e0cfe05490b8c9bbb742d1911bec41765066ea', '8,12,248,372', '["больше","меньше"]'::jsonb, 'а) у пети и мити вместе 248 марок, причем у пети на 8 марок меньше, чем у мити. сколько марок у каждого из ребят? б) у ани и даши вместе 372 открытки, причем у ани на 12 открыток больше, чем у даши. сколько открыток у каждой из девочек');

    VALUES (v_textbook_id, 10, '6', 2, '(Устно.) Определи, что показывают стрелки. Выполни все указанные действия.', '</p>\n\n<p class="text">\n(Устно.) Определи, что показывают стрелки. Выполни все указанные действия.\n</p>', '8 + 12 = 20; 8 + 60 = 68; 8 + 7 = 15; 25 + 12 = 37; 25 + 60 = 85; 25 + 7 = 32; 79 + 12 = 91; 79 + 60 = 139; 79 + 7 = 86; 36 – 32 = 4; 36 – 16 = 20; 36 – 4 = 32; 50 – 32 = 18; 50 – 16 = 34; 50 – 4 = 46; 91 – 32 = 59; 91 – 16 = 75; 91 – 4 = 87; 5 ⋅ 30 = 15; 5 ⋅ 10 = 50; 5 ⋅ 6 = 30; 12 ⋅ 30 = 360; 12 ⋅ 10 = 120; 12 ⋅ 6 = 72; 80 ⋅ 30 = 2400; 80 ⋅ 10 = 800; 80 ⋅ 6 = 480; 56 : 1 = 56; 56 : 28 = 2; 56 : 7 = 8; 28 : 1 = 28; 28 : 28 = 1; 28 : 7 = 4; 84 : 1 = 84; 84 : 28 = 3; 84 : 7 = 12.', '<p>\n8 + 12 = 20;<br/>\n8 + 60 = 68;<br/>\n8 + 7 = 15;<br/>\n\n25 + 12 = 37;<br/>\n25 + 60 = 85;<br/>\n25 + 7 = 32;<br/>\n\n79 + 12 = 91;<br/>\n79 + 60 = 139;<br/>\n79 + 7 = 86;<br/>\n\n36 – 32 = 4;<br/>\n36 – 16 = 20;<br/>\n36 – 4 = 32;<br/>\n\n50 – 32 = 18;<br/>\n50 – 16 = 34;<br/>\n50 – 4 = 46;<br/>\n\n91 – 32 = 59;<br/>\n91 – 16 = 75;<br/>\n91 – 4 = 87;<br/>\n\n5 ⋅ 30 = 15;<br/>\n5 ⋅ 10 = 50;<br/>\n5 ⋅ 6 = 30;<br/>\n\n12 ⋅ 30 = 360;<br/>\n12 ⋅ 10 = 120;<br/>\n12 ⋅ 6 = 72;<br/>\n\n80 ⋅ 30 = 2400;<br/>\n80 ⋅ 10 = 800;<br/>\n80 ⋅ 6 = 480;<br/>\n\n56 : 1 = 56;<br/>\n56 : 28 = 2;<br/>\n56 : 7 = 8;<br/>\n\n28 : 1 = 28;<br/>\n28 : 28 = 1;<br/>\n28 : 7 = 4;<br/>\n\n84 : 1 = 84;<br/>\n84 : 28 = 3;<br/>\n84 : 7 = 12.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-10/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6e5d24a24cef53b79df8efa6de7302db8626edf377c0800e19cdc2bd6b22d0ba', NULL, NULL, '(устно.) определи, что показывают стрелки. выполни все указанные действия');

    VALUES (v_textbook_id, 10, '7', 3, 'Найди значения произведений. Проверь результаты с помощью калькулятора. 140 ⋅ 5; 270 ⋅ 3; 106 ⋅ 7; 4 ⋅ 509; 3270 ⋅ 8; 200 ⋅ 936; 80 160 ⋅ 300; 720 400 ⋅ 500. Что общего в примерах каждого столбика?', '</p>\n\n<p class="text">\nНайди значения произведений. Проверь результаты с помощью калькулятора.<br/>\n140 ⋅ 5;<br/>\n270 ⋅ 3;<br/>\n106 ⋅ 7;<br/>\n4 ⋅ 509;<br/>\n3270 ⋅ 8;<br/>\n200 ⋅ 936;<br/>\n80 160 ⋅ 300;<br/>\n720 400 ⋅ 500.<br/>\nЧто общего в примерах каждого столбика?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica10-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 10, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 10, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-10/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica10-nomer7.jpg', 'peterson/3/part2/page10/task7_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '14ee68b722dd0a2542d643032fc67bc7d4826537466c0265018e8f0911a7a616', '3,4,5,7,8,80,106,140,160,200', '["найди","столбик"]'::jsonb, 'найди значения произведений. проверь результаты с помощью калькулятора. 140 ⋅ 5; 270 ⋅ 3; 106 ⋅ 7; 4 ⋅ 509; 3270 ⋅ 8; 200 ⋅ 936; 80 160 ⋅ 300; 720 400 ⋅ 500. что общего в примерах каждого столбика');

    VALUES (v_textbook_id, 10, '8', 4, 'Определи, сколько груш должно лежать на свободной чаше весов.', '</p>\n\n<p class="text">\nОпредели, сколько груш должно лежать на свободной чаше весов.\n</p>', 'Рассмотрим первые весы Чаши находятся в равновесии, значит, масса груза на них одинакова. Груша + 4 яблока = 2 груши + 2 яблока Получается, что 1 груша весит, как 2 яблока Так как на первой чаше 6 яблок, то на правую чашу нужно положить 3 груши.', '<p>\nРассмотрим первые весы<br/>\nЧаши находятся в равновесии, значит, масса груза на них одинакова.<br/>\nГруша + 4 яблока = 2 груши + 2 яблока<br/>\nПолучается, что 1 груша весит, как 2 яблока<br/>\n<br/>\nТак как на первой чаше 6 яблок, то на правую чашу нужно положить 3 груши.\n</p>', 'Множество Когда какие-нибудь объекты собирают вместе, в математике для их названия используют общее слово – множество . Сказать «стадо чашек» нельзя, а множество чашек – можно. Можно сказать: множество коров, множество птиц, множество цветов, множество марок, множество учеников и т. д.', '<div class="recomended-block">\n<span class="title">Множество</span>\n<p>\nКогда какие-нибудь объекты собирают вместе, в математике для их названия используют общее слово – <b class="black">множество</b>.<br/>\nСказать «стадо чашек» нельзя, а множество чашек – можно.<br/>\nМожно сказать: множество коров, множество птиц, множество цветов, множество марок, множество учеников и т. д.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-10/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1051291ba94b74024518f2eb0dc4337dbae9d28a88b3cf6059afb68a8f337f8f', NULL, NULL, 'определи, сколько груш должно лежать на свободной чаше весов');

    VALUES (v_textbook_id, 10, '9', 5, 'Найди значения выражений: А) 40 800 ⋅ (3500 : 70) : 100 – 328 ⋅ 60; Б) 1321 + (1600 – 600 ⋅ 2550 : 1000) ⋅ 8097.', '</p>\n\n<p class="text">\nНайди значения выражений:<br/>\nА) 40 800 ⋅ (3500 : 70) : 100 – 328 ⋅ 60;<br/>\nБ) 1321 + (1600 – 600 ⋅ 2550 : 1000) ⋅ 8097.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica10-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 10, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 10, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-10/')
