    VALUES (v_task_id, v_textbook_id, 3, 'bbe552305faa52c085042ecfe0fe6f108a4d939404b14e14f365e74d373a9936', '40,60,70,100,328,600,800,1000,1321,1600', '["найди"]'::jsonb, 'найди значения выражений:а) 40 800 ⋅ (3500:70):100-328 ⋅ 60; б) 1321+(1600-600 ⋅ 2550:1000) ⋅ 8097');

    VALUES (v_textbook_id, 10, '10', 6, 'Установи закономерность и найди пропущенное число:', '</p>\n\n<p class="text">\nУстанови закономерность и найди пропущенное число:\n</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica10-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 10, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 10, номер 10, год 2022."/>\n</div>', 'А) Числа первого ряда умножают само на себя. 2 ⋅ 2 = 4; 3 ⋅ 3 = 9; 4 ⋅ 4 = 16; 5 ⋅ 5 = 25; Б) Число первого ряда умножают само на себя и прибавляют единицу: 2 ⋅ 2 + 1 = 5; 3 ⋅ 3 + 1 = 10; 4 ⋅ 4 + 1 = 17; 5 ⋅ 5 + 1 = 26; Б) Число первого ряда умножают само на себя и вычитают единицу: 2 ⋅ 2 - 1 = 3; 3 ⋅ 3 - 1 = 8; 4 ⋅ 4 - 1 = 15; 5 ⋅ 5 - 1 = 24.', '<p>\nА) Числа первого ряда умножают само на себя.<br/>\n2 ⋅ 2 = 4;<br/>\n3 ⋅ 3 = 9;<br/>\n4 ⋅ 4 = 16;<br/>\n5 ⋅ 5 = 25;<br/>\nБ) Число первого ряда умножают само на себя и прибавляют единицу:<br/>\n2 ⋅ 2 + 1 = 5;<br/>\n3 ⋅ 3 + 1 = 10;<br/>\n4 ⋅ 4 + 1 = 17;<br/>\n5 ⋅ 5 + 1 = 26;<br/>\nБ) Число первого ряда умножают само на себя и вычитают единицу:<br/>\n2 ⋅ 2 - 1 = 3;<br/>\n3 ⋅ 3 - 1 = 8;<br/>\n4 ⋅ 4 - 1 = 15;<br/>\n5 ⋅ 5 - 1 = 24.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-10/')
    RETURNING id INTO v_task_id;

