    VALUES (v_textbook_id, 11, '1', 0, 'Составь схему и реши задачу: А) Две ручки стоят вместе 78 р., причем первая ручка на 6 р. дороже второй. Сколько рублей стоит каждая из этих ручек? Б) Дима и Валера весят вместе 100 кг, причем Дима на 8 кг тяжелее, чем Валера. Сколько килограммов весит каждый из ребят?', '</p>\n\n<p class="text">Составь схему и реши задачу:<br/>\nА) Две ручки стоят вместе 78 р., причем первая ручка на 6 р. дороже второй. Сколько рублей стоит каждая из этих ручек?<br/>\nБ) Дима и Валера весят вместе 100 кг, причем Дима на 8 кг тяжелее, чем Валера. Сколько килограммов весит каждый из ребят?\n</p>', '', '<div class="img-wrapper-460">\n<img width="650" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica11-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 11, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 11, номер 1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-11/')
    RETURNING id INTO v_task_id;

