    VALUES (v_task_id, v_textbook_id, 3, '9f8e55e4a2acd4f15e8f3af78efc860f2aa979cca3ff7876a9a83649cc8ab001', '6,8,78,100', '["реши"]'::jsonb, 'составь схему и реши задачу:а) две ручки стоят вместе 78 р., причем первая ручка на 6 р. дороже второй. сколько рублей стоит каждая из этих ручек? б) дима и валера весят вместе 100 кг, причем дима на 8 кг тяжелее, чем валера. сколько килограммов весит каждый из ребят');

    VALUES (v_textbook_id, 11, '2', 1, 'Запиши умножение в столбик и вычисли: А) 3 000 ⋅ 46; Б) 9 670 ⋅ 20; В) 3800 ⋅ 9; Г) 7 040 ⋅ 60; Д) 4 000 ⋅ 520; Е) 90 500 ⋅ 80; Ж) 869 000 ⋅ 70; З) 5 000 ⋅ 120 056.', '</p>\n\n<p class="text">Запиши умножение в столбик и вычисли:<br/>\nА) 3 000 ⋅ 46;<br/>\nБ) 9 670 ⋅ 20;<br/>\nВ) 3800 ⋅ 9;<br/>\nГ) 7 040 ⋅ 60;<br/>\nД) 4 000 ⋅ 520;<br/>\nЕ) 90 500 ⋅ 80;<br/>\nЖ) 869 000 ⋅ 70;<br/>\nЗ) 5 000 ⋅ 120 056.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica11-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 11, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 11, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-11/')
