    VALUES (v_textbook_id, 11, '5', 4, 'БЛИЦтурнир. А) Купили 12 пирожков по а р. за штуку и торт за b р. Сколько всего денег заплатили? Б) В трех одинаковых пакетах n кг муки. Сколько килограммов муки в 10 таких пакетах? В) На двух клумбах посадили поровну s кустов роз. Сколько клумб надо сделать, чтобы разместить на них так же t кустов роз? Г) Надоили с л молока. Из а литров сделали творог, а остальное молоко разлили поровну в 4 банки. Сколько литров молока в каждой банке?', '</p>\n\n<p class="text">\nБЛИЦтурнир.<br/>\nА) Купили 12 пирожков по а р. за штуку и торт за b р. Сколько всего денег заплатили?<br/>\nБ) В трех одинаковых пакетах n кг муки. Сколько килограммов муки в 10 таких пакетах?<br/>\nВ) На двух клумбах посадили поровну s кустов роз. Сколько клумб надо сделать, чтобы разместить на них так же t кустов роз?<br/>\nГ) Надоили  с л молока. Из а литров сделали творог, а остальное молоко разлили поровну в 4 банки. Сколько литров молока в каждой банке?\n</p>', 'А) а ⋅ 12 + b (р.) – всего денег заплатили; Б) n : 3 ⋅ 10 (кг) – муки в 10 таких пакетах; В) t : (s : 2) (шт.) – клумб нужно сделать, чтобы разместить t кустов; Г) (c – a) : 4 (л) – молока в каждой банке.', '<p>\nА) а ⋅ 12 + b (р.) – всего денег заплатили;<br/>\nБ) n : 3 ⋅ 10 (кг) – муки в 10 таких пакетах;<br/>\nВ) t : (s : 2) (шт.) – клумб нужно сделать, чтобы разместить t кустов;<br/>\nГ) (c – a) : 4 (л) – молока в каждой банке.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-11/')
    RETURNING id INTO v_task_id;

