    VALUES (v_textbook_id, 11, '6', 5, 'Запиши число 5 млрд 36 млн 4 тыс. Какая цифра стоит в разряде единиц миллионов этого числа? Сколько в нем всего миллионов?', '</p>\n\n<p class="text">\nЗапиши число 5 млрд 36 млн 4 тыс. Какая цифра стоит в разряде единиц миллионов этого числа? Сколько в нем всего миллионов?\n</p>', '5 036 004 000; В разряде единиц миллионов – цифра 6; Всего миллионов –5 036.', '<p>\n5 036 004 000;<br/>\nВ разряде единиц миллионов – цифра 6;<br/>\nВсего миллионов –5 036.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-11/')
    RETURNING id INTO v_task_id;

