    VALUES (v_textbook_id, 11, '7', 6, 'Вычисли устно наиболее удобным способом: 317 + 9896 + 104 + 183; 52 + 81 + 25 + 319 + 48.', '</p>\n\n<p class="text">\nВычисли устно наиболее удобным способом:<br/>\n317 + 9896 + 104 + 183;<br/>\n52 + 81 + 25 + 319 + 48.\n</p>', '317 + 9896 + 104 + 183 = (317 + 183) + (9896 + 104) = 500 + 10 000 = 10 500; 52 + 81 + 25 + 319 + 48 = (52 + 48) + (81 + 319) + 25 = 100 + 400 + 25 = 525.', '<p>\n317 + 9896 + 104 + 183	= (317 + 183) + (9896 + 104) = 500 + 10 000 = 10 500;<br/>	\n52 + 81 + 25 + 319 + 48 = (52 + 48) + (81 + 319) + 25 = 100 + 400 + 25 = 525.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-11/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '51df755dd93c4a0c25bcc6e0379c52fcfe5cfd82d07b48dbed1cf5f3f9a56a2f', '25,48,52,81,104,183,317,319,9896', '["вычисли"]'::jsonb, 'вычисли устно наиболее удобным способом:317+9896+104+183; 52+81+25+319+48');

    VALUES (v_textbook_id, 12, '8', 0, 'Вырази: А) в метрах: 35 км 12м; 8 600 дм; 500 см; 70 000 мм; Б) в миллиметрах: 4 см 2 мм; 5 дм 9 мм; 7 дм 4 см; В) в килограммах: 8 т 3 ц; 4 ц 5 кг; 78 000 г; Г) в граммах: 6 кг 12 г; 24 кг; 9 ц.', '</p>\n\n<p class="text">Вырази:<br/>\nА) в метрах: 35 км 12м; 8 600 дм; 500 см; 70 000 мм;<br/>\nБ) в миллиметрах: 4 см 2 мм; 5 дм 9 мм; 7 дм 4 см;<br/>\nВ) в килограммах: 8 т 3 ц; 4 ц 5 кг; 78 000 г;<br/>\nГ) в граммах: 6 кг 12 г; 24 кг; 9 ц.\n</p>', 'А) в метрах: 35 км 12 м = 35 000 м + 12 м = 35 012 м; 8 600 дм = 860 м; 500 см = 5 м; 70 000 мм = 7 000 см = 70 м; Б) в миллиметрах: 4 см 2 мм = 40 мм + 2 мм = 42 мм; 5 дм 9 мм = 500 мм + 9 мм = 509 мм; 7 дм 4 см = 700 мм + 40 мм = 740 мм; В) в килограммах: 8 т 3 ц = 8 000 кг + 300 кг = 8 300 кг; 4 ц 5 кг = 400 кг + 5 кг = 405 кг; 78 000 г = 78 кг; Г) в граммах: 6 кг 12 г = 6 000 г + 12 г = 6 012 г; 24 кг = 24 000 г; 9 ц = 900 кг = 900 000 г.', '<p>\nА) в метрах:<br/>\n35 км 12 м = 35 000 м + 12 м = 35 012 м;<br/>\n8 600 дм = 860 м;<br/>\n500 см = 5 м;<br/>\n70 000 мм = 7 000 см = 70 м;<br/>\nБ) в миллиметрах:<br/>\n4 см 2 мм = 40 мм + 2 мм = 42 мм;<br/>\n5 дм 9 мм = 500 мм + 9 мм = 509 мм;<br/>\n7 дм 4 см = 700 мм + 40 мм = 740 мм;<br/>\nВ) в килограммах:<br/>\n8 т 3 ц = 8 000 кг + 300 кг = 8 300 кг;<br/>\n4 ц 5 кг = 400 кг + 5 кг = 405 кг;<br/>\n78 000 г = 78 кг;<br/>\nГ) в граммах:<br/>\n6 кг 12 г = 6 000 г + 12 г = 6 012 г;<br/>\n24 кг = 24 000 г;<br/>\n9 ц = 900 кг = 900 000 г.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-12/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '534d4a6de9a3f3e6655724b6120da73b237b8fd6120471f1dcdfc4f50e9efbda', '000,2,3,4,5,6,7,8,9,12', '["раз"]'::jsonb, 'вырази:а) в метрах:35 км 12м; 8 600 дм; 500 см; 70 000 мм; б) в миллиметрах:4 см 2 мм; 5 дм 9 мм; 7 дм 4 см; в) в килограммах:8 т 3 ц; 4 ц 5 кг; 78 000 г; г) в граммах:6 кг 12 г; 24 кг; 9 ц');

    VALUES (v_textbook_id, 12, '9', 1, 'Сравни выражения: 15 ⋅ а … а ⋅ 15; b : 9 … b : 12; 40 : m … 50 : m; с ⋅ 1 … с : 1; (6 + d) ⋅ 3 … 6 + d ⋅ 3; (а + b) : 5 … а : 5 + b : 5.', '</p>\n\n<p class="text">\nСравни выражения:<br/>\n15 ⋅ а … а ⋅ 15;<br/>\nb : 9 … b : 12;<br/>\n40 : m … 50 : m;<br/>\nс ⋅ 1 … с : 1;<br/>\n(6 + d) ⋅ 3 … 6 + d ⋅ 3;<br/>\n(а + b) : 5 … а : 5 + b : 5.\n</p>', '15 ⋅ а = а ⋅ 15, по переместительному свойству умножения; b : 9 > b : 12, потому что, при одинаковом делимом, значение частного больше там, где делитель меньше; 40 : m < 50 : m, потому что при одинаковом делителе, значение частного будет больше там, где делимое больше; с ⋅ 1 = с : 1, потому что при умножении и делении на единицу получается то число, которое умножали или делили; (6 + d) ⋅ 3 < 6 + d ⋅ 3; (а + b) : 5 = а : 5 + b : 5, по сочетательному свойству деления.', '<p>\n15 ⋅ а = а ⋅ 15, по переместительному свойству умножения;<br/>\nb : 9 &gt; b : 12, потому что, при одинаковом делимом, значение частного больше там, где делитель меньше;<br/>\n40 : m &lt; 50 : m, потому что при одинаковом делителе, значение частного будет больше там, где делимое больше;<br/>\nс ⋅ 1 = с : 1, потому что при умножении и делении на единицу получается то число, которое умножали или делили;<br/>\n(6 + d) ⋅ 3 &lt; 6 + d ⋅ 3;<br/>\n(а + b) : 5 = а : 5 + b : 5, по сочетательному свойству деления.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-12/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '955effec8a391ab60b0bf951e09345dd6699694b0dae155035e56edc6b495734', '1,3,5,6,9,12,15,40,50', '["сравни"]'::jsonb, 'сравни выражения:15 ⋅ а ... а ⋅ 15; b:9 ... b:12; 40:m ... 50:m; с ⋅ 1 ... с:1; (6+d) ⋅ 3 ... 6+d ⋅ 3; (а+b):5 ... а:5+b:5');

    VALUES (v_textbook_id, 12, '10', 2, 'Реши каждую задачу в три действия: А) в автобусе ехало 32 пассажира. На каждой остановке из автобуса выходило, а входило 2 человека. Сколько человек оказалось в автобусе через 9 остановок? Б) в трамвае ехало 14 пассажиров. На каждой остановке из трамвая выходило 3 человека, а входило 5 человек. Сколько человек оказалось в трамвае через 8 остановок?', '</p>\n\n<p class="text">\nРеши каждую задачу в три действия:<br/>\nА) в автобусе ехало 32 пассажира. На каждой остановке из автобуса выходило, а входило 2 человека. Сколько человек оказалось в автобусе через 9 остановок?<br/>\nБ) в трамвае ехало 14 пассажиров. На каждой остановке из трамвая выходило 3 человека, а входило 5 человек. Сколько человек оказалось в трамвае через 8 остановок?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica12-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 12, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 12, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-12/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica12-nomer10.jpg', 'peterson/3/part2/page12/task10_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '474da921f4a0055047f331540c64ddbca32faa313fe8b9ae0cfe365fa8e881e8', '2,3,5,8,9,14,32', '["реши"]'::jsonb, 'реши каждую задачу в три действия:а) в автобусе ехало 32 пассажира. на каждой остановке из автобуса выходило, а входило 2 человека. сколько человек оказалось в автобусе через 9 остановок? б) в трамвае ехало 14 пассажиров. на каждой остановке из трамвая выходило 3 человека, а входило 5 человек. сколько человек оказалось в трамвае через 8 остановок');

    VALUES (v_textbook_id, 12, '11', 3, 'Выполни деление с остатком и сделай проверку: 31 : 5; 54 : 7; 89 : 11; 98 : 16.', '</p>\n\n<p class="text">\nВыполни деление с остатком и сделай проверку:<br/>\n31 : 5;<br/>\n54 : 7;<br/>\n89 : 11;<br/>\n98 : 16.\n</p>', '31 : 5 = 6 (ост.1); Проверка: 6 ⋅ 5 + 1 = 31; 54 : 7 = 7 (ост. 5); Проверка: 7 ⋅ 7 + 5 = 54; 89 : 11 = 8 (ост. 1); Проверка: 8 ⋅ 11 + 1 = 89; 98 : 16 = 6 (ост. 2); Проверка: 16 ⋅ 6 + 2 = 98.', '31 : 5 = 6 (ост.1);<br/>\nПроверка: 6 ⋅ 5 + 1 = 31;<br/>\n<br/>\n54 : 7 = 7 (ост. 5);<br/>\nПроверка: 7 ⋅ 7 + 5 = 54;<br/>\n<br/>\n89 : 11 = 8 (ост. 1);<br/>\nПроверка: 8 ⋅ 11 + 1 = 89;<br/>\n<br/>\n98 : 16 = 6 (ост. 2);<br/>\nПроверка: 16 ⋅ 6 + 2 = 98.', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-12/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '495e95e696fcb4d53019721cc622db6ef4eec6eba3b87d44f0326f26a888f740', '5,7,11,16,31,54,89,98', NULL, 'выполни деление с остатком и сделай проверку:31:5; 54:7; 89:11; 98:16');

    VALUES (v_textbook_id, 12, '12', 4, 'Однажды Юра сказал ребятам: - Я знаю волшебное число. Это число 1089. Оно всегда будет получаться, если выполнить действия по следующему алгоритму: 1) Придумай трёхзначное число, у которого число сотен больше числа единиц. 2) Вычти из него число, записанное теми же цифрами, но в обратном порядке (если в ответе получится двузначное число, то в разряде сотен поставь 0). 3) К полученной разности прибавь число, составленное из тех же цифр, но записанных в обратном порядке. Ребята выполнили алгоритм для числа 752. В ответе у них действительно получилось 1089. Придумай свои числа и проверь, прав ли Юра.', '</p>\n\n<p class="text">\nОднажды Юра сказал ребятам:<br/>\n- Я знаю волшебное число. Это число 1089. Оно всегда будет получаться, если выполнить действия по следующему алгоритму:<br/>\n<br/>\n1) Придумай трёхзначное число, у которого число сотен больше числа единиц.<br/>\n<br/>\n2) Вычти из него число, записанное теми же цифрами, но в обратном порядке (если в ответе получится двузначное число, то в разряде сотен поставь 0).<br/>\n<br/>\n3) К полученной разности прибавь число, составленное из тех же цифр, но записанных в обратном порядке.<br/>\n<br/>\nРебята выполнили алгоритм для числа 752. В ответе у них действительно получилось 1089. Придумай свои числа и проверь, прав ли Юра.\n\n</p>', '752; 752 – 257 = 495; 495 + 594 = 1089; 200; 200 – 2 = 198; 198 + 891 = 1089; 542; 542 – 245 = 297; 297 + 792 = 1089.', '<p>\n752;<br/>\n752 – 257 = 495;<br/>\n495 + 594 = 1089;<br/>\n<br/>\n200;<br/>\n200 – 2 = 198;<br/>\n198 + 891 = 1089;<br/>\n<br/>\n542;<br/>\n542 – 245 = 297;<br/>\n297 + 792 = 1089.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-12/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '2b09623c375959b0d5e65e63115dfd42ce185d1e3c5103ae6fdbd84981e74db0', '0,1,2,3,752,1089', '["вычти","больше","раз"]'::jsonb, 'однажды юра сказал ребятам:-я знаю волшебное число. это число 1089. оно всегда будет получаться, если выполнить действия по следующему алгоритму:1) придумай трёхзначное число, у которого число сотен больше числа единиц. 2) вычти из него число, записанное теми же цифрами, но в обратном порядке (если в ответе получится двузначное число, то в разряде сотен поставь 0). 3) к полученной разности прибавь число, составленное из тех же цифр, но записанных в обратном порядке. ребята выполнили алгоритм для числа 752. в ответе у них действительно получилось 1089. придумай свои числа и проверь, прав ли юра');

    VALUES (v_textbook_id, 13, '1', 0, 'В пачке 10 шариков, а в коробке – 10 пачек. Имеется 5 коробок, 3 пачки и еще 6 шариков. Как разделить их поровну между 4 детьми? Рассмотри и объясни 3 способа деления: 1 способ: 536 : 4 = (400 + 120 + 16) : 4 = 400 : 4 + 120 : 4 + 16 : 4 = 134. 2 способ: 1)Делим сотни: 5 с : 4 = 1 с (ост. 1 с); 2)Делим десятки: 13 д : 4 = 3 д (ост. 1 д); 3) Делим единицы: 16 е : 4 = 4 е; Итак, 536 : 4 = 134. 3 способ: Деление столбиком.', '</p>\n\n<p class="text">В пачке 10 шариков, а в коробке – 10 пачек. Имеется 5 коробок, 3 пачки и еще 6 шариков. Как разделить их поровну между 4 детьми?<br/>\nРассмотри и объясни 3 способа деления:<br/>\n<br/>\n1 способ:<br/>\n536 : 4 = (400 + 120 + 16) : 4 = 400 : 4 + 120 : 4 + 16 : 4 = 134.<br/>\n<br/>\n2 способ:<br/>\n1)Делим сотни:<br/>\n5 с : 4 = 1 с (ост. 1 с);<br/>\n<br/>\n2)Делим десятки:<br/>\n13 д : 4 = 3 д (ост. 1 д);<br/>\n<br/>\n3) Делим единицы:<br/>\n16 е : 4 = 4 е;<br/>\n<br/>\nИтак, 536 : 4 = 134.<br/>\n<br/>\n3 способ:<br/>\nДеление столбиком.\n</p>', 'В первом способе, чтобы разделить на однозначное число, можно представить это число суммой удобных разрядных слагаемых, а полученные и каждое из них разделить на однозначное число, а значения частных сложить. Во втором способе, чтобы разделить на однозначное число, можно по отдельности разделить сотни, десятки и единицы. В третьем способе, используется способ деления углом.', '<p>\nВ первом способе, чтобы разделить на однозначное число, можно представить это число суммой удобных разрядных слагаемых, а полученные и каждое из них разделить на однозначное число, а значения частных сложить.<br/>\n<br/>\nВо втором способе, чтобы разделить на однозначное число, можно по отдельности разделить сотни, десятки и единицы.<br/>\n<br/>\nВ третьем способе, используется способ деления углом.\n</p>', 'Алгоритм деления на однозначное число углом Выделить первое неполное делимое; Отметить количество цифр в частном; Выполнить деление, найти первую цифру частного и остаток; Составить следующее неполное делимое; Выполнить деление, найти следующую цифру частного и остаток; Найдена последняя цифра частного? Назвать ответ.', '<div class="recomended-block">\n<span class="title">Алгоритм деления на однозначное число углом</span>\n<p>\nВыделить первое неполное делимое;<br/>\nОтметить количество цифр в частном;<br/>\nВыполнить деление, найти первую цифру частного и остаток;<br/>\nСоставить следующее неполное делимое;<br/>\nВыполнить деление, найти следующую цифру частного и остаток;<br/>\nНайдена последняя цифра частного?<br/>\nНазвать ответ.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-13/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '538490aa2fe71de06c53f26cebb6b6d4bb28897cb1a1d3f78c3d9c3c035508ca', '1,2,3,4,5,6,10,13,16,120', '["раздели","столбик","раз"]'::jsonb, 'в пачке 10 шариков, а в коробке-10 пачек. имеется 5 коробок, 3 пачки и еще 6 шариков. как разделить их поровну между 4 детьми? рассмотри и объясни 3 способа деления:1 способ:536:4=(400+120+16):4=400:4+120:4+16:4=134. 2 способ:1)делим сотни:5 с:4=1 с (ост. 1 с); 2)делим десятки:13 д:4=3 д (ост. 1 д); 3) делим единицы:16 е:4=4 е; итак, 536:4=134. 3 способ:деление столбиком');

    VALUES (v_textbook_id, 14, '2', 0, 'Реши примеры тремя способами (как в № 1): 1) по правилу деления суммы на число; 2) с помощью поэтапного деления с остатков (от самой крупной счетной единицы к самой мелкой); 3) используя запись деления углом. 375 : 3; 134 : 2; 256 : 4.', '</p>\n\n<p class="text">\nРеши примеры тремя способами (как в № 1):<br/>\n1) по правилу деления суммы на число;<br/>\n2) с помощью поэтапного деления с остатков (от самой крупной счетной единицы к самой мелкой);<br/>\n3) используя запись деления углом.<br/>\n375 : 3;<br/>\n134 : 2;<br/>\n256 : 4.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica14-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 14, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 14, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-14/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica14-nomer2.jpg', 'peterson/3/part2/page14/task2_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'e08b57800d8f7a7fdadd472728e05f4ccf200893e717175fec681025421fa575', '1,2,3,4,134,256,375', '["реши"]'::jsonb, 'реши примеры тремя способами (как в № 1):1) по правилу деления суммы на число; 2) с помощью поэтапного деления с остатков (от самой крупной счетной единицы к самой мелкой); 3) используя запись деления углом. 375:3; 134:2; 256:4');

    VALUES (v_textbook_id, 14, '3', 1, 'Работая в группах, ребята получили разные решения примера 225 : 3. Кто из них прав? Найди ошибку и обоснуй свой ответ. Какой совет ты можешь дать, чтобы не допускать подобных ошибок?', '</p>\n\n<p class="text">\nРаботая в группах, ребята получили разные решения примера 225 : 3. Кто из них прав? Найди ошибку и обоснуй свой ответ.<br/>\nКакой совет ты можешь дать, чтобы не допускать подобных ошибок?\n</p>', 'Первое решение неверное, потому что при делении десятков было взято не максимальное число десятков в делимом. Значит, все остальные неполные делимые неверны. Второе решение верно, потому что каждая цифра десятков и единиц подобрана верно. Вывод: чтобы не допускать ошибку, нужно всегда сравнивать первое неполные делимые с делителем, ведь неполное делимое всегда должно быть меньше.', '<p>\nПервое решение неверное, потому что при делении десятков было взято не максимальное число десятков в делимом. Значит, все остальные неполные делимые неверны.<br/>\nВторое решение верно, потому что каждая цифра десятков и единиц подобрана верно.<br/>\n<br/>\nВывод: чтобы не допускать ошибку, нужно всегда сравнивать первое неполные делимые с делителем, ведь неполное делимое всегда должно быть меньше.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-14/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '5600bf85e23d3424df5f9afd693499537ccf4aa9c96d1c244c8f3acd39ac1dbc', '3,225', '["найди","раз"]'::jsonb, 'работая в группах, ребята получили разные решения примера 225:3. кто из них прав? найди ошибку и обоснуй свой ответ. какой совет ты можешь дать, чтобы не допускать подобных ошибок');

    VALUES (v_textbook_id, 14, '4', 2, 'А)Составь 4 равенства из чисел 7, 5, 35. Как можно проверить деление с помощью умножения? Б) выполни деление и сделай проверку умножением: 792 : 6; 623 : 7; 378 : 9; 475 : 5; 536 : 8.', '</p>\n\n<p class="text">\nА)Составь 4 равенства из чисел 7, 5, 35. Как можно проверить деление с помощью умножения?<br/>\nБ) выполни деление и сделай проверку умножением:<br/>\n792 : 6;<br/>\n623 : 7;<br/>\n378 : 9;<br/>\n475 : 5;<br/>\n536 : 8.\n</p>', 'А) 7 ⋅ 5 = 35, 35 : 5 = 7, 35 : 7 = 5; Б)', '<p>\nА) 7 ⋅ 5 = 35, 35 : 5 = 7, 35 : 7 = 5;<br/>\nБ)\n</p>\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica14-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 14, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 14, номер 4, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-14/')
    RETURNING id INTO v_task_id;

