    VALUES (v_textbook_id, 14, '5', 3, 'Вычисли и сравни примеры каждого столбика. Что ты замечаешь? 672 : 2; 672 : 8; 354 : 3; 354 : 6; 476 : 4; 476 : 7; 855 : 5; 855 : 9; 912 : 6; 912 : 8.', '</p>\n\n<p class="text">\nВычисли и сравни примеры каждого столбика. Что ты замечаешь?<br/>\n672 : 2;<br/>\n672 : 8;<br/>\n354 : 3;<br/>\n354 : 6;<br/>\n476 : 4;<br/>\n476 : 7;<br/>\n855 : 5;<br/>\n855 : 9;<br/>\n912 : 6;<br/>\n912 : 8.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica14-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 14, номер 5, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 14, номер 5, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-14/')
