    VALUES (v_textbook_id, 14, '6', 4, 'А)с двух пальм собрали 152 банана, причем с первой пальми собрали на 28 бананов больше, чем со второй. Сколько бананов собрали с каждой пальмы? Б) В двух ящиках 42 кг апельсинов. В первом ящике на 8 кг меньше, чем во втором. Сколько килограммов апельсинов в каждом ящике?', '</p>\n\n<p class="text">\nА)с двух пальм собрали 152 банана, причем с первой пальми собрали на 28 бананов больше, чем со второй. Сколько бананов собрали с каждой пальмы?<br/>\nБ) В двух ящиках 42 кг апельсинов. В первом ящике на 8 кг меньше, чем во втором. Сколько килограммов апельсинов в каждом ящике?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica14-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 14, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 14, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-14/')
    RETURNING id INTO v_task_id;

