    VALUES (v_task_id, v_textbook_id, 3, '92c3b89eee6c60bb48a75da356cd7ce5899f96870a04816569ac2df08b317873', '8,28,42,152', '["больше","меньше"]'::jsonb, 'а)с двух пальм собрали 152 банана, причем с первой пальми собрали на 28 бананов больше, чем со второй. сколько бананов собрали с каждой пальмы? б) в двух ящиках 42 кг апельсинов. в первом ящике на 8 кг меньше, чем во втором. сколько килограммов апельсинов в каждом ящике');

    VALUES (v_textbook_id, 14, '7', 5, 'Сравни: 603 … 95; 248 … 284; 35 406 … 5 926; 17 325 … 17 340; 5 700 800 … 5 080 900; 999 999 … 2 000 000.', '</p>\n\n<p class="text">\nСравни:<br/>\n603 … 95;<br/>\n248 … 284;<br/>\n<br/>\n35 406 … 5 926;<br/>\n17 325 … 17 340;<br/>\n<br/>\n5 700 800 … 5 080 900;<br/>\n999 999 … 2 000 000.\n</p>', '603 > 95; 248 < 284; 35 406 > 5 926; 17 325 > 17 340; 5 700 800 > 5 080 900; 999 999 < 2 000 000.', '<p>\n603 &gt; 95;<br/>\n248 &lt; 284;<br/>\n<br/>\n35 406 &gt; 5 926;<br/>\n17 325 &gt; 17 340;<br/>\n<br/>\n5 700 800 &gt;  5 080 900;<br/>\n999 999 &lt; 2 000 000.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-14/')
