    VALUES (v_textbook_id, 15, '8', 0, 'Используя циркуль, проведи окружность с центром в точке О и радиусом 2 см. Отметь точки А и В внутри окружности, С и D – на окружности, Е и F – снаружи. Проведи отрезки ОА, ОВ, ОС, ОD, ОЕ, OF и измерь их длину. Что ты замечаешь?', '</p>\n\n<p class="text">Используя циркуль, проведи окружность с центром в точке О и радиусом 2 см. Отметь точки А и В внутри окружности, С и D – на окружности, Е и F – снаружи. Проведи отрезки ОА, ОВ, ОС, ОD, ОЕ, OF и измерь их длину. Что ты замечаешь?</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica15-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 15, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 15, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-15/')
