    VALUES (v_task_id, v_textbook_id, 3, 'ecf29c6acc294cd6b396b40529bb5be9765b672e27464eee56c2b06cff5dc7fb', '2', NULL, 'используя циркуль, проведи окружность с центром в точке о и радиусом 2 см. отметь точки а и в внутри окружности, с и d-на окружности, е и f-снаружи. проведи отрезки оа, ов, ос, оd, ое, of и измерь их длину. что ты замечаешь');

    VALUES (v_textbook_id, 15, '9', 1, 'Вычисли. Что общего в примерах каждого столбика? 9 + 6; 15 – 9; 75 – 28; 28 + 47; 7 ⋅ 9; 63 : 7; 57 : 3; 3 ⋅ 19; 14 ⋅ 6; 84 : 14; 320 : 8; 320 : 40.', '</p>\n\n<p class="text">Вычисли. Что общего в примерах каждого столбика?<br/>\n9 + 6;<br/>\n15 – 9;<br/>\n75 – 28;<br/>\n28 + 47;<br/>\n7 ⋅ 9;<br/>\n63 : 7;<br/>\n57 : 3;<br/>\n3 ⋅ 19;<br/>\n14 ⋅ 6;<br/>\n84 : 14;<br/>\n320 : 8;<br/>\n320 : 40.\n</p>', '9 + 6 = 15; 15 – 9 = 6; 75 – 28 = 47; 28 + 47 = 75; 7 ⋅ 9 = 63; 63 : 7 = 9; 57 : 3 = 19; 3 ⋅ 19 = 57; 14 ⋅ 6 = 84; 84 : 14 = 6; 320 : 8 = 40; 320 : 40 = 8. Вывод: выражения всех столбиков показаны зависимости между компонентами и результатами действий сложения, вычитания, умножения и деления.', '<p>\n9 + 6 = 15;<br/>\n15 – 9 = 6;<br/>\n75 – 28 = 47;<br/>\n28 + 47 = 75;<br/>\n7 ⋅ 9 = 63;<br/>\n63 : 7 = 9;<br/>\n57 : 3 = 19;<br/>\n3 ⋅ 19 = 57;<br/>\n14 ⋅ 6 = 84;<br/>\n84 : 14 = 6;<br/>\n320 : 8 = 40;<br/>\n320 : 40 = 8.<br/>\nВывод: выражения всех столбиков показаны зависимости между компонентами и результатами действий сложения, вычитания, умножения и деления.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-15/')
    RETURNING id INTO v_task_id;

