    VALUES (v_textbook_id, 15, '10', 2, 'Составь программу действий и вычисли: А)1000 : 10 ⋅ 5 : (498 + 2) – 0 : (6 – 30 ⋅ 10 : 100); Б) 0 ⋅ (50 + 4 ⋅ 100 : 10) + 1000 : 100 ⋅ 7 : (14 + 56).', '</p>\n\n<p class="text">\nСоставь программу действий и вычисли:<br/>\nА)1000 : 10 ⋅ 5 : (498 + 2) – 0 : (6 – 30 ⋅ 10 : 100);<br/>\nБ) 0 ⋅ (50 + 4 ⋅ 100 : 10) + 1000 : 100 ⋅ 7 : (14 + 56).\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica15-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 15, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 15, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-15/')
