    VALUES (v_textbook_id, 15, '11', 3, 'Пусть А – множество месяцев в году, В – множество весенних месяцев, С – множество летних месяцев, а D – множество месяцев, в названии которых 4 буквы. Нарисуй диаграмму Эйлера – Венна этих множеств и отметь на ней точками все 12 месяцев.', '</p>\n\n<p class="text">\nПусть А – множество месяцев в году, В – множество весенних месяцев, С – множество летних месяцев, а D – множество месяцев, в названии которых 4 буквы. Нарисуй диаграмму Эйлера – Венна этих множеств и отметь на ней точками все 12 месяцев.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica15-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 15, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 15, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-15/')
