    VALUES (v_textbook_id, 15, '13', 5, 'Задача – рассказ «У школьного окна». Однажды во время прогулки учительница сказала ребятам: - Посмотрите внимательно на окно своего класса и скажите, сколько прямоугольников в нем образуется? - Шесть, - послышался быстрый ответ. - Нас интересует не количество стёкол, - продолжала учительница, - а различные прямоугольники, которые здесь получаются. Помоги ребятам сосчитать все прямоугольники в проёме окна.', '</p>\n\n<p class="text">\nЗадача – рассказ «У школьного окна».<br/>\nОднажды во время прогулки учительница сказала ребятам:<br/>\n- Посмотрите внимательно на окно своего  класса и скажите, сколько прямоугольников в нем образуется?<br/>\n- Шесть, - послышался быстрый ответ.<br/>\n- Нас интересует не количество стёкол, - продолжала учительница, - а различные прямоугольники, которые здесь получаются.<br/>\nПомоги ребятам сосчитать все прямоугольники в проёме окна.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica15-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 15, номер 13, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 15, номер 13, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-15/')
    RETURNING id INTO v_task_id;

