    VALUES (v_task_id, v_textbook_id, 3, 'c73c45061f15e090c912a384e6055b558325d84a949f4f13ac65c8609961dc65', NULL, '["раз"]'::jsonb, 'задача-рассказ "у школьного окна". однажды во время прогулки учительница сказала ребятам:-посмотрите внимательно на окно своего класса и скажите, сколько прямоугольников в нем образуется?-шесть,-послышался быстрый ответ.-нас интересует не количество стёкол,-продолжала учительница,-а различные прямоугольники, которые здесь получаются. помоги ребятам сосчитать все прямоугольники в проёме окна');

    VALUES (v_textbook_id, 15, '14', 6, 'Какое из указанных чисел на равно остальным? (а) тридцать сотен; (b) три тысячи; (с) триста сотен; (d) триста десятков; (е) сто раз по тридцать; (f) десять раз по триста.', '</p>\n\n<p class="text">\nКакое из указанных чисел на равно остальным?<br/>\n(а) тридцать сотен;<br/>\n(b) три тысячи;<br/>\n(с) триста сотен;<br/>\n(d) триста десятков;<br/>\n(е) сто раз по тридцать;<br/>\n(f) десять раз по триста.\n</p>', 'Запишем все числа цифрами. a) 3 000; b) 3 000; c) 30 000; d) 3 000; e) 3 000; f) 3 000. Вывод: лишнее число под буквой с, потому что это число тридцать тысяч, а не три тысячи.', '<p>\nЗапишем все числа цифрами.<br/>\na) 3 000;<br/>\nb) 3 000;<br/>\nc) 30 000;<br/>\nd) 3 000;<br/>\ne) 3 000;<br/>\nf) 3 000.<br/>\nВывод: лишнее число под буквой с, потому что это число тридцать тысяч, а не три тысячи.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-15/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '16ae7faad365fa898b559d8634bd969bb6ad46bd9176848e7eeca60344e51207', NULL, '["равно","раз"]'::jsonb, 'какое из указанных чисел на равно остальным? (а) тридцать сотен; (b) три тысячи; (с) триста сотен; (d) триста десятков; (е) сто раз по тридцать; (f) десять раз по триста');

    VALUES (v_textbook_id, 16, '1', 0, 'Выполни действия: а) 952 : 4; б) 684 : 9; в) 5 865 : 5; г)4 039 : 7; д) 36 816 : 6; е) 92 504 : 8; ж) 72 040 ⋅ 900; з) 3 000 ⋅ 20 580.', '</p>\n\n<p class="text">Выполни действия:<br/>\nа) 952 : 4;<br/>\nб) 684 : 9;<br/>\nв) 5 865 : 5;<br/>\nг)4 039 : 7;<br/>\nд) 36 816 : 6;<br/>\nе) 92 504 : 8;<br/>\nж) 72 040 ⋅ 900;<br/>\nз) 3 000 ⋅ 20 580.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica16-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 16, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 16, номер 1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-16/')
    RETURNING id INTO v_task_id;

