    VALUES (v_task_id, v_textbook_id, 3, '7124c3f6705c6a987b7cc18645825cc14efc5305827ada5c88af9d7b5916c1ad', '0,1,2,6,936,6039', '["найди","раз"]'::jsonb, 'прочитай выражение разными способами:6039 ⋅ а+936:b. найди его значение, если:1) а=0, b=1; 2) а=6, b=2');

    VALUES (v_textbook_id, 17, '8', 0, 'Придумай записи, решением которых являются выражения: а ⋅ 2 + b ⋅ 4; а : 5 + b : 3; (а + b) : 4; подбери подходящие значения а и b и выполни действия.', '</p>\n\n<p class="text">Придумай записи, решением которых являются выражения:<br/>\nа ⋅ 2 + b ⋅ 4;<br/>\nа : 5 + b : 3;<br/>\n(а + b) : 4;<br/>\nподбери подходящие значения а и b и выполни действия.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica17-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 17, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 17, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-17/')
    RETURNING id INTO v_task_id;

