    VALUES (v_task_id, v_textbook_id, 3, 'a7796fc857a582fdce9da4b93499f331660816ae08de1cac487382fe7746ac86', '2,3,4,5', NULL, 'придумай записи, решением которых являются выражения:а ⋅ 2+b ⋅ 4; а:5+b:3; (а+b):4; подбери подходящие значения а и b и выполни действия');

    VALUES (v_textbook_id, 17, '9', 1, 'БЛИЦтурнир. А) В первом аквариуме а рыбок, а во втором – в 4 раза меньше. На сколько рыбок в первом аквариуме больше, чем во втором? Б) торт стоит b р., а пирог – на с р. меньше. Во сколько раз пирог дешевле торта? В) В мешке было m кг яблок. Из него брали 10 дней по n кг. Сколько яблок еще осталось в мешке? Г) На костюм идет х м ткани, а на платье – у м. Сколько нужно этой ткани на пошив таких же 2 костюмов и 3 платьев? Д) В первой коробке d ручек, а во второй – в 3 раза меньше, чем в первой. Сколько ручек в двух коробках?', '</p>\n\n<p class="text">\nБЛИЦтурнир.<br/>\nА) В первом аквариуме а рыбок, а во втором – в 4 раза меньше. На сколько рыбок в первом аквариуме больше, чем во втором?<br/>\nБ) торт стоит b р., а пирог – на с р. меньше. Во сколько раз пирог дешевле торта?<br/>\nВ) В мешке было m кг яблок. Из него брали 10 дней по n кг. Сколько яблок еще осталось в мешке?<br/>\nГ) На костюм идет х м ткани, а на платье – у м. Сколько нужно этой ткани на пошив таких же 2 костюмов и 3 платьев?<br/>\nД) В первой коробке d ручек, а во второй – в 3 раза меньше, чем в первой. Сколько ручек в двух коробках?\n</p>', 'а) а – (а : 4) (шт.) – рыбок больше в первом аквариуме, чем во втором. б) b : (b – c) (раз) – пирог дешевле торта. в) m – (n ⋅ 10) (шт.) – яблок осталось в мешке. г) х ⋅ 3 + у ⋅ 2 (м) – ткани нужно на пошив всей одежды. д) d + d : 3 (шт.) – ручек в двух коробках.', '<p>\nа) а – (а : 4) (шт.) – рыбок больше в первом аквариуме, чем во втором.<br/>\nб) b : (b – c) (раз) – пирог дешевле торта.<br/>\nв) m – (n ⋅ 10) (шт.) – яблок осталось в мешке.<br/>\nг) х ⋅ 3 + у ⋅ 2 (м) – ткани нужно на пошив всей одежды.<br/>\nд) d + d : 3 (шт.) – ручек в двух коробках.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-17/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'fcd2b4e151bc5f854c82c6910b87bc12ca79d26460512b86cb7c4b8bc9b1347f', '2,3,4,10', '["больше","меньше","раз","раза"]'::jsonb, 'блицтурнир. а) в первом аквариуме а рыбок, а во втором-в 4 раза меньше. на сколько рыбок в первом аквариуме больше, чем во втором? б) торт стоит b р., а пирог-на с р. меньше. во сколько раз пирог дешевле торта? в) в мешке было m кг яблок. из него брали 10 дней по n кг. сколько яблок еще осталось в мешке? г) на костюм идет х м ткани, а на платье-у м. сколько нужно этой ткани на пошив таких же 2 костюмов и 3 платьев? д) в первой коробке d ручек, а во второй-в 3 раза меньше, чем в первой. сколько ручек в двух коробках');

    VALUES (v_textbook_id, 17, '10', 2, 'Построй с помощью линейки отрезок АВ, равный 5 см. Используя циркуль, проведи две окружности с центрами в точках А и В так, чтобы: а) они имели две общие точки; б) они имели одну общую точку; в) они не имели общих точек. Найди сумму радиусов построенных окружностей и сравни её с длиной отрезка АВ. Что ты замечаешь?', '</p>\n\n<p class="text">\nПострой с помощью линейки отрезок АВ, равный 5 см. Используя циркуль, проведи две окружности с центрами в точках А и В так, чтобы: <br/>\nа) они имели две общие точки; <br/>\nб) они имели одну общую точку;<br/>\nв) они не имели общих точек. <br/>\nНайди сумму радиусов построенных окружностей и сравни её с длиной отрезка АВ. Что ты замечаешь?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica17-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 17, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 17, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-17/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica17-nomer10.jpg', 'peterson/3/part2/page17/task10_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'c3781bde1420958f6c35743b7492e6b18378c6ff27cbf1e82d41a70360f25403', '5', '["найди","сравни"]'::jsonb, 'построй с помощью линейки отрезок ав, равный 5 см. используя циркуль, проведи две окружности с центрами в точках а и в так, чтобы:а) они имели две общие точки; б) они имели одну общую точку; в) они не имели общих точек. найди сумму радиусов построенных окружностей и сравни её с длиной отрезка ав. что ты замечаешь');

    VALUES (v_textbook_id, 17, '11', 3, 'Артём задумал число, умножил его на 6, разделил на 40, прибавил 65 и вычел 18. В результате у него получилось 50. Какое число задумал Артем?', '</p>\n\n<p class="text">\nАртём задумал число, умножил его на 6, разделил на 40, прибавил 65 и вычел 18. В результате у него получилось 50. Какое число задумал Артем?\n</p>', 'Чтобы узнать, какое число было задумано, нужно выполнить обратные действия. 1)Умножил его на 6; 2) Разделил на 40; 3) Прибавил 65; 4) Вычел 18; Обратные действия будут таковы: 1) прибавить 18; 2) вычесть 65; 3) умножить на 40; 4) разделить на 6; 50 + 18 = 68; 68 – 65 = 3; 3 * 40 = 120; 120 : 6 = 20; Значит, число, которое задумал Артем – 20.', '<p>\nЧтобы узнать, какое число было задумано, нужно выполнить обратные действия.<br/>\n1)Умножил его на 6;<br/>\n2) Разделил на 40;<br/>\n3) Прибавил 65;<br/>\n4) Вычел 18;<br/>\n<br/>\nОбратные действия будут таковы:<br/>\n1) прибавить 18;<br/>\n2) вычесть 65;<br/>\n3) умножить на 40;<br/>\n4) разделить на 6;<br/>\n<br/>\n50 + 18 = 68;<br/>\n68 – 65 = 3;<br/>\n3 * 40 = 120;<br/>\n120 : 6 = 20;<br/>\nЗначит, число, которое задумал Артем – 20.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-17/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '72f83d9966d72f67c7ab337af6c20504d70759ae0a86bd6d65a5f4efc465bd5b', '6,18,40,50,65', '["раздели","раз"]'::jsonb, 'артём задумал число, умножил его на 6, разделил на 40, прибавил 65 и вычел 18. в результате у него получилось 50. какое число задумал артем');

    VALUES (v_textbook_id, 17, '11', 4, 'Используя рисунок, определи, сколько весит одна морковка и сколько весит один кочан капусты. (Масса каждой морковки одна и та же, и все кочаны одинаковые)', '</p>\n\n<p class="text">\nИспользуя рисунок, определи, сколько весит одна морковка и сколько весит один кочан капусты. (Масса каждой морковки одна и та же, и все кочаны одинаковые)\n</p>', 'Первые весы: обе чаши находятся в равновесии, значит, массы грузов на обеих чашах равны. Тогда, 2 моркови + 2 капусты + 2 кг = 3 моркови + 1 капуста + 3 кг Вычеркнем равные объекты. Останется:1 капуста = 1 морковка + 1 кг На вторых весах чаши снова находятся в равновесии. Тогда, 1 капуста = 6 морковок Заменив на первых весах капусту морковью. Получается, 6 морковок = 1 морковка + 1 кг Значит, 5 морковок = 1 кг Тогда, 1 морковь весит 200 грамм. А капуста, 200 г ⋅ 6 = 1 200 г. Ответ: капуста – 1 кг 200 г, морковь – 200 г.', '<p>\nПервые весы: обе чаши находятся в равновесии, значит, массы грузов на обеих чашах равны.<br/>\nТогда, 2 моркови + 2 капусты + 2 кг = 3 моркови + 1 капуста + 3 кг<br/>\nВычеркнем равные объекты. Останется:1 капуста = 1 морковка + 1 кг<br/>\n<br/>\nНа вторых весах чаши снова находятся в равновесии.<br/>\nТогда, 1 капуста = 6 морковок<br/>\nЗаменив на первых весах капусту морковью.<br/>\nПолучается, 6 морковок = 1 морковка + 1 кг<br/>\nЗначит, 5 морковок = 1 кг<br/>\nТогда, 1 морковь весит 200 грамм.<br/>\nА капуста, 200 г ⋅ 6 = 1 200 г.<br/>\nОтвет: капуста – 1 кг 200 г, морковь – 200 г.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-17/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ba6effa82913210dd3db1a7d25807b316881a4c1ebadb1272f7862bbf1fa2b6e', NULL, NULL, 'используя рисунок, определи, сколько весит одна морковка и сколько весит один кочан капусты. (масса каждой морковки одна и та же, и все кочаны одинаковые)');

    VALUES (v_textbook_id, 18, '13', 0, 'Литературная викторина «Волшебные слова» Реши примеры. Расшифруй «волшебные слова». вспомни, кто их говорил. Ф. 48 – 38; А. 54 + 9; Л. 70 – 14; Т. 24 + 36; Е. 27 + 18; Р. 28 : 4 ⋅ 30; У. 450 : 5 ⋅ 2; М. 81 : 9 ⋅ 80; П. 400 ⋅ 2 : 100; О. 140 : 70 ⋅ 10; К. 15 ⋅ 4 : 10; Ч. 560 : 7 ⋅ 4; И. 50 ⋅ 60 : 100; Б. 45 : (13 – 4); С. 8 ⋅ 8 – 6 ⋅ 7. А) 210 45 6 22, 10 45 6 22, 8 45 6 22! Б) 6 63 210 63 - 5 63 210 63 22! В) 5 63 729 5 63 210 63, 320 180 10 63 210 63, 56 20 210 30 6 40, 45 210 30 6 30, 8 30 6 63 8 180, 60 210 30 6 63 8 180, 22 6 20 210 30 6 30, 720 20 210 30 6 30!', '</p>\n\n<p class="text">Литературная викторина «Волшебные слова»<br/>\nРеши примеры. Расшифруй «волшебные слова». вспомни, кто их говорил.<br/>\nФ. 48 – 38;<br/>\nА. 54 + 9;<br/>\nЛ. 70 – 14;<br/>\nТ. 24 + 36;<br/>\nЕ. 27 + 18;<br/>\n\nР. 28 : 4 ⋅ 30;<br/>\nУ. 450 : 5 ⋅ 2;<br/>\nМ. 81 : 9 ⋅ 80;<br/>\nП. 400 ⋅ 2 : 100;<br/>\nО. 140 : 70 ⋅ 10;<br/>\n\nК. 15 ⋅ 4 : 10;<br/>\nЧ. 560 : 7 ⋅ 4;<br/>\nИ. 50 ⋅ 60 : 100;<br/>\nБ. 45 : (13 – 4);<br/>\nС. 8 ⋅ 8 – 6 ⋅ 7.<br/>\n<br/>\nА) 210 45 6 22, <br/>\n10 45 6 22, <br/>\n8 45 6 22!<br/>\n<br/>\nБ) 6 63 210 63 - <br/>\n5 63 210 63 22!<br/>\n<br/>\nВ) 5 63 729 5 63 210 63, 	<br/>\n320 180 10 63 210 63,<br/>\n56 20 210 30 6 40, <br/>\n45 210 30 6 30,<br/>\n8 30 6 63 8 180, <br/>\n60 210 30 6 63 8 180,<br/>\n22 6 20 210 30 6 30, 	<br/>	\n720 20 210 30 6 30!\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica18-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 18, номер 13, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 18, номер 13, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-18/')
