    VALUES (v_textbook_id, 19, '1', 0, 'Рассмотри различные способы деления 312 : 3. Объясни, как получен нуль в частном. 1 способ: 312 : 3 = (300 = 12) : 3 = 300 : 3 + 12 : 3 = 100 + 4 = 104. 2 способ: 1)Делим сотни: 3 с : 3 = 1 с. 2)Делим десятки: Один десяток нельзя разделить на 3, поэтому в разряде десятков пишем 0. 1 д : 3 = 0 д (ост. 1 д). 3)Делим единицы: 12 е : 3 = 4 е. Итак, 312 : 3 = 104 3 способ: Деление уголком.', '</p>\n\n<p class="text">Рассмотри различные способы деления 312 : 3. Объясни, как получен нуль в частном.<br/>\n<br/>\n1 способ:<br/>\n312 : 3 = (300 = 12) : 3 = 300 : 3 + 12 : 3 = 100 + 4 = 104.<br/>\n<br/>\n2 способ:<br/>\n1)Делим сотни: 3 с : 3 = 1 с.<br/>\n2)Делим десятки:<br/>\nОдин десяток нельзя разделить на 3, поэтому в разряде десятков пишем 0.<br/>\n1 д : 3 = 0 д (ост. 1 д).<br/>\n3)Делим единицы: 12 е : 3 = 4 е.<br/>\nИтак, 312 : 3 = 104<br/>\n<br/>\n3 способ:<br/>\nДеление уголком.\n</p>', 'Нуль в частном получается из-за того, что второе неполное делимое – десятки, меньше, чем делитель. Поэтому и получается нуль.', '<p>\nНуль в частном получается из-за того, что второе неполное делимое – десятки, меньше, чем делитель. Поэтому и получается нуль.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-19/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'f657e07f3bc70c0ec5bc19143d18310ee093749ad3150bfd927fb344f813b309', '0,1,2,3,4,12,100,104,300,312', '["раздели","уголком","раз"]'::jsonb, 'рассмотри различные способы деления 312:3. объясни, как получен нуль в частном. 1 способ:312:3=(300=12):3=300:3+12:3=100+4=104. 2 способ:1)делим сотни:3 с:3=1 с. 2)делим десятки:один десяток нельзя разделить на 3, поэтому в разряде десятков пишем 0. 1 д:3=0 д (ост. 1 д). 3)делим единицы:12 е:3=4 е. итак, 312:3=104 3 способ:деление уголком');

    VALUES (v_textbook_id, 19, '2', 1, 'Реши примеры тремя способами (как в №1): 216 : 2; 428 : 4; 1030 : 5.', '</p>\n\n<p class="text">Реши примеры тремя способами (как в №1):<br/>\n216 : 2;<br/>		\n428 : 4;<br/>		\n1030 : 5.\n</p>', '216 : 2. 1 способ: 216 : 2 = (200 + 16) : 2 = 200 : 2 + 16 : 2 = 100 + 8 = 108. 2 способ: Делим сотни. 2 с. : 2 = 1 с. Делим десятки: один десяток разделить на 2 нельзя, поэтому в разряде десятков пишем 0. 1 д. : 2 = 0 д. (ост. 1д.) Делим единицы. 16 ед. : 2 = 8 ед. Итак, 216 : 2 = 108. 3 способ:', '<p>\n216 : 2.<br/>\n<br/>\n1 способ:<br/>\n216 : 2 = (200 + 16) : 2 = 200 : 2 + 16 : 2 = 100 + 8 = 108.<br/>\n2 способ:<br/>\nДелим сотни. 2 с. : 2 = 1 с.<br/>\nДелим десятки: один десяток разделить на 2 нельзя, поэтому в разряде десятков пишем 0.<br/>\n1 д. : 2 = 0 д. (ост. 1д.)<br/>\nДелим единицы. 16 ед. : 2 = 8 ед.<br/>\nИтак, 216 : 2 = 108.<br/>\n3 способ:\n</p>\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica19-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 19, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 19, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-19/')
    RETURNING id INTO v_task_id;

