    VALUES (v_task_id, v_textbook_id, 3, '339189f09d05de70aedda17d9dde3e33d913a632175b35091a057bc9bba308b4', '000,2,3,16,78', '["больше","меньше","раз","раза"]'::jsonb, 'а) за первый день турист прошел 16 км, а за второй-на 2 000 м больше. сколько километров он прошел за эти 2 дня? б) два поезда едут навстречу друг другу из двух городов. первый поезд прошел до встречи 78 км, а второй-в 3 раза больше. чему равна длина пути между этими городами? на сколько километров меньше прошел до встречи первый поезд, чем второй');

    VALUES (v_textbook_id, 20, '8', 2, 'Все натуральные числа от 1 до 100 записаны в один ряд. Сколько раз повторяется в этом ряду цифра 0, цифра 1, цифра 5, цифра 7, цифра 9?', '</p>\n\n<p class="text">Все натуральные числа от 1 до 100 записаны в один ряд. Сколько раз повторяется в этом ряду цифра 0, цифра 1, цифра 5, цифра 7, цифра 9?\n</p>', 'Цифра 0 – 11 раз; Цифра 1 – 21 раз; Цифра 5, 7, 9 – по 20 раз.', '<p>\nЦифра 0 – 11 раз;<br/>\nЦифра 1 – 21 раз;<br/>\nЦифра 5, 7, 9 – по 20 раз.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-20/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'fc6544936f7633b1a6ddf46d4dc2e438dfd2061195b95d4e5f0febd35b1fe583', '0,1,5,7,9,100', '["раз"]'::jsonb, 'все натуральные числа от 1 до 100 записаны в один ряд. сколько раз повторяется в этом ряду цифра 0, цифра 1, цифра 5, цифра 7, цифра 9');

    VALUES (v_textbook_id, 20, '9', 3, 'Игра «Пифагор». 1)Нарисуй на бумаге квадрат со стороной 5 см. 2) Разбей этот квадрат на части, как показано на рисунке. 3) Раскрась части квадрата разными цветами. 4) Вырежи каждую часть квадрата. 5) Составь из этих частей «кораблик» и наклей его в тетрадь.', '</p>\n\n<p class="text">Игра «Пифагор».<br/>\n1)Нарисуй на бумаге квадрат со стороной 5 см.<br/>\n2) Разбей этот квадрат на части, как показано на рисунке.<br/>\n3) Раскрась части квадрата разными цветами.<br/>\n4) Вырежи каждую часть квадрата.<br/>\n5) Составь из этих частей «кораблик» и наклей его в тетрадь.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica20-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 20, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 20, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-20/')
    RETURNING id INTO v_task_id;

