    VALUES (v_task_id, v_textbook_id, 3, '272bb56b10eab6848bf62b2d3ce7c869acc43edff5e6982be4fd577482284695', '1,2,3,4,5', '["раз"]'::jsonb, 'игра "пифагор". 1)нарисуй на бумаге квадрат со стороной 5 см. 2) разбей этот квадрат на части, как показано на рисунке. 3) раскрась части квадрата разными цветами. 4) вырежи каждую часть квадрата. 5) составь из этих частей "кораблик" и наклей его в тетрадь');

    VALUES (v_textbook_id, 21, '1', 0, 'Рассмотри различные способы деления 460 : 2. Объясни, как получен нуль в частном. 1 способ: 460 : 2 = (400 + 60) : 2 = 400 : 2 + 60 : 2 = 230. 2 способ: 1) Делим сотни: 4 с : 2 = 2 с.; 2) Делим десятки: 6 д : 2 = 3 д.; 3) Делим единица: 0 е : 2 = 0 е.; Итак, 460 : 2 = 230. 3 способ: деление углом.', '</p>\n\n<p class="text">Рассмотри различные способы деления 460 : 2. Объясни, как получен нуль в частном.<br/>\n1 способ:<br/>\n460 : 2 = (400 + 60) : 2 = 400 : 2 + 60 : 2 = 230.<br/>\n<br/>\n2 способ:<br/>\n1) Делим сотни: 4 с : 2 = 2 с.;<br/>\n2) Делим десятки: 6 д : 2 = 3 д.;<br/>\n3) Делим единица: 0 е : 2 = 0 е.;<br/>\nИтак, 460 : 2 = 230.<br/>\n<br/>\n3 способ: <br/>\nделение углом.\n</p>', 'Нуль в частном получается так, что количество единиц равно нулю, а при делении нуля на любое число получается ноль. Поэтому, цифра единиц – 0.', '<p>\nНуль в частном получается так, что количество единиц равно нулю, а при делении нуля на любое число получается ноль. Поэтому, цифра единиц – 0.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-21/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ff9a57c85607259094f041029b72b8f6033a451c843e577be553fc3f7d8e71b4', '0,1,2,3,4,6,60,230,400,460', '["раз"]'::jsonb, 'рассмотри различные способы деления 460:2. объясни, как получен нуль в частном. 1 способ:460:2=(400+60):2=400:2+60:2=230. 2 способ:1) делим сотни:4 с:2=2 с.; 2) делим десятки:6 д:2=3 д.; 3) делим единица:0 е:2=0 е.; итак, 460:2=230. 3 способ:деление углом');

    VALUES (v_textbook_id, 21, '2', 1, 'Реши примеры тремя способами (как в № 1): 360 : 3; 540 : 2; 840 : 7; 720 : 4.', '</p>\n\n<p class="text">Реши примеры тремя способами (как в № 1):<br/>\n360 : 3;<br/>	\n540 : 2;<br/>	\n840 : 7;<br/>\n720 : 4.\n\n</p>', '360 : 3. 1 способ: 360 : 3 = (300 + 60) : 3 = 300 : 3 + 60 : 3 = 100 + 20 = 120. 2 способ: 1)Делим сотни: 3 сот. : 3 = 1 сот.; 2)Делим десятки: 6 дес. : 3 = 2 дес.; 3) Делим единицы: 0 ед. : 2 = 0 ед.; Итак, 360 : 3 = 120. 3 способ:', '<p>\n360 : 3.<br/>\n<br/>\n1 способ: <br/>\n360 : 3 = (300 + 60) : 3 = 300 : 3 + 60 : 3 = 100 + 20 = 120.<br/>\n<br/>\n2 способ:<br/>\n1)Делим сотни: 3 сот. : 3 = 1 сот.;<br/>\n2)Делим десятки: 6 дес. : 3 = 2 дес.;<br/>\n3) Делим единицы: 0 ед. : 2 = 0 ед.;<br/>\nИтак, 360 : 3 = 120.<br/>\n<br/>\n3 способ:\n</p>\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica21-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 21, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 21, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-21/')
    RETURNING id INTO v_task_id;

