    VALUES (v_textbook_id, 21, '3', 2, 'Выполни деление углом и сделай проверку: а) 2 730 : 3; б) 3 280 : 4; в) 51 800 : 7; г) 78 500 : 5; д) 48 640 : 8; е) 30 360 : 6; ж) 610 040 : 2; з) 322 000 : 4.', '</p>\n\n<p class="text">\nВыполни деление углом и сделай проверку:<br/>\nа) 2 730 : 3;<br/>\nб) 3 280 : 4;<br/>\nв) 51 800 : 7;<br/>\nг) 78 500 : 5;<br/>\nд) 48 640 : 8;<br/>\nе) 30 360 : 6;<br/>\nж) 610 040 : 2;<br/>\nз) 322 000 : 4.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica21-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 21, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 21, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-21/')
