    VALUES (v_textbook_id, 21, '4', 3, 'Реши уравнения с комментированием и сделай проверку: x + 5591 = 7030; 8005 – х = 6997; x – 36 083 = 568.', '</p>\n\n<p class="text">\nРеши уравнения с комментированием и сделай проверку:<br/>\nx + 5591 = 7030;<br/>\n8005 – х = 6997;<br/>\nx – 36 083 = 568.\n\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica21-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 21, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 21, номер 4, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-21/')
    RETURNING id INTO v_task_id;

