    VALUES (v_task_id, v_textbook_id, 3, '535c0960d0144fec0039aa4b70a13dbedc549be7744b62faf6cc7c65c1952fd2', '36,083,568,5591,6997,7030,8005', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:x+5591=7030; 8005-х=6997; x-36 083=568');

    VALUES (v_textbook_id, 21, '5', 4, 'Запиши выражения и прочитай, называя последнее действие: А) Из произведения чисел а и b вычесть сумму чисел с и d. Б) Частное чисел m и n умножить на разность чисел k и t. В) Сумму чисел х и у разделить на произведение чисел а и с. Г) Разность чисел b и d умножить на частное чисел m и k.', '</p>\n\n<p class="text">\nЗапиши выражения и прочитай, называя последнее действие:<br/>\nА) Из произведения чисел а и b вычесть сумму чисел с и d.<br/>\nБ) Частное чисел m и n умножить на разность чисел k и t.<br/>\nВ) Сумму чисел х и у разделить на произведение чисел а и с.<br/>\nГ) Разность чисел b и d умножить на частное чисел m и k.\n</p>', 'А) (а – b) – (c + d) – разность разности числе а и b и суммы чисел с и d. Б) (m : n) ⋅ (k – t) – значение произведения частного чисел m и n и разности чисел k и t. В) (х + у) : (а ⋅ с) – частное суммы чисел х и у и произведения чисел а и с. Г) (b – d) ⋅ (m : k) – значение произведения разности чисел b и d и частного чисел m и k.', '<p>\nА) (а – b) – (c + d) – разность разности числе а и b и суммы чисел с и d.<br/>\nБ) (m : n) ⋅ (k – t) – значение произведения частного чисел m и n и разности чисел k и t.<br/>\nВ) (х + у) : (а ⋅ с) – частное суммы чисел х и у и произведения чисел а и с.<br/>\nГ) (b – d) ⋅ (m : k) – значение произведения разности чисел b и d и частного чисел m и k.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-21/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'b39207534a3f1e6b6f56d41e689afd8fbf801b6198fe30abb5c006f376ce2166', NULL, '["раздели","разность","произведение","частное","раз"]'::jsonb, 'запиши выражения и прочитай, называя последнее действие:а) из произведения чисел а и b вычесть сумму чисел с и d. б) частное чисел m и n умножить на разность чисел k и t. в) сумму чисел х и у разделить на произведение чисел а и с. г) разность чисел b и d умножить на частное чисел m и k');

    VALUES (v_textbook_id, 21, '6', 5, 'Надо было построить дорогу длиной а км. Сначала построили b км, а потом с км. Сколько километров осталось построить? Составь выражение. Найди его значение, если: 1) а = 32, b = 14, с = 9; 2) а = 234, b = 76, с = 98.', '</p>\n\n<p class="text">\nНадо было построить дорогу длиной а км. Сначала построили b км, а потом с км. Сколько километров осталось построить? Составь выражение. Найди его значение, если:<br/>\n1) а = 32, b = 14, с = 9; <br/>\n2) а = 234, b  = 76, с = 98.\n</p>', 'а – (b + c); 1) при а = 32, b = 14, с = 9; 32 – (14 + 9) = 32 – 23 = 9 (км) – дороги осталось построить; 2) при а = 234, b = 76, с = 98. 234 – (76 + 98) = 234 – 174 = 60 (км) – дороги осталось построить; Ответ: 9 км; 60 км.', '<p>\nа – (b + c);<br/>\n1) при а = 32, b = 14, с = 9;<br/>\n32 – (14 + 9) = 32 – 23 = 9 (км) – дороги осталось построить;<br/>\n<br/>\n2) при а = 234, b  = 76, с = 98.<br/>\n234 – (76 + 98) = 234 – 174 = 60 (км) – дороги осталось построить;<br/>\nОтвет: 9 км; 60 км.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-21/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'e9eab94c491eed6b299418a32bf3b98849189d3a1938796fee1bbf8bc91b4b7f', '1,2,9,14,32,76,98,234', '["найди"]'::jsonb, 'надо было построить дорогу длиной а км. сначала построили b км, а потом с км. сколько километров осталось построить? составь выражение. найди его значение, если:1) а=32, b=14, с=9; 2) а=234, b=76, с=98');

    VALUES (v_textbook_id, 22, '7', 0, 'Два катера отошли от одной пристани в противоположных направлениях. Первый катер прошел 56 км, а второй – в 2 раза меньше. Какое расстояние стало между катерами? На сколько километров больше прошел первый катер, чем второй?', '</p>\n\n<p class="text">Два катера отошли от одной пристани в противоположных направлениях. Первый катер прошел 56 км, а второй – в 2 раза меньше. Какое расстояние стало между катерами? На сколько километров больше прошел первый катер, чем второй?</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica22-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 22, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 22, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-22/')
    RETURNING id INTO v_task_id;

