    VALUES (v_task_id, v_textbook_id, 3, '4dccfbae97c05e643bedd5b6e4cedb01b2b0bc3ee70cccf614f893839029fa77', '2,56', '["больше","меньше","раз","раза"]'::jsonb, 'два катера отошли от одной пристани в противоположных направлениях. первый катер прошел 56 км, а второй-в 2 раза меньше. какое расстояние стало между катерами? на сколько километров больше прошел первый катер, чем второй');

    VALUES (v_textbook_id, 22, '8', 1, 'Придумай задачи, которые решаются так: А) (240 : 6) ⋅ 9; б) 560 : (350 : 5).', '</p>\n\n<p class="text">Придумай задачи, которые решаются так:\nА) (240 : 6) ⋅ 9;			\nб) 560 : (350 : 5).\n\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica22-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 22, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 22, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-22/')
    RETURNING id INTO v_task_id;

