    VALUES (v_textbook_id, 22, '9', 2, 'Какое число «лишнее»: 35, 44, 56, 80, 71, 125, 26? Найди несколько вариантов решения.', '</p>\n\n<p class="text">Какое число «лишнее»: 35, 44, 56, 80, 71, 125, 26? Найди несколько вариантов решения.</p>', 'Лишнее число 44, потому что оно записано одинаковыми цифрами. Лишнее число 80, потому что оно круглое. Лишнее число 125, потому что оно трехзначное. Лишнее число 56, потому что сумма цифр в нем не равна 8, а в других – равна.', '<p>\nЛишнее число 44, потому что оно записано одинаковыми цифрами.<br/>\nЛишнее число 80, потому что оно круглое.<br/>\nЛишнее число 125, потому что оно трехзначное.<br/>\nЛишнее число 56, потому что сумма цифр в нем не равна 8, а в других – равна.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-22/')
    RETURNING id INTO v_task_id;

