    VALUES (v_textbook_id, 22, '10', 3, 'Литературная викторина «Волшебные слова» Вычисли х по алгоритму и заполни таблицу в тетради. Расшифруй название сказки. Назови имя её главного героя и «волшебные слова», которые он говорил.', '</p>\n\n<p class="text">Литературная викторина «Волшебные слова»\nВычисли х по алгоритму и заполни таблицу в тетради. Расшифруй название сказки. Назови имя её главного героя и «волшебные слова», которые он говорил.\n</p>', '1 000 000 000 000 + 1 000 000 000 + 1 000 000 + 1 000 + 1 = 1 001 001 001 001; Значит, в числе 8 нулей. 20, 25, 29; 52, 59, 50; 92, 95, 90; Вывод: из всех цифр на карточках можно составить 9 двузначных чисел.', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica22-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 22, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 22, номер 10, год 2022."/>\n\n\n<p>\n1 000 000 000 000 + 1 000 000 000 + 1 000 000 + 1 000 + 1 = 1 001 001 001 001;<br/>\nЗначит, в числе 8 нулей.\n</p>\n\n\n<p>\n20, 25, 29;<br/>\n52, 59, 50;<br/>\n92, 95, 90;<br/>\nВывод: из всех цифр на карточках можно составить 9 двузначных чисел.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-22/')
    RETURNING id INTO v_task_id;

