    VALUES (v_textbook_id, 23, '2', 1, 'Запиши выражения: А) Частное чисел а и суммы чисел b и c. Б) Разность числа d и произведения чисел m и n. В) Произведение частного чисел b и k и разности чисел у и z. Г) Сумма утроенного числа t и произведения чисел а и m.', '</p>\n\n<p class="text">\nЗапиши выражения:<br/>\nА) Частное чисел а и суммы чисел b и c.<br/>\nБ) Разность числа d и произведения чисел m и n.<br/>\nВ) Произведение частного чисел b и k и разности чисел у и z.<br/>\nГ) Сумма утроенного числа t и произведения чисел а и m.\n</p>', 'А) а : (b + с); Б) d – (m ⋅ n); В) (b ⋅ k) – (y – z); Г) t ⋅ 3 + (a ⋅ m).', '<p>\nА) а : (b + с);<br/>\nБ) d – (m ⋅ n);<br/>\nВ) (b ⋅ k) – (y – z);<br/>\nГ) t ⋅ 3 + (a ⋅ m).\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-23/')
    RETURNING id INTO v_task_id;

