    VALUES (v_textbook_id, 23, '8', 8, 'Валя задумала число, разделила его на 7, умножила на 1000, вычла 654 и прибавила 108. В результате у неё получилось 8 454. Какое число задумала Валя?', '</p>\n\n<p class="text">\nВаля задумала число, разделила его на 7, умножила на 1000, вычла 654 и прибавила 108. В результате у неё получилось 8 454. Какое число задумала Валя?\n</p>', 'Пусть задуманное число – х. Чтобы понять, какое число было задумано, нужно понять, какие действия с числом были выполнены: 1) разделить на 7; 2) умножить на 1 000; 3) вычесть 654; 4) прибавить 108. В результате получилось число 8 454. Значит, чтобы узнать, какое число было задумано, нужно выполнить с числом обратные действия. 8454 – 108 = 8 346; 8 346 + 654 = 9 000; 9 000 : 1 000 = 9; 9 ⋅ 7 = 63; Ответ: было задумано число 63.', 'Пусть задуманное число – х.<br/>\nЧтобы понять, какое число было задумано, нужно понять, какие действия с числом были выполнены:<br/>\n1) разделить на 7;<br/>\n2) умножить на 1 000;<br/>\n3) вычесть 654;<br/>\n4) прибавить 108.<br/>\nВ результате получилось число 8 454.<br/>\nЗначит, чтобы узнать, какое число было задумано, нужно выполнить с числом обратные действия.<br/>\n<br/>\n8454 – 108 = 8 346;<br/>\n8 346 + 654 = 9 000;<br/>\n9 000 : 1 000 = 9;<br/>\n9 ⋅ 7 = 63;<br/>\nОтвет: было задумано число 63.<br/>\n<p></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-23/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '5f86065664e76df0a009ac07c9beae4a0141ff5938979a57d3ac07b96a2351c4', '7,8,108,454,654,1000', '["раздели","раз"]'::jsonb, 'валя задумала число, разделила его на 7, умножила на 1000, вычла 654 и прибавила 108. в результате у неё получилось 8 454. какое число задумала валя');

    VALUES (v_textbook_id, 24, '9', 0, 'Выполни действия. Объясни, почему каждое из полученных чисел может быть «лишним».', '</p>\n\n<p class="text">Выполни действия. Объясни, почему каждое из полученных чисел может быть «лишним».</p>', '1) 72 – 16 = 56; 56 : 8 = 7; 7 ⋅ 100 = 700; 700 : 14 = 50; 2) 900 : 30 = 30; 30 – 12 = 18; 18 + 34 = 52; 52 ⋅ 2 = 104; 3) 16 ⋅ 4 = 64; 64 – 7 = 57; 57 : 19 = 3; 3 ⋅ 150 = 450; 4) 78 : 6 = 13; 13 ⋅ 4 = 52; 52 + 28 = 80; 80 ⋅ 4 = 320; 5) 120 : 10 = 12; 12 ⋅ 7 = 84; 84 – 59 = 25; 25 ⋅ 20 = 500. Вывод: 50 – лишнее число, потому что оно двузначное; 104 – лишнее число, потому что оно не круглое; 450 – лишнее число, потому что сумма цифр в нем не 5; 320 – лишнее число, потому что оно делится на 80; 500 – лишнее число, потому что в его записи два нуля.', '<p>\n1)<br/>\n72 – 16 = 56;<br/>\n56 : 8 = 7;<br/>\n7 ⋅ 100 = 700;<br/>\n700 : 14 = 50;<br/>\n<br/>\n2)<br/>\n900 : 30 = 30;<br/>\n30 – 12 = 18;<br/>\n18 + 34 = 52;<br/>\n52 ⋅ 2 = 104;<br/>\n<br/>\n3)<br/>\n16 ⋅ 4 = 64;<br/>\n64 – 7 = 57;<br/>\n57 : 19 = 3;<br/>\n3 ⋅ 150 = 450;<br/>\n<br/>\n4) <br/>\n78 : 6 = 13;<br/>\n13 ⋅ 4 = 52;<br/>\n52 + 28 = 80;<br/>\n80 ⋅ 4 = 320;<br/>\n<br/>\n5) <br/>\n120 : 10 = 12;<br/>\n12 ⋅ 7 = 84;<br/>\n84 – 59 = 25;<br/>\n25 ⋅ 20 = 500.<br/>\n<br/>\nВывод:<br/>\n50 – лишнее число, потому что оно двузначное;<br/>\n104 – лишнее число, потому что оно не круглое;<br/>\n450 – лишнее число, потому что сумма цифр в нем не 5;<br/>\n320 – лишнее число, потому что оно делится на 80;<br/>\n500 – лишнее число, потому что в его записи два нуля.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-24/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '0f3cbf34685fc9b09f51957cb2a61b261f1167a6eeb96dfcacf4b8ba99e15218', NULL, NULL, 'выполни действия. объясни, почему каждое из полученных чисел может быть "лишним"');

    VALUES (v_textbook_id, 24, '10', 1, 'На выставку привели 156 собак четырех пород: пуделей, шнауцеров, колли и спаниелей. Пуделей было 24, шнауцеров – в 3 раза больше, чем пуделей, а колли – на 38 меньше, чем шнауцеров. Сколько спаниелей привели на выставку? На сколько шнауцеров было больше, чем спаниелей? Что еще можно спросить?', '</p>\n\n<p class="text">На выставку привели 156 собак четырех пород: пуделей, шнауцеров, колли и спаниелей. Пуделей было 24, шнауцеров – в 3 раза больше, чем пуделей, а колли – на 38 меньше, чем шнауцеров. Сколько спаниелей привели на выставку? На сколько шнауцеров было больше, чем спаниелей?<br/>\nЧто еще можно спросить?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica24-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 24, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 24, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-24/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica24-nomer10.jpg', 'peterson/3/part2/page24/task10_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'ff512c354b11e640e4520db1e63b42e39b1cae5a4657523fc0af6ce80a4aab44', '3,24,38,156', '["больше","меньше","раз","раза"]'::jsonb, 'на выставку привели 156 собак четырех пород:пуделей, шнауцеров, колли и спаниелей. пуделей было 24, шнауцеров-в 3 раза больше, чем пуделей, а колли-на 38 меньше, чем шнауцеров. сколько спаниелей привели на выставку? на сколько шнауцеров было больше, чем спаниелей? что еще можно спросить');

    VALUES (v_textbook_id, 24, '11', 2, 'Найди прямые углы многоугольников. Составь множества А, B, С, D, Е и F, запиши их с помощью фигурных скобок. Построй диаграмму Эйлера-Венна этих множеств. А – множество многоугольников; В – множество многоугольников, имеющих хотя бы один прямой угол; С – множество треугольников; D – множество четырехугольников; Е – множество прямоугольников; F – множество квадратов.', '</p>\n\n<p class="text">Найди прямые углы многоугольников. Составь множества А, B, С, D, Е и F, запиши их с помощью фигурных скобок. Построй диаграмму Эйлера-Венна этих множеств.<br/>\nА – множество многоугольников;<br/>\nВ – множество многоугольников, имеющих хотя бы один прямой угол;<br/>\nС – множество треугольников;<br/>\nD – множество четырехугольников;<br/>\nЕ – множество прямоугольников;<br/>\nF – множество квадратов.\n</p>', 'А: {a, b, р, d, f, m, s, k, n, s} B: {a, p, b, d, f, m, s, k} C: {a, n} D: {b, p, d, f, m, s} E: {p, f, m, s} F: {m. s}', '<p>\nА: {a, b, р, d, f, m, s, k, n, s}<br/>\nB: {a, p, b, d, f, m, s, k}<br/>\nC: {a, n}<br/>\nD: {b, p, d, f, m, s}<br/>\nE: {p, f, m, s}<br/>\nF: {m. s}\n</p>\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica24-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 24, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 24, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-24/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica24-nomer11.jpg', 'peterson/3/part2/page24/task11_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '422ef703373bba00b79353cc067be25f2f97d1ad66a9e542b50626662cac153d', NULL, '["найди"]'::jsonb, 'найди прямые углы многоугольников. составь множества а, b, с, d, е и f, запиши их с помощью фигурных скобок. построй диаграмму эйлера-венна этих множеств. а-множество многоугольников; в-множество многоугольников, имеющих хотя бы один прямой угол; с-множество треугольников; d-множество четырехугольников; е-множество прямоугольников; f-множество квадратов');

    VALUES (v_textbook_id, 25, '1', 0, 'Вычисли устно: 810 : 90; 2800 : 400; 6400 : 80; 490 000 : 700; Назови правила деления круглых чисел. Как с их помощью упростить деление круглых чисел углом (без остатка)?', '</p>\n\n<p class="text">Вычисли устно:<br/>\n810 : 90;<br/>		\n2800 : 400;<br/>		\n6400 : 80;<br/>		\n490 000 : 700;<br/>\nНазови правила деления круглых чисел. Как с их помощью упростить деление круглых чисел углом (без остатка)?\n</p>', 'Чтобы разделить 810 на 90, представляю числа в большем разряде. Тогда, 81 дес. : 9 дес. = 9; Чтобы разделить 2 800 на 400, представляю числа в большем разряде. Тогда, 28 сот. : 4 сот. = 7; Чтобы разделить 6 400 на 80, представляю числа в большем разряде. Тогда, 640 дес. : 8 дес. = 80; Чтобы разделить 490 000 на 700, представляю числа в большем разряде. Тогда, 4 900 сот. : 7 сот. = 700; Вывод: когда делю круглые числа, то представляю их в виде большее разряда. При этому исчезают нули. Значит, чтобы упростить деление круглых чисел, можно просто отбрасывать одинаковое количество нулей.', '<p>\nЧтобы разделить 810 на 90, представляю числа в большем разряде. Тогда, 81 дес. : 9 дес. = 9;\nЧтобы разделить 2 800 на 400, представляю числа в большем разряде. Тогда, 28 сот. : 4 сот. = 7;\nЧтобы разделить 6 400 на 80, представляю числа в большем разряде. Тогда, 640 дес. : 8 дес. = 80;\nЧтобы разделить 490 000 на 700, представляю числа в большем разряде. Тогда, 4 900 сот. : 7 сот. = 700;\nВывод: когда делю круглые числа, то представляю их в виде большее разряда. При этому исчезают нули. Значит, чтобы упростить деление круглых чисел, можно просто отбрасывать одинаковое количество нулей.\n</p>', 'Деление круглых чисел углом (без остатка) При делении круглых чисел углом (без остатка) можно отбросить в делимом и делителе поровну нулей.', '<div class="recomended-block">\n<span class="title">Деление круглых чисел углом (без остатка)</span>\n<p>\nПри делении круглых чисел углом (без остатка) можно отбросить в делимом и делителе поровну нулей.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-25/')
    RETURNING id INTO v_task_id;

