    VALUES (v_textbook_id, 25, '2', 1, 'Вычисли устно: Выполни деление углом и сделай проверку: А) 6 950 : 50; Б) 272 000 : 800; В) 185 400 : 600; г) 181 200 : 30; д) 340 160 : 40; е) 457 200 : 90; ж) 8 154 000 : 90; з) 6 230 000 : 700; и) 15 035 000 : 5 000.', '</p>\n\n\n<p class="text">Вычисли устно:<br/>\nВыполни деление углом и сделай проверку:<br/>\nА) 6 950 : 50;<br/>\nБ) 272 000 : 800;<br/>\nВ) 185 400 : 600;<br/>\nг) 181 200 : 30;<br/>\nд) 340 160 : 40;<br/>\nе) 457 200 : 90;<br/>\nж) 8 154 000 : 90;<br/>\nз) 6 230 000 : 700;<br/>\nи) 15 035 000 : 5 000.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica25-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 25, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 25, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-25/')
