    VALUES (v_textbook_id, 25, '3', 2, 'Составь и реши уравнение: А) Какое число надо умножить на 80, чтобы получить 68 800? Б) какое число надо разделить на 500, чтобы получить 8 560? В) На какое число надо разделить 720 630, чтобы получить 90?', '</p>\n\n\n<p class="text">\nСоставь и реши уравнение:<br/>\nА) Какое число надо умножить на 80, чтобы получить 68 800?<br/>\nБ) какое число надо разделить на 500, чтобы получить 8 560?<br/>\nВ) На какое число надо разделить 720 630, чтобы получить 90?\n\n</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica25-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 25, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 25, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-25/')
