    VALUES (v_textbook_id, 26, '6', 1, 'БЛИЦтурнир. А) Три одинаковые тетради стоят а р. Сколько надо заплатить за 7 таких тетрадей? Б) Две одинаковые пачки печенья стоят b р. Сколько таких пачек можно купить на с р.? В)В комнате n стульев, а в коридоре в 4 раза меньше. Сколько стульев в комнате и в коридоре вместе? Г) В двух банках с л молока. В первой банке на d л молока больше. Чем во второй. Сколько литров молока в первой банке? Д) Верёвку длиной х дм разрезали на два куска. Один из кусков на у дм короче другого. Чему равна длина меньшего куска?', '</p>\n\n<p class="text">БЛИЦтурнир.<br/>	\nА) Три одинаковые тетради стоят а р. Сколько надо заплатить за 7 таких тетрадей?<br/>	\nБ) Две одинаковые пачки печенья стоят b р. Сколько таких пачек можно купить на с р.?<br/>	\nВ)В комнате n стульев, а в коридоре в 4 раза меньше. Сколько стульев в комнате и в коридоре вместе?<br/>	\nГ) В двух банках с л молока. В первой банке на d л молока больше. Чем во второй. Сколько литров молока в первой банке?<br/>	\nД) Верёвку длиной х дм разрезали на два куска. Один из кусков на у дм короче другого. Чему равна длина меньшего куска?\n</p>', 'А) (а : 3) ⋅ 7 (руб.) – стоят 7 таких тетрадей; Б) с : (b : 2) (шт.) –пачек печенья можно купить на с рублей; В) n + (n : 4) (шт.) – стульев было в комнате и коридоре; Г) (с – d) : 2 (л) – молока в первой банке; Д) (х – y) : 2 (дм) – длина меньшего куска.', '<p>\nА) (а : 3) ⋅ 7 (руб.) – стоят 7 таких тетрадей;<br/>	\nБ) с : (b : 2) (шт.) –пачек печенья можно купить на с рублей;<br/>	\nВ) n + (n : 4) (шт.) – стульев было в комнате и коридоре;<br/>	\nГ) (с – d) : 2 (л) – молока в первой банке;<br/>	\nД) (х – y) : 2 (дм) – длина меньшего куска.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-26/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '3eddff858e077cf116c0c7d3fd5cf10f89d34b1acf5a87ef7da06b764bf496cd', '4,7', '["больше","меньше","раз","раза"]'::jsonb, 'блицтурнир. а) три одинаковые тетради стоят а р. сколько надо заплатить за 7 таких тетрадей? б) две одинаковые пачки печенья стоят b р. сколько таких пачек можно купить на с р.? в)в комнате n стульев, а в коридоре в 4 раза меньше. сколько стульев в комнате и в коридоре вместе? г) в двух банках с л молока. в первой банке на d л молока больше. чем во второй. сколько литров молока в первой банке? д) верёвку длиной х дм разрезали на два куска. один из кусков на у дм короче другого. чему равна длина меньшего куска');

    VALUES (v_textbook_id, 26, '7', 2, 'Вырази: А) в метрах: 24 км; 3 км 720 м; 2 км 50 м. Б) в километрах и метрах: 6 478 м; 19 003 м; 634 560 м; В) в сантиметрах: 4 дм 6 см; 8 м 35 см; 4 м 7 см; 210 мм; Г) в сантиметрах и миллиметрах: 92 мм; 485 мм; 3 644 мм.', '</p>\n\n<p class="text">Вырази:<br/>	\nА) в метрах: 24 км; 3 км 720 м; 2 км 50 м.<br/>	\nБ) в километрах и метрах: 6 478 м; 19 003 м; 634 560 м;<br/>	\nВ) в сантиметрах: 4 дм 6 см; 8 м 35 см; 4 м 7 см; 210 мм;<br/>	\nГ) в сантиметрах и миллиметрах: 92 мм; 485 мм; 3 644 мм.\n</p>', 'А) в метрах: 24 км = 24 000 м; 3 км 720 м = 3 000 м + 720 м = 3 720 м; 2 км 50 м = 2 000 м + 50 м = 2 050 м; Б) в километрах и метрах: 6 478 м = 6 000 + 478 = 6 км + 478 м; 19 003 м = 19 км 3 м; 634 560 м = 634 км 560 м; В) в сантиметрах: 4 дм 6 см = 40 см + 6 см = 46 см; 8 м 35 см = 800 см + 35 см = 835 см; 4 м 7 см = 400 см + 7 см = 407 см; 210 мм = 21 см; Г) в сантиметрах и миллиметрах: 92 мм = 90 мм + 2 мм = 9 см 2 мм; 485 мм = 480 мм + 5 мм = 48 см 5 мм; 3 644 мм = 3 640 мм + 4 мм = 364 см 4 мм.', '<p>\nА) в метрах:<br/>	\n24 км = 24 000 м;<br/>	\n3 км 720 м = 3 000 м + 720 м = 3 720 м;<br/>	\n2 км 50 м = 2 000 м + 50 м = 2 050 м;<br/>	\n<br/>\nБ) в километрах и метрах:<br/>\n6 478 м = 6 000 + 478 = 6 км + 478 м;<br/>	\n19 003 м = 19 км 3 м;<br/>	\n634 560 м = 634 км 560 м;<br/>	\n<br/>\nВ) в сантиметрах:<br/>\n4 дм 6 см = 40 см + 6 см = 46 см;<br/>	\n8 м 35 см = 800 см + 35 см = 835 см;<br/>	\n4 м 7 см = 400 см + 7 см = 407 см;<br/>	\n210 мм = 21 см;<br/>	\n<br/>\nГ) в сантиметрах и миллиметрах:<br/>\n92 мм = 90 мм + 2 мм = 9 см 2 мм;<br/>	\n485 мм = 480 мм + 5 мм = 48 см 5 мм;<br/>	\n3 644 мм = 3 640 мм + 4 мм = 364 см 4 мм.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-26/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '84168a60a6528f75b36a257368dea35481cc2123ed961323deccbe82eeebac37', '2,003,3,4,6,7,8,19,24,35', '["раз"]'::jsonb, 'вырази:а) в метрах:24 км; 3 км 720 м; 2 км 50 м. б) в километрах и метрах:6 478 м; 19 003 м; 634 560 м; в) в сантиметрах:4 дм 6 см; 8 м 35 см; 4 м 7 см; 210 мм; г) в сантиметрах и миллиметрах:92 мм; 485 мм; 3 644 мм');

    VALUES (v_textbook_id, 26, '8', 3, 'Начерти четырехугольник. Измерь его стороны и запиши результаты измерений. Вычисли периметр этого четырехугольника.', '</p>\n\n<p class="text">Начерти четырехугольник. Измерь его стороны и запиши результаты измерений. Вычисли периметр этого четырехугольника.</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica26-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 26, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 26, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-26/')
    RETURNING id INTO v_task_id;

