    VALUES (v_textbook_id, 26, '10', 5, 'На ферме у Антона живут индюки и козы, причем тех и других поровну. Какое из данных чисел может быть равно количеству ног у всех этих животных вместе: А. 14; Б. 25; В. 32; Г. 54; Д. 80.', '</p>\n\n<p class="text">На ферме у Антона живут индюки и козы, причем тех и других поровну. Какое из данных чисел может быть равно количеству ног у всех этих животных вместе:<br/>\nА. 14;<br/>\nБ. 25;<br/>\nВ. 32;<br/>\nГ. 54;<br/>\nД. 80.\n</p>', 'У коз – 4 ноги. У индюков – 2 ноги. Значит, чтобы узнать, сколько животных было на ферме, нужно понять, какое количество ног делится на общее количество ног, т.е 2 + 4 = 6 – на число 6. Из всех чисел это только число 54, потому что, 54 : 6 = 9. Ответ: Г. 54.', '<p>\nУ коз – 4 ноги.<br/>\nУ индюков – 2 ноги.<br/>\nЗначит, чтобы узнать, сколько животных было на ферме, нужно понять, какое количество ног делится на общее количество ног, т.е 2 + 4 = 6 – на число 6.<br/>\nИз всех чисел это только число 54, потому что, 54 : 6 = 9.<br/>\nОтвет: Г. 54.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-26/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '68dc74285cdd64a5bd27b9a37912a80483805ed3c2d0819e34ae6f9718f38ca4', '14,25,32,54,80', '["равно"]'::jsonb, 'на ферме у антона живут индюки и козы, причем тех и других поровну. какое из данных чисел может быть равно количеству ног у всех этих животных вместе:а. 14; б. 25; в. 32; г. 54; д. 80');

    VALUES (v_textbook_id, 27, '11', 0, 'Литературная викторина «С улыбкой» Найди примеры с одинаковыми ответами – и ты узнаешь, кто написал такие строчки. Из каких произведений они взяты? А. (40 – 27) ⋅ 4; - Я один раз купался в море, - говорит Мишутка, - и на меня напала акула. Я её бац кулаком, а она меня цап за голову – и откусила. Б. 160 – (94 + 46) : 2; Она быстро-быстро прочитала: - Тыкову дали тыблоко. В. (650 – 400) : 5; Я остановился на лестнице и внятно сказал: - Никакие не «сыски», никакие не «хыхки». А коротки и ясно «фыфки»! Г. 50 : 2 + 7 ⋅ 9; - Ребята сейчас на физкультуре прыгают, а мы с тобой сидим – красота! - Эх, хорошо просто так сидеть!.. Давай через парты прыгать! 1.18 + 27 : 3 ⋅ 8; Л.Пантелеев. 2.36 : 2 + 34; Н.Носов. 3.22 ⋅ (120 : 30); В.Голявкин. 4.80 : 16 ⋅ 10; В.Драгунский.', '</p>\n\n<p class="text">Литературная викторина «С улыбкой»<br/>\nНайди примеры с одинаковыми ответами – и ты узнаешь, кто написал такие строчки. Из каких произведений они взяты?<br/>\nА. (40 – 27) ⋅ 4;<br/>\n- Я один раз купался в море,  - говорит Мишутка, - и на меня напала акула. Я её бац кулаком, а она меня цап за голову – и откусила.<br/>\n<br/>\nБ. 160 – (94 + 46) : 2;<br/>\nОна быстро-быстро прочитала: <br/>\n- Тыкову дали тыблоко.<br/>\n<br/>\nВ. (650 – 400) : 5;<br/>\nЯ остановился на лестнице и внятно сказал:<br/>\n- Никакие не «сыски», никакие не «хыхки». А коротки и ясно «фыфки»!<br/>\n<br/>\nГ. 50 : 2 + 7 ⋅ 9;<br/>\n- Ребята сейчас на физкультуре прыгают, а мы с тобой сидим – красота!<br/>\n- Эх, хорошо просто так сидеть!.. Давай через парты прыгать!<br/>\n<br/>\n1.18 + 27 : 3 ⋅ 8;<br/>\nЛ.Пантелеев.<br/>\n<br/>\n2.36 : 2 + 34;<br/>\nН.Носов.<br/>\n<br/>\n3.22 ⋅ (120 : 30);<br/>\nВ.Голявкин.<br/>\n<br/>\n4.80 : 16 ⋅ 10;<br/>\nВ.Драгунский.\n</p>', 'А. (40 – 27) ⋅ 4 = 13 ⋅ 4 = 52; Б. 160 – (94 + 46) : 2 = 160 – (140 : 2) = 160 – 70 = 90; В. (650 – 400) : 5 = 250 : 5 = 50; Г. 50 : 2 + 7 ⋅ 9 = 25 + 63 = 88; 1.18 + 27 : 3 ⋅ 8 = 18 + 9 ⋅ 8 = 18 + 72 = 90; 2. 36 : 2 + 34 = 18 + 34 = 52; 3. 22 ⋅ (120 : 30) = 22 ⋅ 4 = 88; 4. 80 : 16 ⋅ 10 = 5 ⋅ 10 = 50; Значит, А – 2, Б – 1, В – 4, Г – 3. Тогда:', '<p>\nА. (40 – 27) ⋅ 4 = 13 ⋅ 4 = 52;<br/>\nБ. 160 – (94 + 46) : 2 = 160 – (140 : 2) = 160 – 70 = 90;<br/>\nВ. (650 – 400) : 5 = 250 : 5 = 50;<br/>\nГ. 50 : 2 + 7 ⋅ 9 = 25 + 63 = 88;<br/>\n<br/>\n1.18 + 27 : 3 ⋅ 8 = 18 + 9 ⋅ 8 = 18 + 72 = 90;<br/>\n2. 36 : 2 + 34 = 18 + 34 = 52;<br/>\n3. 22 ⋅ (120 : 30) = 22 ⋅ 4 = 88;<br/>\n4. 80 : 16 ⋅ 10 = 5 ⋅ 10 = 50;<br/>\nЗначит, А – 2, Б – 1, В – 4, Г – 3.<br/>\nТогда:\n</p>\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica27-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 27, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 27, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-27/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica27-nomer11.jpg', 'peterson/3/part2/page27/task11_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'ed2694c3b86fa0312908a1d161f2dc334aad795ab23209bf8e24c8867a06de14', '1,2,3,4,5,7,8,9,10,16', '["найди","раз"]'::jsonb, 'литературная викторина "с улыбкой" найди примеры с одинаковыми ответами-и ты узнаешь, кто написал такие строчки. из каких произведений они взяты? а. (40-27) ⋅ 4;-я один раз купался в море,-говорит мишутка,-и на меня напала акула. я её бац кулаком, а она меня цап за голову-и откусила. б. 160-(94+46):2; она быстро-быстро прочитала:-тыкову дали тыблоко. в. (650-400):5; я остановился на лестнице и внятно сказал:-никакие не "сыски", никакие не "хыхки". а коротки и ясно "фыфки"! г. 50:2+7 ⋅ 9;-ребята сейчас на физкультуре прыгают, а мы с тобой сидим-красота!-эх, хорошо просто так сидеть!.. давай через парты прыгать! 1.18+27:3 ⋅ 8; л.пантелеев. 2.36:2+34; н.носов. 3.22 ⋅ (120:30); в.голявкин. 4.80:16 ⋅ 10; в.драгунский');

    VALUES (v_textbook_id, 28, '1', 0, 'Назови правила деления круглых чисел. Вычисли устно: 24 000 : 3; 7 200 : 900; 15 000 : 50 ; 30 000 : 600; 560 000 : 8 000; 4 200 000 : 7 000.', '</p>\n\n<p class="text">Назови правила деления круглых чисел. Вычисли устно:<br/>\n24 000 : 3;<br/>\n7 200 : 900;<br/>\n15 000 : 50	;<br/>\n30 000 : 600;<br/>\n560 000 : 8 000;<br/>\n4 200 000 : 7 000.\n</p>', 'Чтобы поделить круглые числа, нужно отбросить нули и разделить оставшиеся числа. Кроме этого можно представить число в более крупных единицах и выполнить деление. 24 тыс. : 3 = 8 тыс. = 8 000; 7 200 : 900 = 8; 15 000 : 50 = 300; 30 000 : 600 = 50; 560 000 : 8 000 = 560 тыс. : 8 тыс. = 70; 4 200 000 : 7 000 = 4 200 : 7 = 42 сот. : 7 = 6 сот. = 600.', '<p>\nЧтобы поделить круглые числа, нужно отбросить нули и разделить оставшиеся числа. Кроме этого можно представить число в более крупных единицах и выполнить деление.<br/>\n24 тыс. : 3 = 8 тыс. = 8 000;<br/>\n7 200 : 900 = 8;<br/>\n15 000 : 50 = 300;<br/>\n30 000 : 600 = 50;<br/>\n560 000 : 8 000 = 560 тыс. : 8 тыс. = 70;<br/>\n4 200 000 : 7 000 = 4 200 : 7 = 42 сот. : 7 = 6 сот. = 600.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-28/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '950e9a3a386996d07bfad09e8056c42d9652f11a0cc4e672261d2167d05f88a3', '000,3,4,7,8,15,24,30,50,200', '["вычисли"]'::jsonb, 'назови правила деления круглых чисел. вычисли устно:24 000:3; 7 200:900; 15 000:50 ; 30 000:600; 560 000:8 000; 4 200 000:7 000');

    VALUES (v_textbook_id, 28, '2', 1, 'Выполни деление и сделай проверку умножением: А) 3 200 : 5; Б) 28 560 : 70; в) 492 000 : 400; г) 544 400 : 80; д) 275 130 : 90; е) 3 645 000 : 60.', '</p>\n\n<p class="text">\nВыполни деление и сделай проверку умножением:<br/>\nА) 3 200 : 5;<br/>\nБ) 28 560 : 70;<br/>\nв) 492 000 : 400;<br/>\nг) 544 400 : 80;<br/>\nд) 275 130 : 90;<br/>\nе) 3 645 000 : 60.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica28-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 28, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 28, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-28/')
    RETURNING id INTO v_task_id;

