    VALUES (v_textbook_id, 28, '3', 2, 'Составь схемы и реши задачи. Сравни их. Чем они похожи и чем различаются? А) В двух группах детского сада 36 детей. В первой группе на 4 малыша меньше, чем во второй. Сколько детей в каждой из этих групп? Б) За два дня плотник сделал 36 табуреток. В первый день он сделал на 4 табуретки меньше, чем во второй. Сколько табуреток сделал плотник в каждый из этих дней?', '</p>\n\n<p class="text">\nСоставь схемы и реши задачи. Сравни их. Чем они похожи и чем различаются?<br/>\nА) В двух группах детского сада 36 детей. В первой группе на 4 малыша меньше, чем во второй. Сколько детей в каждой из этих групп?<br/>\nБ) За два дня плотник сделал 36 табуреток. В первый день он сделал на 4 табуретки меньше, чем во второй. Сколько табуреток сделал плотник в каждый из этих дней?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica28-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 28, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 28, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-28/')
    RETURNING id INTO v_task_id;

