    VALUES (v_task_id, v_textbook_id, 3, 'ecf9ac3a6ee8066ef01166830737cdbe17b43fc9fea24152c0ba99d473cba142', '4,36', '["реши","сравни","меньше","раз"]'::jsonb, 'составь схемы и реши задачи. сравни их. чем они похожи и чем различаются? а) в двух группах детского сада 36 детей. в первой группе на 4 малыша меньше, чем во второй. сколько детей в каждой из этих групп? б) за два дня плотник сделал 36 табуреток. в первый день он сделал на 4 табуретки меньше, чем во второй. сколько табуреток сделал плотник в каждый из этих дней');

    VALUES (v_textbook_id, 28, '4', 3, 'Реши задачи, составляя выражения. Сравни их. Что ты замечаешь? А) За 3 синих и 5 красных шаров для елки мама заплатила 400 р. Сколько стоит каждый ёлочный шар, если цена шаров одинаковая? Б) в живом уголке было 3 зеленых и 5 желтых попугайчиков. В день они вместе съедают 400 г корма. Сколько граммов корма требуется в день одному попугайчику (при одинаковом расходе корма в день на каждого)?', '</p>\n\n<p class="text">\nРеши задачи, составляя выражения. Сравни их. Что ты замечаешь?<br/>\nА) За 3 синих и 5 красных шаров для елки мама заплатила 400 р. Сколько стоит каждый ёлочный шар, если цена шаров одинаковая?<br/>\nБ) в живом уголке было 3 зеленых и 5 желтых попугайчиков. В день они вместе съедают 400 г корма. Сколько граммов корма требуется в день одному попугайчику (при одинаковом расходе корма в день на каждого)?\n\n</p>', 'А) 400 : (3 + 5) = 400 : 8 = 50 (руб.) – стоит каждый елочный шар. Ответ: 50 рублей. Б) 400 : (3 + 5) = 400 : 8 = 50 (гр.) – корма требуется в день одному попугаю. Ответ: 50 грамм. Вывод: задачи содержат одинаковые числовые данное, но разные жизненные ситуации, т.е. смысловые содержание.', '<p>\nА) 400 : (3 + 5) = 400 : 8 = 50 (руб.) – стоит каждый елочный шар.<br/>\nОтвет: 50 рублей.<br/>\nБ) 400 : (3 + 5) = 400 : 8 = 50 (гр.) – корма требуется в день одному попугаю.<br/>\nОтвет: 50 грамм.<br/>\nВывод: задачи содержат одинаковые числовые данное, но разные жизненные ситуации, т.е. смысловые содержание.\n\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-28/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4b13a8f2e852d0b9cb1b22a7e7bcdcb80a3f6e32074a38e0ac93ea83bd55a827', '3,5,400', '["реши","сравни"]'::jsonb, 'реши задачи, составляя выражения. сравни их. что ты замечаешь? а) за 3 синих и 5 красных шаров для елки мама заплатила 400 р. сколько стоит каждый ёлочный шар, если цена шаров одинаковая? б) в живом уголке было 3 зеленых и 5 желтых попугайчиков. в день они вместе съедают 400 г корма. сколько граммов корма требуется в день одному попугайчику (при одинаковом расходе корма в день на каждого)');

    VALUES (v_textbook_id, 28, '5', 4, 'Реши первую задачу. Дополни вторую задачу так, чтобы её решение совпадало с решением первой. А) В одном отрезе было 58 м ткани, а в другом – 62 м. Из всей этой ткани сшили платья, расходуя на каждое по 3 м. Сколько получилось платьев? Б) Два брата собрали до обеда … кг яблок, а после обеда - … кг. Все яблоки разложили поровну в … ящика. Сколько килограммов яблок было в каждом ящике?', '</p>\n\n<p class="text">\nРеши первую задачу. Дополни вторую задачу так, чтобы её решение совпадало с решением первой.<br/>\nА) В одном отрезе было 58 м ткани, а в другом – 62 м. Из всей этой ткани сшили платья, расходуя на каждое по 3 м. Сколько получилось платьев?<br/>\nБ) Два брата собрали до обеда … кг яблок, а после обеда - … кг. Все яблоки разложили поровну в … ящика. Сколько килограммов яблок было в каждом ящике?\n</p>', 'А) (58 + 62) : 3 = 120 : 3 = 40 (шт.) – платьев из всей ткани получилось. Ответ: 40 платьев. Б) Два брата собрали до обеда 58 кг яблок, а после – 62 кг. Все яблоки разложили поровну в 3 ящика. Сколько килограммов яблок было в каждом ящике?', '<p>\nА) (58 + 62) : 3 = 120 : 3 = 40 (шт.) – платьев из всей ткани получилось.<br/>\nОтвет: 40 платьев.<br/>\nБ) Два брата собрали до обеда 58 кг яблок, а после – 62 кг. Все яблоки разложили поровну в 3 ящика. Сколько килограммов яблок было в каждом ящике?\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-28/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '79a47ac4dfb97af6c6cd0cf53f28462e68cf245bd35cece34bd37958f1ebefd5', '3,58,62', '["реши","раз"]'::jsonb, 'реши первую задачу. дополни вторую задачу так, чтобы её решение совпадало с решением первой. а) в одном отрезе было 58 м ткани, а в другом-62 м. из всей этой ткани сшили платья, расходуя на каждое по 3 м. сколько получилось платьев? б) два брата собрали до обеда ... кг яблок, а после обеда-... кг. все яблоки разложили поровну в ... ящика. сколько килограммов яблок было в каждом ящике');

    VALUES (v_textbook_id, 28, '6', 5, 'Придумай и реши задачи по выражениям: А) (180 + 120) : 60; Б) 700 : (2 + 3); В) 240 : (320 : 8).', '</p>\n\n<p class="text">\nПридумай и реши задачи по выражениям:<br/>\nА) (180 + 120) : 60;<br/>\nБ) 700 : (2 + 3);<br/>\nВ) 240 : (320 : 8).\n</p>', 'А) Первая бригада за смену проложила 180 метров дороги, а вторая – 120 метров. Сколько метров проложил каждый человек в бригадах, если всего их было 60. (180 + 120) : 60 = 300 : 60 = 5 (м) – дороги проложил каждый рабочий. Ответ: 5 метров. Б) Лёша изготавливал 2 самолетика в минуту, а Даша – 3. За сколько минут они вместе изготовят 700 самолетиков? 700 : (2 + 3) = 700 : 5 = 140 (мин) – нужно, чтобы изготовить 700 самолетиков. Ответ: 140 минут. В) у Лили 320 конфет, а у Светы – в 8 раз меньше. Во сколько раз меньше конфет у Светы, чем у Даши, если у Даши их 240?', '<p>\nА) Первая бригада за смену проложила 180 метров дороги, а вторая – 120 метров. Сколько метров проложил каждый человек в бригадах, если всего их было 60.<br/>\n(180 + 120) : 60 = 300 : 60 = 5 (м) – дороги проложил каждый рабочий.<br/>\nОтвет: 5 метров.<br/>\n<br/>\nБ) Лёша изготавливал 2 самолетика в минуту, а Даша – 3. За сколько минут они вместе изготовят 700 самолетиков?<br/>\n700 : (2 + 3) = 700 : 5 = 140 (мин) – нужно, чтобы изготовить 700 самолетиков.<br/>\nОтвет: 140 минут.<br/>\n<br/>\nВ) у Лили 320 конфет, а у Светы – в 8 раз меньше. Во сколько раз меньше конфет у Светы, чем у Даши, если у Даши их 240?\n</p>\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica28-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 28, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 28, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-28/')
    RETURNING id INTO v_task_id;

