    VALUES (v_textbook_id, 29, '7', 0, 'Выполни деление с остатком и сделай проверку: 48 : 9; 53 : 7; 39 : 2; 62 : 3; 29 : 12; 42 : 19; 76 : 15; 90 : 11.', '</p>\n\n<p class="text">Выполни деление с остатком и сделай проверку:<br/>\n48 : 9;<br/>\n53 : 7;<br/>\n39 : 2;<br/>\n62 : 3;<br/>\n29 : 12;<br/>\n42 : 19;<br/>\n76 : 15;<br/>\n90 : 11.\n</p>', '48 : 9 = 5 (ост. 3.); Проверка: 9 * 5 + 3 = 45 + 3 = 48; 53 : 7 = 7 (ост. 4); Проверка: 7 * 7 + 4 = 49 = 4 = 53; 39 : 2 = 19 (ост. 1); Проверка: 19 * 2 + 1 = 38 + 1 = 39; 62 : 3 = 20 (ост. 2); Проверка: 20 * 3 + 3 = 60 + 3 = 63; 29 : 12 = 2 (ост. 5); Проверка: 12 * 2 + 5 = 24 + 5 = 29; 42 : 19 = 2 (ост. 4); Проверка: 19 * 2 + 4 = 38 + 4 = 42; 76 : 15 = 5 (ост. 1); Проверка: 15 * 5 + 1 = 75 + 1 = 76; 90 : 11 = 8 (ост. 2); Проверка: 11 * 8 + 2 = 88 + 2 = 90.', '<p>\n48 : 9 = 5 (ост. 3.);<br/>\nПроверка: 9 * 5 + 3 = 45 + 3 = 48;<br/>\n<br/>\n53 : 7 = 7 (ост. 4);<br/>\nПроверка: 7 * 7 + 4 = 49 = 4 = 53;<br/>\n<br/>\n39 : 2 = 19 (ост. 1);<br/>\nПроверка: 19 * 2 + 1 = 38 + 1 = 39;<br/>\n<br/>\n62 : 3 = 20 (ост. 2);<br/>\nПроверка: 20 * 3 + 3 = 60 + 3 = 63;<br/>\n<br/>\n29 : 12 = 2 (ост. 5);<br/>\nПроверка: 12 * 2 + 5 = 24 + 5 = 29;<br/>\n<br/>\n42 : 19 = 2 (ост. 4);<br/>\nПроверка: 19 * 2 + 4 = 38 + 4 = 42;<br/>\n<br/>\n76 : 15 = 5 (ост. 1);<br/>\nПроверка: 15 * 5 + 1 = 75 + 1 = 76;<br/>\n<br/>\n90 : 11 = 8 (ост. 2);<br/>\nПроверка: 11 * 8 + 2 = 88 + 2 = 90.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-29/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '38451852a97dec90a56f6471ac35429ddd4d00adcd0f2630c795c62e00c6cc84', '2,3,7,9,11,12,15,19,29,39', NULL, 'выполни деление с остатком и сделай проверку:48:9; 53:7; 39:2; 62:3; 29:12; 42:19; 76:15; 90:11');

    VALUES (v_textbook_id, 29, '8', 1, 'Реши уравнения и сделай проверку: х ⋅ 3 = 20 100; 1 000 : х = 5; х : 8 = 906.', '</p>\n\n<p class="text">\nРеши уравнения и сделай проверку:<br/>\nх ⋅ 3 = 20 100;<br/>\n1 000 : х = 5;<br/>\nх : 8 = 906.\n\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica29-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 29, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 29, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-29/')
    RETURNING id INTO v_task_id;

