    VALUES (v_textbook_id, 29, '9', 2, 'Проведи прямую АВ и отметь на ней точки С, D и К. Сколько они образуют лучей, отрезков? Назови их.', '</p>\n\n<p class="text">\nПроведи прямую АВ и отметь на ней точки С, D и К. Сколько они образуют лучей, отрезков? Назови их.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica29-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 29, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 29, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-29/')
