    VALUES (v_textbook_id, 29, '11', 4, 'По рисунку составь и заполни таблицу в тетради. Какую информацию можно извлечь из этой таблицы? Проанализируй таблицу и ответь на вопросы: • Сколько марок каждой серии у обоих мальчиков вместе? • Сколько всего марок у Серёжи, у Саши, у них вместе?', '</p>\n\n<p class="text">\nПо рисунку составь и заполни таблицу в тетради. Какую информацию можно извлечь из этой таблицы?\n</p>\n\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica29-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 29, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 29, номер 10, год 2022."/>\n</div>\n\n\n<p>\nПроанализируй таблицу и ответь на вопросы:<br/>\n•	Сколько марок каждой серии у обоих мальчиков вместе?<br/>\n•	Сколько всего марок у Серёжи, у Саши, у них вместе?\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica29-nomer10-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 29, номер 10-1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 29, номер 10-1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-29/')
