    VALUES (v_task_id, v_textbook_id, 3, 'bb285997f759ad75bd2369de131bfbb9ae704ca2856aad48ea524ee76d7b3c32', NULL, '["заполни"]'::jsonb, 'по рисунку составь и заполни таблицу в тетради. какую информацию можно извлечь из этой таблицы? проанализируй таблицу и ответь на вопросы:• сколько марок каждой серии у обоих мальчиков вместе? • сколько всего марок у серёжи, у саши, у них вместе');

    VALUES (v_textbook_id, 30, '12', 0, 'Пионы связали в букеты по 3 цветка, а гвоздики – по 5 цветков. Взяли х букетов пионов и у букетов гвоздик. Что означают выражения: х + у; у – х; 3 ⋅ х; 5 ⋅ у; 3 ⋅ х + 5 ⋅ у; 5 ⋅ у – 3 ⋅ х; найди значения этих выражений при х = 4, у = 5.', '</p>\n\n<p class="text">Пионы связали в букеты по 3 цветка, а гвоздики – по 5 цветков. Взяли х букетов пионов и у букетов гвоздик. Что означают выражения:<br/>\nх + у;<br/>\nу – х;<br/>\n3 ⋅ х;<br/>\n5 ⋅ у;<br/>\n3 ⋅ х + 5 ⋅ у;<br/>\n5 ⋅ у – 3 ⋅ х;<br/>\nнайди значения этих выражений при х = 4, у = 5.\n</p>', 'х + у – общее количество букетов пионов и гвоздик; у – х – на сколько больше букетов гвоздик, чем пионов; 3 ⋅ х – общее количество цветов в букетах пионов; 5 ⋅ у – общее количество цветов в букетах гвоздик; 3 ⋅ х + 5 ⋅ у – общее количество цветов в букетах гвоздик и пионов; 5 ⋅ у – 3 ⋅ х – на сколько больше цветов в букетах гвоздик, чем пионов; Вычисляю значения выражений: х + у = 4 + 5 = 9 (шт.); у – х = 5 – 4 = 1 (шт.); 3 ⋅ х = 3 ⋅ 4 = 12 (шт.); 5 ⋅ у = 5 ⋅ 5 = 25 (шт.); 3 ⋅ х + 5 ⋅ у = 3 ⋅ 4 + 5 ⋅ 5 = 12 + 25 = 37 (шт.); 5 ⋅ у – 3 ⋅ х = 5 ⋅ 5 – 3 ⋅ 4 = 25 – 12 = 13 (шт.).', '<p>\nх + у – общее количество букетов пионов и гвоздик;<br/>\nу – х – на сколько больше букетов гвоздик, чем пионов;<br/>\n3 ⋅ х – общее количество цветов в букетах пионов;<br/>\n5 ⋅ у – общее количество цветов в букетах гвоздик;<br/>\n3 ⋅ х + 5 ⋅ у – общее количество цветов в букетах гвоздик и пионов;<br/>\n5 ⋅ у – 3 ⋅ х – на сколько больше цветов в букетах гвоздик, чем пионов;<br/>\n<br/>\nВычисляю значения выражений:<br/>\nх + у = 4 + 5 = 9 (шт.);<br/>\nу – х = 5 – 4 = 1 (шт.);<br/>\n3 ⋅ х = 3 ⋅ 4 = 12 (шт.);<br/>\n5 ⋅ у = 5 ⋅ 5 = 25 (шт.);<br/>\n3 ⋅ х + 5 ⋅ у = 3 ⋅ 4 + 5 ⋅ 5 = 12 + 25 = 37 (шт.);<br/>\n5 ⋅ у – 3 ⋅ х = 5 ⋅ 5 – 3 ⋅ 4 = 25 – 12 = 13 (шт.).\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-30/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'f99d7388cd3a707378e5611f49b4f2cc6cd7a27679b4cc47f85a24e7d39130f6', '3,4,5', '["найди"]'::jsonb, 'пионы связали в букеты по 3 цветка, а гвоздики-по 5 цветков. взяли х букетов пионов и у букетов гвоздик. что означают выражения:х+у; у-х; 3 ⋅ х; 5 ⋅ у; 3 ⋅ х+5 ⋅ у; 5 ⋅ у-3 ⋅ х; найди значения этих выражений при х=4, у=5');

    VALUES (v_textbook_id, 30, '13', 1, 'В числах вместо некоторых цифр поставили звёздочки. Можно ли сравнивать эти числа?', '</p>\n\n<p class="text">В числах вместо некоторых цифр поставили звёздочки. Можно ли сравнивать эти числа?\n</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica30-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 30, номер 13, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 30, номер 13, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-30/')
