    VALUES (v_textbook_id, 30, '14', 2, 'Таблицы в каждом столбце заполняются по общему правилу. Установи это правило и найди пропущенные числа:', '</p>\n\n<p class="text">Таблицы в каждом столбце заполняются по общему правилу. Установи это правило и найди пропущенные числа:\n</p>\n\n<div class="img-wrapper-460">\n<img width="350" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica30-nomer14.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 30, номер 14, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 30, номер 14, год 2022."/>\n</div>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica30-nomer14-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 30, номер 14-1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 30, номер 14-1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-30/')
