    VALUES (v_textbook_id, 30, '15', 3, 'Игра «Роботы». Графические роботы умеют выполнять 4 команды: сместиться на а клеток вверх, на b клеток вниз, на с клеток вправо и на d клеток влево. Для них написаны программы 1, 2 и 3. Восстанови изображения, которые получаются на клетчатой бумаге в результате выполнения этих программ (программы читаются по столбцам). Придумай свои фигуры и составь для них программы.', '</p>\n\n<p class="text">Игра «Роботы».<br/>\nГрафические роботы умеют выполнять 4 команды: сместиться на а клеток вверх, на b клеток вниз, на с клеток вправо и на d клеток влево. Для них написаны программы 1, 2 и 3. Восстанови изображения, которые получаются на клетчатой бумаге в результате выполнения этих программ (программы читаются по столбцам).<br/>\nПридумай свои фигуры и составь для них программы.\n</p>', '', '<div class="img-wrapper-460">\n<img width="350" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica30-nomer14.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 30, номер 14, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 30, номер 14, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-30/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica30-nomer14.jpg', 'peterson/3/part2/page30/task15_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '56d229645bbfc9df04a77bcca866dcc51526d48d2ffbf1a60a07379a39f36b2d', '1,2,3,4', NULL, 'игра "роботы". графические роботы умеют выполнять 4 команды:сместиться на а клеток вверх, на b клеток вниз, на с клеток вправо и на d клеток влево. для них написаны программы 1, 2 и 3. восстанови изображения, которые получаются на клетчатой бумаге в результате выполнения этих программ (программы читаются по столбцам). придумай свои фигуры и составь для них программы');

    VALUES (v_textbook_id, 31, '1', 0, 'Выполни деление с остатков и сделай проверку: 25 : 6; 250 : 60; 2 500 : 600; 25 000 : 6 000; Что ты замечаешь? Сделай вывод.', '</p>\n\n<p class="text">Выполни деление с остатков и сделай проверку:<br/>\n25 : 6; 	<br/>	\n250 : 60;	<br/>	\n2 500 : 600;	<br/>	\n25 000 : 6 000;<br/>\nЧто ты замечаешь? Сделай вывод.\n</p>', '', '<div class="img-wrapper-460">\n<img width="500" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica31-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 31, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 31, номер 1, год 2022."/>', 'При увеличении (уменьшении) делимого и делителя в 10, 100, 1 000 и т.д. раз частное не изменяется, а остаток соответственно увеличивается (уменьшается) во столько же раз. 14 : 5 = 2 (ост. 4); 140 : 50 = 2 (ост. 40); 1 400 : 500 = 2 (ост. 400); 14 000 : 5 000 = 2 (ост. 4 000).', '<div class="recomended-block">\n<p>\nПри увеличении (уменьшении) делимого и делителя в 10, 100, 1 000 и т.д. раз частное не изменяется, а остаток соответственно увеличивается (уменьшается) во столько же раз.<br/>\n14 : 5 = 2 (ост. 4);<br/>\n140 : 50 = 2 (ост. 40);<br/>\n1 400 : 500 = 2 (ост. 400);<br/>\n14 000 : 5 000 = 2 (ост. 4 000).\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-31/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica31-nomer1.jpg', 'peterson/3/part2/page31/task1_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'b466d4b873db639d040c195b8866f68ff5a29372091be5e26f8a0c81ee0da6bf', '000,2,6,25,60,250,500,600', NULL, 'выполни деление с остатков и сделай проверку:25:6; 250:60; 2 500:600; 25 000:6 000; что ты замечаешь? сделай вывод');

    VALUES (v_textbook_id, 31, '2', 1, 'А) Рассмотри деление с остатком углом. Назови делимое, делитель, частное и остаток. Как выполнена проверка? 254 : 4 = 63 (ост. 2); Проверка: 63 ⋅ 4 + 2 = 254; Б) выполни деление с остатков 25 400 : 400. Как можно упростить деление? Сделай вывод.', '</p>\n\n<p class="text">	\nА) Рассмотри деление с остатком углом. Назови делимое, делитель, частное и остаток. Как выполнена проверка?<br/>\n254 : 4 = 63 (ост. 2);<br/>\nПроверка:<br/>\n63 ⋅ 4 + 2 = 254;<br/>\nБ) выполни деление с остатков 25 400 : 400. Как можно упростить деление? Сделай вывод.\n</p>', 'А) Делимое – 254, делитель – 4, значение частного – 63. Проверка выполнена так, что делитель умножают на значение частного и прибавляют остаток. Если получается число, равное делимому, то деление выполнено верно. Б)', '<div class="img-wrapper-450">\n<p>\nА) Делимое – 254, делитель – 4, значение частного – 63. Проверка выполнена так, что делитель умножают на значение частного и прибавляют остаток. Если получается число, равное делимому, то деление выполнено верно.\nБ)\n</p>\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica31-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 31, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 31, номер 2, год 2022."/>', 'Правило деления круглых чисел с остатком При делении с остатком круглых чисел можно отбросить в делимом и делителе поровну нулей, а затем приписать столько же нулей к полученному остатку.', '<div class="recomended-block">\n<span class="title">Правило деления круглых чисел с остатком</span>\n<p>\nПри делении с остатком круглых чисел можно отбросить в делимом и делителе поровну нулей, а затем приписать столько же нулей к полученному остатку.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-31/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica31-nomer2.jpg', 'peterson/3/part2/page31/task2_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'ad1351a486727eb1663b199ae3f23ccdaa5d6d3eaba7b1ba5db7ebfd18202bc6', '2,4,25,63,254,400', '["частное","делитель","делимое","остаток"]'::jsonb, 'а) рассмотри деление с остатком углом. назови делимое, делитель, частное и остаток. как выполнена проверка? 254:4=63 (ост. 2); проверка:63 ⋅ 4+2=254; б) выполни деление с остатков 25 400:400. как можно упростить деление? сделай вывод');

    VALUES (v_textbook_id, 31, '3', 2, 'Выполни деление с остатком и сделай проверку: а) 855 : 7; б) 1 219 : 3; в) 540 : 70; г) 320 : 60; д) 80 120 : 90; е) 267 040 : 50; ж) 392 000 : 300; з) 400 600 : 800.', '</p>\n\n<p class="text">	\nВыполни деление с остатком и сделай проверку:<br/>\nа) 855 : 7;<br/>\nб) 1 219 : 3;<br/>\nв) 540 : 70;<br/>\nг) 320 : 60;<br/>\nд) 80 120 : 90;<br/>\nе) 267 040 : 50;<br/>\nж) 392 000 : 300;<br/>\nз) 400 600 : 800.\n\n</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica31-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 31, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 31, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-31/')
