    VALUES (v_task_id, v_textbook_id, 3, '69d30fe4c5cd8ee142940e599a75152a779f1fe0ade1eac0f25463fabf7a81e5', '000,1,3,7,040,50,60,70,80,90', NULL, 'выполни деление с остатком и сделай проверку:а) 855:7; б) 1 219:3; в) 540:70; г) 320:60; д) 80 120:90; е) 267 040:50; ж) 392 000:300; з) 400 600:800');

    VALUES (v_textbook_id, 32, '4', 0, 'Известно, что 387 ⋅ 516 = 199 692. Пользуясь этим равенством, вычисли: 516 ⋅ 387; 387 ⋅ 517; 388 ⋅ 516; 387 ⋅ 526; 199 692 : 387; 199 692 : 516.', '</p>\n\n<p class="text">Известно, что 387 ⋅ 516 = 199 692. Пользуясь этим равенством, вычисли:\n516 ⋅ 387;\n387 ⋅ 517;\n388 ⋅ 516;\n387 ⋅ 526;\n199 692 : 387;\n199 692 : 516.\n</p>', '516 ⋅ 387 = 199 692; 387 ⋅ 517 = 199 692 + 387 = 200 079; 388 ⋅ 516 = 199 692 + 516 = 200 208; 387 ⋅ 526 = 199 692 + 387 ⋅ 10 = 199 692 + 3 870 = 203 562; 199 692 : 387 = 516; 199 692 : 516 = 387.', '<p>\n516 ⋅ 387 = 199 692;<br/>\n387 ⋅ 517 = 199 692 + 387 = 200 079;<br/>\n388 ⋅ 516 = 199 692 + 516 = 200 208;<br/>\n387 ⋅ 526 = 199 692 + 387 ⋅ 10 = 199 692 + 3 870 = 203 562;<br/>\n199 692 : 387 = 516;<br/>\n199 692 : 516 = 387.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-32/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '8f464d6585d7ea8714f78bc30492a92a3ffd3b121c5bcaaa3c3b3af94871576c', '199,387,388,516,517,526,692', '["вычисли"]'::jsonb, 'известно, что 387 ⋅ 516=199 692. пользуясь этим равенством, вычисли:516 ⋅ 387; 387 ⋅ 517; 388 ⋅ 516; 387 ⋅ 526; 199 692:387; 199 692:516');

    VALUES (v_textbook_id, 32, '5', 1, 'БЛИЦ турнир. А) На двух полках стояло по а книг, а на трех других – по b книг. Сколько книг стоит на всех этих полках? Б) На шести полках стояло по с книг. ИИх переставили на d полок, поровну на каждую. Сколько теперь книг стоит на каждой полке? В) Оля прочитала в январе n книг, в феврале – в 2 раза больше книг, а в марте – на 3 книги меньше, чем в январе. Сколько книг прочитала Оля за эти 3 месяца? Г) На первой полке стояло k книг, а на второй – m книг. С первой полки сняли х книг, а со второй – у книг. Сколько всего книг осталось на этих полках?', '</p>\n\n<p class="text">\nБЛИЦ турнир.<br/>\nА) На двух полках стояло по а книг, а на трех других – по b книг. Сколько книг стоит на всех этих полках?<br/>\nБ) На шести полках стояло по с книг. ИИх переставили на d полок, поровну на каждую. Сколько теперь книг стоит на каждой полке?<br/>\nВ) Оля прочитала в январе n книг, в феврале – в 2 раза больше книг, а в марте – на 3 книги меньше, чем в январе. Сколько книг прочитала Оля за эти 3 месяца?<br/>\nГ) На первой полке стояло k книг, а на второй – m книг. С первой полки сняли х книг, а со второй – у книг. Сколько всего книг осталось на этих полках?\n</p>', 'А) а ⋅ 2 + b ⋅ 3 (шт.) – книг стоит на всех полках; Б) (с ⋅ 6) : d (шт.) – книг стоит на каждой полке; В) n + n ⋅ 2 + (n – 3) (шт.) – книг прочитала Оля за 3 месяца; Г) (k – х) + (m – y) (шт.) – книг осталось на этих полках.', '<p>\nА) а ⋅ 2 + b ⋅ 3 (шт.) – книг стоит на всех полках;<br/>\nБ) (с ⋅ 6) : d (шт.) – книг стоит на каждой полке;<br/>\nВ) n + n ⋅ 2 + (n – 3) (шт.) – книг прочитала Оля за 3 месяца;<br/>\nГ) (k – х) + (m – y) (шт.) – книг осталось на этих полках.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-32/')
    RETURNING id INTO v_task_id;

