    VALUES (v_textbook_id, 32, '7', 3, 'Пёс Гримка увлёкся фотоохотой и купил 8 плёнок по 36 кадров в каждой. Своего друга кота Барсика он сфотографировал 56 раз, петуха – на 17 раз меньше, чем кота, а гуся – в 8 раз меньше, чем кота. На фотографии зайцев он истратил столько кадров, сколько на фотографии кота и гуся вместе. Сколько кадров у него еще осталось? На сколько больше кадров он истратил, чем осталось?', '</p>\n\n<p class="text">\nПёс Гримка увлёкся фотоохотой и купил 8 плёнок по 36 кадров в каждой. Своего друга кота Барсика он сфотографировал 56 раз, петуха – на 17 раз меньше, чем кота, а гуся – в 8 раз меньше, чем кота. На фотографии зайцев он истратил столько кадров, сколько на фотографии кота и гуся вместе. Сколько кадров у него еще осталось? На сколько больше кадров он истратил, чем осталось?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica32-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 32, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 32, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-32/')
    RETURNING id INTO v_task_id;

