    VALUES (v_textbook_id, 33, '8', 0, 'Составь и реши уравнения: 1)Какое число надо вычесть из 53 207, чтобы получить 6 435? 2) Какое число надо увеличить на 20 596, чтобы получить 800 903? 3) Какое число надо уменьшить на 385, чтобы получить 42 768?', '</p>\n\n<p class="text">Составь и реши уравнения:<br/>\n1)Какое число надо вычесть из 53 207, чтобы получить 6 435?<br/>\n2) Какое число надо увеличить на 20 596, чтобы получить 800 903?<br/>\n3) Какое число надо уменьшить на 385, чтобы получить 42 768?\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica33-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 33, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 33, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-33/')
    RETURNING id INTO v_task_id;

