    VALUES (v_task_id, v_textbook_id, 3, '04abe4f2c7c686e8e3ffd3c40c27c025b354054c438d1425679ca65ba799e553', '1,2,3,6,20,42,53,207,385,435', '["реши"]'::jsonb, 'составь и реши уравнения:1)какое число надо вычесть из 53 207, чтобы получить 6 435? 2) какое число надо увеличить на 20 596, чтобы получить 800 903? 3) какое число надо уменьшить на 385, чтобы получить 42 768');

    VALUES (v_textbook_id, 33, '9', 1, 'Математический фокус. Выполни следующие команды: 1) Задумай число; 2) Прибавь к нему 25; 3) Прибавить еще 125; 4) Вычти 37; 5) вычти первоначально задуманное число; 6) Результат умножь на 50; 7) Раздели полученное число на 10. Как ты думаешь, почему всегда будет получаться один и тот же ответ – число 565?', '</p>\n\n<p class="text">\nМатематический фокус.<br/>\nВыполни следующие команды:<br/>\n1) Задумай число;<br/>\n2) Прибавь к нему 25;<br/>\n3) Прибавить еще 125;<br/>\n4) Вычти 37;<br/>\n5) вычти первоначально задуманное число;<br/>\n6) Результат умножь на 50;<br/>\n7) Раздели полученное число на 10.<br/>\nКак ты думаешь, почему всегда будет получаться один и тот же ответ – число 565?\n</p>', '1) Задумала число 15; 2) Прибавляю 25 : 15 + 25 = 40; 3) прибавляю 125: 40 + 125 = 165; 4) вычитаю 37 : 165 – 37 = 128; 5) вычитаю первоначально задуманное число: 128 – 15 = 113; 6) Результат умножаю на 50 : 113 ⋅ 50 = 5650; 7) Делю полученное число на 10 – 5 650 : 10 = 565. Получается всегда один и тот же ответ, потому что: 25 + 125 = 150; 150 – 37 = 113; 113 ⋅ 50 = 5650; 5650 : 10 = 565. Само число вычитается из самого себя и получается ноль. А все операции, которые с числом выполняются и образуют число 565.', '<p>\n1) Задумала число 15;<br/>\n2) Прибавляю 25 : 15 + 25 = 40;<br/>\n3) прибавляю 125: 40 + 125 = 165;<br/>\n4) вычитаю 37 : 165 – 37 = 128;<br/>\n5) вычитаю первоначально задуманное число: 128 – 15 = 113;<br/>\n6) Результат умножаю на 50 : 113 ⋅ 50 = 5650;<br/>\n7) Делю полученное число на 10 – 5 650 : 10 = 565.<br/>\n<br/>\nПолучается всегда один и тот же ответ, потому что:<br/>\n25 + 125 = 150;<br/>\n150 – 37 = 113;<br/>\n113 ⋅ 50 = 5650;<br/>\n5650 : 10 = 565.<br/>\n<br/>\nСамо число вычитается из самого себя и получается ноль. А все операции, которые с числом выполняются и образуют число 565.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-33/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'bfe36d643691d4fcb62a4a0b0789c4f8b53fe2ba92da81661b8c76811d16d131', '1,2,3,4,5,6,7,10,25,37', '["вычти","умножь","раздели","раз"]'::jsonb, 'математический фокус. выполни следующие команды:1) задумай число; 2) прибавь к нему 25; 3) прибавить еще 125; 4) вычти 37; 5) вычти первоначально задуманное число; 6) результат умножь на 50; 7) раздели полученное число на 10. как ты думаешь, почему всегда будет получаться один и тот же ответ-число 565');

    VALUES (v_textbook_id, 33, '10', 2, 'Найди общее свойство линий, принадлежащих множеству: А, В, А в пересечении с В.', '</p>\n\n<p class="text">\nНайди общее свойство линий, принадлежащих множеству: А, В, А в пересечении с В.\n</p>', 'А – незамкнутые ломаные линии; В – замкнутые линии; А ⋂ В – замкнутые ломаные линии; А: {а, b, c, d, e, f}; B: {k, n, m, f, e}; А ⋂ В: {e, f}.', '<p>\nА – незамкнутые ломаные линии;\nВ – замкнутые линии;\nА ⋂ В – замкнутые ломаные линии;\nА: {а, b, c, d, e, f};\nB: {k, n, m, f, e};\nА ⋂ В: {e, f}.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-33/')
    RETURNING id INTO v_task_id;

