    VALUES (v_task_id, v_textbook_id, 3, '73cc6f3c9a42246dd66fb78c79caac180944187388dd9aa1754071048b79dfcf', '3', '["реши","раз"]'::jsonb, 'игорь решил сделать в тире 3 выстрела, по оному в разные мишени. он выбрал мишени. укажи различные варианты попадания в эти мишени (порядок выстрелов не принимается во внимание)');

    VALUES (v_textbook_id, 34, '1', 0, 'Вычисли устно. Найди в каждом столбике «лишний» пример: 240 : 80; 350 : 70; 720 : 9; 420 : 60; 78 : 6; 81 : 9; 56 : 4; 34 : 2; 70 ⋅ 700; 600 ⋅ 12; 3 000 ⋅ 7; 90 ⋅ 60.', '</p>\n\n<p class="text">Вычисли устно. Найди в каждом столбике «лишний» пример:<br/>\n240 : 80;<br/>						\n350 : 70;<br/>						\n720 : 9;<br/>						\n420 : 60;<br/>\n<br/>						\n78 : 6;<br/>\n81 : 9;<br/>\n56 : 4;<br/>\n34 : 2;<br/>\n<br/>\n70 ⋅ 700;<br/>\n600 ⋅ 12;<br/>\n3 000 ⋅ 7;<br/>\n90 ⋅ 60.\n</p>', '240 : 80 = 24 дес. : 8 дес. = 3; 350 : 7 = 35 дес. : 7 = 5 дес. = 50; 720 : 9 = 72 дес. : 9 = 8 дес. = 80; 420 : 60 = 42 дес. : 6 дес. = 7. «Лишнее» выражение – 720 : 9, потому что делитель – однозначное число. 78 : 6 = 13; 81 : 9 = 9; 56 : 4 = 14; 32 : 2 = 17. «Лишнее» выражение – 81 : 9, потому что табличный случай деления. 70 ⋅ 700 = 49 000; 600 ⋅ 12 = 7 200; 3 000 ⋅ 7 = 21 000; 90 ⋅ 60 = 5 400. «Лишнее» выражение – 70 ⋅ 700, потому что значение произведения не делится на 3.', '<p>\n240 : 80 = 24 дес. : 8 дес. = 3;<br/> \n350 : 7 = 35 дес. : 7 = 5 дес. = 50;<br/>\n720 : 9 = 72 дес. : 9 = 8 дес. = 80;<br/>\n420 : 60 = 42 дес. : 6 дес. = 7.<br/>\n«Лишнее» выражение – 720 : 9, потому что делитель – однозначное число.<br/>\n<br/>\n78 : 6 = 13;<br/>\n81 : 9 = 9;<br/>\n56 : 4 = 14;<br/>\n32 : 2 = 17.<br/>\n«Лишнее» выражение – 81 : 9, потому что табличный случай деления.<br/>\n<br/>\n70 ⋅ 700 = 49 000;<br/>\n600 ⋅ 12 = 7 200;<br/>\n3 000 ⋅ 7 = 21 000;<br/>\n90 ⋅ 60 = 5 400.<br/>\n«Лишнее» выражение – 70 ⋅ 700, потому что значение произведения не делится на 3.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-34/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '44f6ce492e8448f0431bd1c5d108be2962c0a503aaf25e7c466833cdbdacd082', '000,2,3,4,6,7,9,12,34,56', '["вычисли","найди","столбик"]'::jsonb, 'вычисли устно. найди в каждом столбике "лишний" пример:240:80; 350:70; 720:9; 420:60; 78:6; 81:9; 56:4; 34:2; 70 ⋅ 700; 600 ⋅ 12; 3 000 ⋅ 7; 90 ⋅ 60');

    VALUES (v_textbook_id, 34, '2', 1, 'Выполни деление углом и сделай проверку: а) 274 700 : 90; б) 320 520 : 80; в) 4 812 500 : 600.', '</p>\n\n<p class="text">\nВыполни деление углом и сделай проверку:<br/>\nа) 274 700 : 90;<br/>			\nб) 320 520 : 80;<br/>			\nв) 4 812 500 : 600.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica34-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 34, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 34, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-34/')
