    VALUES (v_textbook_id, 34, '3', 2, 'а) У Васи в кошельке 90 р. Сколько конвертов по цене 12 р. он сможет купить? б) За один день на ферме надоили 500 л молока. Всё молоко надо разлить в бидоны по 30 л. какое минимальное количество таких бидонов для этого потребуется?', '</p>\n\n<p class="text">\nа) У Васи в кошельке 90 р. Сколько конвертов по цене 12 р. он сможет купить?<br/>\nб) За один день на ферме надоили 500 л молока. Всё молоко надо разлить в бидоны по 30 л. какое минимальное количество таких бидонов для этого потребуется?\n</p>', '1) 90 : 12 = 7 (ост.6). Ответ: Вася сможет купить 7 конвертов. 2) 500 : 30 = 50 дес. : 3 дес. = 16 (ост. 2 дес.) = 16 (ост. 20) – бидонов потребуется для молока. Ответ: 16 бидонов.', '<p>\n1) 90 : 12 = 7 (ост.6).<br/>\nОтвет: Вася сможет купить 7 конвертов.<br/>\n<br/>\n2) 500 : 30 = 50 дес. : 3 дес. = 16 (ост. 2 дес.) = 16 (ост. 20) – бидонов потребуется для молока.<br/>\nОтвет: 16 бидонов.\n</p>', '', '', TRUE, '[{"letter":"а","condition":"У Васи в кошельке 90 р. Сколько конвертов по цене 12 р. он сможет купить?","solution":""},{"letter":"б","condition":"За один день на ферме надоили 500 л молока. Всё молоко надо разлить в бидоны по 30 л. какое минимальное количество таких бидонов для этого потребуется?","solution":""}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-34/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '60b2053f84f31e09cee4a1944e4563c14e80e62e85b51a3447d695669e79e69a', '12,30,90,500', '["раз"]'::jsonb, 'а) у васи в кошельке 90 р. сколько конвертов по цене 12 р. он сможет купить? б) за один день на ферме надоили 500 л молока. всё молоко надо разлить в бидоны по 30 л. какое минимальное количество таких бидонов для этого потребуется');

    VALUES (v_textbook_id, 34, '4', 3, 'Вырази в сантиметрах: а) 31 м 8 см = … см; б) 7 дм 30 мм = … см; в) 8 500 мм = … см; г) 4 м 2 дм = … см.', '</p>\n\n<p class="text">\nВырази в сантиметрах:<br/>\nа) 31 м 8 см = … см;<br/>\nб) 7 дм 30 мм =  … см;<br/>\nв) 8 500 мм = … см;<br/>\nг) 4 м 2 дм = … см.\n</p>', 'а) 31 м 8 см = 3 100 см + 8 см = 3 108 см; б) 7 дм 30 мм = 70 см ⋅ 10 мм + 30 мм = 700 мм + 30 мм = 730 мм = 73 см; в) 8 500 мм = 850 см; г) 4 м 2 дм = 400 см + 20 см = 420 см.', '<p>\nа) 31 м 8 см = 3 100 см + 8 см = 3 108 см;<br/>\nб) 7 дм 30 мм = 70 см ⋅ 10 мм + 30 мм = 700 мм + 30 мм = 730 мм = 73 см;<br/>\nв) 8 500 мм = 850 см;<br/>\nг) 4 м 2 дм = 400 см + 20 см = 420 см.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-34/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '5344021d1ed1012fb8db27e6fe0cb79d5f907178d6b47dd8ffecac55d285530d', '2,4,7,8,30,31,500', '["раз"]'::jsonb, 'вырази в сантиметрах:а) 31 м 8 см=... см; б) 7 дм 30 мм=... см; в) 8 500 мм=... см; г) 4 м 2 дм=... см');

    VALUES (v_textbook_id, 34, '5', 4, 'Выполни действия: а) 12 км 30 м – 3 км 500 м; б) 7 м 2 дм 3 см + 4 м 67 см; в) 5 т 620 кг – 8 ц 96 кг + 4 т 78 кг; г) 2 кг 425 г + 580 г – 1 кг 25 г.', '</p>\n\n<p class="text">\nВыполни действия:<br/>\nа) 12 км 30 м – 3 км 500 м;<br/>\nб) 7 м 2 дм 3 см + 4 м 67 см;<br/>\nв) 5 т 620 кг – 8 ц 96 кг + 4 т 78 кг;<br/>\nг) 2 кг 425 г + 580 г – 1 кг 25 г.\n</p>', 'а) 12 км 30 м – 3 км 500 м = 12 030 м – 3 500 м = 8 530 м = 8 км 530 м; б) 7 м 2 дм 3 см + 4 м 67 см = 723 см + 467 см = 1 190 см = 11 м 9 дм; в) 5 т 620 кг – 8 ц 96 кг + 4 т 78 кг = 50 ц 620 кг – 8 ц 96 кг + 40 ц 78 кг = 42 ц 524 кг + 40 ц 78 кг = 82 ц 602 кг = 8 т 2 ц 6 ц 2 кг = 8 т 8 ц 2 кг; г) 2 кг 425 г + 580 г – 1 кг 25 г = 2 425 г + 580 г – 1 025 г = 1980 г = 1 кг 980 г.', '<p>\nа) 12 км 30 м – 3 км 500 м = 12 030 м – 3 500 м = 8 530 м = 8 км 530 м;<br/>\nб) 7 м 2 дм 3 см + 4 м 67 см = 723 см + 467 см = 1 190 см = 11 м 9 дм;<br/>\nв) 5 т 620 кг – 8 ц 96 кг + 4 т 78 кг = 50 ц 620 кг – 8 ц 96 кг + 40 ц 78 кг = 42 ц 524 кг + 40 ц 78 кг = 82 ц 602 кг = 8 т 2 ц 6 ц 2 кг = 8 т 8 ц 2 кг;<br/>\nг) 2 кг 425 г + 580 г – 1 кг 25 г = 2 425 г + 580 г – 1 025 г = 1980 г = 1 кг 980 г.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-34/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'b2870a46d40e3382b1776aefe2951308e70e0e0f0b28eaa8e745d297733cdf1c', '1,2,3,4,5,7,8,12,25,30', NULL, 'выполни действия:а) 12 км 30 м-3 км 500 м; б) 7 м 2 дм 3 см+4 м 67 см; в) 5 т 620 кг-8 ц 96 кг+4 т 78 кг; г) 2 кг 425 г+580 г-1 кг 25 г');

    VALUES (v_textbook_id, 34, '6', 5, 'Вычисли. Расположи ответы в порядке убывания и расшифруй слово. Что оно означает? Щ. 5 584 800 : 600; П. 40 360 ⋅ 70; Ю. 402 837 + 75 268; Л. 500 600 – 21 504.', '</p>\n\n<p class="text">\nВычисли. Расположи ответы в порядке убывания и расшифруй слово. Что оно означает?<br/>\nЩ. 5 584 800 : 600;<br/>\nП. 40 360 ⋅ 70;<br/>\nЮ. 402 837 + 75 268;<br/>\nЛ. 500 600 – 21 504.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica34-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 34, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 34, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-34/')
