    VALUES (v_task_id, v_textbook_id, 3, '0704b91ef3d1f3cec4f8b66fd594b526e2281b3ccd8fe7c30ad9c2c3db443b46', '5,21,40,70,75,268,360,402,500,504', '["вычисли"]'::jsonb, 'вычисли. расположи ответы в порядке убывания и расшифруй слово. что оно означает? щ. 5 584 800:600; п. 40 360 ⋅ 70; ю. 402 837+75 268; л. 500 600-21 504');

