    VALUES (v_textbook_id, 35, '8', 0, 'Придумай задачи, решениями которых являются выражения: а + 2; а ⋅ 2; а + а ⋅ 2.', '</p>\n\n<p class="text">Придумай задачи, решениями которых являются выражения:<br/>\nа + 2;<br/>\nа ⋅ 2;<br/>\nа + а ⋅ 2.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica35-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 35, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 35, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-35/')
