    VALUES (v_textbook_id, 35, '8', 1, 'БЛИЦтурнир. А) в классе а мальчиков и b девочек. Они выстроились парами. Сколько получилось пар? Б) В новогодние подарки разложили с конфет. В каждый подарок положили по 3 шоколадные конфеты и d леденцов. Сколько приготовили подарков? В) Расчёска стоит х р., а заколка – в 2 раза дороже. Сколько пятирублевых монет надо отдать в кассу, чтобы заплатить за расческу и заколку вместе? Г) В книге у страниц. Оля читала каждый день утром n страниц, а вечером – в 3 раза меньше. За сколько дней она прочитали книгу?', '</p>\n\n<p class="text">\nБЛИЦтурнир.<br/>\nА) в классе а мальчиков и b девочек. Они выстроились парами. Сколько получилось пар?<br/>\nБ) В новогодние подарки разложили с конфет. В каждый подарок положили по 3 шоколадные конфеты и d леденцов. Сколько приготовили подарков?<br/>\nВ) Расчёска стоит х р., а заколка – в 2 раза дороже. Сколько пятирублевых монет надо отдать в кассу, чтобы заплатить за расческу и заколку вместе?<br/>\nГ) В книге у страниц. Оля читала каждый день утром n страниц, а вечером – в 3 раза меньше. За сколько дней она прочитали книгу?\n\n</p>', 'а) (а + b) : 2 (шт.) – пар получилось; б) с : (3 + d) (шт.) – подарков приготовили; в) (х + х ⋅ 2) : 5 (шт.) – пятирублевых монет нужно отдать; г) у : (n + n : 3) (шт.) – дней она прочитала книгу.', '<p>\nа) (а + b) : 2 (шт.) – пар получилось;<br/>\nб) с : (3 + d) (шт.) – подарков приготовили;<br/>\nв) (х + х ⋅ 2) : 5 (шт.) – пятирублевых монет  нужно отдать;<br/>\nг) у : (n + n : 3) (шт.) – дней она прочитала книгу.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-35/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '32df797f39b3876f10792373b995e596e3526d9fe69faddab58bd76e56b0a113', '2,3', '["меньше","раз","раза"]'::jsonb, 'блицтурнир. а) в классе а мальчиков и b девочек. они выстроились парами. сколько получилось пар? б) в новогодние подарки разложили с конфет. в каждый подарок положили по 3 шоколадные конфеты и d леденцов. сколько приготовили подарков? в) расчёска стоит х р., а заколка-в 2 раза дороже. сколько пятирублевых монет надо отдать в кассу, чтобы заплатить за расческу и заколку вместе? г) в книге у страниц. оля читала каждый день утром n страниц, а вечером-в 3 раза меньше. за сколько дней она прочитали книгу');

    VALUES (v_textbook_id, 35, '8', 2, 'Вычисли. Наложи прозрачную плёнку и соедини ответы по порядку. Что получилось? 1. 8 325 : 9; 2. 2 530 : 5; 3. 9 440 : 4; 4. 31 806 : 6; 5. 91 490 : 7; 6. 150 160 : 2; 7. 200 520 : 8; 8. 2 775 : 3.', '</p>\n\n<p class="text">\nВычисли. Наложи прозрачную плёнку и соедини ответы по порядку. Что получилось?<br/>\n1. 8 325 : 9;<br/>\n2. 2 530 : 5;<br/>\n3. 9 440 : 4;<br/>\n4. 31 806 : 6;<br/>\n5. 91 490 : 7;<br/>\n6. 150 160 : 2;<br/>\n7. 200 520 : 8;<br/>\n8. 2 775 : 3.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica35-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 35, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 35, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-35/')
