    VALUES (v_task_id, v_textbook_id, 3, '4958ce1d86090b25928fa77f9d297f1f3088093477300f3b5cfd702ab9f34637', '1,2,3,4,5,6,7,8,9,31', '["вычисли"]'::jsonb, 'вычисли. наложи прозрачную плёнку и соедини ответы по порядку. что получилось? 1. 8 325:9; 2. 2 530:5; 3. 9 440:4; 4. 31 806:6; 5. 91 490:7; 6. 150 160:2; 7. 200 520:8; 8. 2 775:3');

    VALUES (v_textbook_id, 36, '11', 0, 'От города до дачи Андрея 28 км. Однажды он поехал на дачу на велосипеде и взял с собой 3 кг гостинцев для своего пса Гримки и кота Барсика. Папа задержался на работе и выехал на дачу позже, взяв с собой 9 кг гостинцев. Он догнал Андрея на расстоянии 6 км от дачи. Какие из следующих вопросов можно поставить к этому условию, чтобы получилась задача? 1) На каком расстоянии от города папа догнал Андрея? 2) Как зовут Андрюшкиного кота? 3) Сколько килограммов гостинцев взял с собой папа? 4) Чьи гостинцы тяжелее – Андрюшкины или папины? На сколько? 5) Чему равна масса пса Гримки? Какие из данных выражений имеют смысл? 3 кг + 9 кг; 9 кг – 3 кг; 9 кг – 6 км; 9 кг : 3 кг.', '</p>\n\n<p class="text">От города до дачи Андрея 28 км. Однажды он поехал на дачу на велосипеде и взял с собой 3 кг гостинцев для своего пса Гримки и кота Барсика. Папа задержался на работе и выехал на дачу позже, взяв с собой 9 кг гостинцев. Он догнал Андрея на расстоянии 6 км от дачи.<br/>\nКакие из следующих вопросов можно поставить к этому условию, чтобы получилась задача?<br/>\n1) На каком расстоянии от города папа догнал Андрея?<br/>\n2) Как зовут Андрюшкиного кота?<br/>\n3) Сколько килограммов гостинцев взял с собой папа?<br/>\n4) Чьи гостинцы тяжелее – Андрюшкины или папины? На сколько?<br/>\n5) Чему равна масса пса Гримки?<br/>\nКакие из данных выражений имеют смысл?<br/>\n3 кг + 9 кг;<br/>\n9 кг – 3 кг;<br/>\n9 кг – 6 км;<br/>\n9 кг : 3 кг.\n</p>', '1) Можно, потому что 28 – 6 = 22 (км) – от города. 2) Можно, Андрюшкиного кота зовут Барсик. 3) Можно, 9 кг. 4) Можно, потому что известна масса груза Андрея и папы. Их можно сравнить. 9 – 3 = 6 (кг) – тяжелее. 5) нельзя. Потому что не хватает данных. Имеют смысл выражения: 3 кг + 9 кг = 12 (кг) – общая масса груза. 9 кг – 3 кг = 6 (кг) – тяжелее гостинцы папы, чем Андрюшки. 9 кг – 6 км – не имеет смысла. 9 кг : 3 кг = 3 (раза) – больше гостинце в папы, чем у Андрюшки.', '<p>\n1) Можно, потому что 28 – 6 = 22 (км) – от города.<br/>\n2) Можно, Андрюшкиного кота зовут Барсик.<br/>\n3) Можно, 9 кг.<br/>\n4) Можно, потому что известна масса груза Андрея и папы. Их можно сравнить. 9 – 3 = 6 (кг) – тяжелее.<br/>\n5) нельзя. Потому что не хватает данных.<br/>\n<br/>\nИмеют смысл выражения:<br/>\n3 кг + 9 кг = 12 (кг) – общая масса груза.<br/>\n9 кг – 3 кг = 6 (кг) – тяжелее гостинцы папы, чем Андрюшки.<br/>\n9 кг – 6 км – не имеет смысла.<br/>\n9 кг : 3 кг = 3 (раза) – больше гостинце в папы, чем у Андрюшки.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-36/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '0ca3c176276b0c086987dc6d51e35d71624c5f8bca794f602750b3e6e069c275', '1,2,3,4,5,6,9,28', NULL, 'от города до дачи андрея 28 км. однажды он поехал на дачу на велосипеде и взял с собой 3 кг гостинцев для своего пса гримки и кота барсика. папа задержался на работе и выехал на дачу позже, взяв с собой 9 кг гостинцев. он догнал андрея на расстоянии 6 км от дачи. какие из следующих вопросов можно поставить к этому условию, чтобы получилась задача? 1) на каком расстоянии от города папа догнал андрея? 2) как зовут андрюшкиного кота? 3) сколько килограммов гостинцев взял с собой папа? 4) чьи гостинцы тяжелее-андрюшкины или папины? на сколько? 5) чему равна масса пса гримки? какие из данных выражений имеют смысл? 3 кг+9 кг; 9 кг-3 кг; 9 кг-6 км; 9 кг:3 кг');

