    VALUES (v_textbook_id, 36, '14', 3, 'Найди значение выражения, выполнив 4 действия. Какие свойства сложения и умножения при этом используются? 2 ⋅ 2 + 2 + 2 ⋅ 2 + 2 + 2 ⋅ 2 + 2 + 2 ⋅ 2 + 2 + 2 ⋅ 2 + 2 + 2 ⋅ 2 + 2 + 2 ⋅ 2.', '</p>\n\n<p class="text">Найди значение выражения, выполнив 4 действия. Какие свойства сложения и умножения при этом используются?<br/>\n2 ⋅ 2 + 2 + 2 ⋅ 2 + 2 + 2 ⋅ 2 + 2 + 2 ⋅ 2 + 2 + 2 ⋅ 2 + 2 + 2 ⋅ 2 + 2 + 2 ⋅ 2.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica36-nomer14.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 36, номер 14, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 36, номер 14, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-36/')
