    VALUES (v_textbook_id, 37, '3', 2, 'Нарисуй квадрат со стороной 5 клеток. Перенеси его на 15 клеток вправо, а потом еще на 8 клеток влево. Каким одним преобразованием можно заменить эти два преобразования? Покажи его стрелкой.', '</p>\n\n<p class="text">Нарисуй квадрат со стороной 5 клеток. Перенеси его на 15 клеток вправо, а потом еще на 8 клеток влево. Каким одним преобразованием можно заменить эти два преобразования? Покажи его стрелкой.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica37-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 37, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 37, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-37/')
