    VALUES (v_textbook_id, 38, '6', 1, 'Используя циркуль, нарисуй круг радиусом 3 клетки. Перенеси его на 9 клеток вниз, затем на 7 клеток вправо, а потом – на 5 клеток вверх. Покажи стрелкой преобразование первого круга в последний?', '</p>\n\n<p class="text">Используя циркуль, нарисуй круг радиусом 3 клетки. Перенеси его на 9 клеток вниз, затем на 7 клеток вправо, а потом – на 5 клеток вверх. Покажи стрелкой преобразование первого круга в последний?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica38-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 38, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 38, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-38/')
