    VALUES (v_textbook_id, 38, '7', 2, 'Как разделить число с остатком на 10, 100, 1000 и т.л.? выполни деление по образцу: Образец: 50 428 : 10 = 5042 (ост. 8); 50 428 : 100 = 504 (ост. 28); 50 428 : 1 000 = 50 (ост. 428); 50 428 : 10 000 = 5 (ост. 428). а) 76 5434 : 10; 76 534 : 100; 76 534 : 1000; 76 534 : 10 000; б) 80 241 : 10; 80 241 : 100; 80 241 : 1 000; 80 241 : 10 000; в) 23 906 : 10; 23 906 : 100; 23 906 : 1 000; 23 906 : 10 000.', '</p>\n\n<p class="text">Как разделить число с остатком на 10, 100, 1000 и т.л.? выполни деление по образцу:\n</p>\n\n<div class="recomended-block">\n<span class="title">Образец:</span>\n<p>\n50 428 : 10 = 5042 (ост. 8);<br/>\n50 428 : 100 = 504 (ост. 28);<br/>\n50 428 : 1 000 = 50 (ост. 428);<br/>\n50 428 : 10 000 = 5 (ост. 428).\n</p>\n</div>\n\n<p class="text">\nа) 76 5434 : 10;<br/>\n76 534 : 100;<br/>\n76 534 : 1000;<br/>\n76 534 : 10 000;<br/>\n<br/>\nб) 80 241 : 10;<br/>\n80 241 : 100;<br/>\n80 241 : 1 000;<br/>\n80 241 : 10 000;<br/>\n<br/>\nв) 23 906 : 10;<br/>\n23 906 : 100;<br/>\n23 906 : 1 000;<br/>\n23 906 : 10 000.\n</p>', 'Чтобы разделить число с остатков на 10, 100, 1000 нужно закрыть в делимом количество знаков, равное количеству нулей. Оставшееся число – неполное частное, а прикрытые цифры – остаток.', '<p>\nЧтобы разделить число с остатков на 10, 100, 1000 нужно закрыть в делимом количество знаков, равное количеству нулей.<br/>\nОставшееся число – неполное частное, а прикрытые цифры – остаток.\n</p>\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica38-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 38, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 38, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-38/')
    RETURNING id INTO v_task_id;

