    VALUES (v_task_id, v_textbook_id, 3, 'b7b69b56b068b24805f3c1fe3bca007fc060d7f9800865e336cc071a65d9cb23', '000,1,5,8,10,23,28,50,76,80', '["раздели","раз"]'::jsonb, 'как разделить число с остатком на 10, 100, 1000 и т.л.? выполни деление по образцу:образец:50 428:10=5042 (ост. 8); 50 428:100=504 (ост. 28); 50 428:1 000=50 (ост. 428); 50 428:10 000=5 (ост. 428). а) 76 5434:10; 76 534:100; 76 534:1000; 76 534:10 000; б) 80 241:10; 80 241:100; 80 241:1 000; 80 241:10 000; в) 23 906:10; 23 906:100; 23 906:1 000; 23 906:10 000');

    VALUES (v_textbook_id, 38, '8', 3, 'Реши задачи, составляя выражения: А) Школа заказала для экскурсии 9 автобусов из расчета 32 человека на автобус. Но автобусов приехало на один меньше. Сколько человек ехало в каждом автобусе, если количество пассажиров во всех автобусах было одинаковое? Б) В красной папке лежало 120 листов бумаги, в зеленой папке – в 2 раза больше, чем в красной, а в голубой – в 3 раза меньше, чем в красной. На сколько листов в зеленой папке было больше, чем в голубой? В) Мише – 11 лет, а сестре – 3 года. Во сколько раз Миша будет старше сестры через 5 лет?', '</p>\n\n<p class="text">Реши задачи, составляя выражения:<br/>\nА) Школа заказала для экскурсии 9 автобусов из расчета 32 человека на автобус. Но автобусов приехало на один меньше. Сколько человек ехало в каждом автобусе, если количество пассажиров во всех автобусах было одинаковое?<br/>\nБ) В красной папке лежало 120 листов бумаги, в зеленой папке – в 2 раза больше, чем в красной, а в голубой – в 3 раза меньше, чем в красной. На сколько листов в зеленой папке было больше, чем в голубой?<br/>\nВ) Мише – 11 лет, а сестре – 3 года. Во сколько раз Миша будет старше сестры через 5 лет?\n</p>', 'А) 32 ⋅ 9 : (9 – 1) = 288 : 8 = 36 (чел.) – ехало в каждом автобусе. Ответ: по 36 человек в автобусе. Б) 120 ⋅ 2 – 120 : 3 = 240 – 40 = 200 (л.) – в зеленой папке больше, чем в голубой. Ответ: на 200 листов больше. В) (11 + 5) : (3 + 5) = 16 : 8 = 2 (раза) – старше сестры через 5 лет. Ответ: в 2 раза старше.', '<p>\nА) 32 ⋅ 9 : (9 – 1) = 288 : 8 = 36 (чел.) – ехало в каждом автобусе.<br/>\nОтвет: по 36 человек в автобусе.<br/>\n<br/>\nБ)  120 ⋅ 2 – 120 : 3 = 240 – 40 = 200 (л.) – в зеленой папке больше, чем в голубой.<br/>\nОтвет: на 200 листов больше.<br/>\n<br/>\nВ) (11 + 5) : (3 + 5) = 16 : 8 = 2 (раза) – старше сестры через 5 лет.<br/>\nОтвет: в 2 раза старше.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-38/')
    RETURNING id INTO v_task_id;

