    VALUES (v_textbook_id, 39, '11', 0, 'Упрости выражения, пользуясь свойствами сложения и умножения: 23 + а + 77; 42 + b + 34 + 158; 25 ⋅ с ⋅ 4; d ⋅ 7 ⋅ 5 ⋅ 2 ⋅ 5 ⋅ 2.', '</p>\n\n<p class="text">Упрости выражения, пользуясь свойствами сложения и умножения:<br/>\n23 + а + 77;<br/>\n42 + b + 34 + 158;<br/>\n25 ⋅ с ⋅ 4;<br/>\nd ⋅ 7 ⋅ 5 ⋅ 2 ⋅ 5 ⋅ 2.\n</p>', '23 + а + 77 = (23 + 77) + а = 100 + а; 42 + b + 34 + 158 = (42 + 158) + 34 + b = 200 + 34 + b = 234 + b; 25 ⋅ с ⋅ 4 = (25 ⋅ 4) ⋅ с = 100 ⋅ с; d ⋅ 7 ⋅ 5 ⋅ 2 ⋅ 5 ⋅ 2 = d ⋅ 7 ⋅ (5 ⋅ 2) ⋅ (5 ⋅ 2) = d ⋅ 7 ⋅ 100 = d ⋅ 700.', '<p>\n23 + а + 77 = (23 + 77) + а = 100 + а;<br/>\n42 + b + 34 + 158 = (42 + 158) + 34 + b = 200 + 34 + b = 234 + b;<br/>\n25 ⋅ с ⋅ 4 = (25 ⋅ 4) ⋅ с = 100 ⋅ с;<br/>\nd ⋅ 7 ⋅ 5 ⋅ 2 ⋅ 5 ⋅ 2 = d ⋅ 7 ⋅ (5 ⋅ 2) ⋅ (5 ⋅ 2) = d ⋅ 7 ⋅ 100 = d ⋅ 700.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-39/')
    RETURNING id INTO v_task_id;

