    VALUES (v_textbook_id, 39, '13', 2, 'Участок образован двумя квадратами, как показано на чертеже. Длина стороны первого квадрата 40 м, а второго – 20 м. Найди площадь этого участка. Чему равна длина забора, который его огораживает?', '</p>\n\n<p class="text">Участок образован двумя квадратами, как показано на чертеже. Длина стороны первого квадрата 40 м, а второго – 20 м. Найди площадь этого участка. Чему равна длина забора, который его огораживает?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica39-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 39, номер 13, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 39, номер 13, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-39/')
