    VALUES (v_textbook_id, 39, '15', 4, 'В классе 32 учащихся. Из них 18 человек занимаются в волейбольной секции, а 16 человек – в баскетбольной. Сколько учащихся занимаются одновременно волейболом и баскетболом? Сколько занимаются только волейболом? Только баскетболом? (Каждый ученик класса занимается хотя бы в одной из этих секций.)', '</p>\n\n<p class="text">В классе 32 учащихся. Из них 18 человек занимаются в волейбольной секции, а 16 человек – в баскетбольной. Сколько учащихся занимаются одновременно волейболом и баскетболом? Сколько занимаются только волейболом? Только баскетболом? (Каждый ученик класса занимается хотя бы в одной из этих секций.)\n</p>', '1) 18 – 16 = 2 (чел.) – занимаются в обеих секциях; 2) 18 – 2 = 16 (чел.) – занимаются только волейболом; 3) 16 – 2 = 14 (чел.) – занимаются только баскетболом; Ответ: 2 человека; 16 человек и 14 человек.', '<p>\n1) 18 – 16 = 2 (чел.) – занимаются в обеих секциях;<br/>\n2) 18 – 2 = 16 (чел.) – занимаются только волейболом;<br/>\n3) 16 – 2 = 14 (чел.) – занимаются только баскетболом;<br/>\nОтвет: 2 человека; 16 человек и 14 человек.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-39/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '66456715a0456d386f8f45d7cad5a3912c5795cfe2a555d8b5788aaf8fb69c34', '16,18,32', NULL, 'в классе 32 учащихся. из них 18 человек занимаются в волейбольной секции, а 16 человек-в баскетбольной. сколько учащихся занимаются одновременно волейболом и баскетболом? сколько занимаются только волейболом? только баскетболом? (каждый ученик класса занимается хотя бы в одной из этих секций.)');

    VALUES (v_textbook_id, 40, '1', 0, 'Практическая работа. А) Лист бумаги сложи пополам и проколи ножкой циркуля. Разогни лист. Обозначь прямую сгиба l, а «проколотые» точки – А и В. Проведи отрезок АВ, обозначь О точку его пересечения с прямой l. Измерь отрезки АО и ВО. Что ты замечаешь? Б) Определи с помощью угольника вид углов, которые образованы при пересечении отрезка АВ и прямой l. Что ты замечаешь? Симметрия относительной прямой Точки А и В симметричны относительно прямой l, если отрезок АВ: 1)перпендикулярен прямой l; 2) пересекает прямую l в своей середине.', '</p>\n\n<p class="text">Практическая работа.<br/>\nА) Лист бумаги сложи пополам и проколи ножкой циркуля. Разогни лист. Обозначь прямую сгиба l, а «проколотые» точки – А и В. Проведи отрезок АВ, обозначь О точку его пересечения с прямой l. Измерь отрезки АО и ВО. Что ты замечаешь?<br/>\nБ) Определи с помощью угольника вид углов, которые образованы при пересечении отрезка АВ и прямой l. Что ты замечаешь?\n</p>\n\n\n\n<div class="recomended-block">\n<span class="title">Симметрия относительной прямой</span>\n<p>\nТочки А и В <b class="black">симметричны</b> относительно прямой l, если отрезок АВ:<br/>\n1)перпендикулярен прямой l;<br/>\n2) пересекает прямую l в своей середине.\n</p>\n</div>', '', '<div class="img-wrapper-460">\n<img width="500" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica40-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 40, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 40, номер 1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-40/')
    RETURNING id INTO v_task_id;

