    VALUES (v_textbook_id, 41, '3', 0, 'Скопируй рисунки в тетради по клеточкам. Построй точки, симметричные данным относительно прямой l. Проверь правильной построений с помощью измерений и с помощью кальки.', '</p>\n\n<p class="text">Скопируй рисунки в тетради по клеточкам. Построй точки, симметричные данным относительно прямой l. Проверь правильной построений с помощью измерений и с помощью кальки.</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica41-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 41, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 41, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-41/')
