    VALUES (v_textbook_id, 41, '4', 1, 'Построй в тетради отрезки, симметричные данным относительно прямой l. Как можно проверить, правильно ли они построены?', '</p>\n\n<p class="text">Построй в тетради отрезки, симметричные данным относительно прямой l. Как можно проверить, правильно ли они построены?</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica41-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 41, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 41, номер 4, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-41/')
