    VALUES (v_textbook_id, 41, '5', 2, 'Вычисли: а) 206 ⋅ 5 000; б) 4 790 ⋅ 600; в) 800 ⋅ 90 250; г) 530 840 : 40; д) 2 725 800 : 30; е) 40 804 200 : 600; ж) 9 300 ⋅ 50 – 46 927; з) 15 786 + 64 400 : 80; и) 436 500 – 255 681 : 9.', '</p>\n\n<p class="text">Вычисли:<br/>\nа) 206 ⋅ 5 000;<br/>\nб) 4 790 ⋅ 600;<br/>\nв) 800 ⋅ 90 250;<br/>\nг) 530 840 : 40;<br/>\nд) 2 725 800 : 30;<br/>\nе) 40 804 200 : 600;<br/>\nж) 9 300 ⋅ 50 – 46 927;<br/>\nз) 15 786 + 64 400 : 80;<br/>\nи) 436 500 – 255 681 : 9.\n</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica41-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 41, номер 5, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 41, номер 5, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-41/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica41-nomer5.jpg', 'peterson/3/part2/page41/task5_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '2ca3b5ef166fde52d44a891d441198792b8adf402060ab12b5461e150e552703', '000,2,4,5,9,15,30,40,46,50', '["вычисли"]'::jsonb, 'вычисли:а) 206 ⋅ 5 000; б) 4 790 ⋅ 600; в) 800 ⋅ 90 250; г) 530 840:40; д) 2 725 800:30; е) 40 804 200:600; ж) 9 300 ⋅ 50-46 927; з) 15 786+64 400:80; и) 436 500-255 681:9');

    VALUES (v_textbook_id, 41, '6', 3, 'Объясни смысл равенств: а – (b + c) = (a – b) – c = (a – c) – b. Используя эти равенства, вычисли наиболее удобным способом: 84 – (64 + 19); 158 – (96 + 58); 349 – (5 + 249).', '</p>\n\n<p class="text">\nОбъясни смысл равенств: а – (b + c) = (a – b) – c = (a – c) – b.<br/>\nИспользуя эти равенства, вычисли наиболее удобным способом:<br/>\n84 – (64 + 19);<br/>			\n158 – (96 + 58);<br/>		\n349 – (5 + 249).\n</p>', 'Чтобы из числа вычесть сумму, можно из этого числа вычесть первое число, а потом вычесть другое. Можно сначала из этого числа вычесть второе число, а потом вычесть второе. 84 – (64 + 19) = (84 – 64) – 19 = 20 – 19 = 1; 158 – (96 + 58) = (158 – 58) – 96 = 100 – 96 = 4; 349 – (5 + 249) = (349 – 249) – 5 = 100 – 5 = 95.', '<p>\nЧтобы из числа вычесть сумму, можно из этого числа вычесть первое число, а потом вычесть другое. Можно сначала из этого числа вычесть второе число, а потом вычесть второе.<br/>\n84 – (64 + 19) = (84 – 64) – 19 = 20 – 19 = 1;<br/>\n158 – (96 + 58) = (158 – 58) – 96 = 100 – 96 = 4;<br/>\n349 – (5 + 249) = (349 – 249) – 5 = 100 – 5 = 95.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-41/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '58b729e15f26031665c7322cdabe6f89e26c36c1fa3eb8a658f981dd44180d08', '5,19,58,64,84,96,158,249,349', '["вычисли"]'::jsonb, 'объясни смысл равенств:а-(b+c)=(a-b)-c=(a-c)-b. используя эти равенства, вычисли наиболее удобным способом:84-(64+19); 158-(96+58); 349-(5+249)');

    VALUES (v_textbook_id, 41, '7', 4, 'Подбери корни уравнений и сделай проверку: х + х = 36; 60 = а + а + а; у + у = у + 5.', '</p>\n\n<p class="text">\nПодбери корни уравнений и сделай проверку:<br/>\nх + х = 36;<br/>		\n60 = а + а + а;<br/>		\nу + у = у + 5.\n\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica41-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 41, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 41, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-41/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica41-nomer7.jpg', 'peterson/3/part2/page41/task7_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '710bbc8d452048a07785152a6c4e96df33bde984482f5d4fcc172ca0bf6d165f', '5,36,60', NULL, 'подбери корни уравнений и сделай проверку:х+х=36; 60=а+а+а; у+у=у+5');

    VALUES (v_textbook_id, 41, '8', 5, 'Сравни выражения, не вычисляя. Обоснуй свой ответ. 60 705 + 124 … 124 + 60 705 и 10 735 : 113 … 10 735 : 5; 64 ⋅ 308 … 308 ⋅ 64 и 2 089 – 916 … 3 000 - 916; 756 ⋅ 32 … 28 ⋅ 736 и (36 + 29) ⋅ 6 … 36 ⋅ 6 + 29 ⋅ 6; 3 094 – 86 … 3 094 – 806 и (56 + 4) ⋅ 2 … 56 + 4 ⋅ 2.', '</p>\n\n<p class="text">\nСравни выражения, не вычисляя. Обоснуй свой ответ.<br/>\n60 705 + 124 … 124 + 60 705	и 10 735 : 113 … 10 735 : 5;<br/>\n64 ⋅ 308 … 308 ⋅ 64 и 2 089 – 916 … 3 000 - 916;<br/>\n756 ⋅ 32 … 28 ⋅ 736 и (36 + 29) ⋅ 6 … 36 ⋅ 6 + 29 ⋅ 6;<br/>\n3 094 – 86 … 3 094 – 806 и (56 + 4) ⋅ 2 … 56 + 4 ⋅ 2.\n</p>', '60 705 + 124 = 124 + 60 705, потому что от перестановки мест слагаемых значение суммы не изменяется; 10 735 : 113 < 10 735 : 5, потому что при делении одного и того же числа на части, больше значение частного там, где делитель меньше; 64 ⋅ 308 = 308 ⋅ 64, потому что от перестановки мест множителей значение произведения не изменяется; 2 089 – 916 < 3 000 – 916, потому что при вычитании одного и того же числа, значение разности больше там, где уменьшаемое больше; 756 ⋅ 32 > 28 ⋅ 736, потому что один из множителей больше, а 32 > 28; (36 + 29) ⋅ 6 = 36 ⋅ 6 + 29 ⋅ 6, по распределительному свойству умножения относительно сложения 3 094 – 86 > 3 094 – 806, потому что из одного и того же числа вычли разные числа, а значение разности больше там, где вычитаемое меньше; (56 + 4) ⋅ 2 < 56 + 4 ⋅ 2, потому что в первом случае применяется распределительное свойство умножения относительно сложения.', '<p>\n60 705 + 124 = 124 + 60 705, потому что от перестановки мест слагаемых значение суммы не изменяется;<br/>	\n10 735 : 113 &lt; 10 735 : 5, потому что при делении одного и того же числа на части, больше значение частного там, где делитель меньше;<br/>\n64 ⋅ 308 = 308 ⋅ 64, потому что от перестановки мест множителей значение произведения не изменяется;<br/>		\n2 089 – 916 &lt; 3 000 – 916, потому что при вычитании одного и того же числа, значение разности больше там, где уменьшаемое больше;<br/>\n756 ⋅ 32 &gt; 28 ⋅ 736, потому что один из множителей больше, а 32 &gt; 28;<br/>		\n(36 + 29) ⋅ 6 = 36 ⋅ 6 + 29 ⋅ 6, по распределительному свойству умножения относительно сложения\n3 094 – 86 &gt; 3 094 – 806, потому что из одного и того же числа вычли разные числа, а значение разности больше там, где вычитаемое меньше;<br/>\n(56 + 4) ⋅ 2 &lt; 56 + 4 ⋅ 2, потому что в первом случае применяется распределительное свойство умножения относительно сложения.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-41/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '28058690e0ae5f2bf3e0335aff5b26a383c58517b44c48e247f6a1443f06ea11', '000,2,3,4,5,6,10,28,29,32', '["сравни"]'::jsonb, 'сравни выражения, не вычисляя. обоснуй свой ответ. 60 705+124 ... 124+60 705 и 10 735:113 ... 10 735:5; 64 ⋅ 308 ... 308 ⋅ 64 и 2 089-916 ... 3 000-916; 756 ⋅ 32 ... 28 ⋅ 736 и (36+29) ⋅ 6 ... 36 ⋅ 6+29 ⋅ 6; 3 094-86 ... 3 094-806 и (56+4) ⋅ 2 ... 56+4 ⋅ 2');

    VALUES (v_textbook_id, 42, '9', 0, 'БЛИЦтрунир. а) Из n пионов сделали букеты по 3 белых и k красных пиона в каждом. Сколько букетов получилось? б) У Пети было а марок, а у Жени – на b марок меньше. Во сколько раз у Пети больше марок, чем у Жени? в) Ася купила 5 бубликов по с р. и 2 батона по d. Р. Сколько стоит вся покупка? г) Валера купил 4 тетради по х р. и 2 одинаковые ручки. За всю покупку он заплатил у р. Сколько стоит каждая такая ручка? д) Длина прямоугольного участка земли равна n м, что на 6 м больше его ширины. Чему равна площадь этого участка? е) Площадь прямоугольника b ь2, а длина – с м. На сколько метров ширина прямоугольника меньше его длины?', '</p>\n\n<p class="text">БЛИЦтрунир.<br/>\nа) Из n пионов сделали букеты по 3 белых и k красных пиона в каждом. Сколько букетов получилось?<br/>\nб) У Пети было а марок, а у Жени – на b марок меньше. Во сколько раз у Пети больше марок, чем у Жени?<br/>\nв) Ася купила 5 бубликов по с р. и 2 батона по d. Р. Сколько стоит вся покупка?<br/>\nг) Валера купил 4 тетради по х р. и 2 одинаковые ручки. За всю покупку он заплатил у р. Сколько стоит каждая такая ручка?<br/>\nд) Длина прямоугольного участка земли равна n м, что на 6 м больше его ширины. Чему равна площадь этого участка?<br/>\nе) Площадь прямоугольника b ь2, а длина – с м. На сколько метров ширина прямоугольника меньше его длины?\n</p>', 'а) n : (3 + k); б) а : (а – b); в) с ⋅ 5 + d ⋅ 2; г) (у – (х ⋅ 4)) : 2; д) n ⋅ (n – 6); е) с – b : с.', '<p>\nа) n : (3 + k);<br/>\nб) а : (а – b);<br/>\nв) с ⋅ 5 + d ⋅ 2;<br/>\nг) (у – (х ⋅ 4)) : 2;<br/>\nд) n ⋅ (n – 6);<br/>\nе) с – b : с.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-42/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '991d8ec2f2a46ba7fb7c3309440dcb490fdded0b5a92a2c0c5c4366e71d0d10e', '2,3,4,5,6', '["площадь","больше","меньше","раз"]'::jsonb, 'блицтрунир. а) из n пионов сделали букеты по 3 белых и k красных пиона в каждом. сколько букетов получилось? б) у пети было а марок, а у жени-на b марок меньше. во сколько раз у пети больше марок, чем у жени? в) ася купила 5 бубликов по с р. и 2 батона по d. р. сколько стоит вся покупка? г) валера купил 4 тетради по х р. и 2 одинаковые ручки. за всю покупку он заплатил у р. сколько стоит каждая такая ручка? д) длина прямоугольного участка земли равна n м, что на 6 м больше его ширины. чему равна площадь этого участка? е) площадь прямоугольника b ь2, а длина-с м. на сколько метров ширина прямоугольника меньше его длины');

    VALUES (v_textbook_id, 42, '10', 1, 'Математический фокус. Задумай число, прибавить к нему 6, из суммы вычти 2, затем вычти задуманное число и к результату прибавь 1. Получится 5. Отгадай, почему так получается.', '</p>\n\n<p class="text">Математический фокус.<br/>\nЗадумай число, прибавить к нему 6, из суммы вычти 2, затем вычти задуманное число и к результату прибавь 1. Получится 5. Отгадай, почему так получается.\n</p>', '1)Задумываю число: 6; 2) Прибавляю к нему 6: 6 + 6 = 12; 3) из суммы вычитаю 2: 12 – 2 = 10; 4) Вычитаю задуманное число: 10 – 6 = 4; 5) Прибавляю 1: 4 + 1 = 5. Так получается, потому что число, которое мы задумывали вычитается само из себя, а все действия с ним образуют 7: 6 – 2 + 1 = 4 + 1 = 5.', '<p>\n1)Задумываю число: 6;<br/>\n2) Прибавляю к нему 6: 6 + 6 = 12;<br/>\n3) из суммы вычитаю 2: 12 – 2 = 10;<br/>\n4) Вычитаю задуманное число: 10 – 6 = 4;<br/>\n5) Прибавляю 1: 4 + 1 = 5.<br/>\n<br/>\nТак получается, потому что число, которое мы задумывали вычитается само из себя, а все действия с ним образуют 7: 6 – 2 + 1 = 4 + 1 = 5.\n\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-42/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'bca21475c73a6cfc1d0a21c0723dd7c893fc9a17863a02019715d7cafd1c9a40', '1,2,5,6', '["вычти"]'::jsonb, 'математический фокус. задумай число, прибавить к нему 6, из суммы вычти 2, затем вычти задуманное число и к результату прибавь 1. получится 5. отгадай, почему так получается');

