    VALUES (v_task_id, v_textbook_id, 3, '98d3f09e76492afb34c0d88cbc5d30265ecfdcec9c7c1d8f8f19f8ebd919e624', '3,5,8,20', '["вычисли","найди","периметр","меньше"]'::jsonb, 'а) измерь длину и ширину своей тетради. вычисли её периметр. б) длина тетради равна 20 см 5 мм, а ширина-на 3 см 8 мм меньше. найди ширину тетради и её периметр');

    VALUES (v_textbook_id, 44, '9', 6, 'Продолжи ряд на три числа, сохраняя закономерность: 1, 4, 10, 19, 31, 46, 64, …', '</p>\n\n<p class="text">\nПродолжи ряд на три числа, сохраняя закономерность:<br/>\n1, 4, 10, 19, 31, 46, 64, …\n</p>', 'Каждое следующее число больше предыдущего на 3, 6, 9, т.е. большее количество троек. 1 + 3 = 4; 4 + 6 = 10; 10 + 9 = 19; 19 + 12 = 31; 31 + 15 = 46; 46 + 18 = 64; 64 + 21 = 85; 85 + 24 = 109; 109 + 27 = 136.', '<p>\nКаждое следующее число больше предыдущего на 3, 6, 9, т.е. большее количество троек.\n1 + 3 = 4;<br/>\n4 + 6 = 10;<br/>\n10 + 9 = 19;<br/>\n19 + 12 = 31;<br/>\n31 + 15 = 46;<br/>\n46 + 18 = 64;<br/>\n64 + 21 = 85;<br/>\n85 + 24 = 109;<br/>\n109 + 27 = 136.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-44/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6ffeedd564b3fd1e6e18655d938df962550d47fb0f66c32a1ec5b9a494a1a42f', '1,4,10,19,31,46,64', NULL, 'продолжи ряд на три числа, сохраняя закономерность:1, 4, 10, 19, 31, 46, 64');

    VALUES (v_textbook_id, 45, '1', 0, 'Практическая работа. Начерти на листе бумаги и вырежи прямоугольник со сторонами 3 см и 5 см. перегни его по указанным линиям. Что ты замечаешь?', '</p>\n\n<p class="text">Практическая работа.<br/>\nНачерти на листе бумаги и вырежи прямоугольник со сторонами 3 см и 5 см. перегни его по указанным линиям. Что ты замечаешь?\n</p>', 'При сгибании, как на рисунках 1 и 3, половинки фигур совпадают, а при сгибании на рисунках 2 и 4 – нет. Значит, линии сгиба 1 и 3 – доказывают, что прямоугольник – фигура симметричная.', '<p>\nПри сгибании, как на рисунках 1 и 3, половинки фигур совпадают, а при сгибании на рисунках 2 и 4 – нет. Значит, линии сгиба 1 и 3 – доказывают, что прямоугольник – фигура симметричная.\n</p>', 'Симметричные фигуры Фигуру F называют симметричной относительно прямой l, если она состоит из двух частей, симметричных относительно l. Фигура F симметрична относительно прямой l. Прямая l – ось симметрии фигуры F.', '<div class="recomended-block">\n<span class="title">Симметричные фигуры</span>\n<p>\nФигуру F называют <b class="black">симметричной</b> относительно прямой l, если она состоит из двух частей, симметричных относительно l.<br/>\nФигура F симметрична  относительно прямой l.<br/>\nПрямая l – ось симметрии фигуры F.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-45/')
    RETURNING id INTO v_task_id;

