    VALUES (v_textbook_id, 46, '10', 5, 'Игры со словами. Палиндромы. Палиндромы (перевёртыши) – это слова и предложения, которые читаются одинаково слева направо и справа налево. Например, НАГАН; А РОЗА УПАЛА НА ЛАПУ АЗОРА; Я НЕ МИЛ – И НЕ ЖЕНИЛИ МЕНЯ; Я НЕ СТАР, БРАТ СЕНЯ. Среди слов, приведенных ниже, найди палиндромы, которые имеют оси симметрии: ПОП, ДОВОД, ДОХОД, ПОТОП, ЗАКАЗ, КАЗАК. Придумай свои палиндромы.', '</p>\n\n<p class="text">\nИгры со словами. Палиндромы.<br/>\nПалиндромы (перевёртыши) – это слова и предложения, которые читаются одинаково слева направо и справа налево.<br/>\nНапример, НАГАН; А РОЗА УПАЛА НА ЛАПУ АЗОРА; Я НЕ МИЛ – И НЕ ЖЕНИЛИ МЕНЯ; Я НЕ СТАР, БРАТ СЕНЯ.<br/>\nСреди слов, приведенных ниже, найди палиндромы, которые имеют оси симметрии:<br/>\nПОП, ДОВОД, ДОХОД, ПОТОП, ЗАКАЗ, КАЗАК.<br/>\nПридумай свои палиндромы.\n</p>', 'Все слова могут читаться слева направо и справа налево. Симметричные палиндромы:', '<p>\nВсе слова могут читаться слева направо и справа налево.\nСимметричные палиндромы: \n</p>\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica46-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 46, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 46, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-46/')
    RETURNING id INTO v_task_id;

