    VALUES (v_task_id, v_textbook_id, 3, 'ce8db8d008e6886f31ec2a1a67a38874e6d160d3e9af711aa37c75a7865dd8b1', NULL, '["найди"]'::jsonb, 'игры со словами. палиндромы. палиндромы (перевёртыши)-это слова и предложения, которые читаются одинаково слева направо и справа налево. например, наган; а роза упала на лапу азора; я не мил-и не женили меня; я не стар, брат сеня. среди слов, приведенных ниже, найди палиндромы, которые имеют оси симметрии:поп, довод, доход, потоп, заказ, казак. придумай свои палиндромы');

