    VALUES (v_textbook_id, 47, '3', 2, 'Составь и реши уравнения: а) На какое число надо разделить 3 003 600, чтобы получить 60? б) На какое число надо умножить 400, чтобы получить 21 236 000? в) какое число надо разделить на 500, чтобы получить 80 060?', '</p>\n\n<p class="text">Составь и реши уравнения:<br/>\nа) На какое число надо разделить 3 003 600, чтобы получить 60?<br/>\nб) На какое число надо умножить 400, чтобы получить 21 236 000?<br/>\nв) какое число надо разделить на 500, чтобы получить 80 060?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica47-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 47, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 47, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-47/')
