    VALUES (v_textbook_id, 47, '4', 3, 'Составь программу действий и вычисли: а) 750 : 650 ⋅ 9 – 9 ⋅ (16 : 2 + 14 : 14) + (7 – 7) ⋅ 28; б) 8 ⋅ (63 : 7 – 0 : 5) – 720 : 60 ⋅ 4 + (90 – 36) : 9.', '</p>\n\n<p class="text">Составь программу действий и вычисли:<br/>\nа) 750 : 650 ⋅ 9 – 9 ⋅ (16 : 2 + 14 : 14) + (7 – 7) ⋅ 28;<br/>\nб) 8 ⋅ (63 : 7 – 0 : 5) – 720 : 60 ⋅ 4 + (90 – 36) : 9.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica47-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 47, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 47, номер 4, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-47/')
