    VALUES (v_task_id, v_textbook_id, 3, 'fba6146f108ec17de54503036630e9ee646772339cdf1a544d93618b524d03fa', '3,4,7,18', '["больше","меньше","раз","раза"]'::jsonb, 'а) масса птички зарянки 18 г, а её яйца-3 г. во сколько раз масса зарянки больше массы её яйца? б) масса яйца сороки 7 г, что в 4 раза меньше массы яйца фазана. чему равна масса яйца фазана');

    VALUES (v_textbook_id, 47, '6', 5, 'В первом бочонке было 20 кг мёда. После того как Винни-Пух взял из него 2 кг мёда, в нем осталось на 4 кг меньше, чем во втором бочонке. Сколько мёда стало в двух бочонках вместе?', '</p>\n\n<p class="text">В первом бочонке было 20 кг мёда. После того как Винни-Пух взял из него 2 кг мёда, в нем осталось на 4 кг меньше, чем во втором бочонке. Сколько мёда стало в двух бочонках вместе?</p>', '1) 20 – 2 = 18 (кг) – масса оставшегося меда первого бочонка; 2) 18 + 4 = 22 (кг) – масса меда во втором бочонке; 3) 18 + 22 = 40 (кг) – масса меда в обоих бочонках. Ответ: 40 кг.', '<p>\n1) 20 – 2 = 18 (кг) – масса оставшегося меда первого бочонка;<br/>\n2) 18 + 4 = 22 (кг) – масса меда во втором бочонке;<br/>\n3) 18 + 22 = 40 (кг) – масса меда в обоих бочонках.<br/>\nОтвет: 40 кг.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-47/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6359718be57f991933983db8e311faec93b92d62303ff980c4d14a1112662f4b', '2,4,20', '["меньше"]'::jsonb, 'в первом бочонке было 20 кг мёда. после того как винни-пух взял из него 2 кг мёда, в нем осталось на 4 кг меньше, чем во втором бочонке. сколько мёда стало в двух бочонках вместе');

    VALUES (v_textbook_id, 48, '7', 0, 'Объясни смысл равенств: (а + b) – с = (а – с) + b = а + (b – c). Используя эти равенства, вычисли наиболее удобным способом: (1527 + 2814) – 527; (3276 + 964) – 964.', '</p>\n\n<p class="text">Объясни смысл равенств: (а + b) – с = (а – с) + b = а + (b – c).<br/>\nИспользуя эти равенства, вычисли наиболее удобным способом:<br/>\n(1527 + 2814) – 527;<br/>\n(3276 + 964) – 964.\n</p>', 'Из суммы разность можно вычесть так, если из первого слагаемого вычесть число, а затем прибавить оставшееся слагаемое. (1527 + 2814) – 527 = (1527 – 527) + 2814 = 100 + 2814 = 3814 (3276 + 964) – 964 = 3276 + (964 – 964) = 3276 + 0 = 3276', '<p>\nИз суммы разность можно вычесть так, если из первого слагаемого вычесть число, а затем прибавить оставшееся слагаемое.\n(1527 + 2814) – 527 = (1527 – 527) + 2814 = 100 + 2814 = 3814\n(3276 + 964) – 964 = 3276 + (964 – 964) = 3276 + 0 = 3276\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-48/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'e0a7601cf9146b4ca01d86255a3a4ce794792593e8f1f73151b3f2b0031f901e', '527,964,1527,2814,3276', '["вычисли"]'::jsonb, 'объясни смысл равенств:(а+b)-с=(а-с)+b=а+(b-c). используя эти равенства, вычисли наиболее удобным способом:(1527+2814)-527; (3276+964)-964');

    VALUES (v_textbook_id, 48, '8', 1, 'БЛИЦтурнир. а) В одинаковых ящиках d кг винограда. Сколько килограммов винограда уместится в 12 таких ящиках? б) За 3 одинаковые булочки заплатили а р. Сколько таких булочек можно купить на b р.? в) Брат старше сестры на k лет, а вместе им t лет. Сколько лет сестре? г) В трех кусках m метров ткани. В первом куске х метров, а во втором – в 3 раза больше, чем в первом. Сколько метров ткани в третьем куске?', '</p>\n\n<p class="text">БЛИЦтурнир.<br/>\nа) В одинаковых ящиках d кг винограда. Сколько килограммов винограда уместится в 12 таких ящиках?<br/>\nб) За 3 одинаковые булочки заплатили а р. Сколько таких булочек можно купить на b р.?<br/>\nв) Брат старше сестры на k лет, а вместе им t лет. Сколько лет сестре?<br/>\nг) В трех кусках m метров ткани. В первом куске х метров, а во втором – в 3 раза больше, чем в первом. Сколько метров ткани в третьем куске?\n</p>', 'а) d : 7 ⋅ 12 (кг) – в 12 ящиках; б) b : (а : 3) (шт.) – булочек можно купить; в) t – k : 2 (лет) – сестре; г) m – x – 3 ⋅ х (м) – в третьем куске.', '<p>\nа) d : 7 ⋅ 12 (кг) – в 12 ящиках;<br/>\nб) b : (а : 3) (шт.) – булочек можно купить;<br/>\nв) t – k : 2 (лет) – сестре;<br/>\nг) m – x – 3 ⋅ х (м) – в третьем куске.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-48/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '369faf30960e2ded103fcfe8a803a46e381a5913438ef8366195b7760feb6dab', '3,12', '["больше","раз","раза"]'::jsonb, 'блицтурнир. а) в одинаковых ящиках d кг винограда. сколько килограммов винограда уместится в 12 таких ящиках? б) за 3 одинаковые булочки заплатили а р. сколько таких булочек можно купить на b р.? в) брат старше сестры на k лет, а вместе им t лет. сколько лет сестре? г) в трех кусках m метров ткани. в первом куске х метров, а во втором-в 3 раза больше, чем в первом. сколько метров ткани в третьем куске');

    VALUES (v_textbook_id, 48, '9', 2, 'Вычисли. Наложи прозрачную плёнку и соедини ответы по порядку. Что получилось? 1. 96 ⋅ 10 : 8; 2. 8 100 : 10 : 90; 3. 87 : 3 ⋅ 5; 4. 72 : 8 ⋅ 7 : 3; 5. (100 – 30) ⋅ 60 : 100; 6. (80 + 240 ⋅ 3) : 20; 7. 36 ⋅ (150 – 140) : 4; 8. 540 : (196 – 106) ⋅ 20.', '</p>\n\n<p class="text">Вычисли. Наложи прозрачную плёнку и соедини ответы по порядку. Что получилось?<br/>\n1. 96 ⋅ 10 : 8;<br/>\n2. 8 100 : 10 : 90;<br/>\n3. 87 : 3 ⋅ 5;<br/>\n4. 72 : 8 ⋅ 7 : 3;<br/>\n5. (100 – 30) ⋅ 60 : 100;<br/>\n6. (80 + 240 ⋅ 3) : 20;<br/>\n7. 36 ⋅ (150 – 140) : 4;<br/>\n8. 540 : (196 – 106) ⋅ 20.\n</p>', '1. 96 ⋅ 10 : 8 = 960 : 8 = 120; 2. 8 100 : 10 : 90 = 81 : 9 = 9; 3. 87 : 3 ⋅ 5 = 29 ⋅ 5 = 145; 4. 72 : 8 ⋅ 7 : 3 = 9 ⋅ 7 : 3 = 63 : 3 = 21; 5. (100 – 30) ⋅ 60 : 100 = 70 ⋅ 60 : 100 = 4200 : 100 = 42; 6. (80 + 240 ⋅ 3) : 20 = (80 + 720) : 20 = 800 : 20 = 40; 7. 36 ⋅ (150 – 140) : 4 = 36 ⋅ 10 : 4 = 360 : 4 = 90; 8. 540 : (196 – 106) ⋅ 20 = 540 : 90 * 20 = 6 ⋅ 20 = 120.', '<p>\n1. 96 ⋅ 10 : 8 = 960 : 8 = 120;<br/>\n2. 8 100 : 10 : 90 = 81 : 9 = 9;<br/>\n3. 87 : 3 ⋅ 5 = 29 ⋅ 5 = 145;<br/>\n4. 72 : 8 ⋅ 7 : 3 = 9 ⋅ 7 : 3 = 63 : 3 = 21;<br/>\n5. (100 – 30) ⋅ 60 : 100 = 70 ⋅ 60 : 100 = 4200 : 100 = 42;<br/>\n6. (80 + 240 ⋅ 3) : 20 = (80 + 720) : 20 = 800 : 20 = 40;<br/>\n7. 36 ⋅ (150 – 140) : 4 = 36 ⋅ 10 : 4 = 360 : 4 = 90;<br/>\n8. 540 : (196 – 106) ⋅ 20 = 540 : 90 * 20 = 6 ⋅ 20 = 120.\n</p>\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica48-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 48, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 48, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-48/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica48-nomer9.jpg', 'peterson/3/part2/page48/task9_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '4bd065cc5305f00c1af436ce2128314c8a4e68313772186d42e280ed9e770c4b', '1,2,3,4,5,6,7,8,10,20', '["вычисли"]'::jsonb, 'вычисли. наложи прозрачную плёнку и соедини ответы по порядку. что получилось? 1. 96 ⋅ 10:8; 2. 8 100:10:90; 3. 87:3 ⋅ 5; 4. 72:8 ⋅ 7:3; 5. (100-30) ⋅ 60:100; 6. (80+240 ⋅ 3):20; 7. 36 ⋅ (150-140):4; 8. 540:(196-106) ⋅ 20');

    VALUES (v_textbook_id, 48, '10', 3, 'Сколькими способами можно раскрасить флаг из 5 полос так, чтобы: а) 3 полосы были красным, а 2 – синими; б) 1 полоса была красной, 1 полос – жёлтой, а 3 – зелёными? Нарисуй их.', '</p>\n\n<p class="text">Сколькими способами можно раскрасить флаг из 5 полос так, чтобы:<br/>\nа) 3 полосы были красным, а 2 – синими;<br/>\nб) 1 полоса была красной, 1 полос – жёлтой, а 3 – зелёными?<br/>\nНарисуй их.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica48-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 48, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 48, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-48/')
    RETURNING id INTO v_task_id;

