    VALUES (v_textbook_id, 49, '2', 1, 'Составь и реши уравнения: А) Из какого числа надо вычесть 395 507, чтобы получить 9898? Б) какое число надо вычесть из числа 740 030, чтобы получить 35 518? В) к какому числу надо прибавить число 1076, чтобы получить 304 305?', '</p>\n\n<p class="text">Составь и реши уравнения:<br/>\nА) Из какого числа надо вычесть 395 507, чтобы получить 9898?<br/>\nБ) какое число надо вычесть из числа 740 030, чтобы получить 35 518?<br/>\nВ) к какому числу надо прибавить число 1076, чтобы получить 304 305?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica49-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 49, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 49, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-49/')
