    VALUES (v_textbook_id, 49, '3', 2, 'БЛИЦтурнир. А) в 6 одинаковых вагонах поезда k мест. Сколько человек можно разместить в n таких вагонах? Б) Рабочий в каждый час делает поровну деталей. За 4 часа он сделал b деталей. За сколько часов, работая так же, он сделает 90 деталей? В) Миша за два дня подтянулся d раз, причем во второй день – на 8 раз больше, чем в первый. Сколько раз он подтянулся во второй день? Г) Три книги вместе стоят а р. Первая книга стоит с р., а вторая – в 4 раза дороже первой. Сколько рублей стоит третья книга?', '</p>\n\n<p class="text">БЛИЦтурнир.<br/>\nА) в 6 одинаковых вагонах поезда k мест. Сколько человек можно разместить в n таких вагонах?<br/>\nБ) Рабочий в каждый час делает поровну деталей. За 4 часа он сделал b деталей. За сколько часов, работая так же, он сделает 90 деталей?<br/>\nВ) Миша за два дня подтянулся d раз, причем во второй день – на 8 раз больше, чем в первый. Сколько раз он подтянулся во второй день?<br/>\nГ) Три книги  вместе стоят а р. Первая книга стоит с р., а вторая – в 4 раза дороже первой. Сколько рублей стоит третья книга?\n</p>', 'А) n ⋅ (k : 6) (шт.) –человек можно разместить в таких вагонах; Б) 90 : (b : 4) (ч) – рабочий сделает 90 деталей; В) (d – 8) : 2 + 8 (раз) – подтянулся он во второй день; Г) а – (с + с ⋅ 4) (руб.) – стоит третья книга.', '<p>\nА) n ⋅ (k : 6) (шт.) –человек можно разместить в таких вагонах;<br/>\nБ) 90 : (b : 4) (ч) – рабочий сделает 90 деталей;<br/>\nВ) (d – 8) : 2 + 8 (раз) – подтянулся он во второй день;<br/>\nГ) а – (с + с ⋅ 4)  (руб.) – стоит третья книга.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-49/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '747fdfb849fad0976ca34a9986dd5de1e230915c33acbe68357b5921ed2b953c', '4,6,8,90', '["больше","раз","раза"]'::jsonb, 'блицтурнир. а) в 6 одинаковых вагонах поезда k мест. сколько человек можно разместить в n таких вагонах? б) рабочий в каждый час делает поровну деталей. за 4 часа он сделал b деталей. за сколько часов, работая так же, он сделает 90 деталей? в) миша за два дня подтянулся d раз, причем во второй день-на 8 раз больше, чем в первый. сколько раз он подтянулся во второй день? г) три книги вместе стоят а р. первая книга стоит с р., а вторая-в 4 раза дороже первой. сколько рублей стоит третья книга');

