    VALUES (v_textbook_id, 50, '7', 0, 'Вычисли. Расположи ответы в порядке возрастания и расшифруй высказывание. Как ты его понимаешь? Соглашаешься ли ты с ним? РЕЖ. 7400 ⋅ 700; АСБЕ. 580 090 ⋅ 6; ЁТ. 200 900 ⋅ 90; УТАЧ. 720 464 : 8; Н. 16 403 200 : 400; МИ. 1 456 000 : 70.', '</p>\n\n<p class="text">Вычисли. Расположи ответы в порядке возрастания и расшифруй высказывание. Как ты его понимаешь? Соглашаешься ли ты с ним?<br/>\nРЕЖ. 7400 ⋅ 700;<br/>\nАСБЕ. 580 090 ⋅ 6;<br/>\nЁТ. 200 900 ⋅ 90;<br/>\nУТАЧ. 720 464 : 8;<br/>\nН. 16 403 200 : 400;<br/>\nМИ. 1 456 000 : 70.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica50-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 50, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 50, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-50/')
