    VALUES (v_textbook_id, 50, '8', 1, 'Начерти прямые АВ, CD и MN, которые пересекаются в одной точке О. Назови все лучи на чертеже. На сколько частей они делят плоскость? Назови образовавшиеся углы и раскрась в разные цвета. С помощью чертежного угольника определи вид углов.', '</p>\n\n<p class="text">Начерти прямые АВ, CD и MN, которые пересекаются в одной точке О. Назови все лучи на чертеже. На сколько частей они делят плоскость? Назови образовавшиеся углы и раскрась в разные цвета. С помощью чертежного угольника определи вид углов.</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica50-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 50, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 50, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-50/')
