    VALUES (v_task_id, v_textbook_id, 3, 'bda995d68b488a5faa3680a473e2f1a9000389d7378657e9550f80a3ea8fae61', NULL, '["раз"]'::jsonb, 'начерти прямые ав, cd и mn, которые пересекаются в одной точке о. назови все лучи на чертеже. на сколько частей они делят плоскость? назови образовавшиеся углы и раскрась в разные цвета. с помощью чертежного угольника определи вид углов');

    VALUES (v_textbook_id, 50, '9', 2, 'Чтобы попасть из села в город, нужно подняться в гору, спуститься вниз и пройти по ровной дороге. Подъем в гору составляет а км, путь с горы – в 2 раза длиннее, чем путь в гору, и на 3 км короче ровной дороги. Чему равно расстояние от села до города? Составь выражение и найди его значение при а = 2.', '</p>\n\n<p class="text">Чтобы попасть из села в город, нужно подняться в гору, спуститься вниз и пройти по ровной дороге. Подъем в гору составляет а км, путь с горы – в 2 раза длиннее, чем путь в гору, и на 3 км короче ровной дороги. Чему равно расстояние от села до города?<br/>\nСоставь выражение и найди его значение при а = 2.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica50-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 50, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 50, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-50/')
    RETURNING id INTO v_task_id;

