    VALUES (v_task_id, v_textbook_id, 3, '3624a6651589b81ac6c471559771909acad0d3a702ee78180de3eb57b7f4bd43', '2,3', '["найди","равно","раз","раза"]'::jsonb, 'чтобы попасть из села в город, нужно подняться в гору, спуститься вниз и пройти по ровной дороге. подъем в гору составляет а км, путь с горы-в 2 раза длиннее, чем путь в гору, и на 3 км короче ровной дороги. чему равно расстояние от села до города? составь выражение и найди его значение при а=2');

