    VALUES (v_textbook_id, 50, '12', 5, 'Арифметические ребусы. Расшифруй арифметические ребусы (одинаковым буквам в ребусах соответствуют одинаковые цифры, а разным – разные).', '</p>\n\n<p class="text">Арифметические ребусы.<br/>\nРасшифруй арифметические ребусы (одинаковым буквам в ребусах соответствуют одинаковые цифры, а разным – разные).\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica50-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 50, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 50, номер 12, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-50/')
