    VALUES (v_textbook_id, 53, '1', 0, 'Рассмотри календарь. Сколько месяцев в году? Запиши множество месяцев, в которых 31 день, и множество месяцев, в которых 30 дней. Есть ли идущие подряд месяцы, в которых по 31 дню? Остались ли ещё месяцы? Сколько дней в феврале?', '</p>\n\n<p class="text">Рассмотри календарь. Сколько месяцев в году? Запиши множество месяцев, в которых 31 день, и множество месяцев, в которых 30 дней. Есть ли идущие подряд месяцы, в которых по 31 дню? Остались ли ещё месяцы? Сколько дней в феврале?\n</p>', 'В году 12 месяцев. А – множество месяцев в году, в которых 31 день. А: {Январь, Март, Май, Июль, Август, Октябрь, Декабрь}. В – множество месяцев в году, в которых 30 дней. В: {Апрель, Июнь, Сентябрь, Ноябрь}. Есть два месяца, идущие подряд в которых по 31 дню: Июль и Август, Декабрь и Январь. Остался февраль. В феврале 28 дней или 29.', '<p>\nВ году 12 месяцев.<br/>\nА – множество месяцев в году, в которых 31 день.<br/>\nА: {Январь, Март, Май, Июль, Август, Октябрь, Декабрь}.<br/>\n<br/>\nВ – множество месяцев в году, в которых 30 дней.<br/>\nВ: {Апрель, Июнь, Сентябрь, Ноябрь}.<br/>\n<br/>\nЕсть два месяца, идущие подряд в которых по 31 дню: Июль и Август, Декабрь и Январь.<br/>\n<br/>\nОстался февраль. В феврале 28 дней или 29.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-53/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '033d225baa68ca054ef1edc13b8020275c34d889da0533034f8ae549a5f33937', '30,31', NULL, 'рассмотри календарь. сколько месяцев в году? запиши множество месяцев, в которых 31 день, и множество месяцев, в которых 30 дней. есть ли идущие подряд месяцы, в которых по 31 дню? остались ли ещё месяцы? сколько дней в феврале');

    VALUES (v_textbook_id, 53, '2', 1, 'А) Сколько дней в 2014 году? Как определить это, не считая? Б) Сколько дней в високосном году? Какие 3 последних високосных года были в XX веке? Назови первые пять високосных лет XXI века. Будет ли високосным 2300 год? А 2400 год?', '</p>\n\n<p class="text">А) Сколько дней в 2014 году? Как определить это, не считая?<br/>\nБ) Сколько дней в високосном году? Какие 3 последних високосных года были в XX веке? Назови первые пять високосных лет XXI века. Будет ли високосным 2300 год? А 2400 год?\n\n</p>', 'А) В году может быть 365 дней или 366, если этот год високосный. Високосный год наступает каждые четыре года. Чтобы понять, год високосный или нет, нужно узнать, делится ли число года на 4. 2014 на 4 не делится. Значит, что этот год не високосный и в нем 365 дней. Б) В високосном году 366 дней. Последние три високосных года в XX веке: 1996, 1992, 1988. Первые пять високосных лет XXI века: 2004, 2008, 2012. 2300 будет високосным, потому что 2 300 делится на 4, т.к. 2 300 : 4 = 574. 2400 будет високосным, потому что 2400 делится на 4, т.к. 2 400 : 4 = 600.', '<p>\nА) В году может быть 365 дней или 366, если этот год високосный.<br/>\nВисокосный год наступает каждые четыре года. Чтобы понять, год високосный или нет, нужно узнать, делится ли число года на 4.<br/>\n2014 на 4 не делится. Значит, что этот год не високосный и в нем 365 дней.<br/>\n<br/>\nБ) В високосном году 366 дней. <br/>\nПоследние три високосных года в XX веке: 1996, 1992, 1988.<br/>\nПервые пять високосных лет XXI века: 2004, 2008, 2012.<br/>\n<br/>\n2300 будет високосным, потому что 2 300 делится на 4, т.к. 2 300 : 4 = 574.<br/>\n2400 будет високосным, потому что 2400 делится на 4, т.к. 2 400 : 4 = 600.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-53/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'aa50f940f7480023b399a45785d5df843acac927bc46bd06eb1792b1b3f4375f', '3,2014,2300,2400', NULL, 'а) сколько дней в 2014 году? как определить это, не считая? б) сколько дней в високосном году? какие 3 последних високосных года были в xx веке? назови первые пять високосных лет xxi века. будет ли високосным 2300 год? а 2400 год');

    VALUES (v_textbook_id, 53, '3', 2, 'А) Какого числа начинаются занятия в школе? На какие месяцы приходятся каникулы? Б) Сколько месяцев длятся зима, весна, лето и осень? Какие это месяцы?', '</p>\n\n<p class="text">А) Какого числа начинаются занятия в школе? На какие месяцы приходятся каникулы?<br/>\nБ) Сколько месяцев длятся зима, весна, лето и осень? Какие это месяцы?\n</p>', 'А) Занятия в школе начинаются 1 сентября, т.е. 01.09. Каникулы приходятся на летние месяцы: Июнь, Июль, Август. Б) Зима, весна, лето, осень, т.е. каждый сезон длятся три месяца каждый. Зима: Декабрь, Январь, Февраль. Весна: Март, Апрель, Май. Лето: Июнь, Июль, Август. Осень: Сентябрь, Октябрь, Ноябрь.', '<p>\nА) Занятия в школе начинаются 1 сентября, т.е. 01.09.<br/>\nКаникулы приходятся на летние месяцы: Июнь, Июль, Август.<br/>\nБ) Зима, весна, лето, осень, т.е. каждый сезон длятся три месяца каждый.<br/>\nЗима: Декабрь, Январь, Февраль.<br/>\nВесна: Март, Апрель, Май.<br/>\nЛето: Июнь, Июль, Август.<br/>\nОсень: Сентябрь, Октябрь, Ноябрь.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-53/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '545a0924e46544899313a44f8bc62dafe6ed73b81674f9db744199eb1f1be98b', NULL, NULL, 'а) какого числа начинаются занятия в школе? на какие месяцы приходятся каникулы? б) сколько месяцев длятся зима, весна, лето и осень? какие это месяцы');

    VALUES (v_textbook_id, 53, '4', 3, 'Год делится на 4 квартала по 3 месяца в каждом (начиная с января). Сколько дней в каждом квартале в обычном и високосном году?', '</p>\n\n<p class="text">Год делится на 4 квартала по 3 месяца в каждом (начиная с января). Сколько дней в каждом квартале в обычном и високосном году?\n</p>', 'Так как в каждом квартале по три месяца, а в году – 365 дней, то, получается, что в каждом квартале разное количество дней. В обычном году: 1 квартал – 90 дней; 2 квартал – 91 день; 3 квартал – 92 дня; 4 квартал – 92 дня. В високосном году: 1 квартал – 91 дней; 2 квартал – 91 день; 3 квартал – 92 дня; 4 квартал – 92 дня.', '<p>\nТак как в каждом квартале по три месяца, а в году – 365 дней, то, получается, что в каждом квартале разное количество дней.<br/>\nВ обычном году:<br/>\n1 квартал – 90 дней;<br/>\n2 квартал – 91 день;<br/>\n3 квартал – 92 дня;<br/>\n4 квартал – 92 дня.<br/>\n<br/>\nВ високосном году:<br/>\n1 квартал – 91 дней;<br/>\n2 квартал – 91 день;<br/>\n3 квартал – 92 дня;<br/>\n4 квартал – 92 дня.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-53/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '2f6828525fc6345028635100d8a505a433aaf00dc49a83445452d46d526dfc8c', '3,4', NULL, 'год делится на 4 квартала по 3 месяца в каждом (начиная с января). сколько дней в каждом квартале в обычном и високосном году');

    VALUES (v_textbook_id, 53, '5', 4, 'Прочитай выражение а + b разными способами. Найди его значение, если: А) а = 8, b = 9; Б) а = 25, b = 36; В) а = 6974, b = 476.', '</p>\n\n<p class="text">Прочитай выражение а + b разными способами. Найди его значение, если:<br/>\nА) а = 8, b = 9;<br/>\nБ) а = 25, b = 36;<br/>\nВ) а = 6974, b = 476.\n</p>', 'Значение суммы от сложения а и b. Первое слагаемое – а, второе – b. а + b. А) при а = 8, b = 9; 8 + 9 = 17. Б) при а = 25, b = 36; 25 + 36 = 61. В) при а = 6974, b = 476; 6974 + 476 = 6974 + (26 + 450) = (6974 + 26) + 450 = 7000 + 450 = 7 450.', '<p>\nЗначение суммы от сложения а и b.<br/>\nПервое слагаемое – а, второе – b.<br/>\nа + b.<br/>\nА) при а = 8, b = 9;<br/>\n8 + 9 = 17.<br/>\nБ) при а = 25, b = 36;<br/>\n25 + 36 = 61.<br/>\nВ) при а = 6974, b = 476;<br/>\n6974 + 476 = 6974 + (26 + 450) = (6974 + 26) + 450 = 7000 + 450 = 7 450.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-53/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '85c439c1c03a964409b2a5d45706e3291198e8655ec2620cc0c9ac891f50457b', '8,9,25,36,476,6974', '["найди","раз"]'::jsonb, 'прочитай выражение а+b разными способами. найди его значение, если:а) а=8, b=9; б) а=25, b=36; в) а=6974, b=476');

    VALUES (v_textbook_id, 53, '6', 5, 'Прочитай выражение а – b разными способами. Найди его значение, если: А) а = 50; b = 3; Б) а = 81, b = 18; В) а = 7 000, b = 6942.', '</p>\n\n<p class="text">Прочитай выражение а – b разными способами. Найди его значение, если:<br/>\nА) а = 50; b = 3;<br/>\nБ) а = 81, b = 18;<br/>\nВ) а = 7 000, b = 6942.\n</p>', 'Значение разности от вычитания b из а. Уменьшаемое – а, вычитаемое – b. a – b. а) при а = 50; b = 3; 50 – 3 = 47. Б) при а = 81, b = 18; 81 – 18 = 63. В) при а = 7 000, b = 6942; 7 000 – 6 942 = 58.', '<p>\nЗначение разности от вычитания b из а.<br/>\nУменьшаемое – а, вычитаемое – b.<br/>\na – b.<br/>\nа) при а = 50; b = 3;<br/>\n50 – 3 = 47.<br/>\nБ) при а = 81, b = 18;<br/>\n81 – 18 = 63.<br/>\nВ) при а = 7 000, b = 6942;<br/>\n7 000 – 6 942 = 58.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-53/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '45630ef3f3028a800cec9941c3b502f24b9abfe4f0578ceba2cd960830e67210', '000,3,7,18,50,81,6942', '["найди","раз"]'::jsonb, 'прочитай выражение а-b разными способами. найди его значение, если:а) а=50; b=3; б) а=81, b=18; в) а=7 000, b=6942');

    VALUES (v_textbook_id, 53, '7', 6, 'Реши уравнения с комментированием и сделай проверку: 756 – х = 94; 251 + х = 1003; х – 384 = 675.', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:<br/>\n756 – х = 94;		<br/>\n251 + х = 1003;		<br/>	\nх – 384 = 675.\n\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica53-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 53, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 53, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-53/')
    RETURNING id INTO v_task_id;

