    VALUES (v_textbook_id, 53, '9', 8, 'За 3 дня турист прошел 52 км. В первый день он прошел 12 км, а во второй день – в 2 раза больше, чем в первый. Сколько километров прошел турист в третий день?', '</p>\n\n<p class="text">За 3 дня турист прошел 52 км. В первый день он прошел 12 км, а во второй день – в 2 раза больше, чем в первый. Сколько километров прошел турист в третий день?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica53-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 53, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 53, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-53/')
