    VALUES (v_textbook_id, 53, '11', 10, 'Какие даты в XXI веке можно записать с помощью лишь одной цифры в формате «День. Месяц. Две последние цфиры года» (например, 5.5.55 – 5 мая 2055 года)?', '</p>\n\n<p class="text">Какие даты в XXI веке можно записать с помощью лишь одной цифры в формате «День. Месяц. Две последние цфиры года» (например, 5.5.55 – 5 мая 2055 года)?\n</p>', '1.11.11 – 1 ноября 2011 года; 1.1.11 – 1 января 2011 года; 11.1.11 – 11 января 2011 года; 11.11.11 – 11 ноября 2011 года; 2.2.22 – 2 февраля 2022 года; 22.2.22 – 22 февраля 2022 года; 3.3.33 – 3 февраля 2033 года; 4.4.44 – 4 апреля 2044 года; 5.5.55 – 5 мая 2055 года; 6.6.66 – 6 июня 2066 года; 7.7.77 – 7 июля 2077 года; 8.8.88 – 8 августа 2088 года; 9.9.99 – 9 сентября 2099 года.', '<p>\n1.11.11 – 1 ноября 2011 года;<br/>\n1.1.11 – 1 января 2011 года;<br/>\n11.1.11 – 11 января 2011 года;<br/>\n11.11.11 – 11 ноября 2011 года;<br/>\n2.2.22 – 2 февраля 2022 года;<br/>\n22.2.22 – 22 февраля 2022 года;<br/>\n3.3.33 – 3 февраля 2033 года;<br/>\n4.4.44 – 4 апреля 2044 года;<br/>\n5.5.55 – 5 мая 2055 года;<br/>\n6.6.66 – 6 июня 2066 года;<br/>\n7.7.77 – 7 июля 2077 года;<br/>\n8.8.88 – 8 августа 2088 года;<br/>\n9.9.99 – 9 сентября 2099 года.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-53/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '66c6a863c8d25ff228a3d1055ddc821b4c9d4a8ae8e86cd0770178aa8b437f00', '5,55,2055', NULL, 'какие даты в xxi веке можно записать с помощью лишь одной цифры в формате "день. месяц. две последние цфиры года" (например, 5.5.55-5 мая 2055 года)');

    VALUES (v_textbook_id, 54, '1', 0, 'Прочитай, вставляя пропущенные числа: 1) Мы живём в … веке. 2) Я родился в … году … века. 3) Мне … лет. 4) Теперь идёт … год.', '</p>\n\n<p class="text">Прочитай, вставляя пропущенные числа:<br/>\n1) Мы живём в … веке.<br/>\n2) Я родился в … году … века.<br/>\n3) Мне … лет.<br/>\n4) Теперь идёт … год.\n</p>', '1) Мы живем в XXI веке. 2) Я родился в 2013 году. 3) Мне 10 лет. 4) Теперь идёт 2023 год..', '<p>\n1) Мы живем в XXI веке.<br/>\n2) Я родился в 2013 году.<br/>\n3) Мне 10 лет.<br/>\n4) Теперь идёт 2023 год..\n</p>', 'Таблица мер времени Век равен 100 годам, год равен 12 месяцам. Месяц содержит в себе 30 или 31 сутки (в феврале 28 или 29 суток). В простом году 365 суток, а в високосном – 366 суток. В неделе 7 дней: понедельник, вторник, среда, четверг, пятница, суббота, воскресенье. Неделей (не делать) в старину называли день отдыха. Первый день после недели был назван понедельником, второй – вторником, четвертый – четвергом, пятый – пятницей. Середина недели стала средой.', '<div class="recomended-block">\n<span class="title">Таблица мер времени</span>\n<p>\n<b class="black">Век</b> равен 100 годам, год равен 12 месяцам.<br/>\n<b class="black">Месяц</b> содержит в себе 30 или 31 сутки (в феврале 28 или 29 суток).<br/>\nВ простом году 365 суток, а в <b class="black">високосном</b> – 366 суток.<br/>\nВ <b class="black">неделе</b> 7 дней: понедельник, вторник, среда, четверг, пятница, суббота, воскресенье.<br/>\nНеделей (не делать) в старину называли день отдыха. Первый день после недели был назван понедельником, второй – вторником, четвертый – четвергом, пятый – пятницей. Середина недели стала средой.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-54/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'af89615aa31436d70873ce1fe7dd9efa34ccb48bf55f19972fc28e34861acb27', '1,2,3,4', NULL, 'прочитай, вставляя пропущенные числа:1) мы живём в ... веке. 2) я родился в ... году ... века. 3) мне ... лет. 4) теперь идёт ... год');

    VALUES (v_textbook_id, 54, '2', 1, 'А) Составь множество дней недели, которые начинаются с буквы «с». Б) Какой день недели следует за четвергом? Какой день недели предшествует вторнику?', '</p>\n\n<p class="text">А) Составь множество дней недели, которые начинаются с буквы «с».<br/>\nБ) Какой день недели следует за четвергом? Какой день недели предшествует вторнику?\n</p>', 'А) А – множество дней недели, название которых начинается с буквы «с». А : {среда, суббота}. Б) За четвергом следует пятница. Вторнику предшествует понедельник.', '<p>\nА) А – множество дней недели, название которых начинается с буквы «с».<br/>\nА : {среда, суббота}.<br/>\nБ) За четвергом следует пятница. Вторнику предшествует понедельник.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-54/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7d24e6d341ee29ce4987063553d7ff570f5c48e85cb680d9ed697a685574b239', NULL, NULL, 'а) составь множество дней недели, которые начинаются с буквы "с". б) какой день недели следует за четвергом? какой день недели предшествует вторнику');

    VALUES (v_textbook_id, 54, '3', 2, 'Расставь по порядку слова: сегодня, позавчера, завтра, вчера, послезавтра.', '</p>\n\n<p class="text">Расставь по порядку слова: сегодня, позавчера, завтра, вчера, послезавтра.\n</p>', 'Позавчера, вчера, сегодня, завтра, послезавтра.', '<p>\nПозавчера, вчера, сегодня, завтра, послезавтра.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-54/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'fe6002a1ebc2487a10746c71f114a07ab6751bbb9bbed9768f6adb2717dcc188', NULL, NULL, 'расставь по порядку слова:сегодня, позавчера, завтра, вчера, послезавтра');

    VALUES (v_textbook_id, 54, '4', 3, 'Игра «Кто ошибся?». Известно, что один из ребят ошибся. Кто это? Толя: сегодня суббота; Люда: вчера была пятница; Ваня: завтра воскресенье; Олег: позавчера была среда; Рита: послезавтра будет понедельник.', '</p>\n\n<p class="text">Игра «Кто ошибся?».<br/>\nИзвестно, что один из ребят ошибся. Кто это?<br/>\nТоля: сегодня суббота;<br/>\nЛюда: вчера была пятница;<br/>\nВаня: завтра воскресенье;<br/>\nОлег: позавчера была среда;<br/>\nРита: послезавтра будет понедельник.\n</p>', 'Условия, которые нам известны. Сегодня суббота, вчера была пятница, завтра воскресенье, позавчера была среда, послезавтра будет понедельник. Пусть правдиво высказывание «Завтра воскресенье». Тогда, сегодня суббота – истинна, вчера была пятница – истинна, послезавтра будет понедельник – истинна, а позавчера была среда – ложь. Ответ: ошибся Олег.', '<p>\nУсловия, которые нам известны.<br/>\nСегодня суббота, вчера была пятница, завтра воскресенье, позавчера была среда, послезавтра будет понедельник.<br/>\nПусть правдиво высказывание «Завтра воскресенье».<br/>\nТогда, сегодня суббота – истинна, вчера была пятница – истинна, послезавтра будет понедельник – истинна, а позавчера была среда – ложь.<br/>\nОтвет: ошибся Олег.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-54/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7ecab4371ba968335a5e3005a7ad54cbe2eb234eca331e85f2d362705f04baa2', NULL, NULL, 'игра "кто ошибся?". известно, что один из ребят ошибся. кто это? толя:сегодня суббота; люда:вчера была пятница; ваня:завтра воскресенье; олег:позавчера была среда; рита:послезавтра будет понедельник');

    VALUES (v_textbook_id, 55, '5', 0, 'Сколько полных недель в обычном году? В високосном году? Сколько дней при этом остаётся? (Под полной неделей здесь понимаются любые 7 дней, идущих подряд.)', '</p>\n\n<p class="text">Сколько полных недель в обычном году? В високосном году? Сколько дней при этом остаётся? (Под полной неделей здесь понимаются любые 7 дней, идущих подряд.)\n</p>', '365 : 7 = 52 полных недели в обычном году и остается 1 день. 366 : 7 = 52 полные недели в високосном году и остается 2 дня.', '<p>\n365 : 7 = 52 полных недели в обычном году и остается 1 день.<br/>\n366 : 7 = 52 полные недели в високосном году и остается 2 дня.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-55/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '30ed8d43bac4a1c67c105d26dcad0816702606b20bfa73134ebd389aa64f71d2', '7', NULL, 'сколько полных недель в обычном году? в високосном году? сколько дней при этом остаётся? (под полной неделей здесь понимаются любые 7 дней, идущих подряд.)');

    VALUES (v_textbook_id, 55, '6', 1, 'Назови, какой сейчас год. В какой день недели в этом году твой день рождения? Какие дни в марте этого года воскресные? На какие дни в июле приходится пятница?', '</p>\n\n<p class="text">Назови, какой сейчас  год. В какой день недели в этом году твой день рождения? Какие дни в марте этого года воскресные? На какие дни в июле приходится пятница?</p>', 'Сейчас 2023 год. Мой день рождения в этом году в четверг. В марте воскресенья 5, 12, 19 и 26 числа. Пятница приходится в июле на 7, 14, 21 и 28 числа.', '<p>\nСейчас 2023 год.<br/>\nМой день рождения в этом году в четверг.<br/>\nВ марте воскресенья 5, 12, 19 и 26 числа.<br/>\nПятница приходится в июле на 7, 14, 21 и 28 числа.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-55/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7a72386ea79c3edec6b7ac335ab2b73f0d83b3c9eea8c5142fa38984437fb414', NULL, NULL, 'назови, какой сейчас год. в какой день недели в этом году твой день рождения? какие дни в марте этого года воскресные? на какие дни в июле приходится пятница');

    VALUES (v_textbook_id, 55, '7', 2, 'Первая четверть начинается 1 сентября, а заканчивается 29 октября. Сколько дней оно длится? Сколько в этой четверти в 2014 году воскресений? Сколько учебных дней?', '</p>\n\n<p class="text">Первая четверть начинается 1 сентября, а заканчивается 29 октября. Сколько дней оно длится? Сколько в этой четверти в 2014 году воскресений? Сколько учебных дней?\n</p>', '30 дней + 29 дней = 59 дней – длится первая четверть. В 2014 году в этой четверти 8 воскресений, 42 учебных дня.', '<p>\n30 дней + 29 дней = 59 дней – длится первая четверть.<br/>\nВ 2014 году в этой четверти 8 воскресений, 42 учебных дня.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-55/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'a0c562a860692370391a5f68a6650882bb3e29fc12f75316b87f264738ff828e', '1,29,2014', NULL, 'первая четверть начинается 1 сентября, а заканчивается 29 октября. сколько дней оно длится? сколько в этой четверти в 2014 году воскресений? сколько учебных дней');

    VALUES (v_textbook_id, 55, '8', 3, 'Определи, какое число и месяц наступили, если от начала года прошло: А) 4 месяца; Б) 5 месяцев 10 дней; В) 87 дней; Г) 225 дней; Д) 328 дней? (Рассмотри год простой и високосный.)', '</p>\n\n<p class="text">Определи, какое число и месяц наступили, если от начала года прошло: <br/>\nА) 4 месяца; <br/>\nБ) 5 месяцев 10 дней; <br/>\nВ) 87 дней; <br/>\nГ) 225 дней; <br/>\nД) 328 дней? (Рассмотри год простой и високосный.)\n</p>', 'А) прошло 4 месяца – 1 мая. Б) 5 месяцев 10 дней – 11 июня. В) 87 дней – Простой год: 31 + 28 = 59 дней за январь и февраль, значит, 29 марта. ВИСОКОСНЫЙ ГОД: 31 + 29 = 60 дней за январь и февраль, значит, 28 марта. Г) 225 дней – ПРОСТОЙ ГОД: 31 + 28 + 31 + 30 + 31 + 30 + 31 = 212 дней за январь, февраль, март, апрель, май, июнь, июль, значит, 14 августа. ВИСОКОСНЫЙ ГОД: 31 + 29 + 31 + 30 + 31 + 30 + 31 = 13 августа. Д) 328 дней. Всего в простом году 365 дней, значит, 365 – 31 = 334. 334 – 328 = 6 дней не хватает до конца ноября, значит, 30 – 6 = 24, т.е. уже 25 ноября. Всего в високосном году 366 дней, значит, дней будет на 1 больше, чем в простом, а дата будет на 1 день меньше. Тогда, 24 ноября.', '<p>\nА) прошло 4 месяца – 1 мая.<br/>\nБ) 5 месяцев 10 дней – 11 июня.<br/>\nВ) 87 дней – Простой год: 31 + 28 = 59 дней за январь и февраль, значит, 29 марта. ВИСОКОСНЫЙ ГОД: 31 + 29 = 60 дней за январь и февраль, значит, 28 марта.<br/>\nГ) 225 дней – ПРОСТОЙ ГОД: 31 + 28 + 31 + 30 + 31 + 30 + 31 = 212 дней за январь, февраль, март, апрель, май, июнь, июль, значит, 14 августа. ВИСОКОСНЫЙ ГОД: 31 + 29 + 31 + 30 + 31 + 30 + 31 = 13 августа.<br/>\nД) 328 дней.<br/>\nВсего в простом году 365 дней, значит, 365 – 31 = 334. <br/>\n334 – 328 = 6 дней не хватает до конца ноября, значит, 30 – 6 = 24, т.е. уже 25 ноября.<br/>\nВсего в високосном году 366 дней, значит, дней будет на 1 больше, чем в простом, а дата будет на 1 день меньше. Тогда, 24 ноября.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-55/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'a3de694bae69f293f459d6535fdb7b386921b7d5a425d613f20f7c2e2367fc3f', '4,5,10,87,225,328', NULL, 'определи, какое число и месяц наступили, если от начала года прошло:а) 4 месяца; б) 5 месяцев 10 дней; в) 87 дней; г) 225 дней; д) 328 дней? (рассмотри год простой и високосный.)');

