    VALUES (v_textbook_id, 55, '10', 5, 'Придумай и нарисуй на клетчатой бумаге фигуру, имеющую: А) одну ось симметрии; Б) две оси симметрии; В) больше двух осей симметрии.', '</p>\n\n<p class="text">Придумай и нарисуй на клетчатой бумаге фигуру, имеющую: <br/>\nА) одну ось симметрии; <br/>\nБ) две оси симметрии; <br/>\nВ) больше двух осей симметрии.</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica55-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 55, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 55, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-55/')
