    VALUES (v_textbook_id, 55, '11', 6, 'Придумай задачи по схемам и составь выражения:', '</p>\n\n<p class="text">Придумай задачи по схемам и составь выражения:\n</p>', 'А) У Миши было а кубиков зеленого цвета и b кубиков красного цвета. Сколько всего кубов было у Миши? а + b (шт.) – кубиков было у Миши. Б) Бабушка закрутила а банок с вареньем из вишни, а банок варенья с клубникой на b банок больше. Сколько всего банок варенья было заготовлено? а + (a + b) (шт.) – банок было заготовлено . В) Папа закрутил всего a шуруп. Из них b вкручено в полки. Сколько шурупов потрачено для создания стола? a – b (шт.) – шурупов вкрутил папа в стол.', '<p>\nА) У Миши было а кубиков зеленого цвета и b кубиков красного цвета. Сколько всего кубов было у Миши?<br/>\nа + b (шт.) – кубиков было у Миши.<br/>\nБ) Бабушка закрутила а банок с вареньем из вишни, а банок варенья с клубникой на b банок больше. Сколько всего банок варенья было заготовлено?<br/>\nа + (a + b) (шт.) – банок было заготовлено<br/>.\nВ) Папа закрутил всего a шуруп. Из них b вкручено в полки. Сколько шурупов потрачено для создания стола?<br/>\na – b (шт.) – шурупов вкрутил папа в стол.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-55/')
    RETURNING id INTO v_task_id;

