    VALUES (v_textbook_id, 55, '14', 10, 'Перенеси в тетрадь и заполни таблицу:', '</p>\n\n<p class="text">Перенеси в тетрадь и заполни таблицу:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica55-nomer14.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 55, номер 14, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 55, номер 14, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica55-nomer14-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 55, номер 14-1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 55, номер 14-1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-55/')
