    VALUES (v_textbook_id, 55, '15', 11, 'В любом месяце есть 4 субботы. Но в некоторых месяцах суббот больше. Какое наибольшее число таких месяцев может быть в году?', '</p>\n\n<p class="text">В любом месяце есть 4 субботы. Но в некоторых месяцах суббот больше. Какое наибольшее число таких месяцев может быть в году?\n</p>', 'В году 365 дней, а каждая неделя – 7 дней. Значит, 365 : 7 = 52 недели (ост. 1 или 2, потому что может быть високосный год). Значит, суббота может быть 52 раза в год. За 12 месяцев по 4 субботы – 48 раз, т.е. 48 недель. Получается, 52 – 48 = 4 недели, в которых больше, чем 4 субботы. Их там 5. Ответ: 5 месяцев', '<p>\nВ году 365 дней, а каждая неделя – 7 дней. <br/>\nЗначит, 365 : 7 = 52 недели (ост. 1 или 2, потому что может быть високосный год).<br/>\nЗначит, суббота может быть 52 раза в год.<br/>\nЗа 12 месяцев по 4 субботы – 48 раз, т.е. 48 недель.<br/>\nПолучается, 52 – 48 = 4 недели, в которых больше, чем 4 субботы. Их там 5.<br/>\nОтвет: 5 месяцев\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-55/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '8f12ad0033b2bbdda6a249ec3329daa22c7d24980b3ccd4d5bdb168960293546', '4', '["больше"]'::jsonb, 'в любом месяце есть 4 субботы. но в некоторых месяцах суббот больше. какое наибольшее число таких месяцев может быть в году');

    VALUES (v_textbook_id, 56, '1', 0, 'А) Определи название месяца по порядковому номеру: II, IV, VII, IX, XII. Б) Какой порядковый номер имеют месяцы май, июль, ноябрь? Запиши их римскими цифрами.', '</p>\n\n<p class="text">\nА) Определи название месяца по порядковому номеру: II, IV, VII, IX, XII.<br/>\nБ) Какой порядковый номер имеют месяцы май, июль, ноябрь? Запиши их римскими цифрами.\n</p>', 'А) II – 2 – февраль; IV – 4 – апрель; VII – 7 – июль; IX – 9 – сентябрь; XII – 12 – декабрь. Б) Май – 5 – V; Июль – 7 – VII; Ноябрь – 11 – XI.', '<p>\nА) \nII – 2 – февраль;<br/>\nIV – 4 – апрель;<br/>\nVII – 7 – июль;<br/>\nIX – 9 – сентябрь;<br/>\nXII – 12 – декабрь.<br/>\n<br/>\nБ) <br/>\nМай – 5 – V;<br/>\nИюль – 7 – VII;<br/>\nНоябрь – 11 – XI.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-56/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '48457cc4e168b0f4dd392c358393954ed4d5135dd5f2c9083715d9717b4ef870', NULL, '["римск"]'::jsonb, 'а) определи название месяца по порядковому номеру:ii, iv, vii, ix, xii. б) какой порядковый номер имеют месяцы май, июль, ноябрь? запиши их римскими цифрами');

    VALUES (v_textbook_id, 56, '2', 1, 'А) Ира родилась 17 апреля 2006 года, а Даша – 23 июня того же года. Кто из них старше и на сколько? Вырази ответ в месяцах и днях. Б) Сева родился 14 мая 2009 года, а Гена на 2 года, 3 месяца и 8 дней младше Севы. Когда день рождения у Гены?', '</p>\n\n<p class="text">\nА) Ира родилась 17 апреля 2006 года, а Даша – 23 июня того же года. Кто из них старше и на сколько? Вырази ответ в месяцах и днях.<br/>\nБ) Сева родился 14 мая 2009 года, а Гена на 2 года, 3 месяца и 8 дней младше Севы. Когда день рождения у Гены?\n</p>', 'А) Так как июнь следует позже, чем апрель, то Даша младше Иры. Значит, Ира старше Даши на 13 + 31 + 23 = 67, т.е. 2 месяца и 7 дней. Б) Сева – 14 мая 2009 года. Гена на 2 года 3 месяца и 8 дней младше, т.е. позже. 22 августа 2011 года – день рождения Гены.', '<p>\nА) <br/>\nТак как июнь следует позже, чем апрель, то Даша младше Иры. Значит, Ира старше Даши на 13 + 31 + 23 = 67, т.е. 2 месяца и 7 дней.<br/>\nБ) <br/>\nСева – 14 мая 2009 года.<br/>\nГена на 2 года 3 месяца и 8 дней младше, т.е. позже.<br/>\n22 августа 2011 года – день рождения Гены.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-56/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '5edf9c6484c99af20d03a11668df4c3140441e34ebf8cc5ae0b4cfaa8942555c', '2,3,8,14,17,23,2006,2009', '["раз"]'::jsonb, 'а) ира родилась 17 апреля 2006 года, а даша-23 июня того же года. кто из них старше и на сколько? вырази ответ в месяцах и днях. б) сева родился 14 мая 2009 года, а гена на 2 года, 3 месяца и 8 дней младше севы. когда день рождения у гены');

    VALUES (v_textbook_id, 56, '3', 2, 'А) Олег старше Марины на 4 года и 2 дня. Марина родилась 1 января 2008 года. Когда родился Олег? Б) Маша младше Тани на 3 года, 2 месяца и 5 дней. Таня родилась 30 декабря 2007 года. Какой день рождения у Маши?', '</p>\n\n<p class="text">А) Олег старше Марины на 4 года и 2 дня. Марина родилась 1 января 2008 года. Когда родился Олег?<br/>\nБ) Маша младше Тани на 3 года, 2 месяца и 5 дней. Таня родилась 30 декабря 2007 года. Какой день рождения у Маши?\n</p>', 'А) Старше на 4 года и 2 дня, значит, родился раньше. Тогда, 1 января 2008 года – 4 года 2 дня = 30 декабря 2003 года. Б) Младше на 3 года 2 месяца и 5 дней, значит, родилась позже. Тогда, 30 декабря 2007 года + 3 года = 30 декабря 2010 года. 30 декабря 2007 года + 2 месяца = 2 марта 2011 года. 2 марта 2011 года + 5 дней = 7 марта 2011 года.', '<p>\nА) Старше на 4 года и 2 дня, значит, родился раньше. Тогда, 1 января 2008 года – 4 года 2 дня = 30 декабря 2003 года.<br/>\nБ) Младше на 3 года 2 месяца и 5 дней, значит, родилась позже. Тогда, 30 декабря 2007 года + 3 года = 30 декабря 2010 года.<br/>\n30 декабря 2007 года + 2 месяца = 2 марта 2011 года.<br/>\n2 марта 2011 года + 5 дней = 7 марта 2011 года.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-56/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ef91e32cf0c0dd5a62a9e1decea16d1eab02ecf8c0add57ff518e809b7cc847b', '1,2,3,4,5,30,2007,2008', NULL, 'а) олег старше марины на 4 года и 2 дня. марина родилась 1 января 2008 года. когда родился олег? б) маша младше тани на 3 года, 2 месяца и 5 дней. таня родилась 30 декабря 2007 года. какой день рождения у маши');

    VALUES (v_textbook_id, 56, '4', 3, 'А) Прочитай число: 37 208 056 914. Назови предшествующее и последующее числа. Б) Сколько классов и сколько разрядов в записи этого числа? Назови их. В) Какая цифра стоит в разряде единиц миллионов? Сколько всего миллионов в этом числе?', '</p>\n\n<p class="text">А) Прочитай число: 37 208 056 914. Назови предшествующее и последующее числа.<br/>\nБ) Сколько классов и сколько разрядов в записи этого числа? Назови их.<br/>\nВ) Какая цифра стоит в разряде единиц миллионов? Сколько всего миллионов в этом числе?\n</p>', 'А) Тридцать семь миллиардов двести восемь миллионов пятьдесят шесть тысяч девятьсот четырнадцать. Предшествующее число: 37 208 056 913 - тридцать семь миллиардов двести восемь миллионов пятьдесят шесть тысяч девятьсот тринадцать. Последующее число: 37 208 056 915 – тридцать семь миллиардов двести восемь миллионов пятьдесят шесть тысяч девятьсот пятнадцать. Б) в этом числе 4 класса и 11 разрядов: Единицы; Десятки; Тысячи; Единиц тысяч; Десятки тысяч; Сотни тысяч; Единицы миллионов; Десятки миллионов; Сотни миллионов; Единицы миллиардов; Десятки миллиардов. В) В разряде единиц миллионов стоит цифра 8. Всего в этом числе 208 миллионов.', '<p>\nА) <br/>\nТридцать семь миллиардов двести восемь миллионов пятьдесят шесть тысяч девятьсот четырнадцать.<br/>\nПредшествующее число: 37 208 056 913 - тридцать семь миллиардов двести восемь миллионов пятьдесят шесть тысяч девятьсот тринадцать.<br/>\nПоследующее число: 37 208 056 915 – тридцать семь миллиардов двести восемь миллионов пятьдесят шесть тысяч девятьсот пятнадцать.<br/>\n<br/>\nБ) <br/>\nв этом числе 4 класса и 11 разрядов:<br/>\nЕдиницы;<br/>\nДесятки;<br/>\nТысячи;<br/>\nЕдиниц тысяч;<br/>\nДесятки тысяч;<br/>\nСотни тысяч;<br/>\nЕдиницы миллионов;<br/>\nДесятки миллионов;<br/>\nСотни миллионов;<br/>\nЕдиницы миллиардов;<br/>\nДесятки миллиардов.<br/>\n<br/>\nВ) <br/>\nВ разряде единиц миллионов стоит цифра 8.<br/>\nВсего в этом числе 208 миллионов.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-56/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '63a86561afce349f5fc374792091787a292f34a418fc43825f520afa37721807', '37,056,208,914', '["раз"]'::jsonb, 'а) прочитай число:37 208 056 914. назови предшествующее и последующее числа. б) сколько классов и сколько разрядов в записи этого числа? назови их. в) какая цифра стоит в разряде единиц миллионов? сколько всего миллионов в этом числе');

    VALUES (v_textbook_id, 56, '5', 4, 'Запиши числа в виде суммы разрядных слагаемых: А) 5321; Б) 8020; В) 70 564.', '</p>\n\n<p class="text">\nЗапиши числа в виде суммы разрядных слагаемых:<br/>\nА) 5321; <br/>\nБ) 8020; <br/>\nВ) 70 564.\n</p>', 'А) 5 321 = 5000 + 300 + 20 + 1; Б) 8 020 = 8000 + 20; В) 70 564 = 70 000 + 500 + 60 + 4.', '<p>\nА) 5 321 = 5000 + 300 + 20 + 1;<br/>\nБ) 8 020 = 8000 + 20;<br/>\nВ) 70 564 = 70 000 + 500 + 60 + 4.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-56/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd72c9e9e233e1098503390337ba62352baf53d43e34f8053959348e071467d06', '70,564,5321,8020', '["раз"]'::jsonb, 'запиши числа в виде суммы разрядных слагаемых:а) 5321; б) 8020; в) 70 564');

    VALUES (v_textbook_id, 56, '6', 5, 'Вычисли суммы. Что ты замечаешь? 2000 + 400 + 30 + 1; 500 000 + 600 + 7; 40 000 + 8 000 + 90 + 5; 3 000 000 + 10 000 + 5 000 + 600.', '</p>\n\n<p class="text">\nВычисли суммы. Что ты замечаешь?<br/>\n2000 + 400 + 30 + 1;<br/>\n500 000 + 600 + 7;<br/>\n40 000 + 8 000 + 90 + 5;<br/>\n3 000 000 + 10 000 + 5 000 + 600.\n</p>', '2 000 + 400 + 30 = 1 = 2 431; 500 000 + 600 + 7 = 500 607; 40 000 + 8 000 + 90 + 5 = 48 095; 3 000 000 + 10 000 + 5 000 + 600 = 3 015 600. Числа представлены в виде суммы разрядных слагаемых.', '<p>\n2 000 + 400 + 30 = 1 = 2 431;<br/>\n500 000 + 600 + 7 = 500 607;<br/>\n40 000 + 8 000 + 90 + 5 = 48 095;<br/>\n3 000 000 + 10 000 + 5 000 + 600 = 3 015 600.<br/>\nЧисла представлены в виде суммы разрядных слагаемых.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-56/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4fa43dc1ab93f6983b1c65e723ab4075ac3af985e4089f96434bfcd6314b0d45', '000,1,3,5,7,8,10,30,40,90', '["вычисли"]'::jsonb, 'вычисли суммы. что ты замечаешь? 2000+400+30+1; 500 000+600+7; 40 000+8 000+90+5; 3 000 000+10 000+5 000+600');

    VALUES (v_textbook_id, 56, '7', 6, 'Определи порядок действий и назови последнее действие. Прочитай сначала суммы, а потом – разности: а : b – c; x + y ⋅ t; b ⋅ d + x : y; a : k – (c + d); (m – n) + a ⋅ d; k : b + (c – x).', '</p>\n\n<p class="text">Определи порядок действий и назови последнее действие. Прочитай сначала суммы, а потом –  разности:<br/>\nа : b – c;<br/>\nx + y ⋅ t;<br/>\nb ⋅ d + x : y;<br/>\na : k – (c + d);<br/>\n(m – n) + a ⋅ d;<br/>\nk : b + (c – x).\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica56-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 56, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 56, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-56/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica56-nomer7.jpg', 'peterson/3/part2/page56/task7_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'af2bcbdb0bb226a9f0dd3020be11de03046b407c4c95d6c1cbd004fddd0187d8', NULL, '["раз"]'::jsonb, 'определи порядок действий и назови последнее действие. прочитай сначала суммы, а потом-разности:а:b-c; x+y ⋅ t; b ⋅ d+x:y; a:k-(c+d); (m-n)+a ⋅ d; k:b+(c-x)');

    VALUES (v_textbook_id, 56, '8', 7, 'Измерь отрезки АВ и CD и вырази их длины: А) в сантиметрах и миллиметрах; Б) в миллиметрах.', '</p>\n\n<p class="text">\nИзмерь отрезки АВ и CD и вырази их длины:<br/> \nА) в сантиметрах и миллиметрах; <br/>\nБ) в миллиметрах.\n</p>', 'А) АВ = 3 см 1 мм; CD = 6 см 8 мм; Б) АВ = 3 см 1 мм = 30 мм + 1 мм = 31 мм; CD = 6 см 8 мм = 60 мм + 8 мм = 68 мм.', '<p>\nА) АВ = 3 см 1 мм; CD = 6 см 8 мм;<br/>\nБ) АВ = 3 см 1 мм = 30 мм + 1 мм = 31 мм; CD = 6 см 8 мм = 60 мм + 8 мм = 68 мм.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-56/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '8855b3a64531f65c4583c4e7558b7402aa263c8ff76ab119d09db64237fb5a95', NULL, '["раз"]'::jsonb, 'измерь отрезки ав и cd и вырази их длины:а) в сантиметрах и миллиметрах; б) в миллиметрах');

    VALUES (v_textbook_id, 57, '9', 0, 'Игорь болел а дней, а Сергей – b дней. Что означают выражения: a + b; b – a; b : а.', '</p>\n\n<p class="text">\nИгорь болел а дней, а Сергей – b дней. Что означают выражения:<br/>\na + b;<br/>\nb – a;<br/>\nb : а.\n</p>', 'а + b – общее количество дней, когда мальчики болели вместе. b – a – на сколько больше дней Сергей болел, чем Игорь. b : а – во сколько раз больше дней Сергей болел, чем Игорь.', '<p>\nа + b – общее количество дней, когда мальчики болели вместе.<br/>\nb – a – на сколько больше дней Сергей болел, чем Игорь.<br/>\nb : а – во сколько раз больше дней Сергей болел, чем Игорь.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-57/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'bd0ff82eb9709cc41891bc2935066b7f2ee51494da50421614d0e5e3204af0ce', NULL, NULL, 'игорь болел а дней, а сергей-b дней. что означают выражения:a+b; b-a; b:а');

    VALUES (v_textbook_id, 57, '10', 1, 'БЛИЦтурнир. А) Маша съела а слив, а Миша – b слив. Сколько слив съели они вместе? Б) Маша съела а слив, а Миша – b слив. На сколько больше слив съела Маша, чем Мша? В) Маша съела а слив, а Миша – b слив. Во сколько раз меньше слив съел Миша, чем Маша? Г) У Тани а орехов, а у Лены на b орехов больше. Сколько орехов у Лены? Д) у Тани а орехов, а у Лены на b орехов больше. Сколько орехов у Тани и Лены вместе? Е) У Тани а орехов. Это на b орехов меньше, чем у Лены. Во сколько раз больше орехов у Лены, чем у Тани?', '</p>\n\n<p class="text">\nБЛИЦтурнир.<br/>\nА) Маша съела а слив, а Миша – b слив.  Сколько слив съели они вместе?<br/>\nБ) Маша съела а слив, а Миша – b слив. На сколько больше слив съела Маша, чем Мша?<br/>\nВ) Маша съела а слив, а Миша – b слив. Во сколько раз меньше слив съел Миша, чем Маша?<br/>\nГ) У Тани а орехов, а у Лены на b орехов больше. Сколько орехов у Лены?<br/>\nД) у Тани а орехов, а у Лены на b орехов больше. Сколько орехов у Тани и Лены вместе?<br/>\nЕ) У Тани а орехов. Это на b орехов меньше, чем у Лены. Во сколько раз больше орехов у Лены, чем у Тани?\n</p>', 'А) а + b (шт.) – слив вместе; Б) а – b (шт.) – слив больше съела Маша, чем Миша; В) а : b (раз.) – больше слив съел Миша, чем Маша; Г) а + b (шт.) – орехов в Лены; Д) а + (а + b) (шт.) – орехов у Тани и Лены вместе; Е) (а + b) : а (раз.) – орехов больше у Лены, чем у Тани.', '<p>\nА) а + b (шт.) – слив вместе;<br/>\nБ) а – b (шт.) – слив больше съела Маша, чем Миша;<br/>\nВ) а : b (раз.) – больше слив съел Миша, чем Маша;<br/>\nГ) а + b (шт.) – орехов в Лены;<br/>\nД) а + (а + b) (шт.) – орехов у Тани и Лены вместе;<br/>\nЕ) (а + b) : а (раз.) – орехов больше у Лены, чем у Тани.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-57/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '8a038482d7a102d88a33f5ec3ae04b16f835aa36757d9510e1eb00456cf6a665', NULL, '["больше","меньше","раз"]'::jsonb, 'блицтурнир. а) маша съела а слив, а миша-b слив. сколько слив съели они вместе? б) маша съела а слив, а миша-b слив. на сколько больше слив съела маша, чем мша? в) маша съела а слив, а миша-b слив. во сколько раз меньше слив съел миша, чем маша? г) у тани а орехов, а у лены на b орехов больше. сколько орехов у лены? д) у тани а орехов, а у лены на b орехов больше. сколько орехов у тани и лены вместе? е) у тани а орехов. это на b орехов меньше, чем у лены. во сколько раз больше орехов у лены, чем у тани');

    VALUES (v_textbook_id, 57, '11', 2, 'Выполни действия и заполни таблицу в тетради. Расшифруй имя среднеазиатского математика и поэта, предложившего одну из самых интересных систем календарей. Найди информацию о нем.', '</p>\n\n<p class="text">Выполни действия и заполни таблицу в тетради. Расшифруй имя среднеазиатского математика и поэта, предложившего одну из самых интересных систем календарей. Найди информацию о нем.</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica57-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 57, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 57, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-57/')
    RETURNING id INTO v_task_id;

