    VALUES (v_task_id, v_textbook_id, 3, '02738df13a3bdd09df76f4c12a803a25267c88887ae212a68f05bd58b3c13f28', NULL, '["найди","заполни"]'::jsonb, 'выполни действия и заполни таблицу в тетради. расшифруй имя среднеазиатского математика и поэта, предложившего одну из самых интересных систем календарей. найди информацию о нем');

    VALUES (v_textbook_id, 57, '12', 3, 'Сложи 5 квадратов из 16 палочек. Переложи четыре палочки так, чтобы получилось 4 квадрата.', '</p>\n\n<p class="text">Сложи 5 квадратов из 16 палочек. Переложи четыре палочки так, чтобы получилось 4 квадрата.</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica57-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 57, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 57, номер 12, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-57/')
