    VALUES (v_task_id, v_textbook_id, 3, '90fb8b25bd37646826e948c1f809b36f2af606b41d52408f18f66fcf5d54b5e7', '4,5,16', '["сложи"]'::jsonb, 'сложи 5 квадратов из 16 палочек. переложи четыре палочки так, чтобы получилось 4 квадрата');

    VALUES (v_textbook_id, 58, '1', 0, 'Прочитай, вставляя пропущенные числа: 1) Первый урок в школе начинается в … часов … минут. 2) Сейчас … часов … минут. 3) В одном часе … минут. 4) В одной минуте … секунд.', '</p>\n\n<p class="text">\nПрочитай, вставляя пропущенные числа:<br/>\n1) Первый урок в школе начинается в … часов … минут.<br/>\n2) Сейчас … часов … минут.<br/>\n3) В одном часе … минут.<br/>\n4) В одной минуте … секунд.\n</p>', '1) Первый урок в школе начинается в 8 часов 30 минут. 2) Сейчас 20 часов 28 минут. 3) В одном часе 60 минут. 4) В одной минуте 60секунд.', '<p>\n1) Первый урок в школе начинается в 8 часов 30 минут.<br/>\n2) Сейчас 20 часов 28 минут.<br/>\n3) В одном часе 60 минут.<br/>\n4) В одной минуте 60секунд.\n</p>', 'Меры времени: час, минута, секунда в сутках сутках 24 часа в часе часе 60 минут в минуте минуте 60 секунд', '<div class="recomended-block">\n<span class="title">Меры времени: час, минута, секунда</span>\n<p>\nв <b class="black">сутках</b>сутках 24 часа<br/>\nв <b class="black">часе</b>часе 60 минут<br/>\nв <b class="black">минуте</b>минуте 60 секунд\n\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-58/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'bc449c7c4d1a9ef7149d2a40901e0ad286df4c14f9e4407cd7843eac2550cbc4', '1,2,3,4', NULL, 'прочитай, вставляя пропущенные числа:1) первый урок в школе начинается в ... часов ... минут. 2) сейчас ... часов ... минут. 3) в одном часе ... минут. 4) в одной минуте ... секунд');

    VALUES (v_textbook_id, 58, '2', 1, 'А) Сколько секунд в 2 минутах, в 10 минутах, в 1 часе? Б) Сколько минут составляют 120 с, 180 с, 360 с, 600 с?', '</p>\n\n<p class="text">\nА) Сколько секунд в 2 минутах, в 10 минутах, в 1 часе?<br/>\nБ) Сколько минут составляют 120 с, 180 с, 360 с, 600 с?\n</p>', 'А) 2 мин = 60 с ⋅ 2 = 120 с; 10 мин = 60 с ⋅ 10 = 600 с; 1 ч = 60 с ⋅ 60 мин = 3600 с. Б) 120 с = 120 с : 60 с = 2 мин; 180 с : 60 с = 3 мин; 360 с : 60 с = 6 мин; 600 с : 60 с = 10 мин.', '<p>\nА)<br/>\n2 мин = 60 с ⋅ 2 = 120 с;<br/>\n10 мин = 60 с ⋅ 10 = 600 с;<br/>\n1 ч = 60 с ⋅ 60 мин = 3600 с.<br/>\nБ)<br/>\n120 с = 120 с : 60 с = 2 мин;<br/>\n180 с : 60 с = 3 мин;<br/>\n360 с : 60 с = 6 мин;<br/>\n600 с : 60 с = 10 мин.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-58/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '890438dd91c928e966f86254b29d4ff827011847a42cf8be64092b53cde0dada', '1,2,10,120,180,360,600', NULL, 'а) сколько секунд в 2 минутах, в 10 минутах, в 1 часе? б) сколько минут составляют 120 с, 180 с, 360 с, 600 с');

    VALUES (v_textbook_id, 58, '3', 2, 'Сколько часов составляют: А) 2 суток 7 часов; Б) 3 суток 10 часов; В) 10 суток 15 часов; Г) 100 суток 6 часов?', '</p>\n\n<p class="text">\nСколько часов составляют: <br/>\nА) 2 суток 7 часов; <br/>\nБ) 3 суток 10 часов; <br/>\nВ) 10 суток 15 часов; <br/>\nГ) 100 суток 6 часов?\n</p>', 'А) 2 суток 7 часов = 24 ч * 2 + 7 = 48 + 7 = 56 ч; Б) 3 суток 10 часов = 24 ч * 3 + 10 = 72 + 10 = 82 ч; В) 10 суток 15 часов = 24 ч * 10 + 15 = 240 + 15 = 255 ч; Г) 100 суток 6 часов = 24 ч * 100 + 6 ч = 2400 ч + 6 ч = 2 406 ч.', '<p>\nА) 2 суток 7 часов = 24 ч * 2 + 7 = 48 + 7 = 56 ч;<br/>\nБ) 3 суток 10 часов = 24 ч * 3 + 10 = 72 + 10 = 82 ч;<br/>\nВ) 10 суток 15 часов = 24 ч * 10 + 15 = 240 + 15 = 255 ч;<br/>\nГ) 100 суток 6 часов = 24 ч * 100 + 6 ч = 2400 ч + 6 ч = 2 406 ч.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-58/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '904b996c253ff1dc405608be9832833fece3a17b26f73ee34c84200a49efede9', '2,3,6,7,10,15,100', NULL, 'сколько часов составляют:а) 2 суток 7 часов; б) 3 суток 10 часов; в) 10 суток 15 часов; г) 100 суток 6 часов');

    VALUES (v_textbook_id, 58, '4', 3, 'Сколько дыханий ты делаешь в течение 30 секунд? (проверь по часам.)', '</p>\n\n<p class="text">Сколько дыханий ты делаешь в течение 30 секунд? (проверь по часам.)\n</p>', '9 дыханий за 30 секунд.', '<p>\n9 дыханий за 30 секунд.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-58/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '25261e1c714372d78aba427e46d505159ad032e4ce29586bf560844aaedce08c', '30', NULL, 'сколько дыханий ты делаешь в течение 30 секунд? (проверь по часам.)');

    VALUES (v_textbook_id, 58, '5', 4, 'А) Сколько секунд длится урок (45 мин)? Б) Саша пришёл в школу в 8 часов, а ушёл в 12 часов. Сколько секунд он пробыл в школе?', '</p>\n\n<p class="text">\nА) Сколько секунд длится урок (45 мин)?<br/>\nБ) Саша пришёл в школу в 8 часов, а ушёл в 12 часов. Сколько секунд он пробыл в школе?\n</p>', 'А) 60 с ⋅ 45 = 2 700 с – длится урок. Б) 12 – 8 = 4 ч – Саша был в школе. 4 ч = 60 ⋅ 60 ⋅ 4 = 14 400 с – он пробыл в школе.', '<p>\nА) <br/>\n60 с ⋅ 45 = 2 700 с – длится урок.<br/>\n<br/>\nБ) <br/>\n12 – 8 = 4 ч – Саша был в школе.<br/>\n4 ч = 60 ⋅ 60 ⋅ 4 = 14 400 с – он пробыл в школе.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-58/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '78d8693e64e6d9eade8cedb391fbab330bdc9ab0ce9fe5ea4ba24ec5d0f89ead', '8,12,45', NULL, 'а) сколько секунд длится урок (45 мин)? б) саша пришёл в школу в 8 часов, а ушёл в 12 часов. сколько секунд он пробыл в школе');

    VALUES (v_textbook_id, 58, '6', 5, 'Время в течение суток показано на схеме: Определи с помощью этой схемы, как по-другому можно назвать: 13 ч, 3 ч дня, 16 ч 48 мин, 7 ч 15 мин вечера, 21 ч 10 мин? О каком времени говорят: полдень, полночь?', '</p>\n\n<p class="text">\nВремя в течение суток показано на схеме:<br/>\nОпредели с помощью этой схемы, как по-другому можно назвать: 13 ч, 3 ч дня, 16 ч 48 мин, 7 ч 15 мин вечера, 21 ч 10 мин? О каком времени говорят: полдень, полночь?\n</p>', '13 ч – 1 час дня; 3 ч – 3 часа дня, 3 часа ночи; 16 ч 48 мин – 4 часа вечера 48 минут; 7 ч 15 мин – 7 часов утра 15 минут, 7 часов вечера 15 минут; 21 ч 10 мин – 9 часов вечера; Полдень говорят о времени: 12 : 00; Полночь – о времени ночи: 00: 00 или 24 : 00.', '<p>\n13 ч – 1 час дня;<br/>\n3 ч – 3 часа дня, 3 часа ночи;<br/>\n16 ч 48 мин – 4 часа вечера 48 минут;<br/>\n7 ч 15 мин – 7 часов утра 15 минут, 7 часов вечера 15 минут;<br/>\n21 ч 10 мин – 9 часов вечера;<br/>\n<b class="black">Полдень</b> говорят о времени: 12 : 00;<br/>\n<b class="black">Полночь</b> – о времени ночи: 00: 00 или 24 : 00.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-58/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '2be45f2f136eec3d2b14c25d6670ef3f8f90a91c7f07b9cb259d241af4e9c624', '3,7,10,13,15,16,21,48', NULL, 'время в течение суток показано на схеме:определи с помощью этой схемы, как по-другому можно назвать:13 ч, 3 ч дня, 16 ч 48 мин, 7 ч 15 мин вечера, 21 ч 10 мин? о каком времени говорят:полдень, полночь');

    VALUES (v_textbook_id, 59, '7', 0, 'Сколько времени прошло: А) с 9 ч 05 мин до 13 ч 20 мин; Б) с 10 ч 45 мин утра до 7 ч 57 мин вечера; В) с 10 ч вечера до 7 ч утра; Г) с 21 ч 30 мин до 8 ч 45 мин следующего дня?', '</p>\n\n<p class="text">Сколько времени прошло:<br/>\nА) с 9 ч 05 мин до 13 ч 20 мин;<br/>\nБ) с 10 ч 45 мин утра до 7 ч 57 мин вечера;<br/>\nВ) с 10 ч вечера до 7 ч утра;<br/>\nГ) с 21 ч 30 мин до 8 ч 45 мин следующего дня?\n</p>', 'А) 13 ч 20 мин – 9 ч 05 мин = 4 ч 15 мин; Б) 19 ч 57 мин – 10 ч 45 мин = 9 ч 12 мин; В) 9 часов; Г) 2 ч 30 мин + 8 ч 45 мин = 11 ч 15 мин.', '<p>\nА) 13 ч 20 мин – 9 ч 05 мин = 4 ч 15 мин;<br/>\nБ) 19 ч 57 мин – 10 ч 45 мин = 9 ч 12 мин;<br/>\nВ) 9 часов;<br/>\nГ) 2 ч 30 мин + 8 ч 45 мин = 11 ч 15 мин.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-59/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '5b1d5fa8a4a600e23c4b02c045e28b5786802c8acd87af354a1c549dd459c735', '05,7,8,9,10,13,20,21,30,45', NULL, 'сколько времени прошло:а) с 9 ч 05 мин до 13 ч 20 мин; б) с 10 ч 45 мин утра до 7 ч 57 мин вечера; в) с 10 ч вечера до 7 ч утра; г) с 21 ч 30 мин до 8 ч 45 мин следующего дня');

    VALUES (v_textbook_id, 59, '8', 1, 'Если сейчас 6 часов 10 минут вечера 18 марта, то какое число и который час будет через: А) 5 ч 35 мин; Б) 20 ч 17 мин; В) 8 сут. 2 ч 48 мин; Г) 12 сут. 15 ч 36 мин?', '</p>\n\n<p class="text">Если сейчас 6 часов 10 минут вечера 18 марта, то какое число и который час будет через: <br/>\nА) 5 ч 35 мин; <br/>\nБ) 20 ч 17 мин; <br/>\nВ) 8 сут. 2 ч 48 мин; <br/>\nГ) 12 сут. 15 ч 36 мин?\n</p>', '6 ч 19 мин = 18 ч 19 мин; А) Через 5 ч 35 мин: 18 ч 19 мин + 5 ч 35 мин = 23 ч 54 минуты 18 марта; Б) Через 20 ч 17 мин: 18 ч 19 мин + (5 ч 41 мин + 14 ч 36 мин) = 14 ч 36 минут 19 марта; В) Через 8 сут. 2 ч 48 мин: 18 ч 19 мин + 2 ч 48 мин = 21 ч 7 мин 26 марта; Г) Через 12 сут. 5 ч 36 мин: 18 ч 19 мин + 15 ч 36 мин = 18 ч 19 мин + (5 ч 41 мин + 9 ч 55 мин) = 9 ч 55 мин 31 марта.', '<p></p>\n6 ч 19 мин = 18 ч 19 мин;<br/>\nА) Через 5 ч 35 мин: 18 ч 19 мин + 5 ч 35 мин = 23 ч 54 минуты 18 марта;<br/>\nБ) Через 20 ч 17 мин: 18 ч 19 мин + (5 ч 41 мин + 14 ч 36 мин) = 14 ч 36 минут 19 марта;<br/>\nВ) Через 8 сут. 2 ч 48 мин: 18 ч 19 мин + 2 ч 48 мин = 21 ч 7 мин 26 марта;<br/>\nГ) Через 12 сут. 5 ч 36 мин: 18 ч 19 мин + 15 ч 36 мин = 18 ч 19 мин + (5 ч 41 мин + 9 ч 55 мин) = 9 ч 55 мин 31 марта.\n<p></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-59/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '2a76afe5c62a6990d67d77ee05d622741850536ff8f4f5a8cb386aa292edbf17', '2,5,6,8,10,12,15,17,18,20', NULL, 'если сейчас 6 часов 10 минут вечера 18 марта, то какое число и который час будет через:а) 5 ч 35 мин; б) 20 ч 17 мин; в) 8 сут. 2 ч 48 мин; г) 12 сут. 15 ч 36 мин');

    VALUES (v_textbook_id, 59, '9', 2, 'Сравни в каждом равенстве натуральные числа, обозначенные буквами. Какое из них больше, а какое меньше? На сколько или во сколько раз? b = a + 7; x – y = 9; m – n = 5; c = d ⋅ 7; t : k = 9; p : s = 5.', '</p>\n\n<p class="text">Сравни в каждом равенстве натуральные числа, обозначенные буквами. Какое из них больше, а какое меньше? На сколько или во сколько раз?<br/>\nb = a + 7;<br/>\nx – y = 9;<br/>\nm – n = 5;<br/>\n<br/>\nc = d ⋅ 7;<br/>\nt : k = 9;<br/>\np : s = 5.\n</p>', 'b = a + 7, значит, а = b – 7, т.е. число а меньше b на 7 единиц. x – y = 9, значит, х = у + 9, т.е. число у на 9 меньше числа х. m – n = 5, значит, m = n + 5, т.е. число m на 5 единиц больше n. c = d ⋅ 7, значит, число с в 7 раз больше числа d. t : k = 9, значит, t = k * 9, т.е. число t в 9 раз больше числа k. p : s = 5, значит, р = s * 5, т.е. число р в 5 раз больше числа s.', '<p></p>\nb = a + 7, значит, а = b – 7, т.е. число а меньше 	b на 7 единиц.<br/>\nx – y = 9, значит, х = у + 9, т.е. число у на 9 меньше числа х.<br/>\nm – n = 5, значит, m = n + 5, т.е. число m на 5 единиц больше n.<br/>\n<br/>\nc = d ⋅ 7, значит, число с в 7 раз больше числа d.<br/>\nt : k = 9, значит, t = k * 9, т.е. число t в 9 раз больше числа k.<br/>\np : s = 5, значит, р = s * 5, т.е. число р в 5 раз больше числа s.\n<p></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-59/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1194239b88d656c946c8d5c1bbc7fcc95e00138e4ca80e91e4518b0bd457c16a', '5,7,9', '["сравни","больше","меньше","раз"]'::jsonb, 'сравни в каждом равенстве натуральные числа, обозначенные буквами. какое из них больше, а какое меньше? на сколько или во сколько раз? b=a+7; x-y=9; m-n=5; c=d ⋅ 7; t:k=9; p:s=5');

    VALUES (v_textbook_id, 59, '10', 3, 'Составь программу действий и вычисли: А) 900 ⋅ (148 + 752) – 7 ⋅ 6730 + 5 878; Б) 52 060 – 340 ⋅ 5 + 24 160 : (120 : 30) – 44 055.', '</p>\n\n<p class="text">\nСоставь программу действий и вычисли:<br/>\nА) 900 ⋅ (148 + 752) – 7 ⋅ 6730 + 5 878;<br/>\nБ) 52 060 – 340 ⋅ 5 + 24 160 : (120 : 30) – 44 055.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica59-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 59, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 59, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-59/')
    RETURNING id INTO v_task_id;

