    VALUES (v_task_id, v_textbook_id, 3, '291495c4d6fe9115b1292daba5c97dac630eb3e62f9baa287ad68aa15c22fcd1', '5,7,24,30,44,52,055,060,120,148', '["вычисли"]'::jsonb, 'составь программу действий и вычисли:а) 900 ⋅ (148+752)-7 ⋅ 6730+5 878; б) 52 060-340 ⋅ 5+24 160:(120:30)-44 055');

    VALUES (v_textbook_id, 59, '11', 4, 'Выполни деление с остатком и сделай проверку: 75 : 9; 750 : 90; 7500 : 900; 75 000 : 9 000.', '</p>\n\n<p class="text">\nВыполни деление с остатком и сделай проверку:<br/>\n75 : 9;<br/>\n750 : 90;<br/>\n7500 : 900;<br/>\n75 000 : 9 000.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica59-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 59, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 59, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-59/')
