    VALUES (v_textbook_id, 59, '12', 5, 'Мама заготовила на зиму варенье. Клубничного варенья было 12 л. Малинового – на 4 л меньше, чем клубничного. А яблочного – в 2 раза больше, чем клубничного и малинового вместе Сколько всего литров варенья заготовила мама на зиму?', '</p>\n\n<p class="text">Мама заготовила на зиму варенье. Клубничного варенья было 12 л. Малинового – на 4 л меньше, чем клубничного. А яблочного – в 2 раза больше, чем клубничного и малинового вместе Сколько всего литров варенья заготовила мама на зиму?</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica59-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 59, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 59, номер 12, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-59/')
