    VALUES (v_textbook_id, 59, '13', 6, 'Не вычисляя, расположи выражения в порядке возрастания их значений: А) 38 + 92, 38 + 102, 92 + 15, 45 + 164; Б) 74 – 25, 89 – 25, 74 – 40, 89 – 14.', '</p>\n\n<p class="text">\nНе вычисляя, расположи выражения в порядке возрастания их значений:<br/>\nА) 38 + 92, 38 + 102, 92 + 15, 45 + 164;<br/>\nБ) 74 – 25, 89 – 25, 74 – 40, 89 – 14.\n</p>', 'А) 92 + 15; 38 + 92; 38 + 102; 45 + 164. Б) 74 – 40; 74 – 25; 89 – 25; 89 – 14.', '<p>\nА) 92 + 15; 38 + 92; 38 + 102; 45 + 164.<br/>\nБ) 74 – 40; 74 – 25; 89 – 25; 89 – 14.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-59/')
    RETURNING id INTO v_task_id;

