    VALUES (v_textbook_id, 60, '1', 0, 'За какое время большая и маленькая стрелки пройдут расстояние между 2 большими штрихами; между 3 большими штрихами; между n большими штрихами, где n = 4, 6, 9, 12? За какое время каждая стрелка сделает полный оборот?', '</p>\n\n<p class="text">За какое время большая и маленькая стрелки пройдут расстояние между 2 большими штрихами; между 3 большими штрихами; между n большими штрихами, где n = 4, 6, 9, 12? За какое время каждая стрелка сделает полный оборот?\n</p>', 'Между 2 большими штрихами – 5 минут большая, 1 ч маленькая; Между 3 большими штрихами – 10 минут большая, 2 часа маленькая; n = 4; расстояние – 15 минут большая, 3 часа маленькая; n = 6; расстояние – 25 минут большая; 5 часов маленькая; n = 9; расстояние – 40 минут большая; 8 часов маленькая; n = 12; расстояние – 55 минут большая; 11 часов маленькая. полный оборот большая стрелка делает за 60 минут, а маленькая – за 12 часов.', '<p>\nМежду 2 большими штрихами – 5 минут большая, 1 ч маленькая;<br/>\nМежду 3 большими штрихами – 10 минут большая, 2 часа маленькая;<br/>\nn = 4; расстояние – 15 минут большая, 3 часа маленькая;<br/>\nn = 6; расстояние – 25 минут большая; 5 часов маленькая;<br/>\nn = 9; расстояние – 40 минут большая; 8 часов маленькая;<br/>\nn = 12; расстояние – 55 минут большая; 11 часов маленькая.<br/>\n<br/>\nполный оборот большая стрелка делает за 60 минут, а маленькая – за 12 часов.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-60/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4ece59d712364a56f7c1effb86d174212987f75ede2d24efabeb6bdd1d357126', '2,3,4,6,9,12', NULL, 'за какое время большая и маленькая стрелки пройдут расстояние между 2 большими штрихами; между 3 большими штрихами; между n большими штрихами, где n=4, 6, 9, 12? за какое время каждая стрелка сделает полный оборот');

    VALUES (v_textbook_id, 60, '2', 1, 'Покажи на модели часов, как будут стоять стрелки в указанное время: 4 ч 15 мин; 9 ч 48 мин; 15 ч 55 мин; 22 ч 10 мин.', '</p>\n\n<p class="text">\nПокажи на модели часов, как будут стоять стрелки в указанное время:<br/>\n4 ч 15 мин;<br/>\n9 ч 48 мин;<br/>\n15 ч 55 мин;<br/>\n22 ч 10 мин.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica60-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 60, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 60, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-60/')
    RETURNING id INTO v_task_id;

