    VALUES (v_task_id, v_textbook_id, 3, 'a94188103fea2caec52d04ff81a5c11559d9d42129aee26ce7b2e8eba5cefdf4', '4,9,10,15,22,48,55', NULL, 'покажи на модели часов, как будут стоять стрелки в указанное время:4 ч 15 мин; 9 ч 48 мин; 15 ч 55 мин; 22 ч 10 мин');

    VALUES (v_textbook_id, 61, '3', 0, 'Определи по рисункам, который час. Рассмотри два случая – до полудня и после полудня.', '</p>\n\n<p class="text">Определи по рисункам, который час. Рассмотри два случая – до полудня и после полудня.\n</p>', 'А) 8 : 00 или 20 : 00; Б) 01 : 10 или 13 : 10; В) 15 : 40 или 3 : 40; Г) 11 : 55 или 23 : 55.', '<p>\nА) 8 : 00 или 20 : 00;<br/>\nБ) 01 : 10 или 13 : 10;<br/>\nВ) 15 : 40 или 3 : 40;<br/>\nГ) 11 : 55 или 23 : 55.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-61/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '330bf54f17d26f7030fa53dd45882160b71c5a6c359eb7cdfcc4ba206570c3fa', NULL, NULL, 'определи по рисункам, который час. рассмотри два случая-до полудня и после полудня');

    VALUES (v_textbook_id, 61, '4', 1, 'Вместо «Сейчас 1 час 15 минут» можно сказать: «Сейчас 15 минут второго». А вместо «Сейчас 5 часов 40 минут» говорят: «Сейчас без двадцати шесть» (то есть до шести осталось 20 мин). Прочитай по-разному.', '</p>\n\n<p class="text">Вместо «Сейчас 1 час 15 минут» можно сказать: «Сейчас 15 минут второго». А вместо «Сейчас 5 часов 40 минут» говорят: «Сейчас без двадцати шесть» (то есть до шести осталось 20 мин). Прочитай по-разному.\n</p>', 'А) Двадцать минут девятого; Б) Без двадцати пяти минут десять; В) Пять минут шестого; Г) Половина третьего.', 'А) Двадцать минут девятого;<br/>\nБ) Без двадцати пяти минут десять;<br/>\nВ) Пять минут шестого;<br/>\nГ) Половина третьего.', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-61/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'dbaacb0d66f5beb0e18567fb111ff245ebe607132648315de2b022aaeb74f282', '1,5,15,20,40', '["раз"]'::jsonb, 'вместо "сейчас 1 час 15 минут" можно сказать:"сейчас 15 минут второго". а вместо "сейчас 5 часов 40 минут" говорят:"сейчас без двадцати шесть" (то есть до шести осталось 20 мин). прочитай по-разному');

    VALUES (v_textbook_id, 61, '5', 2, 'А) Как стоят стрелки в 12 часов? Куда передвинется часовая стрелка, если минутная сделает 3 полных оборота? Как будут расположены стрелки в это время? Б) Какой угол – прямой, острый или тупой – образуют стрелки часов, если сейчас: 2 ч; 4 ч; 5 ч; 7 ч; 11 ч; 9 ч.', '</p>\n\n<p class="text">\nА) Как стоят стрелки в 12 часов? Куда передвинется часовая стрелка, если минутная сделает 3 полных оборота? Как будут расположены стрелки в это время?<br/>\nБ) Какой угол – прямой, острый или тупой – образуют стрелки часов, если сейчас:<br/>\n2 ч;<br/>\n4 ч;<br/>\n5 ч;<br/>\n7 ч;<br/>\n11 ч;<br/>\n9 ч.\n</p>', 'А) В 12 часов стрелки направлены вверх и совпадают. Если минутная стрелка сделает 3 полных оборота, то пройдет 3 часа и часовая стрелка окажется на цифре 3. В это время минутная стрелка на 12, а часовая – на 3. Б) 2 часа – угол острый; 4 часа – угол тупой; 5 часов – угол тупой; 7 часов – угол тупой; 11 ч – угол острый; 9 ч – угол прямой.', '<p>\nА) В 12 часов стрелки направлены вверх и совпадают.<br/>\nЕсли минутная стрелка сделает 3 полных оборота, то пройдет 3 часа и часовая стрелка окажется на цифре 3.<br/>\nВ это время минутная стрелка на 12, а часовая – на 3.<br/>\nБ) 2 часа – угол острый;<br/>\n4 часа – угол тупой;<br/>\n5 часов – угол тупой;<br/>\n7 часов – угол тупой;<br/>\n11 ч – угол острый;<br/>\n9 ч – угол прямой.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-61/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '97b6b322469dae9840ec1e742e28f178b930b20669cc2e928ef95689e59d0bc3', '2,3,4,5,7,9,11,12', '["раз"]'::jsonb, 'а) как стоят стрелки в 12 часов? куда передвинется часовая стрелка, если минутная сделает 3 полных оборота? как будут расположены стрелки в это время? б) какой угол-прямой, острый или тупой-образуют стрелки часов, если сейчас:2 ч; 4 ч; 5 ч; 7 ч; 11 ч; 9 ч');

    VALUES (v_textbook_id, 62, '6', 0, 'Самолёт вылетел в 7 ч 35 мин утра, а прилетел через 10 ч 20 мин. В котором часу прилетел самолет?', '</p>\n\n<p class="text">Самолёт вылетел в 7 ч 35 мин утра, а прилетел через 10 ч 20 мин. В котором часу прилетел самолет?\n</p>', '7 ч 35 мин + 10 ч 20 мин = 17 ч 55 мин; Ответ: самолет прилетел в 17 ч 55 минут.', '<p>\n7 ч 35 мин + 10 ч 20 мин = 17 ч 55 мин;<br/>\nОтвет: самолет прилетел в 17 ч 55 минут.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-62/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6da77c5a27dcbcbf95a1400ee71f53575403496ab548aa81446219b7f41906d5', '7,10,20,35', NULL, 'самолёт вылетел в 7 ч 35 мин утра, а прилетел через 10 ч 20 мин. в котором часу прилетел самолет');

    VALUES (v_textbook_id, 62, '7', 1, 'Поезд вышел утром в 9 ч 18 мин, а прибыл на станцию назначения в 21 ч 56 мин. Сколько времени он был в пути?', '</p>\n\n<p class="text">Поезд вышел утром в 9 ч 18 мин, а прибыл на станцию назначения в 21 ч 56 мин. Сколько времени он был в пути?</p>', '21 ч 56 мин – 9 ч 18 мин = 12 ч 38 мин; Ответ: поезд был в пути 12 ч 38 минут.', '<p></p>\n21 ч 56 мин – 9 ч 18 мин = 12 ч 38 мин;<br/>\nОтвет: поезд был в пути 12 ч 38 минут.\n<p></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-62/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '2c875590c4b9de50fb897d338501b806b658dc15bb5693aebe8854f06d1c0260', '9,18,21,56', NULL, 'поезд вышел утром в 9 ч 18 мин, а прибыл на станцию назначения в 21 ч 56 мин. сколько времени он был в пути');

    VALUES (v_textbook_id, 62, '8', 2, 'Теплоход отплыл от поселка Ветрово в 9 ч 15 мин утра и плыл до пристани Макеевка 4 ч 20 мин. В Макеевке он простоял 12 мин, а на обратный путь в Ветров затратил 5 ч 10 мин. В котором часу теплоход вернулся обратно?', '</p>\n\n<p class="text">Теплоход отплыл от поселка Ветрово в 9 ч 15 мин утра и плыл до пристани Макеевка 4 ч 20 мин. В Макеевке он простоял 12 мин, а на обратный путь в Ветров затратил 5 ч 10 мин. В котором часу теплоход вернулся обратно?</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica62-nomer8_11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 62, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 62, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-62/')
    RETURNING id INTO v_task_id;

