    VALUES (v_task_id, v_textbook_id, 3, 'c7cae36a43db13f9f454d9503d06a3cd83563697e0d59b3d856d85d589d41261', '4,5,9,10,12,15,20', NULL, 'теплоход отплыл от поселка ветрово в 9 ч 15 мин утра и плыл до пристани макеевка 4 ч 20 мин. в макеевке он простоял 12 мин, а на обратный путь в ветров затратил 5 ч 10 мин. в котором часу теплоход вернулся обратно');

    VALUES (v_textbook_id, 62, '9', 3, 'А) Спектакль закончился в 9 ч 45 мин вечера. Когда он начался, если продолжался 2 ч 15 мин? Б) Сеанс кино начался в 11 ч 35 мин, а закончился в 13 ч 40 мин. Сколько времени он продолжался?', '</p>\n\n<p class="text">\nА) Спектакль закончился в 9 ч 45 мин вечера. Когда он начался, если продолжался 2 ч 15 мин?<br/>\nБ) Сеанс кино начался в 11 ч 35 мин, а закончился в 13 ч 40 мин. Сколько времени он продолжался?\n</p>', 'А) 9 ч 45 мин – 2 ч 15 мин = 7 ч 30 мин – время начала спектакля; Б) 13 ч 40 мин – 11 ч 35 мин = 2 ч 5 мин – длился сеанс кино.', '<p>\nА) 9 ч 45 мин – 2 ч 15 мин = 7 ч 30 мин – время начала спектакля;<br/>\nБ) 13 ч 40 мин – 11 ч 35 мин = 2 ч 5 мин – длился сеанс кино.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-62/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '16d10c4557a65d8fc31467a5b034c354fae0e53753176aff69129b18c5129b29', '2,9,11,13,15,35,40,45', NULL, 'а) спектакль закончился в 9 ч 45 мин вечера. когда он начался, если продолжался 2 ч 15 мин? б) сеанс кино начался в 11 ч 35 мин, а закончился в 13 ч 40 мин. сколько времени он продолжался');

    VALUES (v_textbook_id, 62, '10', 4, 'Сравни: 3 ч … 48 мин; 36 с … 7 мин; 1 ч 18 мин … 118 мин; 5 ч 6 мин … 56 мин; 2 мин 40 с … 200 с; 4 мин 5 с … 45 с.', '</p>\n\n<p class="text">\nСравни:<br/>\n3 ч … 48 мин;<br/>\n36 с … 7 мин;<br/>\n1 ч 18 мин … 118 мин;<br/>\n5 ч 6 мин … 56 мин;<br/>\n2 мин 40 с … 200 с;<br/>\n4 мин 5 с … 45 с.\n</p>', '3 ч > 48 мин, потому что 180 мин > 48 мин; 36 с < 7 мин, потому что 36 с < 420 c; 1 ч 18 мин < 118 мин, потому что 78 мин < 118 мин; 5 ч 6 мин > 56 мин, потому что 306 мин > 56 мин; 2 мин 40 с < 200 с, потому что 160 с < 200 c; 4 мин 5 с > 45 c, потому что 245 с > 45 с.', '<p>\n3 ч &gt; 48 мин, потому что 180 мин &gt; 48 мин;<br/>\n36 с &lt; 7 мин, потому что 36 с &lt; 420 c;<br/>\n1 ч 18 мин &lt; 118 мин, потому что 78 мин &lt; 118 мин;<br/>\n5 ч 6 мин &gt; 56 мин, потому что 306 мин &gt; 56 мин;<br/>\n2 мин 40 с &lt; 200 с, потому что 160 с &lt; 200 c;<br/>\n4 мин 5 с &gt; 45 c, потому что 245 с &gt; 45 с.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-62/')
    RETURNING id INTO v_task_id;

