    VALUES (v_textbook_id, 62, '14', 8, 'Найди «лишнюю» фигуру. По какому признаку она отличается от остальных?', '</p>\n\n<p class="text">Найди «лишнюю» фигуру. По какому признаку она отличается от остальных?\n</p>', 'Лишняя фигура – 5, потому что она отражена. Имеет форму отличную от прочих. А если первую фигуру всё время поворачивать по часовой стрелке, то получаются фигуры 2, 3, 4, 6.', '<p>\nЛишняя фигура – 5, потому что она отражена. Имеет форму отличную от прочих. А если первую фигуру всё время поворачивать по часовой стрелке, то получаются фигуры 2, 3, 4, 6.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-62/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'c9227adb3c9a8327a88b836b080dcde8b87b8461759cd01f5b58332c43bc1915', NULL, '["найди"]'::jsonb, 'найди "лишнюю" фигуру. по какому признаку она отличается от остальных');

    VALUES (v_textbook_id, 63, '1', 0, 'Вырази время в указанных единицах измерения: 5 ч = … мин; 8 мин = … с; 3 сут. 18 ч = … ч; 720 с = … мин; 4 ч 15 мин = … мин; 500 с = … мин … с.', '</p>\n\n<p class="text">Вырази время в указанных единицах измерения:<br/>\n5 ч = … мин;<br/>\n8 мин = … с;<br/>\n3 сут. 18 ч = … ч;<br/>\n720 с = … мин;<br/>\n4 ч 15 мин = … мин;<br/>\n500 с = … мин … с.\n</p>', '5 ч = 60 ⋅ 5 = 300 мин; 8 мин = 60 ⋅ 8 = 480 с; 3 сут 18 ч = 24 ⋅ 3 + 18 = 90 ч; 720 с = 720 : 60 = 12 мин; 4 ч 15 мин = 60 ⋅ 4 + 15 = 255 мин; 500 с = 8 мин 20 с.', '<p>\n5 ч = 60 ⋅ 5 = 300 мин;<br/>\n8 мин = 60 ⋅ 8 = 480 с;<br/>\n3 сут 18 ч = 24 ⋅ 3 + 18 = 90 ч;<br/>\n720 с = 720 : 60 = 12 мин;<br/>\n4 ч 15 мин = 60 ⋅ 4 + 15 = 255 мин;<br/>\n500 с = 8 мин 20 с.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-63/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1d05fb6220219830ff45872f35bb1364bd2fae748137cfb7443f2edc7174ecc5', '3,4,5,8,15,18,500,720', '["раз"]'::jsonb, 'вырази время в указанных единицах измерения:5 ч=... мин; 8 мин=... с; 3 сут. 18 ч=... ч; 720 с=... мин; 4 ч 15 мин=... мин; 500 с=... мин ... с');

    VALUES (v_textbook_id, 63, '2', 1, 'Определи по рисунку, который час. Найди разные варианты ответа. Рассмотри два случая – до полудня и после полудня.', '</p>\n\n<p class="text">Определи по рисунку, который час. Найди разные варианты ответа. Рассмотри два случая – до полудня и после полудня.\n</p>', 'А) 14 : 10 или 2 : 10; Б) 19 : 45 или 7 : 45; В) 9 : 30 или 21 : 30; Г) 11 : 50 или 23 : 50.', '<p>\nА) 14 : 10 или 2 : 10;<br/>\nБ) 19 : 45 или 7 : 45;<br/>\nВ) 9 : 30 или 21 : 30;<br/>\nГ) 11 : 50 или 23 : 50.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-63/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'b1e2cd5818c69b94e432f2a0cd7a8ecea92f78a623e8a231cb5b206eeb17a9e1', NULL, '["найди","раз"]'::jsonb, 'определи по рисунку, который час. найди разные варианты ответа. рассмотри два случая-до полудня и после полудня');

    VALUES (v_textbook_id, 63, '3', 2, 'Покажи на модели часов, как будут стоять стрелки в 8 ч 15 мин, 12 ч 40 мин, 16 ч, 19 ч 35 мин, 0 ч 20 мин? Прочитай это время разными способами.', '</p>\n\n<p class="text">Покажи на модели часов, как будут стоять стрелки в 8 ч 15 мин, 12 ч 40 мин, 16 ч, 19 ч 35 мин, 0 ч 20 мин? Прочитай это время разными способами.</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica63-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 63, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 63, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-63/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica63-nomer3.jpg', 'peterson/3/part2/page63/task3_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'd446231a4578a5765d2513864f7c99ddabb37a51981737f3742e74a16f19f0a3', '0,8,12,15,16,19,20,35,40', '["раз"]'::jsonb, 'покажи на модели часов, как будут стоять стрелки в 8 ч 15 мин, 12 ч 40 мин, 16 ч, 19 ч 35 мин, 0 ч 20 мин? прочитай это время разными способами');

    VALUES (v_textbook_id, 63, '4', 3, 'А) Маша вышла гулять в 14 ч 15 мин, а вернулась домой в 15 ч 40 мин. Сколько времени длилась её прогулка? Б) Спектакль в театре начался в 19 ч 39 мин и длился 3 ч 20 мин. В котором часу он закончился? В) Поезд «Сапсан» едет из Москвы в Санкт-Петербург 4 ч 30 мин. В котором часу он выехал из Москвы, если прибыл в Санкт-Петербург в 22 ч 40 мин?', '</p>\n\n<p class="text">\nА) Маша вышла гулять в 14 ч 15 мин, а вернулась домой в 15 ч 40 мин. Сколько времени длилась её прогулка?<br/>\nБ) Спектакль в театре начался в 19 ч 39 мин и длился 3 ч 20 мин. В котором часу он закончился?<br/>\nВ) Поезд «Сапсан» едет из Москвы в Санкт-Петербург 4 ч 30 мин. В котором часу он выехал из Москвы, если прибыл в Санкт-Петербург в 22 ч 40 мин?\n</p>', 'А) 15 ч 40 мин – 14 ч 15 мин = 1 ч 25 мин – длилась прогулка Маши; Б) 19 ч 39 мин + 3 ч 20 мин = 22 ч 59 мин – закончился спектакль; В) 22 ч 40 мин – 4 ч 30 мин = 18 ч 10 мин – Сапсан выехал из Москвы.', '<p>\nА) 15 ч 40 мин – 14 ч 15 мин = 1 ч 25 мин – длилась прогулка  Маши;<br/>\nБ) 19 ч 39 мин + 3 ч 20 мин = 22 ч 59 мин – закончился спектакль;<br/>\nВ) 22 ч 40 мин – 4 ч 30 мин = 18 ч 10 мин – Сапсан выехал из Москвы.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-63/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'e3d58d7b21c47e9e14bf530e3ebfa8987ec511318e5018019c7914cf0030d2e4', '3,4,14,15,19,20,22,30,39,40', NULL, 'а) маша вышла гулять в 14 ч 15 мин, а вернулась домой в 15 ч 40 мин. сколько времени длилась её прогулка? б) спектакль в театре начался в 19 ч 39 мин и длился 3 ч 20 мин. в котором часу он закончился? в) поезд "сапсан" едет из москвы в санкт-петербург 4 ч 30 мин. в котором часу он выехал из москвы, если прибыл в санкт-петербург в 22 ч 40 мин');

    VALUES (v_textbook_id, 63, '5', 4, '22 июня 1941 года немецко-фашисткие воска предательски напали на Советский Союз. 9 мая 1945 года Советский союз победил фашисткую Германию. Сколько дней продолжалась Великая отечественная война? (1944 год был високосным).', '</p>\n\n<p class="text">22 июня 1941 года немецко-фашисткие воска предательски напали на Советский Союз. 9 мая 1945 года Советский союз победил фашисткую Германию. Сколько дней продолжалась Великая отечественная война? (1944 год был високосным).\n</p>', '22 июня 1941 года – время начала войны. 1.Узнаю, сколько дней прошло до 1 января 1942 года: 9 + 31 + 31 + 30 + 31 + 30 + 31 = 8 + 60 + 124 = 193 дня до наступления 1942 года; 1942 год простой – 365 дней; 1943 год простой – 365 дней; 1944 год високосный – 366 дней. 2. Узнаю, сколько дней прошло от начала 1945 года до 9 мая: 31 + 28 + 31 + 30 + 9 = 40 + 61 + 28 = 129 дней до 9 мая. ИТОГО: 193 + 365 + 365 + 366 + 129 = 1418 дней; Ответ: война длилась 1418 дней.', '<p>\n22 июня 1941 года – время начала войны.<br/>\n<br/>\n1.Узнаю, сколько дней прошло до 1 января 1942 года:<br/>\n9 + 31 + 31 + 30 + 31 + 30 + 31 = 8 + 60 + 124 = 193 дня до наступления 1942 года;<br/>\n1942 год простой – 365 дней;<br/>\n1943 год простой – 365 дней;<br/>\n1944 год високосный – 366 дней.<br/>\n<br/>\n2. Узнаю, сколько дней прошло от начала 1945 года до 9 мая:<br/>\n31 + 28 + 31 + 30 + 9 = 40 + 61 + 28 = 129 дней до 9 мая.<br/>\n<br/>\nИТОГО: 193 + 365 + 365 + 366 + 129 = 1418 дней;<br/>\nОтвет: война длилась 1418 дней.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-63/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'f89fb0cb62e8ee013f91c18ecba01ad44f1e82c4a20eb4a4306c787cbb6460c4', '9,22,1941,1944,1945', NULL, '22 июня 1941 года немецко-фашисткие воска предательски напали на советский союз. 9 мая 1945 года советский союз победил фашисткую германию. сколько дней продолжалась великая отечественная война? (1944 год был високосным)');

    VALUES (v_textbook_id, 63, '6', 5, 'Битва на Курской дуге началась 5 июля 1943 года, а закончилась 23 августа того же года. Сколько дней длилась эта битва? Сколько дней прошло после Курского сражения до окончательной победы в Великов Отечественной войне (9 мая 1945 года)?', '</p>\n\n<p class="text">Битва на Курской дуге началась 5 июля 1943 года, а закончилась 23 августа того же года. Сколько дней длилась эта битва? Сколько дней прошло после Курского сражения до окончательной победы в Великов Отечественной войне (9 мая 1945 года)?\n</p>', '1. Определяю, сколько длилась битва на Курской дуге: 5 июля 1943 года – 23 августа 1943 года; 31 – 5 = 26 дней длилась битва в Июле; 23 дня длился битва в августе; Значит, 26 + 23 = 49 дней – длилась битва на Курской дуге. 2. Определяю, сколько дней прошло после сражения до победы: 23 августа 1943 – 9 мая 1945 года; 8 + 30 + 31 + 30 + 31 = 130 дней в 1943 году; 1944 год високосный – 366 дней; В 1945 году война длилась 129 дней (из задачи в номере 5). ИТОГО: 130 + 366 + 129 = 625 дней – прошло до окончания битвы до конца войны.', '<p>\n1. Определяю, сколько длилась битва на Курской дуге:<br/>\n5 июля 1943 года – 23 августа 1943 года;<br/>\n31 – 5 = 26 дней длилась битва в Июле;<br/>\n23 дня длился битва в августе;<br/>\nЗначит, 26 + 23 = 49 дней – длилась битва на Курской дуге.<br/>\n<br/>\n2. Определяю, сколько дней прошло после сражения до победы:<br/>\n23 августа 1943 – 9 мая 1945 года;<br/>\n8 + 30 + 31 + 30 + 31 = 130 дней в 1943 году;<br/>\n1944 год високосный – 366 дней;<br/>\nВ 1945 году война длилась 129 дней (из задачи в номере 5).<br/>\n<br/>\nИТОГО: 130 + 366 + 129 = 625 дней – прошло до окончания битвы до конца войны.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-63/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'eb6835459c1d4e461725a8e445ae24c5549da23b468e808f4c88666da4a49aa3', '5,9,23,1943,1945', NULL, 'битва на курской дуге началась 5 июля 1943 года, а закончилась 23 августа того же года. сколько дней длилась эта битва? сколько дней прошло после курского сражения до окончательной победы в великов отечественной войне (9 мая 1945 года)');

    VALUES (v_textbook_id, 63, '7', 6, 'Узнай дату начала и завершения какого-нибудь исторического события. Вычисли, сколько дней оно длилось.', '</p>\n\n<p class="text">Узнай дату начала и завершения какого-нибудь исторического события. Вычисли, сколько дней оно длилось.\n</p>', '24 июля – 11 августа 1938 г. – военный конфликт с Японией на оз. Хасан. В Июле конфликт длился 7 дней да еще в августе – 11 дней, значит: 7 + 11 = 18 дней – длился военный конфликт с Японией.', '<p>\n24 июля – 11 августа 1938 г. – военный конфликт с Японией на оз. Хасан.<br/>\nВ Июле конфликт длился 7 дней да еще в августе – 11 дней, значит: 7 + 11 = 18 дней – длился военный конфликт с Японией.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-63/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '2c95c93534988e32ab78e23c4b7decf0f16ea2dcfbe1ca1036e756dbeae73ffe', NULL, '["вычисли"]'::jsonb, 'узнай дату начала и завершения какого-нибудь исторического события. вычисли, сколько дней оно длилось');

