    VALUES (v_textbook_id, 64, '9', 1, 'Запиши число, которое: А) на 5 больше числа р; Б) на 5 меньше числа р; В) в 5 раз больше числа р; Г) в 5 раз меньше числа р.', '</p>\n\n<p class="text">Запиши число, которое: <br/>\nА) на 5 больше числа р;<br/>\nБ) на 5 меньше числа р;<br/>\nВ) в 5 раз больше числа р;<br/>\nГ) в 5 раз меньше числа р.\n</p>', 'А) р + 5; Б) р – 5; В) р ⋅ 5; Г) р : 5.', '<p>\nА) р + 5;<br/>\nБ) р – 5;<br/>\nВ) р ⋅ 5;<br/>\nГ) р : 5.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-64/')
