    VALUES (v_textbook_id, 64, '10', 2, 'Вычисли. Наложи прозрачную пленку и соедини ответы по порядку. Что получилось? 1.20 ⋅ 40; 2.800 ⋅ 4; 3.70 ⋅ 900; 4.5000 ⋅ 4; 5.4900 : 700; 6.360 : 60; 7.5600 : 8; 8.24 000 : 30.', '</p>\n\n<p class="text">\nВычисли. Наложи прозрачную пленку и соедини ответы по порядку. Что получилось?<br/>\n1.20 ⋅ 40;<br/>\n2.800 ⋅ 4;<br/>\n3.70 ⋅ 900;	<br/>\n4.5000 ⋅ 4;<br/>\n5.4900 : 700;<br/>\n6.360 : 60;<br/>\n7.5600 : 8;<br/>\n8.24 000 : 30.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica64-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 64, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 64, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-64/')
