    VALUES (v_textbook_id, 64, '11', 3, 'Составь и реши уравнения: А) на сколько надо разделить число 125 880, чтобы получить 6? Б) какое число надо разделить на число 900, чтобы получить 5097? В) какое число надо умножить на 50, чтобы получить 1 222 000?', '</p>\n\n<p class="text">\nСоставь и реши уравнения:<br/>\nА) на сколько надо разделить число 125 880, чтобы получить 6?<br/>\nБ) какое число надо разделить на число 900, чтобы получить 5097?<br/>\nВ) какое число надо умножить на 50, чтобы получить 1 222 000?\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica64-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 64, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 64, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-64/')
    RETURNING id INTO v_task_id;

