    VALUES (v_task_id, v_textbook_id, 3, '220c9444eff864b0597b682910c0b9c492085733b535cb05580f0edd0f21f2e7', '000,1,6,50,125,222,880,900,5097', '["раздели","реши","раз"]'::jsonb, 'составь и реши уравнения:а) на сколько надо разделить число 125 880, чтобы получить 6? б) какое число надо разделить на число 900, чтобы получить 5097? в) какое число надо умножить на 50, чтобы получить 1 222 000');

    VALUES (v_textbook_id, 64, '12', 4, 'Арифметический ребус. Мишу спросили: «Три да три да три – что будет?» Он ответил: «Дыра». Это записали так: ТРИ + ТРИ + ТРИ = ДЫРА. (одинаковые буквы обозначают одинаковые цифры, а разные буквы – разные цифры). Известно, что: (Ы + Ы) : Ы = Ы. Какие цифры зашифрованы в этой записи?', '</p>\n\n<p class="text">\nАрифметический ребус.<br/>\nМишу спросили: «Три да три да три – что  будет?»<br/>\nОн ответил: «Дыра». Это записали так:<br/>\nТРИ + ТРИ + ТРИ = ДЫРА.<br/>\n(одинаковые буквы обозначают одинаковые цифры, а разные буквы – разные цифры). Известно, что:<br/>\n(Ы + Ы) : Ы = Ы.<br/>\nКакие цифры зашифрованы в этой записи?\n</p>', 'Узнаю, чему равна Ы в выражении (ы + ы) : ы = ы. Она равна 2, потому что (2 + 2) : 2 = 2. Тогда, подставляем: ТРИ + ТРИ + ТРИ = Д2РА. Если оставить только первые буквы, то получится: Т + Т + Т = Д2, т.е. двузначное число с двойкой на конце. Это может быть число 4, потому что 4 + 4 + 4 = 12. Значит, Т = 4, Д = 1. Тогда подставляю: 4РИ + 4РИ + 4РИ = 12РА. Смотрим на букву Р и видим, что Р + Р + Р = Р, что возможно только при Р = 0, значит, Р = 0. 40И + 40И + 40И = 120А. И и А – это точно не 1, 2, 4, 0. Пусть это число 3. Тогда: 403 + 403 + 403 = 1209. Ответ: Т = 4, Р = 0, И = 3, А = 9.', '<p>\nУзнаю, чему равна Ы в выражении (ы + ы) : ы = ы.<br/>\nОна равна 2, потому что (2 + 2) : 2 = 2.<br/>\nТогда, подставляем:<br/>\nТРИ + ТРИ + ТРИ = Д2РА.<br/>\nЕсли оставить только первые буквы, то получится: Т + Т + Т = Д2, т.е. двузначное число с двойкой на конце.<br/>\nЭто может быть число 4, потому что 4 + 4 + 4 = 12.<br/>\nЗначит, Т = 4, Д = 1.<br/>\nТогда подставляю: 4РИ + 4РИ + 4РИ = 12РА.<br/>\nСмотрим на букву Р и видим, что Р + Р + Р = Р, что возможно только при Р = 0, значит, Р = 0.<br/>\n40И + 40И + 40И = 120А.<br/>\nИ и А – это точно не 1, 2, 4, 0.<br/>\nПусть это число 3. Тогда:<br/>\n403 + 403 + 403 = 1209.<br/>\n<br/>\nОтвет: Т = 4, Р = 0, И = 3, А = 9.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-64/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'a7dc0ce1a85b42f79debcc0ee4421fe286601a23ebe3e2b75118a71f12e7ea07', NULL, '["раз"]'::jsonb, 'арифметический ребус. мишу спросили:"три да три да три-что будет?" он ответил:"дыра". это записали так:три+три+три=дыра. (одинаковые буквы обозначают одинаковые цифры, а разные буквы-разные цифры). известно, что:(ы+ы):ы=ы. какие цифры зашифрованы в этой записи');

    VALUES (v_textbook_id, 65, '1', 0, 'Самолёт вылетел из Краснодара в Нижний Новгород в 9 ч 35 мин. Сколько времени он был в пути, если прибыл в Нижний Новгород в 11 ч 10 мин? Как выполнить переход через разряд в действиях с единицами времени?', '</p>\n\n<p class="text">Самолёт вылетел из Краснодара в Нижний Новгород в 9 ч 35 мин. Сколько времени он был в пути, если прибыл в Нижний Новгород в 11 ч 10 мин?\nКак выполнить переход через разряд в действиях с единицами времени?\n</p>', '11 ч 10 мин – 9 ч 35 мин; 11 ч 10 мин = 60 * 11 + 10 = 670 мин; 9 ч 35 мин = 60 * 9 + 35 = 575 мин; 670 – 575 = 95 (мин) = 1 ч 35 мин – в пути был самолёт; Ответ: 1 ч 35 минут', '<p>\n11 ч 10 мин – 9 ч 35 мин;\n11 ч 10 мин = 60 * 11 + 10 = 670 мин;\n9 ч 35 мин = 60 * 9 + 35 = 575 мин;\n670 – 575 = 95 (мин) = 1 ч 35 мин – в пути был самолёт;\nОтвет: 1 ч 35 минут\n</p>', 'Преобразование единиц времени В задачах часто бывает нужно преобразовать единицы времени. При переходе от одних единиц времени к другим надо помнить, что соотношения между ними не являются десятичными. Поэтому умножают и делят в данном случае не на 10, 100, 1000 и т.д., как обычно, а на 24, 60 и т.д. Примеры: 1) Выразить в часах 9 сут 14 ч. 9 сут 14 ч = 24 ч ⋅ 9 + 14 ч = 216 ч + 14 ч = 230 ч. 2) Выразить в минутах 19 ч 28 мин. 19 ч 28 мин = 60 мин ⋅ 19 + 28 мин = 1168 мин. 3) 17 ч 5 мин – 9 ч 30 мин = 16 ч 65 мин – 9 ч 30 мин = 7 ч 35 мин. 4) 5 ч 42 мин + 9 ч 36 мин = 15 ч 18 мин.', '<div class="recomended-block">\n<span class="title">Преобразование единиц времени</span>\n<p>\nВ задачах часто бывает нужно преобразовать единицы времени. При переходе от одних единиц времени к другим надо помнить, что соотношения между ними не являются десятичными.<br/>\nПоэтому умножают и делят в данном случае не на 10, 100, 1000 и т.д., как обычно, а на 24, 60 и т.д.<br/>\n<b class="black">Примеры:</b><br/>\n1) Выразить в часах 9 сут 14 ч.<br/>\n9 сут 14 ч = 24 ч ⋅ 9 + 14 ч = 216 ч + 14 ч = 230 ч.<br/>\n2) Выразить в минутах 19 ч 28 мин.<br/>\n19 ч 28 мин = 60 мин ⋅ 19 + 28 мин = 1168 мин.<br/>\n3) 17 ч 5 мин – 9 ч 30 мин = 16 ч 65 мин – 9 ч 30 мин = 7 ч 35 мин.<br/>\n4) 5 ч 42 мин + 9 ч 36 мин = 15 ч 18 мин.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-65/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1e7c41b6712368f7719203ca596f5bb6354898c7216336ed24f8122df80f033f', '9,10,11,35', '["раз"]'::jsonb, 'самолёт вылетел из краснодара в нижний новгород в 9 ч 35 мин. сколько времени он был в пути, если прибыл в нижний новгород в 11 ч 10 мин? как выполнить переход через разряд в действиях с единицами времени');

    VALUES (v_textbook_id, 66, '2', 0, 'А) Вырази в часах: 2 сут. 15 ч; 7 сут. 3 ч; 10 сут. 18 ч. Б) Вырази в минутах: 5 ч 38 мин; 8 ч 7 мин; 12 ч 42 мин. В) Вырази в секундах: 2 мин 8 с; 6 мин 24 с; 45 мин 36 с.', '</p>\n\n<p class="text">\nА) Вырази в часах: 2 сут. 15 ч; 7 сут. 3 ч; 10 сут. 18 ч.<br/>\nБ) Вырази в минутах: 5 ч 38 мин; 8 ч 7 мин; 12 ч 42 мин.<br/>\nВ) Вырази в секундах: 2 мин 8 с; 6 мин 24 с; 45 мин 36 с.\n</p>', 'А) В часах: 2 сут 15 ч = 24 ч ⋅ 2 + 15 ч = 48 ч + 15 ч = 63 ч; 7 сут 3 ч = 24 ⋅ 7 + 3 = 168 ч + 3 ч = 171 ч; 10 сут 18 ч = 24 ⋅ 10 + 18 = 258 ч. Б) в минутах: 5 ч 38 мин = 60 ⋅ 5 + 38 = 300 + 38 = 338 мин; 8 ч 7 мин = 60 ⋅ 8 + 7 = 480 + 7 = 487 мин; 12 ч 42 мин = 60 ⋅ 12 + 42 = 720 + 42 = 762 мин. В) в секундах: 2 мин 8 с = 60 ⋅ 2 + 8 = 120 + 8 = 128 с; 6 мин 24 с = 60 ⋅ 6 + 24 = 360 + 24 = 384 с; 45 мин 36 с = 60 ⋅ 45 + 36 = 2700 + 36 = 2 736 с.', '<p>\nА) В часах:<br/>\n2 сут 15 ч = 24 ч ⋅ 2 + 15 ч = 48 ч + 15 ч = 63 ч;<br/>\n7 сут 3 ч = 24 ⋅ 7 + 3 = 168 ч + 3 ч = 171 ч;<br/>\n10 сут 18 ч = 24 ⋅ 10 + 18 = 258 ч.<br/>\n<br/>\nБ) в минутах:<br/>\n5 ч 38 мин = 60 ⋅ 5 + 38 = 300 + 38 = 338 мин;<br/>\n8 ч 7 мин = 60 ⋅ 8 + 7 = 480 + 7 = 487 мин;<br/>\n12 ч 42 мин = 60 ⋅ 12 + 42 = 720 + 42 = 762 мин.<br/>\n<br/>\nВ) в секундах:<br/>\n2 мин 8 с = 60 ⋅ 2 + 8 = 120 + 8 = 128 с;<br/>\n6 мин 24 с = 60 ⋅ 6 + 24 = 360 + 24 = 384 с;<br/>\n45 мин 36 с = 60 ⋅ 45 + 36 = 2700 + 36 = 2 736 с.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-66/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '59dbdeb28b5c8fc88116695f43599586e5c5d1798d592c88f17c9d42d3d803ef', '2,3,5,6,7,8,10,12,15,18', '["раз"]'::jsonb, 'а) вырази в часах:2 сут. 15 ч; 7 сут. 3 ч; 10 сут. 18 ч. б) вырази в минутах:5 ч 38 мин; 8 ч 7 мин; 12 ч 42 мин. в) вырази в секундах:2 мин 8 с; 6 мин 24 с; 45 мин 36 с');

    VALUES (v_textbook_id, 66, '3', 1, 'Прочитай по-разному время на электронных часах: 14-23; 6-45; 19-54; 10-30.', '</p>\n\n<p class="text">\nПрочитай по-разному время на электронных часах:<br/>\n14-23;<br/>\n6-45;<br/>\n19-54;<br/>\n10-30.\n</p>', 'Двадцать три минуты третьего; четырнадцать двадцать три. Без пятнадцати минут семь; шесть сорок пять; сорок пять минут седьмого. Без шести минут восемь; девятнадцать пятьдесят четыре. Половина одиннадцатого; десять тридцать;', '<p>\nДвадцать три минуты третьего; четырнадцать двадцать три.<br/>\nБез пятнадцати минут семь; шесть сорок пять; сорок пять минут седьмого.<br/>\nБез шести минут восемь; девятнадцать пятьдесят четыре.<br/>\nПоловина одиннадцатого; десять тридцать; \n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-66/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1c4b737b15f5e469b39349fb0b07d6a7c6f0dfa389218c8f421415add7c4ebe2', '6,10,14,19,23,30,45,54', '["раз"]'::jsonb, 'прочитай по-разному время на электронных часах:14-23; 6-45; 19-54; 10-30');

    VALUES (v_textbook_id, 66, '4', 2, 'Сравни: 1 век … 360 лет; 1 год … 360 сут; 1 мес 7 сут … 27 сут; 1 сут. 20 ч … 120 ч; 4 мин 2 с … 42 с; 3 ч 5 мин … 35 мин.', '</p>\n\n<p class="text">\nСравни:<br/>\n1 век … 360 лет;<br/>\n1 год … 360 сут;<br/>\n1 мес 7 сут … 27 сут;<br/>\n1 сут. 20 ч … 120 ч;<br/>\n4 мин 2 с … 42 с;<br/>\n3 ч 5 мин … 35 мин.\n</p>', '1 век < 360 лет, потому что 100 лет < 360 лет; 1 год > 360 сут., потому что 365/366 сут. > 360 сут; 1 мес. 7 сут. > 27 сут., потому что 37 сут. > 27 сут; 1 сут. 20 ч < 120 ч, потому что 44 ч < 120 ч; 4 мин 2 с > 42 с, потому что 242 с > 42 с; 3 ч 5 мин > 35 мин, потому что 185 мин > 35 мин.', '<p>\n1 век &lt; 360 лет, потому что 100 лет &lt; 360 лет;<br/>\n1 год &gt; 360 сут., потому что 365/366 сут. &gt; 360 сут;<br/>\n1 мес. 7 сут. &gt; 27 сут., потому что 37 сут. &gt; 27 сут;<br/>\n1 сут. 20 ч &lt; 120 ч, потому что 44 ч &lt; 120 ч;<br/>\n4 мин 2 с &gt; 42 с, потому что 242 с  &gt; 42 с;<br/>\n3 ч 5 мин &gt; 35 мин, потому что 185 мин &gt; 35 мин.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-66/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'f68de0a74bf6d464ea8cb4f28c41b1485ccfabe964677f0daf7c5fc19a7418ce', '1,2,3,4,5,7,20,27,35,42', '["сравни"]'::jsonb, 'сравни:1 век ... 360 лет; 1 год ... 360 сут; 1 мес 7 сут ... 27 сут; 1 сут. 20 ч ... 120 ч; 4 мин 2 с ... 42 с; 3 ч 5 мин ... 35 мин');

    VALUES (v_textbook_id, 66, '5', 3, 'Выполни действия: А) 5 ч 28 мин – 2 ч 16 мин; Б) 14 мин 6 с + 7 мин 24 с; В) 3 сут – 1 сут 8 ч 57 мин; Г) 4 ч 53 мин + 1 ч 45 мин Д) 2 ч 42 мин : 3; Е) 7 мин 30 с ⋅ 8; Ж) 1 ч 21 мин 48 с : 4; З) 9 ч 36 мин ⋅ 5.', '</p>\n\n<p class="text">\nВыполни действия:<br/>\nА) 5 ч 28 мин – 2 ч 16 мин;<br/>\nБ) 14 мин 6 с + 7 мин 24 с;<br/>\nВ) 3 сут – 1 сут 8 ч 57 мин;<br/>\nГ) 4 ч 53 мин + 1 ч 45 мин\nД) 2 ч 42 мин : 3;<br/>\nЕ) 7 мин 30 с ⋅ 8;<br/>\nЖ) 1 ч 21 мин 48 с : 4;<br/>\nЗ) 9 ч 36 мин ⋅ 5.\n</p>', 'А) 5 ч 28 мин – 2 ч 16 мин = 3 ч 12 мин; Б) 14 мин 6 с + 7 мин 24 с = 21 мин 30 с; В) 3 сут – 1 сут 8 ч 57 мин = 2 сут 23 ч 60 мин – 1 сут 8 ч 57 мин = 1 сут 15 ч 3 мин; Г) 4 ч 53 мин + 1 ч 45 мин = 5 ч 98 мин = 6 ч 38 мин; Д) 2 ч 42 мин : 3 = (120 мин + 42 мин) : 3 = 162 мин : 3 = 54 мин; Е) 7 мин 30 с ⋅ 8 = (420 с + 30 с) ⋅ 8 = 450 с ⋅ 8 = 3600 с = 60 мин = 1 ч; Ж) 1 ч 21 мин 48 с : 4 = (3600 с + 1260 с + 48 с) : 4 = 1227 с; З) 9 ч 36 мин ⋅ 5 = (540 мин + 36 мин) ⋅ 5 = 2 880 мин = 48 ч = 2 сут.', '<p>\nА) 5 ч 28 мин – 2 ч 16 мин =  3 ч 12 мин;<br/>\nБ) 14 мин 6 с + 7 мин 24 с = 21 мин 30 с;<br/>\nВ) 3 сут – 1 сут 8 ч 57 мин = 2 сут 23 ч 60 мин – 1 сут 8 ч 57 мин = 1 сут 15 ч 3 мин;<br/>\nГ) 4 ч 53 мин + 1 ч 45 мин = 5 ч 98 мин = 6 ч 38 мин;<br/>\nД) 2 ч 42 мин : 3 = (120 мин + 42 мин) : 3 = 162 мин : 3 = 54 мин;<br/>\nЕ) 7 мин 30 с ⋅ 8 = (420 с + 30 с) ⋅ 8 = 450 с ⋅ 8 = 3600 с = 60 мин = 1 ч;<br/>\nЖ) 1 ч 21 мин 48 с : 4 = (3600 с + 1260 с + 48 с) : 4 = 1227 с;<br/>\nЗ) 9 ч 36 мин ⋅ 5 = (540 мин + 36 мин) ⋅ 5 = 2 880 мин = 48 ч = 2 сут.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-66/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '2de9599b46fb0750132b1bb538f988bac0a06cb28b2429259502404af842bcc6', '1,2,3,4,5,6,7,8,9,14', NULL, 'выполни действия:а) 5 ч 28 мин-2 ч 16 мин; б) 14 мин 6 с+7 мин 24 с; в) 3 сут-1 сут 8 ч 57 мин; г) 4 ч 53 мин+1 ч 45 мин д) 2 ч 42 мин:3; е) 7 мин 30 с ⋅ 8; ж) 1 ч 21 мин 48 с:4; з) 9 ч 36 мин ⋅ 5');

    VALUES (v_textbook_id, 66, '6', 4, 'Максим ушёл за грибами утром в 6 ч 40 мин, а вернулся только в 2 ч 15 мин дня. Сколько времени его не было дома?', '</p>\n\n<p class="text">\nМаксим ушёл за грибами утром в 6 ч 40 мин, а вернулся только в 2 ч 15 мин дня. Сколько времени его не было дома?\n</p>', 'Максим ушел за грибами в 6 ч 40 мин; Вернулся в 2 ч 15 минут дня или 14 ч 15 мин; Чтобы узнать, сколько времени Максим провел вне дома, вычитаю: 14 ч 15 мин – 6 ч 40 мин = 13 ч 75 мин – 6 ч 40 мин = 7 ч 35 мин – дома не было Максима. Ответ: 7 ч 35 минут.', '<p>\nМаксим ушел за грибами в 6 ч 40 мин;<br/>\nВернулся в 2 ч 15 минут дня или 14 ч 15 мин;<br/>\nЧтобы узнать, сколько времени Максим провел вне дома, вычитаю:<br/>\n14 ч 15 мин – 6 ч 40 мин = 13 ч 75 мин – 6 ч 40 мин = 7 ч 35 мин – дома не было Максима.<br/>\n<br/>\nОтвет: 7 ч 35 минут.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-66/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '5be0728cd7071a153934be2a642b8a3577af3dfe2b58025b14aba63d05000a6b', '2,6,15,40', NULL, 'максим ушёл за грибами утром в 6 ч 40 мин, а вернулся только в 2 ч 15 мин дня. сколько времени его не было дома');

    VALUES (v_textbook_id, 66, '7', 5, 'Соревнования по теннису закончились в 4 ч 10 мин дня. В котором часу они начались, если длились 5 ч 40 мин?', '</p>\n\n<p class="text">\nСоревнования по теннису закончились в 4 ч 10 мин дня. В котором часу они начались, если длились 5 ч 40 мин?\n</p>', 'Соревнования закончились в 4 ч 10 мин или иначе в 16 ч 10 мин. Значит, чтобы узнать, в котором часу начались соревнования, из времени окончания вычитаю длительность. Тогда, 16 ч 10 мин – 5 ч 40 мин = 15 ч 50 мин – 5 ч 40 мин = 10 ч 10 мин. Ответ: 10 ч 10 минут – время начала соревнований.', '<p>\nСоревнования закончились в 4 ч 10 мин или иначе в 16 ч 10 мин.<br/>\nЗначит, чтобы узнать, в котором часу начались соревнования, из времени окончания вычитаю длительность.<br/>\nТогда, 16 ч 10 мин – 5 ч 40 мин = 15 ч 50 мин – 5 ч 40 мин = 10 ч 10 мин.<br/>\nОтвет: 10 ч 10 минут – время начала соревнований.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-66/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'c760cd5dd82e0ace07606c1cbabc105cb92bf833eced2fb3ddb24df25dc18544', '4,5,10,40', NULL, 'соревнования по теннису закончились в 4 ч 10 мин дня. в котором часу они начались, если длились 5 ч 40 мин');

    VALUES (v_textbook_id, 66, '8', 6, 'Из Москвы в Сергиев Посад в 8 ч 30 мин утра выехал экскурсионный автобус. По расписанию автобус проезжает путь от Москвы до Сергиева посада за 2 ч 35 мин. Обратный путь занимает столько же времени. Экскурсия по Сергиеву посаду длится 5 ч 20 мин. В котором часу автобус должен вернуться в Москву?', '</p>\n\n<p class="text">\nИз Москвы в Сергиев Посад в 8 ч 30 мин утра выехал экскурсионный автобус. По расписанию автобус проезжает путь от Москвы до Сергиева посада за 2 ч 35 мин. Обратный путь занимает столько же времени. Экскурсия по Сергиеву посаду длится 5 ч 20 мин. В котором часу автобус должен вернуться в Москву?\n</p>', 'Автобус выехал в 8 ч 30 минут. Ехал 2 ч 35 мин. Экскурсия длилась 5 ч 20 мин. Автобус ехал обратно 2 ч 35 мин. Значит, чтобы узнать, в каком часу автобус вернется обратно, нужно все время сложить. 8 ч 30 мин + 2 ч 35 мин = 11 ч 5 мин – время прибытия в Сергиев Посад; 11 ч 5 мин + 5 ч 20 мин = 16 ч 25 мин – время окончания экскурсии; 16 ч 25 мин + 2 ч 35 мин = 19 ч – время прибытия в Москву. Значит, автобус вернется в Москву в 19 ч 00 мин.', '<p>\nАвтобус выехал в 8 ч 30 минут.<br/>\nЕхал 2 ч 35 мин.<br/>\nЭкскурсия длилась 5 ч 20 мин.<br/>\nАвтобус ехал обратно 2 ч 35 мин.<br/>\nЗначит, чтобы узнать, в каком часу автобус вернется обратно, нужно все время сложить.<br/>\n8 ч 30 мин + 2 ч 35 мин = 11 ч 5 мин – время прибытия в Сергиев Посад;<br/>\n11 ч 5 мин + 5 ч 20 мин = 16 ч 25 мин – время окончания экскурсии;<br/>\n16 ч 25 мин + 2 ч 35 мин = 19 ч – время прибытия в Москву.<br/>\nЗначит, автобус вернется в Москву в 19 ч 00 мин.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-66/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'eb5f2d5f10513e61db25fdb4fc7e7ba6f9618abca26e34b4188ebdea39a5445d', '2,5,8,20,30,35', NULL, 'из москвы в сергиев посад в 8 ч 30 мин утра выехал экскурсионный автобус. по расписанию автобус проезжает путь от москвы до сергиева посада за 2 ч 35 мин. обратный путь занимает столько же времени. экскурсия по сергиеву посаду длится 5 ч 20 мин. в котором часу автобус должен вернуться в москву');

    VALUES (v_textbook_id, 66, '9', 7, 'Составь программу действий и вычисли: А) (34 249 + 1 796) : 9 – (400 004 – 95 284) : 80; Б) 16 000 – (249 200 : 700 + 29 748) : 2 + 155 350 : 50.', '</p>\n\n<p class="text">\nСоставь программу действий и вычисли:<br/>\nА) (34 249 + 1 796) : 9 – (400 004 – 95 284) : 80;<br/>\nБ) 16 000 – (249 200 : 700 + 29 748) : 2 + 155 350 : 50.\n\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica66-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 66, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 66, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-66/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica66-nomer9.jpg', 'peterson/3/part2/page66/task9_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '2c59840b87232d4f585985ce7019601acadfb15bc8bde985efe2715b083e6934', '000,1,2,004,9,16,29,34,50,80', '["вычисли"]'::jsonb, 'составь программу действий и вычисли:а) (34 249+1 796):9-(400 004-95 284):80; б) 16 000-(249 200:700+29 748):2+155 350:50');

    VALUES (v_textbook_id, 66, '10', 8, 'Найди число, которое обладает следующими свойствами: оно нечётное, все цифры различные, сумма цифр равна 9, цифра десятков в 2 раза меньше цифры единиц тысяч.', '</p>\n\n<p class="text">\nНайди число, которое обладает следующими свойствами: оно нечётное, все цифры различные, сумма цифр равна 9, цифра десятков в 2 раза меньше цифры единиц тысяч.\n</p>', 'Свойства числа: 1) Нечетное, значит, оканчивается на 1, 3, 5, 7, 9; 2) Все цифры различные; 3) Сумма цифр равна 9; 4) Цифра десятков в 2 раза меньше цифры единиц тысяч. Так как по условию цифры десятков в 2 раза меньше цифры единиц тысяч, то это могут быть пары чисел 4 и 2 или 2 и 1 (6 и 3 не подходит, потому что сумма цифр уже равна 9, пары чисел 8 и 4 не подходят, потому что сумма уже больше 9). Значит, это могут быть числа с такими цифрами: 2 * 1 * или 4 * 2 * . Число нечетное, значит, оканчивается на 1, 3, 5, 7 или 9. 1 не подходит, потому что уже использована, может быть цифра 3. Цифр 5 и 7 не подходит, потому что сумма будет больше 9. Возможны такие варианты: 2 * 1 3, 2 * 1 5 или 4 * 2 1, 4 * 2 3. Вариант 2 * 1 3 не подходит, потому что оставшаяся цифра будет 3, а цифры повторяться не могут. Вариант 2 * 1 5 не подходит, потому что останется цифра 1, а повторяться не могут. Вариант 4 * 2 1 не подходит, потому что останется цифра 2, а она повторяться не может. Вариант 4 0 2 3 – подходит и соответствует условию. Ответ: число 4023.', '<p>\nСвойства числа:<br/>\n1) Нечетное, значит, оканчивается на 1, 3, 5, 7, 9;<br/>\n2) Все цифры различные;<br/>\n3) Сумма цифр равна 9;<br/>\n4) Цифра десятков в 2 раза меньше цифры единиц тысяч.<br/>\n\nТак как по условию цифры десятков в 2 раза меньше цифры единиц тысяч, то это могут быть пары чисел 4 и 2 или 2 и 1 (6 и 3 не подходит, потому что сумма цифр уже равна 9, пары чисел 8 и 4 не подходят, потому что сумма уже больше 9).<br/>\n<br/>\nЗначит, это могут быть числа с такими цифрами: 2 * 1 *  или 4 * 2 * .<br/>\nЧисло нечетное, значит, оканчивается на 1, 3, 5, 7 или 9. <br/>\n1 не подходит, потому что уже использована, может быть цифра 3. Цифр 5 и 7 не подходит, потому что сумма будет больше 9.<br/>\nВозможны такие варианты: 2 * 1 3, 2 * 1 5 или 4 * 2 1, 4 * 2 3.<br/>\nВариант 2 * 1 3 не подходит, потому что оставшаяся цифра будет 3, а цифры повторяться не могут.<br/>\nВариант 2 * 1 5 не подходит, потому что останется цифра 1, а повторяться не могут.<br/>\nВариант 4 * 2 1 не подходит, потому что останется цифра 2, а она повторяться не может.<br/>\nВариант 4 0 2 3 – подходит и соответствует условию.<br/>\n<br/>\nОтвет: число 4023.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-66/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '0d2d6b0c481915ca3252f4f20f6d9b5a4aabca4d8fb2287cb4c37dfbdb9ed9b4', '2,9', '["найди","сумма","меньше","раз","раза","чётн","нечётн"]'::jsonb, 'найди число, которое обладает следующими свойствами:оно нечётное, все цифры различные, сумма цифр равна 9, цифра десятков в 2 раза меньше цифры единиц тысяч');

    VALUES (v_textbook_id, 67, '1', 0, 'Вырази в указанных единицах измерения: 2 сут 7 ч 36 мин = … мин; 3 ч 24 мин 52 с = … с; 8 ч 31 мин 18 с = … с; 5 сут 16 ч 40 мин = … мин.', '</p>\n\n<p class="text">Вырази в указанных единицах измерения:<br/>\n2 сут 7 ч 36 мин = … мин;<br/>\n3 ч 24 мин 52 с = … с;<br/>\n8 ч 31 мин 18 с = … с;<br/>\n5 сут 16 ч 40 мин = … мин.\n</p>', '2 сут 7 ч 36 мин = 24 ⋅ 2 ⋅ 60 + 7 ⋅ 60 + 36 = 48 ⋅ 60 + 420 + 36 = 2 880 + 420 + 36 = 3 336 мин; 8 ч 31 мин 18 с = 8 ⋅ 60 ⋅ 60 + 31 ⋅ 60 + 18 = 28 800 с + 1 860 с + 18 с = 30 678 с; 3 ч 24 мин 52 с = 3 ⋅ 60 ⋅ 60 + 24 ⋅ 60 + 52 = 10 800 + 1 440 + 52 = 12 292 с; 5 сут 16 ч 40 мин = 5 ⋅ 24 ⋅ 60 + 16 ⋅ 60 + 40 = 7 200 + 960 + 40 = 8 200 мин.', '<p>\n2 сут 7 ч 36 мин = 24 ⋅ 2 ⋅ 60 + 7 ⋅ 60 + 36 = 48 ⋅ 60 + 420 + 36 = 2 880 + 420 + 36 = 3 336 мин;<br/>\n8 ч 31 мин 18 с = 8 ⋅ 60 ⋅ 60 + 31 ⋅ 60 + 18 = 28 800 с + 1 860 с + 18 с = 30 678 с;<br/>\n3 ч 24 мин 52 с = 3 ⋅ 60 ⋅ 60 + 24 ⋅ 60 + 52 = 10 800 + 1 440 + 52 = 12 292 с;<br/>\n5 сут 16 ч 40 мин = 5 ⋅ 24 ⋅ 60 + 16 ⋅ 60 + 40 = 7 200 + 960 + 40 = 8 200 мин.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-67/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4d3ffc167accea3c70c52de7c10304ab56449c8376f20b24befe92d9e35dc1f0', '2,3,5,7,8,16,18,24,31,36', '["раз"]'::jsonb, 'вырази в указанных единицах измерения:2 сут 7 ч 36 мин=... мин; 3 ч 24 мин 52 с=... с; 8 ч 31 мин 18 с=... с; 5 сут 16 ч 40 мин=... мин');

    VALUES (v_textbook_id, 67, '2', 1, 'Сравни: 5 мин 6 с … 56 с; 123 мин … 1 ч 23 мин; 4 сут 3 ч … 43 ч; 214 с … 2 ч 52 с; 9 ч 20 мин … 560 мин; 100 ч … 3 сут. 15 ч.', '</p>\n\n\n<p class="text">Сравни:<br/>\n5 мин 6 с … 56 с;<br/>\n123 мин … 1 ч 23 мин;<br/>\n4 сут 3 ч … 43 ч;<br/>\n<br/>\n214 с … 2 ч 52 с;<br/>\n9 ч 20 мин … 560 мин;<br/>\n100 ч … 3 сут. 15 ч.\n</p>', '5 мин 6 с > 56 с, потому что 306 с > 56 c; 123мин > 1 ч 23 мин, потому что 123 мин > 83 мин; 4 сут 3 ч > 43 ч, потому что 99 ч > 43 ч; 214 с < 2 ч 52 с, потому что 3 мин 34 с < 2 ч 52 с; 9 ч 20 мин = 560 мин, потому что 560 мин = 560 мин; 100 ч > 3 сут 15 ч, потому что 100 ч > 87 ч.', '<p>\n5 мин 6 с &gt; 56 с, потому что 306 с &gt; 56 c;<br/>\n123мин &gt; 1 ч 23 мин, потому что 123 мин &gt; 83 мин;<br/>\n4 сут 3 ч &gt; 43 ч, потому что 99 ч &gt; 43 ч;<br/>\n<br/>\n214 с &lt; 2 ч 52 с, потому что 3 мин 34 с &lt; 2 ч 52 с;<br/>\n9 ч 20 мин = 560 мин, потому что 560 мин = 560 мин;<br/>\n100 ч &gt; 3 сут 15 ч, потому что 100 ч &gt; 87 ч.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-67/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'a35c7a680087186130e5c4516fbfe60caa79dd0c2ca8da8e513f1f0edbcc9739', '1,2,3,4,5,6,9,15,20,23', '["сравни"]'::jsonb, 'сравни:5 мин 6 с ... 56 с; 123 мин ... 1 ч 23 мин; 4 сут 3 ч ... 43 ч; 214 с ... 2 ч 52 с; 9 ч 20 мин ... 560 мин; 100 ч ... 3 сут. 15 ч');

    VALUES (v_textbook_id, 67, '3', 2, 'Выполни действия: А) 2 мин 43 с + 6 мин 17 с; Б) 3 ч – 1 ч 33 мин; В) 4 ч 6 мин – 2 ч 12 мин + 5 ч 38 мин; Г) 9 мин 41 с – 6 мин 43 с + 1 мин 35 с.', '</p>\n\n<p class="text">Выполни действия:<br/>\nА) 2 мин 43 с + 6 мин 17 с;<br/>\nБ) 3 ч – 1 ч 33 мин;<br/>\nВ) 4 ч 6 мин – 2 ч 12 мин + 5 ч 38 мин;<br/>\nГ) 9 мин 41 с – 6 мин 43 с + 1 мин 35 с.\n</p>', 'А) 2 мин 43 с + 6 мин 17 с = 8 мин 60 с = 9 мин; Б) 3 ч – 1 ч 33 мин = 2 ч 60 мин – 1 ч 33 мин = 1 ч 27 мин; В) 4 ч 6 мин – 2 ч 12 мин + 5 ч 38 мин = 3 ч 66 мин – 2 ч 12 мин + 5 ч 38 мин = 1 ч 54 мин + 5 ч 38 мин = 6 ч 92 мин = 7 ч 32 мин; Г) 9 мин 41 с – 6 мин 43 с + 1 мин 35 с = 8 мин 101 с – 6 мин 43 с + 1 мин 35 с = 2 мин 58 с + 1 мин 35 с = 3 мин 93 с = 4 мин 33 с.', '<p>\nА) 2 мин 43 с + 6 мин 17 с = 8 мин 60 с = 9 мин;<br/>\nБ) 3 ч – 1 ч 33 мин = 2 ч 60 мин – 1 ч 33 мин = 1 ч 27 мин;<br/>\nВ) 4 ч 6 мин – 2 ч 12 мин + 5 ч 38 мин = 3 ч 66 мин – 2 ч 12 мин + 5 ч 38 мин = 1 ч 54 мин + 5 ч 38 мин = 6 ч 92 мин = 7 ч 32 мин;<br/>\nГ) 9 мин 41 с – 6 мин 43 с + 1 мин 35 с = 8 мин 101 с – 6 мин 43 с + 1 мин 35 с = 2 мин 58 с + 1 мин 35 с = 3 мин 93 с = 4 мин 33 с.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-67/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '51346ee7285af95df2705d1d3b9a7db593c0dceece421d26396b2ed1d93d6540', '1,2,3,4,5,6,9,12,17,33', NULL, 'выполни действия:а) 2 мин 43 с+6 мин 17 с; б) 3 ч-1 ч 33 мин; в) 4 ч 6 мин-2 ч 12 мин+5 ч 38 мин; г) 9 мин 41 с-6 мин 43 с+1 мин 35 с');

    VALUES (v_textbook_id, 67, '4', 3, 'Надя младше Кости на 5 лет 6 месяцев и 8 дней. День рождения Кости 14 апреля 2003 года. Когда день рождения Нади?', '</p>\n\n<p class="text">\nНадя младше Кости на 5 лет 6 месяцев и 8 дней. День рождения Кости 14 апреля 2003 года. Когда день рождения Нади?\n</p>', 'Костя родился 14 апреля 2003 года, а Надя младше его, т.е. она родилась позже на 5 лет 6 месяцев и 8 дней. Значит, через 5 лет будет: 14 апреля 2008 года. Значит, через 6 месяцев будет: 14 октября 2008 года. Тогда, через 8 дней будет: 22 октября 2008 года. Ответ: Надя родилась 22 октября 2008 года.', '<p>\nКостя родился 14 апреля 2003 года, а Надя младше его, т.е. она родилась позже на 5 лет 6 месяцев и 8 дней.<br/>\nЗначит, через 5 лет будет: 14 апреля 2008 года.<br/>\nЗначит, через 6 месяцев будет: 14 октября 2008 года.<br/>\nТогда, через 8 дней будет: 22 октября 2008 года.<br/>\nОтвет: Надя родилась 22 октября 2008 года.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-67/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '9ffb2c43cf9867cdd1b9a9e9fdc9b5791efd386b33b11d5ad959745f871a6d43', '5,6,8,14,2003', NULL, 'надя младше кости на 5 лет 6 месяцев и 8 дней. день рождения кости 14 апреля 2003 года. когда день рождения нади');

