    VALUES (v_textbook_id, 67, '6', 5, 'Умный муравей решил построить себе дом на прямоугольном участке земли со сторонами 8 дм и 5 дм. Чему равна площадь его участка? Какой длины забор должен он себе сделать?', '</p>\n\n<p class="text">Умный муравей решил построить себе дом на прямоугольном участке земли со сторонами 8 дм и 5 дм. Чему равна площадь его участка? Какой длины забор должен он себе сделать?</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica67-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 67, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 67, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-67/')
