    VALUES (v_textbook_id, 67, '7', 6, 'Найди значение х, пользуясь графической моделью:', '</p>\n\n<p class="text">Найди значение х, пользуясь графической моделью:</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica67-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 67, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 67, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-67/')
