    VALUES (v_task_id, v_textbook_id, 3, '99c544330f248c1584d578729c7d367b0abc261c9737ce356f71345300d5d607', NULL, '["найди"]'::jsonb, 'найди значение х, пользуясь графической моделью');

    VALUES (v_textbook_id, 67, '8', 7, 'Реши уравнения с комментированием и сделай проверку: Х ⋅ 80 = 640; 4200 : х = 6; х : 50 = 500.', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:\nХ ⋅ 80 = 640;<br/>\n4200 : х = 6;<br/>\nх : 50 = 500.\n</p>', 'х ⋅ 80 = 640; х = 640 : 80; х = 8. Проверка: 8 ⋅ 80 = 640; 640 = 640; Ответ: х = 8. 4200 : х = 6; х = 4200 : 6; х = 700. Проверка: 4200 : 700 = 6; 6 = 6; Ответ: х = 700. х : 50 = 500; х = 500 ⋅ 50; х = 25 000. Проверка: 25 000 : 50 = 500; 500 = 500; Ответ: х = 25 000.', '<p>\nх ⋅ 80 = 640;<br/>\nх = 640 : 80;<br/>\nх = 8.<br/>\n<br/>\nПроверка:<br/>\n8 ⋅ 80 = 640;<br/>\n640 = 640;<br/>\nОтвет: х = 8.<br/>\n<br/>\n4200 : х = 6;<br/>\nх = 4200 : 6;<br/>\nх = 700.<br/>\n<br/>\nПроверка:<br/>\n4200 : 700 = 6;<br/>\n6 = 6;<br/>\nОтвет: х = 700.<br/>\n<br/>\nх : 50 = 500;<br/>\nх = 500 ⋅ 50;<br/>\nх = 25 000.<br/>\n<br/>\nПроверка:<br/>\n25 000 : 50 = 500;<br/>\n500 = 500;<br/>\nОтвет: х = 25 000.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-67/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd465b3a217e668298fc935eff34711ea4a2b6a674d6dd71af3179ad7b71facd1', '6,50,80,500,640,4200', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:х ⋅ 80=640; 4200:х=6; х:50=500');

    VALUES (v_textbook_id, 67, '9', 8, 'Запиши выражения и определи порядок действий. Что ты замечаешь? А) Сумма числа а и произведения чисел b и c; Б) Разность частного чисел х и у и числа 5; В) Произведение суммы чисел а и b и частного чисел c и d; Г) Частное от деления суммы чисел m и n на разность чисел k и t.', '</p>\n\n<p class="text">\nЗапиши выражения и определи порядок действий. Что ты замечаешь?<br/>\nА) Сумма числа а и произведения чисел b и c;<br/>\nБ) Разность частного чисел х и у и числа 5;<br/>\nВ) Произведение суммы чисел а и b и частного чисел c и d;<br/>\nГ) Частное от деления суммы чисел m и n на разность чисел k и t.\n</p>', 'А) а + b ⋅ c; Б) х : у – 5; В) (а + b) ⋅ (с : d); Г) (m + n) : (k – t).', '<p>\nА) а + b ⋅ c;<br/>\nБ) х : у – 5;<br/>\nВ) (а + b) ⋅ (с : d);<br/>\nГ) (m + n) : (k – t).\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-67/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd1b6b0b67f36086f8d60f885d13aea0fe6942ced9744ad123e7365d7c7f443db', '5', '["сумма","разность","произведение","частное","раз"]'::jsonb, 'запиши выражения и определи порядок действий. что ты замечаешь? а) сумма числа а и произведения чисел b и c; б) разность частного чисел х и у и числа 5; в) произведение суммы чисел а и b и частного чисел c и d; г) частное от деления суммы чисел m и n на разность чисел k и t');

    VALUES (v_textbook_id, 68, '10', 0, 'Какой знак пропущен? Обоснуй свой ответ. Имеются ли другие варианты? 824 … 90 = 734; 36 … 5 = 180; 915 … 3 = 305; 258 … 1 = 258; 436 … 0 = 436; 732 … 732 = 1.', '</p>\n\n<p class="text">\nКакой знак пропущен? Обоснуй свой ответ. Имеются ли другие варианты?<br/>\n824 … 90 = 734;<br/>\n36 … 5 = 180;<br/>\n915 … 3 = 305;<br/>\n258 … 1 = 258;<br/>\n436 … 0 = 436;<br/>\n732 … 732 = 1.\n</p>', '824 – 90 = 734, потому что 734 = 734; 36 ⋅ 5 = 180, потому что 180 = 180; 915 : 3 = 305, потому что 305 = 305; 258 ⋅ 1 = 258 или 258 : 1 = 258; 436 + 0 = 436 или 436 – 0 = 436; 732 : 732 = 1, потому что 1 = 1.', '<p>\n824 – 90 = 734, потому что 734 = 734;<br/>\n36 ⋅ 5 = 180, потому что 180 = 180;<br/>\n915 : 3 = 305, потому что 305 = 305;<br/>\n258 ⋅ 1 = 258 или 258 : 1 = 258;<br/>\n436 + 0 = 436 или 436 – 0 = 436;<br/>\n732 : 732 = 1, потому что 1 = 1.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-68/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '8d42f81ec5ebea81c1daaf867f5247184e2fdf294c1001d0869703eac85deef2', '0,1,3,5,36,90,180,258,305,436', NULL, 'какой знак пропущен? обоснуй свой ответ. имеются ли другие варианты? 824 ... 90=734; 36 ... 5=180; 915 ... 3=305; 258 ... 1=258; 436 ... 0=436; 732 ... 732=1');

    VALUES (v_textbook_id, 68, '11', 1, 'Выполни задания, используя линейку и циркуль: А) построй квадрат со стороной 4 см. Сколько у него осей смметрии? Проведи их. Б) построй прямоугольник со сторонами 6 см и 2 см. Найди и проведи все его оси симметрии. Сколько осей симметрии получилось? В) Построй окружность радиусом 3 см. Сколько у неё осей симметрии? Проведи 5 осей симметрии этой окружности.', '</p>\n\n<p class="text">\nВыполни задания, используя линейку и циркуль:\nА) построй квадрат со стороной 4 см. Сколько у него осей смметрии? Проведи их.\nБ) построй прямоугольник со сторонами 6 см и 2 см. Найди и проведи все его оси симметрии. Сколько осей симметрии получилось?\nВ) Построй окружность радиусом 3 см. Сколько у неё осей симметрии? Проведи 5 осей симметрии этой окружности.\n</p>', '', '<div class="img-wrapper-460">\n<img width="750" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica68-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 68, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 68, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-68/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica68-nomer11.jpg', 'peterson/3/part2/page68/task11_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'f82c0c5a171d92010160b2fb79b421aadeca16b0004ccc2f84fbf86fea653fd1', '2,3,4,5,6', '["найди","сторона"]'::jsonb, 'выполни задания, используя линейку и циркуль:а) построй квадрат со стороной 4 см. сколько у него осей смметрии? проведи их. б) построй прямоугольник со сторонами 6 см и 2 см. найди и проведи все его оси симметрии. сколько осей симметрии получилось? в) построй окружность радиусом 3 см. сколько у неё осей симметрии? проведи 5 осей симметрии этой окружности');

    VALUES (v_textbook_id, 68, '12', 2, 'Как можно быстро разделить на 10, 100, 1000, 10 000 с остатком? Раздели на 10, 100, 1000 и 10 000 числа: 602 524; 7 478 925; 25 800 348.', '</p>\n\n<p class="text">\nКак можно быстро разделить на 10, 100, 1000, 10 000 с остатком?<br/>\nРаздели на 10, 100, 1000 и 10 000 числа:<br/>\n602 524;<br/>\n7 478 925;<br/>\n25 800 348.\n</p>', 'Чтобы быстро разделить число на 10, 100, 1000 или 10 000, нужно закрыть с конца числа такое количество цифр, которое соответствует количеству нулей в делителе. Оставшиеся цифры – неполное частное, а закрытее цифры – остаток. 602 524 : 10 = 60252 (ост. 4); 602 524 : 100 = 6025 (ост. 24); 602 524 : 1 000 = 602 (ост. 524); 602 524 : 10 000 = 60 (ост. 2524); 7 478 925 : 10 = 747892 (ост. 5); 7 478 925 : 100 = 74789 (ост. 25); 7 478 925 : 1000 = 7478 (ост. 925); 7 478 925 : 10 000 = 747 (ост. 8 925); 25 800 348 : 10 = 2 580 034 (ост. 8); 25 800 348 : 100 = 258003 (ост. 48); 25 800 348 : 1000 = 25 800 (ост. 348); 25 800 348 : 10 000 = 2580 (ост. 348).', '<p>\nЧтобы быстро разделить число на 10, 100, 1000 или 10 000, нужно закрыть с конца числа такое количество цифр, которое соответствует количеству нулей в делителе. Оставшиеся цифры – неполное частное, а закрытее цифры – остаток.<br/>\n602 524 : 10 = 60252 (ост. 4);<br/>\n602 524 : 100 = 6025 (ост. 24);<br/>\n602 524 : 1 000 = 602 (ост. 524);<br/>\n602 524 : 10 000 = 60 (ост. 2524);<br/>\n<br/>\n7 478 925 : 10 = 747892 (ост. 5);<br/>\n7 478 925 : 100 = 74789 (ост. 25);<br/>\n7 478 925 : 1000 = 7478 (ост. 925);<br/>\n7 478 925 : 10 000 = 747 (ост. 8 925);<br/>\n<br/>\n25 800 348 : 10 = 2 580 034 (ост. 8);<br/>\n25 800 348 : 100 = 258003 (ост. 48);<br/>\n25 800 348 : 1000 = 25 800 (ост. 348);<br/>\n25 800 348 : 10 000 = 2580 (ост. 348).\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-68/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ab17b92c93765f327726f388ba39816237c1da23300c4225c506c16a4417a31c', '000,7,10,25,100,348,478,524,602,800', '["раздели","раз"]'::jsonb, 'как можно быстро разделить на 10, 100, 1000, 10 000 с остатком? раздели на 10, 100, 1000 и 10 000 числа:602 524; 7 478 925; 25 800 348');

    VALUES (v_textbook_id, 68, '13', 3, 'Найди значения выражений: А) 800 ⋅ 2530; Б) 90 200 ⋅ 70; В) 270 000 : 500; Г) 336 360 : 40; Д) 490 ⋅ 6000; Е) 6 372 000 : 90.', '</p>\n\n<p class="text">Найди значения выражений:<br/>\nА) 800 ⋅ 2530;<br/>\nБ) 90 200 ⋅ 70;<br/>\nВ) 270 000 : 500;<br/>\nГ) 336 360 : 40;<br/>\nД) 490 ⋅ 6000;<br/>\nЕ) 6 372 000 : 90.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica68-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 68, номер 13, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 68, номер 13, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-68/')
    RETURNING id INTO v_task_id;

