    VALUES (v_task_id, v_textbook_id, 3, '9853771b80ccd40f9b609b139eb3f0c6cf54975f2317cedbaf5952a5e94584d7', '000,6,40,70,90,200,270,336,360,372', '["найди"]'::jsonb, 'найди значения выражений:а) 800 ⋅ 2530; б) 90 200 ⋅ 70; в) 270 000:500; г) 336 360:40; д) 490 ⋅ 6000; е) 6 372 000:90');

    VALUES (v_textbook_id, 68, '14', 4, 'Серёжа задумал число, разделил его на 5, потом умножил на 100, из произведения вычел 300, полученный результат разделил на 2 и прибавил 150. В результате у него получилось 500. Какое число задумал Серёжа?', '</p>\n\n<p class="text">Серёжа задумал число, разделил его на 5, потом умножил на 100, из произведения вычел 300, полученный результат разделил на 2 и прибавил 150. В результате у него получилось 500. Какое число задумал Серёжа?</p>', 'Пусть задумано число Х. Действия, которые производят с числом: 1) Разделить на 5, т.е. (: 5); 2) Умножить на 100, т.е. (⋅ 100); 3) Разделить на 2, т.е. (: 2); 4) Прибавить 150, т.е. (+ 150). В результате получилось 500. Тогда, выполняю с числом-результатом обратные действия, чтобы найти число х. 500 – 150 = 350; 350 ⋅ 2 = 700; 700 : 100 = 7; 7 ⋅ 5 = 35. Ответ: было задумано число 35.', '<p>\nПусть задумано число Х.<br/>\nДействия, которые производят с числом:<br/>\n1) Разделить на 5, т.е. (: 5);<br/>\n2) Умножить на 100, т.е. (⋅ 100);<br/>\n3) Разделить на 2, т.е. (: 2);<br/>\n4) Прибавить 150, т.е. (+ 150).<br/>\nВ результате получилось 500.<br/>\n<br/>\nТогда, выполняю с числом-результатом обратные действия, чтобы найти число х.<br/>\n500 – 150 = 350;<br/>\n350 ⋅ 2 = 700;<br/>\n700 : 100 = 7;<br/>\n7 ⋅ 5 = 35.<br/>\n<br/>\nОтвет: было задумано число 35.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-68/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'e404f6838a9feb62d089faf3bb555d3abafda5dbab2165b86e5b1141d630a6a4', '2,5,100,150,300,500', '["раздели","раз"]'::jsonb, 'серёжа задумал число, разделил его на 5, потом умножил на 100, из произведения вычел 300, полученный результат разделил на 2 и прибавил 150. в результате у него получилось 500. какое число задумал серёжа');

    VALUES (v_textbook_id, 68, '15', 5, 'Игра «Роботы». Отступи от края листа вправо 8 клеток и поставь точку. Построй фигуру по программе (запись читать по столбцам). Перенеси построенную фигуру на 12 клеток вправо. Раскрась обе фигуры разными цветами.', '</p>\n\n<p class="text">Игра «Роботы».<br/>\nОтступи от края листа вправо 8 клеток и поставь точку. Построй фигуру по программе (запись читать по столбцам).<br/>\nПеренеси построенную фигуру на 12 клеток вправо. Раскрась обе фигуры разными цветами.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica68-nomer15.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 68, номер 15, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 68, номер 15, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-68/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica68-nomer15.jpg', 'peterson/3/part2/page68/task15_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'd3789bf1a775fe0769c6abcc27be94e5f127ce13f86d4bfd85fbeeba3fbe533b', '8,12', '["раз"]'::jsonb, 'игра "роботы". отступи от края листа вправо 8 клеток и поставь точку. построй фигуру по программе (запись читать по столбцам). перенеси построенную фигуру на 12 клеток вправо. раскрась обе фигуры разными цветами');

    VALUES (v_textbook_id, 69, '1', 0, 'В начале урока учитель сказал: «К доске пойдет Петя». В середине урока он сказал: «К доске пойдет Серёжа». А незадолго до конца урока он сказал: «К доске пойдет Таня». Что меняется в этих предложениях? Замени их одним предложением с помощью буквенного обозначения имени ученика.', '</p>\n\n<p class="text">В начале урока учитель сказал:<br/>\n«К доске пойдет Петя».<br/>\nВ середине урока он сказал: <br/>\n«К доске пойдет Серёжа».<br/>\nА незадолго до конца урока он сказал:<br/>\n«К доске пойдет Таня».<br/>\nЧто меняется в этих предложениях? Замени их одним предложением с помощью буквенного обозначения имени ученика.\n</p>', 'В этих предложениях каждый раз меняется имя ученика. Значит, обозначить это предложение можно с помощью буквенного обозначения так: «К доске пойдет С», где С – имя ученика.', '<p>\nВ этих предложениях каждый раз меняется имя ученика. Значит, обозначить это предложение можно с помощью буквенного обозначения так: «К доске пойдет С», где С – имя ученика.\n</p>', 'Переменная Переменная – буквенное обозначение для произвольного элемента некоторого множества. Каждый элемент этого множества называют значением переменной. Пример: В месяце k дней. k – переменная. 28, 29, 30, 31 – значения переменной k.', '<div class="recomended-block">\n<span class="title">Переменная</span>\n<p>\n<b class="black">Переменная</b> – буквенное обозначение для произвольного элемента некоторого множества.<br/>\nКаждый элемент этого множества называют значением переменной.<br/>\nПример:<br/>\nВ месяце k дней.<br/>\nk – переменная.<br/>\n28, 29, 30, 31 – значения переменной k.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-69/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '2390ee557cf2b65de74527b61b9abd1aa861f5cc052cd087e30f2f818339cf5f', NULL, NULL, 'в начале урока учитель сказал:"к доске пойдет петя". в середине урока он сказал:"к доске пойдет серёжа". а незадолго до конца урока он сказал:"к доске пойдет таня". что меняется в этих предложениях? замени их одним предложением с помощью буквенного обозначения имени ученика');

    VALUES (v_textbook_id, 69, '2', 1, 'Какие слова можно подставить вместо переменной а в предложении: «В моём портфеле лежит а»?', '</p>\n\n<p class="text">Какие слова можно подставить вместо переменной а в предложении:\n«В моём портфеле лежит а»?\n</p>', 'а: {тетрадь, дневник, пенал}.', '<p>\nа: {тетрадь, дневник, пенал}.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-69/')
    RETURNING id INTO v_task_id;

