    VALUES (v_textbook_id, 69, '4', 3, 'Может ли переменная с в предложении «За ответ ученик получил отметку с» принимать значения 3, 4, 5, 6, 0, 24?', '</p>\n\n<p class="text">Может ли переменная с в предложении «За ответ ученик получил отметку с» принимать значения 3, 4, 5, 6, 0, 24?</p>', 'Переменная с не может принимать все эти значения, а только некоторые. с : {3, 4, 5}.', '<p>\nПеременная с не может принимать все эти значения, а только некоторые.<br/>\nс : {3, 4, 5}.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-69/')
    RETURNING id INTO v_task_id;

