    VALUES (v_textbook_id, 69, '5', 4, 'Прочитай предложение: «В нашем классе сегодня n уроков». Какие значения может принимать переменная n?', '</p>\n\n<p class="text">Прочитай предложение: «В нашем классе сегодня n уроков». Какие значения может принимать переменная n?\n</p>', 'n: {0, 1, 2, 3, 4, 5}.', '<p>\nn: {0, 1, 2, 3, 4, 5}.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-69/')
    RETURNING id INTO v_task_id;

