    VALUES (v_textbook_id, 69, '6', 5, 'В предложении «Планета t вращается вокруг Солнца» переменная t принимает множество значений {Венера, Земля, Марс, Меркурий, Нептун, Сатурн, Уран, Юпитер}. Прочитай это предложение, подставив вместо t одно из его значений.', '</p>\n\n<p class="text">В предложении «Планета t вращается вокруг Солнца» переменная t принимает множество значений {Венера, Земля, Марс, Меркурий, Нептун, Сатурн, Уран, Юпитер}. Прочитай это предложение, подставив вместо t одно из его значений.\n</p>', 'Планета Венера вращается вокруг Солнца. Планета Земля вращается вокруг Солнца. Планета Марс вращается вокруг Солнца. Планета Меркурий вращается вокруг Солнца. Планета Нептун вращается вокруг Солнца. Планета Сатурн вращается вокруг Солнца. Планета Уран вращается вокруг Солнца. Планета Юпитер вращается вокруг Солнца.', '<p>\nПланета Венера вращается вокруг Солнца.<br/>\nПланета Земля вращается вокруг Солнца.<br/>\nПланета Марс вращается вокруг Солнца.<br/>\nПланета Меркурий вращается вокруг Солнца.<br/>\nПланета Нептун вращается вокруг Солнца.<br/>\nПланета Сатурн вращается вокруг Солнца.<br/>\nПланета Уран вращается вокруг Солнца.<br/>\nПланета Юпитер вращается вокруг Солнца.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-69/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'e251359601748045191035f993356134e2755b944c4fe3023f95eb2dfc1aa028', NULL, NULL, 'в предложении "планета t вращается вокруг солнца" переменная t принимает множество значений {венера, земля, марс, меркурий, нептун, сатурн, уран, юпитер}. прочитай это предложение, подставив вместо t одно из его значений');

    VALUES (v_textbook_id, 69, '7', 6, 'Придумай предложение с переменной а. Какие значения может принимать а?', '</p>\n\n<p class="text">Придумай предложение с переменной а. Какие значения может принимать а?\n</p>', '«Я не люблю такие продукты, как М», где М – продукты, которые я не люблю. М: {морковь, лук, рыба}.', '<p>\n«Я не люблю такие продукты, как М», где М – продукты, которые я не люблю.<br/>\nМ: {морковь, лук, рыба}.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-69/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4e2f47e1eb87857cf1f12d686a9b34d7e474cf5d4c3ceaee26e524de0920773f', NULL, NULL, 'придумай предложение с переменной а. какие значения может принимать а');

    VALUES (v_textbook_id, 70, '8', 0, 'Прочитай предложения. Что в них изменяется? Составь предложение с переменной х и запиши множество его значений. А) «Я читаю книгу», «Я читаю газету», «Я читаю журнал». Б) «Ира дружит с Таней», «Катя дружит с Таней», «Миша дружит с Таней». Ответ:', '</p>\n\n<p class="text">Прочитай предложения. Что в них изменяется? Составь предложение с переменной х и запиши множество его значений.<br/>\nА) «Я читаю книгу», «Я читаю газету», «Я читаю журнал».<br/>\nБ) «Ира дружит с Таней», «Катя дружит с Таней», «Миша дружит с Таней».\n\nОтвет:\n\n</p>', 'А) «Я читаю х», где х – то, что я читаю. Х: {книга, журнал, газета}. Б) «х дружит с Таней», где х – та, кто дружит с Таней. Х: {Ира, Катя, Миша}.', '<p>\nА) «Я читаю х», где х – то, что я читаю.<br/>\nХ: {книга, журнал, газета}.<br/>\n<br/>\nБ) «х дружит с Таней», где х – та, кто дружит с Таней.<br/>\nХ: {Ира, Катя, Миша}.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-70/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '57b89b834b37b7108d2c313c8f91d3ca98ddc198bfb4d54a6ecf5f236c1c092b', NULL, NULL, 'прочитай предложения. что в них изменяется? составь предложение с переменной х и запиши множество его значений. а) "я читаю книгу", "я читаю газету", "я читаю журнал". б) "ира дружит с таней", "катя дружит с таней", "миша дружит с таней". ответ');

    VALUES (v_textbook_id, 70, '9', 1, 'Вырази в указанных единицах измерения: 2 м 30 см = … см; 2 км 30 м = … м; 2 ч 30 мин = … мин; 4 дм 15 мм = … мм; 4 т 15 кг = … кг; 4 мин 15 с = … с.', '</p>\n\n<p class="text">\nВырази в указанных единицах измерения:<br/>\n2 м 30 см = … см;<br/>\n2 км 30 м = … м;<br/>\n2 ч 30 мин = … мин;<br/>\n<br/>\n4 дм 15 мм = … мм;<br/>\n4 т 15 кг = … кг;<br/>\n4 мин 15 с = … с.\n</p>', '2 м 30 см = 200 см + 30 см = 230 см; 2 км 30 м = 2 000 м + 30 м = 2 030 м; 2 ч 30 мин = 120 мин + 30 мин = 150 мин; 4 дм 15 мм = 400 мм + 15 мм = 415 мм; 4 т 15 кг = 4 000 кг + 15 кг = 4 015 кг; 4 мин 15с = 240 с + 15 с = 255 с.', '<p>\n2 м 30 см = 200 см + 30 см = 230 см;<br/>\n2 км 30 м = 2 000 м + 30 м = 2 030 м;<br/>\n2 ч 30 мин = 120 мин + 30 мин = 150 мин;<br/>\n<br/>\n4 дм 15 мм = 400 мм + 15 мм = 415 мм;<br/>\n4 т 15 кг = 4 000 кг + 15 кг = 4 015 кг;<br/>\n4 мин 15с = 240 с + 15 с = 255 с.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-70/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'def711d239381dfdf9b6a27df78fdf19eecf739095af4656104b420f2d918c80', '2,4,15,30', '["раз"]'::jsonb, 'вырази в указанных единицах измерения:2 м 30 см=... см; 2 км 30 м=... м; 2 ч 30 мин=... мин; 4 дм 15 мм=... мм; 4 т 15 кг=... кг; 4 мин 15 с=... с');

    VALUES (v_textbook_id, 70, '10', 2, 'Папа с Димой отправились путешествовать. Они плыли на катере 1 ч 20 мин, затем гуляли по парку 2 ч 45 мин, обедали в течение 40 мин и шли домой пешком 2 ч 10 мин. Домой они вернулись в 5 ч вечера. В котором часу они вышли из дома?', '</p>\n\n<p class="text">Папа с Димой отправились путешествовать. Они плыли на катере 1 ч 20 мин, затем гуляли по парку 2 ч 45 мин, обедали в течение 40 мин и шли домой пешком 2 ч 10 мин. Домой они вернулись в 5 ч вечера. В котором часу они вышли из дома?</p>', 'Вышли из дома - ? ч. Плыли на катере – 1 ч 20 мин. Гуляли по парку – 2 ч 45 мин. Обедали – 40 мин. Шли домой – 2 ч 10 мин. Вернулись домой – в 5 ч. Значит, чтобы узнать, в котором часу они ушли из дома, нужно из времени возвращения домой вычесть время, проведенное вне дома. Тогда, 1 ч 20 мин + 2 ч 45 мин + 40 мин + 2 ч 10 мин = 5 ч 115 мин = 6 ч 55 мин. Тогда, 17 ч – 6 ч 55 мин = 15 ч 60 мин – 6 ч 55 мин = 9 ч 5 мин – время, когда папа с Димой вышли из дома. Ответ: в 9 ч 5 мин.', '<p>\nВышли из дома - ? ч.<br/>\nПлыли на катере – 1 ч 20 мин.<br/>\nГуляли по парку – 2 ч 45 мин.<br/>\nОбедали – 40 мин.<br/>\nШли домой – 2 ч 10 мин.<br/>\nВернулись домой – в 5 ч.<br/>\nЗначит, чтобы узнать, в котором часу они ушли из дома, нужно из времени возвращения домой вычесть время, проведенное вне дома.<br/>\nТогда, 1 ч 20 мин + 2 ч 45 мин + 40 мин + 2 ч 10 мин = 5 ч 115 мин = 6 ч 55 мин.<br/>\nТогда, 17 ч – 6 ч 55 мин = 15 ч 60 мин – 6 ч 55 мин = 9 ч 5 мин – время, когда папа с Димой вышли из дома.<br/>\n<br/>\nОтвет: в 9 ч 5 мин.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-70/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '39135bc134644fc9170a019d8d9e4a2b8ee6558969e0f5f79bf50fd505f927cb', '1,2,5,10,20,40,45', NULL, 'папа с димой отправились путешествовать. они плыли на катере 1 ч 20 мин, затем гуляли по парку 2 ч 45 мин, обедали в течение 40 мин и шли домой пешком 2 ч 10 мин. домой они вернулись в 5 ч вечера. в котором часу они вышли из дома');

    VALUES (v_textbook_id, 70, '11', 3, 'Реши уравнения с комментированием и сделай проверку: А) х + 2548 = 15 700; Б) 90 050 – х = 4806; В) х – 534 = 30 967; Г) х ⋅ 300 = 1500; Д) 2700 : х = 9; Е) х : 80 = 800.', '</p>\n\n<p class="text">\nРеши уравнения с комментированием и сделай проверку:<br/>\nА) х + 2548 = 15 700;<br/>\nБ) 90 050 – х = 4806;<br/>\nВ) х – 534 = 30 967;<br/>\nГ) х ⋅ 300 = 1500;<br/>\nД) 2700 : х = 9;<br/>\nЕ) х : 80 = 800.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica70-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 70, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 70, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-70/')
