    VALUES (v_textbook_id, 71, '1', 0, 'Составь выражение к задаче: «Дима и Саша занимаются теннисом. Дима ходит на занятия 4 дня в неделю, а Саша – на х дней в неделю больше. Сколько раз в неделю занимается теннисом Саша?» Какие значения может принимать в полученном выражении переменная х? Найди значение выражения при х = 2.', '</p>\n\n<p class="text">Составь выражение к задаче:<br/>\n«Дима и Саша занимаются теннисом. Дима ходит на занятия 4 дня в неделю, а Саша – на х дней в неделю больше. Сколько раз в неделю занимается теннисом Саша?»<br/>\nКакие значения может принимать в полученном выражении переменная х? Найди значение выражения при х = 2.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica71-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 71, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 71, номер 1, год 2022."/>', 'Выражение с переменной Буквенное выражение, содержащее переменную, называют выражением с переменной . х – 5 – выражение с переменной х. 5, 6, 7, … - значения переменной х. Пример: х = 7, то х – 5 = 7 – 5 = 2. Число 2 – значение выражения х = 5 при х = 7.', '<div class="recomended-block">\n<span class="title">Выражение с переменной</span>\n<p>\nБуквенное выражение, содержащее переменную, называют <b class="black">выражением с переменной</b>.<br/>\nх – 5 – выражение с переменной х.<br/>\n5, 6, 7, … - значения переменной х.<br/>\nПример:<br/>\nх = 7, то х – 5 = 7 – 5 = 2.<br/>\nЧисло 2 – значение выражения х = 5 при х = 7.\n\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-71/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica71-nomer1.jpg', 'peterson/3/part2/page71/task1_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '3b4d287d06c7fab0bd5870b15b67f2ec52de088b811dba34ca4552f942933eab', '2,4', '["найди","больше","раз"]'::jsonb, 'составь выражение к задаче:"дима и саша занимаются теннисом. дима ходит на занятия 4 дня в неделю, а саша-на х дней в неделю больше. сколько раз в неделю занимается теннисом саша?" какие значения может принимать в полученном выражении переменная х? найди значение выражения при х=2');

    VALUES (v_textbook_id, 71, '2', 1, 'Составь выражение к задаче: «У Тани 3 розы и k пионов. Сколько цветков у Тани?» Прочитай задачи, которые получаются при k = 5, 6, 12. По условию каждой задачи составь выражение и найди его значение.', '</p>\n\n<p class="text">Составь выражение к задаче:<br/>\n«У Тани 3 розы и k пионов. Сколько цветков у Тани?»<br/>\nПрочитай задачи, которые получаются при k = 5, 6, 12. По условию каждой задачи составь выражение и найди его значение.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica71-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 71, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 71, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-71/')
    RETURNING id INTO v_task_id;

