    VALUES (v_task_id, v_textbook_id, 3, '63bd73240444d50cc54c461761530614496098bbfe8dcc22f9d091708dc1e2af', '3,5,6,12', '["найди"]'::jsonb, 'составь выражение к задаче:"у тани 3 розы и k пионов. сколько цветков у тани?" прочитай задачи, которые получаются при k=5, 6, 12. по условию каждой задачи составь выражение и найди его значение');

    VALUES (v_textbook_id, 71, '3', 2, 'Составь выражение к задаче: «В первой коробке 6 карандашей, а во второй – в n раз больше. Сколько карандашей во второй коробке? Найди значение составленного выражения при n = 2, 4, 8. Прочитай задачи, которые при этом получаются.', '</p>\n\n<p class="text">\nСоставь выражение к задаче:<br/>\n«В первой коробке 6 карандашей, а во второй – в n раз больше. Сколько карандашей во второй коробке?<br/>\nНайди значение составленного выражения при n = 2, 4, 8. Прочитай задачи, которые при этом получаются.\n</p>', '6 ⋅ n – (шт.) – карандашей во второй коробке. При n = 2, «В первой коробке 6 карандашей, а во второй – в 2 раза больше. Сколько карандашей во второй коробке?»: 6 ⋅ 2 = 12 (шт.). При n = 4, «В первой коробке 6 карандашей, а во второй – в 4 раза больше. Сколько карандашей во второй коробке?»: 6 ⋅ 4 = 24 (шт.). При n = 8, «В первой коробке 6 карандашей, а во второй – в 8 раз больше. Сколько карандашей во второй коробке?»: 6 ⋅ 8 = 48 (шт.).', '<p>\n6 ⋅ n – (шт.) – карандашей во второй коробке.<br/>\nПри n = 2, «В первой коробке 6 карандашей, а во второй – в 2 раза больше. Сколько карандашей во второй коробке?»: 6 ⋅ 2 = 12 (шт.).<br/>\nПри n = 4, «В первой коробке 6 карандашей, а во второй – в 4 раза больше. Сколько карандашей во второй коробке?»: 6 ⋅ 4 = 24 (шт.).<br/>\nПри n = 8, «В первой коробке 6 карандашей, а во второй – в 8 раз больше. Сколько карандашей во второй коробке?»: 6 ⋅ 8 = 48 (шт.).\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-71/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '0bd8bae94ed3833d67623b06cddb51616112b209f2c406e1f15bfb5883cc9809', '2,4,6,8', '["найди","больше","раз"]'::jsonb, 'составь выражение к задаче:"в первой коробке 6 карандашей, а во второй-в n раз больше. сколько карандашей во второй коробке? найди значение составленного выражения при n=2, 4, 8. прочитай задачи, которые при этом получаются');

    VALUES (v_textbook_id, 71, '4', 3, 'Подставь в задачу вместо переменной а какое-нибудь значение: «Ира купила 3 конфеты и а из них съела. Сколько конфет у неё осталось?» Какие значения может принимать переменная а?', '</p>\n\n<p class="text">Подставь в задачу вместо переменной а какое-нибудь значение:<br/>\n«Ира купила 3 конфеты и а из них съела. Сколько конфет у неё осталось?»<br/>\nКакие значения может принимать переменная а?\n</p>', '«Ира купила 3 конфеты и а из них съела. Сколько конфет у неё осталось?» 3 – а, где а – количество съеденных конфет. А: {0, 1, 2, 3}. Пусть а = 2. Тогда: 3 – 2 = 1 (шт.) – конфет осталось. Ответ: 1 конфета.', '<p>\n«Ира купила 3 конфеты и а из них съела. Сколько конфет у неё осталось?»<br/>\n3 – а, где а – количество съеденных конфет. А: {0, 1, 2, 3}.<br/>\nПусть а = 2. Тогда: 3 – 2 = 1 (шт.) – конфет осталось.<br/>\nОтвет: 1 конфета.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-71/')
    RETURNING id INTO v_task_id;

