    VALUES (v_textbook_id, 72, '6', 0, 'Рассмотри таблицы. Назови переменные, их значения, выражения с переменными. Заполни таблицы в тетради:', '</p>\n\n<p class="text">Рассмотри таблицы. Назови переменные, их значения, выражения с переменными. Заполни таблицы в тетради:</p>\n\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica72-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 72, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 72, номер 6, год 2022."/>\n</div>', 'А)', '<p>\nА)\n</p>\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica72-nomer6-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 72, номер 6-1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 72, номер 6-1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-72/')
    RETURNING id INTO v_task_id;

