    VALUES (v_textbook_id, 72, '7', 1, 'Прочитай выражение 80 ⋅ х разными способами. Найди его значения, если х = 0, 1, 2, 3, 4, 56.', '</p>\n\n<p class="text">\nПрочитай выражение 80 ⋅ х разными способами. Найди его значения, если х = 0, 1, 2, 3, 4, 56.\n</p>', '80 ⋅ х – первый множитель 80, второй множитель х; произведение 80 и х. При х = 0, 80 ⋅ 0 = 0; При х = 1, 80 ⋅ 1 = 80; При х = 2, 80 ⋅ 2 = 160; При х = 3, 80 ⋅ 3 = 240; При х = 4, 80 ⋅ 4 = 320; При х = 5, 80 ⋅ 5 = 400; При х = 6, 80 ⋅ 6 = 480', '<p>\n80 ⋅ х – первый множитель 80, второй множитель х; произведение 80 и х.<br/>\nПри х = 0, 80 ⋅ 0 = 0;<br/>\nПри х = 1, 80 ⋅ 1 = 80;<br/>\nПри х = 2, 80 ⋅ 2 = 160;<br/>\nПри х = 3, 80 ⋅ 3 = 240;<br/>\nПри х = 4, 80 ⋅ 4 = 320;<br/>\nПри х = 5, 80 ⋅ 5 = 400;<br/>\nПри х = 6, 80 ⋅ 6 = 480\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-72/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '24f9080bff16fcefc989d2645370e8c82d9639fc0448843dd657711be7bf4747', '0,1,2,3,4,56,80', '["найди","раз"]'::jsonb, 'прочитай выражение 80 ⋅ х разными способами. найди его значения, если х=0, 1, 2, 3, 4, 56');

    VALUES (v_textbook_id, 72, '8', 2, 'Найди значения выражений а – (b + c) и а – b – с, если а = 5308, b = 924, с = 3758. Что ты замечаешь? Как объяснить полученный результат?', '</p>\n\n<p class="text">Найди значения выражений а – (b + c) и а – b – с, если а = 5308, b = 924, с = 3758. Что ты замечаешь? Как объяснить полученный результат?</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica72-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 72, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 72, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-72/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica72-nomer8.jpg', 'peterson/3/part2/page72/task8_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '91f7df37281c0c5bbb62b7201582bb34559f68f3ad9a53a8ceb3841447b41bdc', '924,3758,5308', '["найди"]'::jsonb, 'найди значения выражений а-(b+c) и а-b-с, если а=5308, b=924, с=3758. что ты замечаешь? как объяснить полученный результат');

    VALUES (v_textbook_id, 72, '9', 3, 'Найди х. Сравни в каждом столбике уравнения и их решения. Что ты замечаешь? x + а = n; x ⋅ a = n; x – b = c; x : b = c; d – x = k; d : x = k.', '</p>\n\n<p class="text">Найди х. Сравни в каждом столбике уравнения и их решения. Что ты замечаешь?<br/>\nx + а = n;<br/>\nx ⋅ a = n;<br/>\nx – b = c;<br/>\nx : b = c;<br/>\nd – x = k;<br/>\nd : x = k.\n</p>', 'х + а = n; a = n – a; x ⋅ a = n; x = n : a; х – b = c; x = c + b; x : b = c; x = b ⋅ c; d – x = k; x = d – k; d : x = k; x = d : k. Таким образом, сложение и умножение, а также вычитание и деление похожи порядком действия при поиске неизвестного.', '<p>\nх + а = n;<br/>\na = n – a;<br/>\n<br/>\nx ⋅ a = n;<br/>\nx = n : a;<br/>\n<br/>\nх – b = c;<br/>\nx = c + b;<br/>\n<br/>\nx : b = c;<br/>\nx = b ⋅ c;<br/>\n<br/>\nd – x = k;<br/>\nx = d – k;<br/>\n<br/>\nd : x = k;<br/>\nx = d : k.<br/>\nТаким образом, сложение и умножение, а также вычитание и деление похожи порядком действия при поиске неизвестного.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-72/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '787a319c3ab10a596b7fe38993ced80e4000e95284ac84ecb5bf2f11a98257e7', NULL, '["найди","сравни","столбик"]'::jsonb, 'найди х. сравни в каждом столбике уравнения и их решения. что ты замечаешь? x+а=n; x ⋅ a=n; x-b=c; x:b=c; d-x=k; d:x=k');

    VALUES (v_textbook_id, 72, '10', 4, 'БЛИЦтурнир. А) В автобусе ехали а человек. На остановке вышли 5 человек, а вошли 7 человек. Сколько человек стало в автобусе? Б) Масса гуся 4 кг, а масса утки на b кг меньше. Чему равна масса гуся и утки вместе? В) В гирлянде 30 лампочек. Из них с красных, а остальные – зелёные. На сколько красных лампочек больше, чем зелёных? Г) Юбка стоит d р., а платье – в 3 раза дороже. На сколько рублей юбка дешевле платья? Д) Лошадь выпила 3 ведра воды. Это на х вёдер воды меньше, чем выпил верблюд. Во сколько раз больше воды выпил верблюд, чем лошадь?', '</p>\n\n<p class="text">БЛИЦтурнир.<br/>\nА) В автобусе ехали а человек. На остановке вышли 5 человек, а вошли 7 человек. Сколько человек стало в автобусе?<br/>\nБ) Масса гуся 4 кг, а масса утки на b кг меньше. Чему равна масса гуся и утки вместе?<br/>\nВ) В гирлянде 30 лампочек. Из них с красных, а остальные – зелёные. На сколько красных лампочек больше, чем зелёных?<br/>\nГ) Юбка стоит d р., а платье – в 3 раза дороже. На сколько рублей юбка дешевле платья?<br/>\nД) Лошадь выпила 3 ведра воды. Это на х вёдер воды меньше, чем выпил верблюд. Во сколько раз больше воды выпил верблюд, чем лошадь?\n</p>', 'А) а – 5 + 7 (чел.) – стало в автобусе; Б) 4 + (4 – b) (кг) – масса гуся и утки вместе; В) с – (30 – с) (шт.) – больше красных лампочек, чем зелёных; Г) d ⋅ 3 : d (руб.) – юбка дешевле платья; Д) (3 + х) : 3 (раз.) – больше воды выпил верблюде, чем лошадь.', '<p>\nА) а – 5 + 7 (чел.) – стало в автобусе;<br/>\nБ) 4 + (4 – b) (кг) – масса гуся и утки вместе;<br/>\nВ) с – (30 – с) (шт.) – больше красных лампочек, чем зелёных;<br/>\nГ) d ⋅ 3 : d (руб.) – юбка дешевле платья;<br/>\nД) (3 + х) : 3 (раз.) – больше воды выпил верблюде, чем лошадь.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-72/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '3b444f6aedb86ae27c60e895edfc4a659b0d675ac3868b43246f8319f832b248', '3,4,5,7,30', '["больше","меньше","раз","раза"]'::jsonb, 'блицтурнир. а) в автобусе ехали а человек. на остановке вышли 5 человек, а вошли 7 человек. сколько человек стало в автобусе? б) масса гуся 4 кг, а масса утки на b кг меньше. чему равна масса гуся и утки вместе? в) в гирлянде 30 лампочек. из них с красных, а остальные-зелёные. на сколько красных лампочек больше, чем зелёных? г) юбка стоит d р., а платье-в 3 раза дороже. на сколько рублей юбка дешевле платья? д) лошадь выпила 3 ведра воды. это на х вёдер воды меньше, чем выпил верблюд. во сколько раз больше воды выпил верблюд, чем лошадь');

    VALUES (v_textbook_id, 72, '11', 5, 'Найди значения выражений: А) 9752 + 141 763; Б) 60 203 – 5 658; В) 1 083 060 : 90; Г) 2087 ⋅ 600; Д) (410 020 – 69 945) ⋅ 400; Е) (228 102 + 92 458) : 80.', '</p>\n\n<p class="text">Найди значения выражений:<br/>\nА) 9752 + 141 763;<br/>\nБ) 60 203 – 5 658;<br/>\nВ) 1 083 060 : 90;<br/>\nГ) 2087 ⋅ 600;<br/>\nД) (410 020 – 69 945) ⋅ 400;<br/>\nЕ) (228 102 + 92 458) : 80.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica72-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 72, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 72, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-72/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica72-nomer11.jpg', 'peterson/3/part2/page72/task11_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'b2bb824305e1a99854d149ecf397b721972209708646e0ca97a156897089319a', '1,5,020,060,60,69,80,083,90,92', '["найди"]'::jsonb, 'найди значения выражений:а) 9752+141 763; б) 60 203-5 658; в) 1 083 060:90; г) 2087 ⋅ 600; д) (410 020-69 945) ⋅ 400; е) (228 102+92 458):80');

    VALUES (v_textbook_id, 72, '12', 6, 'У каждого двузначного числа нашли произведение цифр. Потом у каждого такого произведения подсчитали сумму цифр. Какая из этих сумм самая большая?', '</p>\n\n<p class="text">У каждого двузначного числа нашли произведение цифр. Потом у каждого такого произведения подсчитали сумму цифр. Какая из этих сумм самая большая?\n</p>', 'Произведение любых двух чисел будет равно двузначному числу. Для того, чтобы решить задачу, нужно вспомнить таблицу умножения. Большие цифры встречаются в таблице редко, но вместе в значении произведения они не встречаются. 7 ⋅ 7 = 49, 4 + 9 = 13; 8 ⋅ 8 = 64, 6 + 4 = 10; 9 ⋅ 9 = 81, 8 + 1 = 9. Получается, что наибольшая сумма цифр в числе равном произведению цифр в 77.', '<p>\nПроизведение любых двух чисел будет равно двузначному числу.<br/>\nДля того, чтобы решить задачу, нужно вспомнить таблицу умножения. Большие цифры встречаются в таблице редко, но вместе в значении произведения они не встречаются. <br/>\n7 ⋅ 7 = 49, 4 + 9 = 13;<br/>\n8 ⋅ 8 = 64, 6 + 4 = 10;<br/>\n9 ⋅ 9 = 81, 8 + 1 = 9.<br/>\nПолучается, что наибольшая сумма цифр в числе равном произведению цифр в  77.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-72/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'c39ecdc7c9d2436301cf411ccdf5963f9414bd6c4770fbb723cf7cbf58363960', NULL, '["произведение"]'::jsonb, 'у каждого двузначного числа нашли произведение цифр. потом у каждого такого произведения подсчитали сумму цифр. какая из этих сумм самая большая');

    VALUES (v_textbook_id, 73, '1', 0, 'Прочитай предложения. Какие из них верные (истинные), а какие – неверные (ложные)? А) В году 12 месяцев. Б) В неделе 8 дней. В) Квадрат является прямоугольником. Г) Диагонали прямоугольника параллельны. Д) Все ученики изучают математику. Е) некоторые ученики летали на Марс. Ж) Любое число с нулём на конце делится на 3. З) Некоторые числа делятся на нуль.', '</p>\n\n<p class="text">Прочитай предложения. Какие из них верные (истинные), а какие – неверные (ложные)?<br/>\nА) В году 12 месяцев.<br/>\nБ) В неделе 8 дней.<br/>\nВ) Квадрат является прямоугольником.<br/>\nГ) Диагонали прямоугольника параллельны.<br/>\nД) Все ученики изучают математику.<br/>\nЕ) некоторые ученики летали на Марс.<br/>\nЖ) Любое число с нулём на конце делится на 3.<br/>\nЗ) Некоторые числа делятся на нуль.\n</p>', 'А) В году 12 месяцев. – истинное. Б) В неделе 8 дней. – ложное, потому что в неделе 7 дней. В) Квадрат является прямоугольником. - истинное. Г) Диагонали прямоугольника параллельны. - истинное. Д) Все ученики изучают математику. – истинное. Е) некоторые ученики летали на Марс. – ложное, потому что люди не были на Марсе. Ж) Любое число с нулём на конце делится на 3. – ложное, потому что 30 делится на 3, а 40 – нет. З) Некоторые числа делятся на нуль. – истинное.', '<p>\nА) В году 12 месяцев. – истинное.<br/>\nБ) В неделе 8 дней. – ложное, потому что в неделе 7 дней.<br/>\nВ) Квадрат является прямоугольником. - истинное.<br/>\nГ) Диагонали прямоугольника параллельны. - истинное.<br/>\nД) Все ученики изучают математику. – истинное.<br/>\nЕ) некоторые ученики летали на Марс. – ложное, потому что люди не были на Марсе.<br/>\nЖ) Любое число с нулём на конце делится на 3. – ложное, потому что 30 делится на 3, а 40 – нет.<br/>\nЗ) Некоторые числа делятся на нуль. – истинное.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-73/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '502f3d3963b55c9809c95eff2b32cb79d5763dadae4f00e9f66729b77d036a60', '3,8,12', NULL, 'прочитай предложения. какие из них верные (истинные), а какие-неверные (ложные)? а) в году 12 месяцев. б) в неделе 8 дней. в) квадрат является прямоугольником. г) диагонали прямоугольника параллельны. д) все ученики изучают математику. е) некоторые ученики летали на марс. ж) любое число с нулём на конце делится на 3. з) некоторые числа делятся на нуль');

    VALUES (v_textbook_id, 73, '2', 1, 'Прочитай предложение с переменной k: «Число k делится на 5». При каких значениях k оно истинно, а при каких – ложно?', '</p>\n\n<p class="text">Прочитай предложение с переменной k: «Число k делится на 5». При каких значениях k оно истинно, а при каких – ложно?\n</p>', '«Число k делится на 5». Это выражение истинно, когда k – число, которое делится на 5. Например, k : {5, 10, 15, …}.', '<p>\n«Число k делится на 5».<br/>\nЭто выражение истинно, когда k – число, которое делится на 5. Например, k : {5, 10, 15, …}.\n</p>', 'Высказывания Высказыванием Высказыванием называют предложение, о котором омжно сказать, верно оно или неверно (истинно или ложно). Например, высказывание «Буква М гласная» неверно, а «Дважды два равно 4» - верно. А вот предложение «Который сейчас час?» высказыванием не является. Предложение «В нашем классе а учеников» - содержит переменную а. Оно также не является высказывание. Но если вместо переменной а подставить различные значения, то получатся верные и неверные высказывания.', '<div class="recomended-block">\n<span class="title">Высказывания</span>\n<p>\n<b class="black">Высказыванием</b>Высказыванием называют предложение, о котором омжно сказать, верно оно или неверно (истинно или ложно).<br/>\nНапример, высказывание «Буква М гласная» неверно, а «Дважды два равно 4» - верно. А вот предложение «Который сейчас час?» высказыванием не является.<br/>\nПредложение «В нашем классе а учеников» - содержит переменную а. Оно также не является высказывание. Но если вместо переменной а подставить различные значения, то получатся верные и неверные высказывания.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-73/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '3ae2b7107d00b14372bdbbfe8234b1f457d1897ec8e02b98bdf69c95d649a67b', '5', NULL, 'прочитай предложение с переменной k:"число k делится на 5". при каких значениях k оно истинно, а при каких-ложно');

    VALUES (v_textbook_id, 73, '3', 2, 'Прочитай предложение с переменной. Приведи значение переменной, при котором это предложение становится: А) Верным высказыванием; Б) Неверным высказыванием. 1) Город х расположен в России. 2) Гриб k съедобен. 3) Сумма n + 4 равно 9. 4) Разность b – 3 меньше 7. 5) Число с делится на 5. 6) Число d при делении на 4 даёт остаток 3.', '</p>\n\n<p class="text">Прочитай предложение с переменной. Приведи значение переменной, при котором это предложение становится: <br/>\nА) Верным высказыванием; <br/>\nБ) Неверным высказыванием.<br/>\n<br/>\n1) Город х расположен в России.<br/>\n2) Гриб k съедобен.<br/>\n3) Сумма n + 4 равно 9.<br/>\n4) Разность b – 3 меньше 7.<br/>\n5) Число с делится на 5.<br/>\n6) Число d при делении на 4 даёт остаток 3.\n</p>', 'А) Становится верным высказыванием. 1) Город Новосибирск расположен в России. 2) Гриб Белый съедобен. 3) Сумма 5 + 4 равно 9. 4) Разность 7 – 3 меньше 7. 5) Число 25 делится на 5. 6) число 15 при делении на 4 даёт остаток 3. Б) Становится ложным высказыванием. 1) Город Нью-Йорк расположен в России. 2) Гриб Мухомор съедобен. 3) Сумма 6 + 4 равно 9. 4) Разность 10 – 3 меньше 7. 5) Число 27 делится на 5. 6) Число 18 при делении на 4 даёт остаток 3.', '<p>\nА) Становится верным высказыванием.<br/>\n<br/>\n1) Город Новосибирск расположен в России.<br/>\n2) Гриб Белый съедобен.<br/>\n3) Сумма 5 + 4 равно 9.<br/>\n4) Разность 7 – 3 меньше 7.<br/>\n5) Число 25 делится на 5.<br/>\n6) число 15 при делении на 4 даёт остаток 3.<br/>\n<br/>\nБ) Становится ложным высказыванием.<br/>\n<br/>\n1) Город Нью-Йорк расположен в России.<br/>\n2) Гриб Мухомор съедобен.<br/>\n3) Сумма 6 + 4 равно 9.<br/>\n4) Разность 10 – 3 меньше 7.<br/>\n5) Число 27 делится на 5.<br/>\n6) Число 18 при делении на 4 даёт остаток 3.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-73/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '0a4c6a782abdbb8b7f413b5303e382e3efa9656fb3853eb65d04b2209d24d55d', '1,2,3,4,5,6,7,9', '["сумма","разность","меньше","равно","раз","остаток"]'::jsonb, 'прочитай предложение с переменной. приведи значение переменной, при котором это предложение становится:а) верным высказыванием; б) неверным высказыванием. 1) город х расположен в россии. 2) гриб k съедобен. 3) сумма n+4 равно 9. 4) разность b-3 меньше 7. 5) число с делится на 5. 6) число d при делении на 4 даёт остаток 3');

    VALUES (v_textbook_id, 73, '4', 3, 'Придумай несколько верных и несколько неверных высказываний.', '</p>\n\n<p class="text">Придумай несколько верных и несколько неверных высказываний.\n</p>', 'Верные высказывания: 1) В русском алфавите 33 буквы. 2) В светофоре знаки трёх цветов: красный, зеленый, желтый. 3) Город Москва – столица России. Неверные высказывания: 1) Результат деления называется произведением. 2) Мяч – это предмет кубической формы. 3) Мягкий знак указывает на твердость предшествующего согласного.', '<p>\nВерные высказывания:<br/>\n1) В русском алфавите 33 буквы.<br/>\n2) В светофоре знаки трёх цветов: красный, зеленый, желтый.<br/>\n3) Город Москва – столица России.<br/>\n<br/>\nНеверные высказывания:<br/>\n1) Результат деления называется произведением.<br/>\n2) Мяч – это предмет кубической формы.<br/>\n3) Мягкий знак указывает на твердость предшествующего согласного.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-73/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '954c6405a456f6774708b8c1d81a2594d2de0dded3c3620a8a46901312fac4f2', NULL, NULL, 'придумай несколько верных и несколько неверных высказываний');

    VALUES (v_textbook_id, 74, '5', 0, 'Является ли выражение 7 ⋅ 23 – 36 высказыванием? Дополни его так, чтобы получилось: А) верное высказывание; Б) неверное высказывание.', '</p>\n\n<p class="text">\nЯвляется ли выражение 7 ⋅ 23 – 36 высказыванием? Дополни его так, чтобы получилось:<br/>\nА) верное высказывание;<br/>\nБ) неверное высказывание.\n</p>', 'Выражение не является высказывание. А) Верное высказывание: «Значение выражения 7 ⋅ 23 – 36 равно 125». Б) Неверное высказывание: «Значение выражения 7 ⋅ 23 – 36 больше 200»', '<p>\nВыражение не является высказывание.<br/>\nА) Верное высказывание: «Значение выражения 7 ⋅ 23 – 36 равно 125».<br/>\nБ) Неверное высказывание: «Значение выражения 7 ⋅ 23 – 36 больше 200»\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-74/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'bfc60fd61a7733b589583a9393d148908b8447935631e369ccc0b4cdc4603085', '7,23,36', NULL, 'является ли выражение 7 ⋅ 23-36 высказыванием? дополни его так, чтобы получилось:а) верное высказывание; б) неверное высказывание');

    VALUES (v_textbook_id, 74, '6', 1, 'Прочитай выражения: 14 – 5; 14 – 7; 14 – 9; 14 – 6; 14 – 8; 14 – 10. Используя переменную а, составь выражение, объединяющее все шесть числовых выражений в одно.', '</p>\n\n<p class="text">\nПрочитай выражения:<br/>\n14 – 5;<br/>\n14 – 7;<br/>\n14 – 9;<br/>\n14 – 6;<br/>\n14 – 8;<br/>\n14 – 10.<br/>\nИспользуя переменную а, составь выражение, объединяющее все шесть числовых выражений в одно.\n</p>', '14 – 5: Уменьшаемое 14, вычитаемое – 5; 14 – 7: Уменьшаемое 14, вычитаемое – 7; 14 – 9: Уменьшаемое 14, вычитаемое – 9; 14 – 6: Уменьшаемое 14, вычитаемое – 6; 14 – 8: Уменьшаемое 14, вычитаемое – 8; 14 – 10: Уменьшаемое 14, вычитаемое – 10. Выражение, объединяющее все шесть числовых выражений: 14 – х, где х = {5, 7, 9, 6, 8, 10}.', '<p>\n14 – 5: Уменьшаемое 14, вычитаемое – 5;<br/>\n14 – 7: Уменьшаемое 14, вычитаемое – 7;<br/>\n14 – 9: Уменьшаемое 14, вычитаемое – 9;<br/>\n14 – 6: Уменьшаемое 14, вычитаемое – 6;<br/>\n14 – 8: Уменьшаемое 14, вычитаемое – 8;<br/>		\n14 – 10: Уменьшаемое 14, вычитаемое – 10.<br/>\n<br/>\nВыражение, объединяющее все шесть числовых выражений: 14 – х, где х = {5, 7, 9, 6, 8, 10}.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-74/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '515bf18e71f3c0d5cb4271d9e1bacf2e781a3669fe554788cb33a85f91328517', '5,6,7,8,9,10,14', NULL, 'прочитай выражения:14-5; 14-7; 14-9; 14-6; 14-8; 14-10. используя переменную а, составь выражение, объединяющее все шесть числовых выражений в одно');

    VALUES (v_textbook_id, 74, '7', 2, 'Какие значения можно подставить вместо переменной у в выражение 36 : у, чтобы 36 делилось на у без остатка? Как в этом случае называют число 36, число у?', '</p>\n\n<p class="text">Какие значения можно подставить вместо переменной у в выражение 36 : у, чтобы 36 делилось на у без остатка? Как в этом случае называют число 36, число у?\n</p>', 'Делится без остатка: 36 : у, где у = {1, 2, 3, 4, 6, 9, 12, 18, 36}. Тогда, 36 – делимое, а у – делитель.', '<p>\nДелится без остатка:<br/>		\n36 : у, где у = {1, 2, 3, 4, 6, 9, 12, 18, 36}.<br/>		\nТогда, 36 – делимое, а у – делитель.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-74/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4aea0b50606f2127fcfb8284c0eb915a0b74efd45d809d3a600922a6105a0e5d', '36', NULL, 'какие значения можно подставить вместо переменной у в выражение 36:у, чтобы 36 делилось на у без остатка? как в этом случае называют число 36, число у');

    VALUES (v_textbook_id, 74, '8', 3, 'Выполни деление с остатком и сделай проверку: А) 38 : 5; Б) 63 : 8; В) 523 : 10; Г) 7459 : 100; Д) 440 : 60; Е) 780 : 90; Ж) 5200 : 160; З) 7500 : 120.', '</p>\n\n\n<p class="text">\nВыполни деление с остатком и сделай проверку:<br/>	\nА) 38 : 5;<br/>	\nБ) 63 : 8;<br/>	\nВ) 523 : 10;<br/>	\nГ) 7459 : 100;<br/>	\nД) 440 : 60;<br/>	\nЕ) 780 : 90;<br/>	\nЖ) 5200 : 160;<br/>	\nЗ) 7500 : 120.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica74-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 74, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 74, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-74/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica74-nomer8.jpg', 'peterson/3/part2/page74/task8_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'be0f9d61cd82254810c227f81a40f55cfa6fa8dacb5cee01713c49b0d646cfe8', '5,8,10,38,60,63,90,100,120,160', NULL, 'выполни деление с остатком и сделай проверку:а) 38:5; б) 63:8; в) 523:10; г) 7459:100; д) 440:60; е) 780:90; ж) 5200:160; з) 7500:120');

    VALUES (v_textbook_id, 74, '9', 4, 'Вася задумал число, умножил его на 2, разделил на 10, умножил на 14 и вычел 18. В ответе у него получилось 52. Какое число задумал Вася?', '</p>\n\n<p class="text">Вася задумал число, умножил его на 2, разделил на 10, умножил на 14 и вычел 18. В ответе у него получилось 52. Какое число задумал Вася?\n</p>', 'Вася задумал число х. Он произвел с ними такие действия: 1) умножить на 2, т.е. (⋅ 2); 2) разделить на 10, т.е. (: 10); 3) умножил на 14, т.е, (⋅ 14); 4) вычел 18, т.е. (- 18). В результате получил число 52. Значит, чтобы найти искомое число, нужно с результатом выполнить обратные действия. Тогда, 52 + 18 = 70; 70 : 14 = 5; 5 ⋅ 10 = 50; 50 : 2 = 25. Ответ: было задумано число 25.', '<p>\nВася задумал число х.<br/>\nОн произвел с ними такие действия:<br/>\n1) умножить на 2, т.е. (⋅ 2);<br/>\n2) разделить на 10, т.е. (: 10);<br/>\n3) умножил на 14, т.е, (⋅ 14);<br/>\n4) вычел 18, т.е. (- 18).<br/>\nВ результате получил число 52.<br/>\nЗначит, чтобы найти искомое число, нужно с результатом выполнить обратные действия.<br/>	\nТогда, <br/>\n52 + 18 = 70;<br/>\n70 : 14 = 5;<br/>\n5 ⋅ 10 = 50;<br/>\n50 : 2 = 25.<br/>\nОтвет: было задумано число 25.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-74/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7d6ea4d5c8904928be2886275107834385129bc587e076ea06b4b87fed7db0b2', '2,10,14,18,52', '["раздели","раз"]'::jsonb, 'вася задумал число, умножил его на 2, разделил на 10, умножил на 14 и вычел 18. в ответе у него получилось 52. какое число задумал вася');

    VALUES (v_textbook_id, 74, '10', 5, 'В первом саду росло 12 яблонь и 7 груш. Во втором – 50 деревьев, из которых 14 груш, а остальные яблони. Сколько всего яблонь в обоих садах? Сколько в них груш? Каких деревьев больше и на сколько? Что еще можно узнать исходя из условия задачи?', '</p>\n\n<p class="text">В первом саду росло 12 яблонь и 7 груш. Во втором – 50 деревьев,  из которых 14 груш, а остальные яблони. Сколько всего яблонь в обоих садах? Сколько в них груш? Каких деревьев больше и на сколько? Что еще можно узнать исходя из условия задачи?</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica74-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 74, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 74, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-74/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica74-nomer10.jpg', 'peterson/3/part2/page74/task10_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'ea6d940d9524713f7b788aafa8e402cc44b98f55b504ab804d9ff95a2d1e6115', '7,12,14,50', '["больше"]'::jsonb, 'в первом саду росло 12 яблонь и 7 груш. во втором-50 деревьев, из которых 14 груш, а остальные яблони. сколько всего яблонь в обоих садах? сколько в них груш? каких деревьев больше и на сколько? что еще можно узнать исходя из условия задачи');

    VALUES (v_textbook_id, 74, '11', 6, 'Составь программу действий и вычисли: А) (92 578 + 3206 ⋅ 8 – (50 010 – 3215) ⋅ 90; Б) (42 071 – 970 ⋅ 40) ⋅ 7000 – 48 000 : 80 + 256 740 ⋅ 600.', '</p>\n\n<p class="text">Составь программу действий и вычисли:<br/>\nА) (92 578 + 3206 ⋅ 8 – (50 010 – 3215) ⋅ 90;<br/>\nБ) (42 071 – 970 ⋅ 40) ⋅ 7000 – 48 000 : 80 + 256 740 ⋅ 600.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica74-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 74, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 74, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-74/')
