    VALUES (v_textbook_id, 74, '12', 7, 'Найди значения выражений при данных значениях а. Перенеси в тетрадь и заполни таблицу:', '</p>\n\n<p class="text">Найди значения выражений при данных значениях а. Перенеси в тетрадь и заполни таблицу:</p>\n\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica74-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 74, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 74, номер 12, год 2022."/>\n</div>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica74-nomer12-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 74, номер 12-1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 74, номер 12-1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-74/')
