    VALUES (v_task_id, v_textbook_id, 3, '95808c107c73a4fc4a31c6cd6e6f20f375dfe9fcaead59a9b1c16212f2ad0f6e', NULL, '["найди","заполни"]'::jsonb, 'найди значения выражений при данных значениях а. перенеси в тетрадь и заполни таблицу');

    VALUES (v_textbook_id, 74, '13', 8, 'Верно ли высказывании: «Существуют три последовательных натуральных числа, сумма которых равна 70»?', '</p>\n\n<p class="text">Верно ли высказывании: «Существуют три последовательных натуральных числа, сумма которых равна 70»?\n</p>', 'Такого быть не может, потому что сложение никаких трех последовательных однозначных чисел не образует десяток. 0 + 1 + 2 = 3; 1 + 2 + 3 = 6; 2 + 3 + 4 = 9. Хотя есть такая комбинация: 9 + 0 + 1 = 10, но 19 + 20 + 21 = 60; 29 + 30 + 31 = 90. Вывод: таких чисел не существует. Ответ: высказывание неверное.', '<p>\nТакого быть не может, потому что сложение никаких трех последовательных однозначных чисел не образует десяток.<br/>\n0 + 1 + 2 = 3;<br/>\n1 + 2 + 3 = 6;<br/>\n2 + 3 + 4 = 9.<br/>\nХотя есть такая комбинация: 9 + 0 + 1 = 10, но<br/>\n19 + 20 + 21 = 60;<br/>\n29 + 30 + 31 = 90.<br/>\nВывод: таких чисел не существует.<br/>\nОтвет: высказывание неверное.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-74/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '9eaa017b5111a2460fbc78cce5d8560435a927ed0da0ebbc0e39141646fcb58e', '70', '["сумма"]'::jsonb, 'верно ли высказывании:"существуют три последовательных натуральных числа, сумма которых равна 70"');

    VALUES (v_textbook_id, 75, '1', 0, 'Найди истинные и ложные высказывания. Что общего в высказываниях каждого столбика? Как их можно назвать? А) 35 : 5 = 6; Б) 27 = 3 ⋅ 9; В) 14 + 56 = 56 + 14; Г) 62 ⋅ 408 = 804 ⋅ 62; Д) 91 < 91; Е) 18 760 > 18 670; Ж) 32 + 85 < 58 + 32; З) 54 ⋅ 16 > 16 ⋅ 49.', '</p>\n\n<p class="text">\nНайди истинные и ложные высказывания. Что общего в высказываниях каждого столбика? Как их можно назвать?<br/>\nА) 35 : 5 = 6;<br/>\nБ) 27 = 3 ⋅ 9;<br/>\nВ) 14 + 56 = 56 + 14;<br/>\nГ) 62 ⋅ 408 = 804 ⋅ 62;<br/>\nД) 91 &lt; 91;<br/>\nЕ) 18 760 &gt; 18 670;<br/>\nЖ) 32 + 85 &lt; 58 + 32;<br/>\nЗ) 54 ⋅ 16 &gt; 16 ⋅ 49.\n</p>', 'А) 35 : 5 = 6 – ложное, потому что 35 : 5 = 7; Б) 27 = 3 ⋅ 9 – истинное ; В) 14 + 56 = 56 + 14 – истинное по переместительному свойству; Г) 62 ⋅ 408 = 804 * 62 – ложное, потому что только 62 ⋅ 408 = 408 ⋅ 62; Д) 91 < 91 – неверно, потому что 91 = 91; Е) 18 760 > 18 670, истинно; Ж) 32 + 85 < 58 + 32, ложно, потому что 117 > 90; З) 54 ⋅ 16 > 16 ⋅ 49, истинно. В первом столбце выражения со знаком равно. Равенства. Во втором столбце выражения со знаками > или <. Неравенства.', '<p>\nА) 35 : 5 = 6 – ложное, потому что 35 : 5 = 7;<br/>		\nБ) 27 = 3 ⋅ 9 – истинное	;<br/>\nВ) 14 + 56 = 56 + 14 – истинное по переместительному свойству;<br/>\nГ) 62 ⋅ 408 = 804 * 62 – ложное, потому что только 62 ⋅ 408 = 408 ⋅ 62;<br/>	\nД) 91 &lt; 91 – неверно, потому что 91 = 91;<br/>\nЕ) 18 760 &gt; 18 670, истинно;<br/>\nЖ) 32 + 85 &lt; 58 + 32, ложно, потому что 117 &gt; 90;<br/>\nЗ) 54 ⋅ 16 &gt; 16 ⋅ 49, истинно.<br/>\nВ первом столбце выражения со знаком равно. Равенства.<br/>\nВо втором столбце выражения со знаками &gt; или &lt;. Неравенства.\n</p>', 'Равенство и неравенство Равенством называют два выражения, соединенных знаком =. В неравенствах два выражения соединены знаками > или <.', '<div class="recomended-block">\n<span class="title">Равенство и неравенство</span>\n<p>\n<b class="black">Равенством</b> называют два выражения, соединенных знаком =.<br/>\nВ <b class="black">неравенствах</b> два выражения соединены знаками &gt; или &lt;.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-75/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd2e38821235eba89c2fc2333990969173de38f1345ec9a23f9a8aa7f7938bff5', '3,5,6,9,14,16,18,27,32,35', '["найди","столбик"]'::jsonb, 'найди истинные и ложные высказывания. что общего в высказываниях каждого столбика? как их можно назвать? а) 35:5=6; б) 27=3 ⋅ 9; в) 14+56=56+14; г) 62 ⋅ 408=804 ⋅ 62; д) 91<91; е) 18 760>18 670; ж) 32+85<58+32; з) 54 ⋅ 16>16 ⋅ 49');

    VALUES (v_textbook_id, 75, '2', 1, 'Найди равенства и неравенства. Какие из них являются истинными, а какие – ложными? 18 + 37 = 37 + 18; 45 ⋅ 30 < 45 ⋅ 20; 84 – 35 > 84 – 45; 90 – 16 = 70 – 16; 256 : 64 = 320 : 64; 432 : 48 < 432 : 54.', '</p>\n\n<p class="text">\nНайди равенства и неравенства. Какие из них являются истинными, а какие – ложными?<br/>\n18 + 37 = 37 + 18;<br/>\n45 ⋅ 30 &lt; 45 ⋅ 20;<br/>\n84 – 35 &gt; 84 – 45;<br/>\n90 – 16 = 70 – 16;<br/>\n256 : 64 = 320 : 64;<br/>\n432 : 48 &lt; 432 : 54.\n</p>', 'Равенства: 18 + 37 = 37 + 18 – истинно по переместительному свойству; 90 – 16 = 70 – 16 – ложно, потому что 74 ≠ 54; 256 : 64 = 320 : 64 – ложно, потому что 4 ≠ 5. Неравенства: 45 ⋅ 30 < 45 ⋅ 20 – ложно, потому что 45 ⋅ 30 > 45 ⋅ 20; 84 – 35 > 84 – 45 – истинно; 432 : 48 < 432 : 54 – ложно, потому что 9 > 8.', '<p>\nРавенства:<br/>\n18 + 37 = 37 + 18 – истинно по переместительному свойству;<br/>\n90 – 16 = 70 – 16 – ложно, потому что 74 ≠ 54;<br/>\n256 : 64 = 320 : 64 – ложно, потому что 4 ≠ 5.<br/>\n<br/>\nНеравенства:<br/>\n45 ⋅ 30 &lt; 45 ⋅ 20 – ложно, потому что 45 ⋅ 30 &gt; 45 ⋅ 20;<br/>\n84 – 35 &gt; 84 – 45 – истинно;<br/>\n432 : 48 &lt; 432 : 54 – ложно, потому что 9 &gt; 8.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-75/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'c0b375afbf441b94a0c0685a9217ed703b5299ca61e434ae7579021c38f74986', '16,18,20,30,35,37,45,48,54,64', '["найди"]'::jsonb, 'найди равенства и неравенства. какие из них являются истинными, а какие-ложными? 18+37=37+18; 45 ⋅ 30<45 ⋅ 20; 84-35>84-45; 90-16=70-16; 256:64=320:64; 432:48<432:54');

    VALUES (v_textbook_id, 75, '3', 2, 'Укажи множество значений переменной, при которых верно равенство или неравенство: а * 1 = а; х + 6 = 15; k < 4; b ⋅ 0 = 1; у ⋅ (у – 3) = 0; n > 0.', '</p>\n\n<p class="text">\nУкажи множество значений переменной, при которых верно равенство или неравенство:<br/>\nа * 1 = а;<br/>\nх + 6 = 15;<br/>\nk &lt; 4;<br/>\nb ⋅ 0 = 1;<br/>\nу ⋅ (у – 3) = 0;<br/>\nn &gt; 0.\n</p>', 'а ⋅ 1 = а, при любых значениях а; х + 6 = 15, при х = 9; k < 4, при k = {0, 1, 2, 3}; b ⋅ 0 = 1, нет таких значений переменной b; у ⋅ (у – 3) = 0, при у = 3; n > 0, при любых значениях переменной n кроме 0.', '<p>\nа ⋅ 1 = а, при любых значениях а;<br/>	\nх + 6 = 15, при х = 9;<br/>\nk &lt; 4, при k = {0, 1, 2, 3};<br/>\n<br/>\nb ⋅ 0 = 1, нет таких значений переменной b;<br/>\nу ⋅ (у – 3) = 0, при у = 3;<br/>\nn &gt; 0, при любых значениях переменной n кроме 0.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-75/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '56c412b423aa23dc31d93425d363cff2eb303174b2edd1879efd174fe3ca7c80', '0,1,3,4,6,15', NULL, 'укажи множество значений переменной, при которых верно равенство или неравенство:а*1=а; х+6=15; k<4; b ⋅ 0=1; у ⋅ (у-3)=0; n>0');

    VALUES (v_textbook_id, 75, '4', 3, 'Запиши в виде равенства предложения: А) 5 больше 3 на 2; Б) 7 меньше 8 на 1; В) 12 больше 2 в 6 раз; Г) 4 меньше 20 в 5 раз; Д) а больше b в 4 раза; Е) х меньше у на 3; Ж) m больше n на 10; З) k меньше t в 7 раз.', '</p>\n\n<p class="text">Запиши в виде равенства предложения:<br/>\nА) 5 больше 3 на 2;<br/>\nБ) 7 меньше 8 на 1;<br/>\nВ) 12 больше 2 в 6 раз;<br/>\nГ) 4 меньше 20 в 5 раз;<br/>\nД) а больше b в 4 раза;<br/>\nЕ) х меньше у на 3;<br/>\nЖ) m больше n на 10;<br/>\nЗ) k меньше t в 7 раз.\n</p>', 'А) 5 – 3 = 2; Б) 8 – 7 = 1; В) 12 : 2 = 6; Г) 20 : 4 = 5; Д) а : b = 4; Е) у – х = 3; Ж) m – n = 10; З) t : k = 7.', '<p>\nА) 5 – 3 = 2;<br/>\nБ) 8 – 7 = 1;<br/>\nВ) 12 : 2 = 6;<br/>\nГ) 20 : 4 = 5;<br/>\nД) а : b = 4;<br/>\nЕ) у – х = 3;<br/>\nЖ) m – n = 10;<br/>\nЗ) t : k = 7.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-75/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd882fd4c793d9692868ebfbb151062ef3c721f17f8f1e0de93736f491418e41c', '1,2,3,4,5,6,7,8,10,12', '["больше","меньше","раз","раза"]'::jsonb, 'запиши в виде равенства предложения:а) 5 больше 3 на 2; б) 7 меньше 8 на 1; в) 12 больше 2 в 6 раз; г) 4 меньше 20 в 5 раз; д) а больше b в 4 раза; е) х меньше у на 3; ж) m больше n на 10; з) k меньше t в 7 раз');

    VALUES (v_textbook_id, 76, '5', 0, 'А) Таня сказала, что для всех значений переменной х верно равенство 2 ⋅ х + 3 = 11. Как опровергнуть слова Тани? Б) Валера сказал, что для некоторых значений k неравенство k + 24 < k + 25. Как доказать, что Валера не прав?', '</p>\n\n<p class="text">\nА) Таня сказала, что для всех значений переменной х верно равенство 2 ⋅ х + 3 = 11. Как опровергнуть слова Тани?<br/>\nБ) Валера сказал, что для некоторых значений k неравенство k + 24 &lt; k + 25. Как доказать, что Валера не прав?\n</p>', 'А) 2 ⋅ х + 3 = 11. Значение этого равенства верно при х = 4, ведь 2 ⋅ 4 + 3 = 11. А при х = 5, равенство будет неверно, потому что 2 ⋅ 5 + 3 ≠ 11. Вывод: не при любых значениях переменной равенство будет верно. Б) k + 24 < k + 25. Значение этого неравенства верно при любых значениях k, потому что при сложении двух слагаемых одно из которых одинаковое, сумма будет больше там, где второе слагаемое больше. Вывод: неравенство будет верно при любых значениях переменной.', '<p>\nА) 2 ⋅ х + 3 = 11.\nЗначение этого равенства верно при х = 4, ведь 2 ⋅ 4 + 3 = 11.<br/>\nА при х = 5, равенство будет неверно, потому что 2 ⋅ 5 + 3 ≠ 11.<br/>\nВывод: не при любых значениях переменной равенство будет верно.<br/>\n<br/>\nБ) k + 24 &lt; k + 25.<br/>\nЗначение этого неравенства верно при любых значениях k, потому что при сложении двух слагаемых одно из которых одинаковое, сумма будет больше там, где второе слагаемое больше.<br/>\nВывод: неравенство будет верно при любых значениях переменной.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-76/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'a877afc8f1fe3711d76827bdfd598e53211debd2795fe09a447f4a201c2c01ad', '2,3,11,24,25', NULL, 'а) таня сказала, что для всех значений переменной х верно равенство 2 ⋅ х+3=11. как опровергнуть слова тани? б) валера сказал, что для некоторых значений k неравенство k+24<k+25. как доказать, что валера не прав');

    VALUES (v_textbook_id, 76, '6', 1, 'Найди среди записей: 1) Выражения; 2) Высказывания; 3) Предложения с переменными; 4) равенства; 5) неравенства. А. 8 + 12 = 20; Б. 8 + 12 + 20; В. 8 + 12 > 20; Г. 20 = 8 + 12; Д. а > b; Е. а – b; Ж. а + b = с; З. а + b ⋅ c.', '</p>\n\n<p class="text">\nНайди среди записей: <br/>\n1) Выражения; <br/>\n2) Высказывания; <br/>\n3) Предложения с переменными; <br/>\n4) равенства; <br/>\n5) неравенства.<br/>\n<br/>\nА. 8 + 12 = 20;<br/>\nБ. 8 + 12 + 20;<br/>\nВ. 8 + 12 &gt; 20;<br/>\nГ. 20 = 8 + 12;<br/>\nД. а &gt; b;<br/>\nЕ. а – b;<br/>\nЖ. а + b = с;<br/>\nЗ. а + b ⋅ c.\n</p>', '1) Выражения: б, е, з; 2) Высказывания: а, в, г, ж; 3) Предложения с переменными: д, е, ж, з; 4) Равенства: а, г, ж; 5) Неравенства: в, д.', '<p>\n1) Выражения: б, е, з;<br/>\n2) Высказывания: а, в, г, ж;<br/>\n3) Предложения с переменными:  д, е, ж, з;<br/>\n4) Равенства: а, г, ж;<br/>\n5) Неравенства: в, д.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-76/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '610477067d39f85a453f1f69c46a572128799a2a49700edfa811c16377e90fe9', '1,2,3,4,5,8,12,20', '["найди"]'::jsonb, 'найди среди записей:1) выражения; 2) высказывания; 3) предложения с переменными; 4) равенства; 5) неравенства. а. 8+12=20; б. 8+12+20; в. 8+12>20; г. 20=8+12; д. а>b; е. а-b; ж. а+b=с; з. а+b ⋅ c');

    VALUES (v_textbook_id, 76, '7', 2, 'Митя поймал с окуней, а Коля – d окуней. Сколько окуней поймали они вместе? Составь выражений. Найди его значение, если: А) с = 27, d = 3; Б) с = 16, d = 8; В) с = 28, d = 14.', '</p>\n\n<p class="text">\nМитя поймал с окуней, а Коля – d окуней. Сколько окуней поймали они вместе?<br/>\nСоставь выражений. Найди его значение, если:<br/>\nА) с = 27, d = 3;<br/>\nБ) с = 16, d = 8;<br/>\nВ) с = 28, d = 14.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica76-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 76, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 76, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-76/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica76-nomer7.jpg', 'peterson/3/part2/page76/task7_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '3e662c2ff123cd851587294485b7b64590507b36e90d74b1d581d9596a6d954f', '3,8,14,16,27,28', '["найди"]'::jsonb, 'митя поймал с окуней, а коля-d окуней. сколько окуней поймали они вместе? составь выражений. найди его значение, если:а) с=27, d=3; б) с=16, d=8; в) с=28, d=14');

    VALUES (v_textbook_id, 76, '8', 3, 'Чему равен периметр треугольника со сторонами а см, b см и с см? Составь выражение. Найди его значение, если: 1) а = 25, b = 37 и с = 49; 2) а = 451, b = 394 и с = 673.', '</p>\n\n<p class="text">\nЧему равен периметр треугольника со сторонами а см, b см и с см? Составь выражение. Найди его значение, если:<br/>\n1) а = 25, b = 37 и с = 49;<br/>\n2) а = 451, b = 394 и с = 673.\n</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica76-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 76, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 76, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-76/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica76-nomer8.jpg', 'peterson/3/part2/page76/task8_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'a16797311be744ab4b62b868c6ac5a557d3fda590fb067bdf33f860b0b846cdc', '1,2,25,37,49,394,451,673', '["найди","периметр","сторона"]'::jsonb, 'чему равен периметр треугольника со сторонами а см, b см и с см? составь выражение. найди его значение, если:1) а=25, b=37 и с=49; 2) а=451, b=394 и с=673');

    VALUES (v_textbook_id, 76, '9', 4, 'А) За 6 м ткани заплатили 1680 р. Сколько надо заплатить за 9 м такой ткани? Б) В 5 одинаковых ящиков разложили 60 кг винограда. Сколько таких ящиков потребуется, чтобы разложить в них 84 кг винограда?', '</p>\n\n<p class="text">\nА) За 6 м ткани заплатили 1680 р. Сколько надо заплатить за 9 м такой ткани?<br/>\nБ) В 5 одинаковых ящиков разложили 60 кг винограда. Сколько таких ящиков потребуется, чтобы разложить в них 84 кг винограда?\n</p>', 'А)', '<p>\nА)\n</p>\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica76-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 76, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 76, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-76/')
    RETURNING id INTO v_task_id;

