    VALUES (v_textbook_id, 76, '10', 5, 'Выполни деление и сделай проверку: А) 3612 : 2; Б) 27 420 : 3; В) 224 320 : 4; Г) 453 750 : 50; Д) 527 400 : 600; Е) 6 792 800 : 70.', '</p>\n\n<p class="text">\nВыполни деление и сделай проверку:<br/>\nА) 3612 : 2;<br/>\nБ) 27 420 : 3;<br/>\nВ) 224 320 : 4;<br/>\nГ) 453 750 : 50;<br/>\nД) 527 400 : 600;<br/>\nЕ) 6 792 800 : 70.\n</p>', '', '<div class="img-wrapper-460">\n<img width="750" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica76-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 76, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 76, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-76/')
