    VALUES (v_textbook_id, 76, '11', 6, 'К Саше на день рождения прилетели 5 инопланетян. Их было на 2 меньше, чем его одноклассников, и на одного больше, чем родственников. Сколько всего гостей собралось у Саши, если других гостей не было?', '</p>\n\n<p class="text">К Саше на день рождения прилетели 5 инопланетян. Их было на 2 меньше, чем его одноклассников, и на одного больше, чем родственников. Сколько всего гостей собралось у Саши, если других гостей не было?</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica76-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 76, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 76, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-76/')
