    VALUES (v_textbook_id, 78, '8', 1, 'Алик, Боря и Витя решали пример 641 920 : 8. У них получились разные ответы. Проверь их решения и найди правильный ответ. Какие ошибки допущены в остальных решениях?', '</p>\n\n<p class="text">Алик, Боря и Витя решали пример 641 920 : 8. У них получились разные ответы. Проверь их решения и найди правильный ответ. Какие ошибки допущены в остальных решениях?\n</p>', 'Решение Алика: пропустил 0 в разряде тысяч, потому что ответ – пятизначное число. Цифра десятков подобрана неверно, потому что 32 : 8 = 4. Решение Бори: цифра десятков тысяч определена верно, потому что остаток равен делителю, значит, цифра десятков тысяч не максимальная. Ноль в конце записи делимого не приписан к частному. Решение Вити: верное, потому что количество знаков в частном определено верно.', '<p>\nРешение Алика: пропустил 0 в разряде тысяч, потому что ответ – пятизначное число. Цифра десятков подобрана неверно, потому что 32 : 8 = 4.<br/>\nРешение Бори: цифра десятков тысяч определена верно, потому что остаток равен делителю, значит, цифра десятков тысяч не максимальная. Ноль в конце записи делимого не приписан к частному.<br/>\nРешение Вити: верное, потому что количество знаков в частном определено верно.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-78/')
    RETURNING id INTO v_task_id;

