    VALUES (v_textbook_id, 80, '7', 5, 'Вырази в указанных единицах измерения: 7 ч 15 мин = … мин; 3 ч 26 мин 40 с = … с; 840 мин = … ч; 9 сут 8 ч = … ч.', '</p>\n\n<p class="text">\nВырази в указанных единицах измерения:<br/>\n7 ч 15 мин = … мин;<br/>\n3 ч 26 мин 40 с = … с;<br/>\n840 мин = … ч;<br/>\n9 сут 8 ч = … ч.\n</p>', '7 ч 15 мин = 420 мин + 15 мин = 435 мин; 3 ч 26 мин 40 с = 10 800 с + 1560 с + 40 с = 12 400 с; 840 мин = 840 : 60 = 14 ч; 9 сут 8 ч = 9 ⋅ 24 + 8 = 216 ч + 8 ч = 224 ч.', '<p>\n7 ч 15 мин = 420 мин + 15 мин = 435 мин;<br/>\n3 ч 26 мин 40 с = 10 800 с + 1560 с + 40 с = 12 400 с;<br/>\n840 мин = 840 : 60 = 14 ч;<br/>\n9 сут 8 ч = 9 ⋅ 24 + 8 = 216 ч + 8 ч = 224 ч.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-80/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '81c3992e1eeff97f1b68cc245c42b4e667b68c86c3c11f288ec994182bed6d6a', '3,7,8,9,15,26,40,840', '["раз"]'::jsonb, 'вырази в указанных единицах измерения:7 ч 15 мин=... мин; 3 ч 26 мин 40 с=... с; 840 мин=... ч; 9 сут 8 ч=... ч');

    VALUES (v_textbook_id, 80, '8', 6, 'Задача-шутка. Одно яйцо варится 4 мин. За какое наименьшее время можно сварить 6 яиц?', '</p>\n\n<p class="text">\nЗадача-шутка.<br/>\nОдно яйцо варится 4 мин. За какое наименьшее время можно сварить 6 яиц?\n</p>', 'Раз одно яйцо варится 4 мин, то любое количество яиц можно сварить за это время. Значит, чтобы сварить 6 яиц, нужно 4 минуты. Это наименьшее время, если в кастрюлю поместятся все шесть яиц за раз.', '<p>\nРаз одно яйцо варится 4 мин, то любое количество яиц можно сварить за это время.<br/>\nЗначит, чтобы сварить 6 яиц, нужно 4 минуты. Это наименьшее время, если в кастрюлю поместятся все шесть яиц за раз.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-80/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'f47c767019f666dd03b9459d5d4dde833a8889f28382e5a0439e96179d40d22e', '4,6', '["меньше"]'::jsonb, 'задача-шутка. одно яйцо варится 4 мин. за какое наименьшее время можно сварить 6 яиц');

    VALUES (v_textbook_id, 81, '1', 0, 'Реши уравнения с комментированием и сделай проверку: А) 37 + z = 34 ⋅ 9; Б) р : 50 = 2766 + 182; В) 640 – х = 414 : 6; Г) d ⋅ 70 = 50 785 – 1785; Д) k – 156 = 470 ⋅ 4; Е) 3200 : у = 640 : 160.', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:<br/>\nА) 37 + z = 34 ⋅ 9;<br/>\nБ) р : 50 = 2766 + 182;<br/>\nВ) 640 – х = 414 : 6;<br/>\nГ) d ⋅ 70 = 50 785 – 1785;<br/>\nД) k – 156 = 470 ⋅ 4;<br/>\nЕ) 3200 : у = 640 : 160.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica81-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 81, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 81, номер 1, год 2022."/>', 'Упрощение записи уравнений Уравнения новых видов иногда можно привести к уже известным . Например, числовое выражение в записи уравнения можно заменить значением этого выражения. Задача: Для класса купили 21 коробку карандашей по 10 штук в каждой коробке. Взяли 7 карандашей. Сколько сталось? Решение: пусть осталось у карандашей, тогда общее число карандашей равно 7 + у, или 10 ⋅ 21, значит: 7 + у = 10 ⋅ 21; 7 + у = 210; у = 210 – 7; у = 203. Ответ: осталось 203 карандаша. Таким образом, алгоритм решения уравнений, требующих упрощения записи , имеет следующий вид: 1. Найти значение числового выражения. 2. Определить неизвестный компонент действия. 3. Выбрать и применить правило его нахождения. 4. Выполнить действия. 5. При необходимости сделать проверку. 6. Назвать ответ.', '<div class="recomended-block">\n<span class="title">Упрощение записи уравнений</span>\n<p>\nУравнения новых видов иногда можно <b class="black">привести к уже известным</b>. Например, числовое выражение в записи уравнения можно заменить значением этого выражения.<br/>\n<br/>\nЗадача:<br/>\nДля класса купили 21 коробку карандашей по 10 штук в каждой коробке. Взяли 7 карандашей. Сколько сталось?<br/>\n<br/>\nРешение:\nпусть осталось у карандашей, тогда общее число карандашей равно 7 + у, или 10 ⋅ 21, значит:<br/>\n<br/>\n7 + у = 10 ⋅ 21;<br/>\n7 + у = 210;<br/>\nу = 210 – 7;<br/>\nу = 203.<br/>\nОтвет: осталось 203 карандаша.<br/>\n<br/>\nТаким образом, <b class="black">алгоритм решения уравнений, требующих упрощения записи</b>, имеет следующий вид:<br/>\n1. Найти значение числового выражения.<br/>\n2. Определить неизвестный компонент действия.<br/>\n3. Выбрать и применить правило его нахождения.<br/>\n4. Выполнить действия. <br/>\n5. При необходимости сделать проверку.<br/>\n6. Назвать ответ.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-81/')
    RETURNING id INTO v_task_id;

