    VALUES (v_textbook_id, 81, '2', 1, 'Запиши выражения: А) Сумма числа b и произведения чисел 8 и n. Б) Разность частного чисел d и 5 и числа р. В) Произведение суммы чисел р и 16 и частного чисел 5 и d. Г) частное произведения чисел а и 32 и разности чисел х и у.', '</p>\n\n<p class="text">\nЗапиши выражения:<br/>\nА) Сумма числа b и произведения чисел 8 и n.<br/>\nБ) Разность частного чисел d и 5 и числа р.<br/>\nВ) Произведение суммы чисел р и 16 и частного чисел 5 и d.<br/>\nГ) частное произведения чисел а и 32 и разности чисел х и у.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica81-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 81, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 81, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-81/')
