    VALUES (v_textbook_id, 82, '4', 1, 'Запиши выражения: А) Сумма числа b и произведения чисел 8 и n. Б) Разность частного чисел d и 5 и числа р. В) Произведение суммы чисел р и 16 и частного чисел 5 и d. Г) частное произведения чисел а и 32 и разности чисел х и у.', '</p>\n\n<p class="text">\nЗапиши выражения:<br/>\nА) Сумма числа b и произведения чисел 8 и n.<br/>\nБ) Разность частного чисел d и 5 и числа р.<br/>\nВ) Произведение суммы чисел р и 16 и частного чисел 5 и d.<br/>\nГ) частное произведения чисел а и 32 и разности чисел х и у.\n</p>', 'a) b + 8 ⋅ n; б) d : 5 – p; в) (р + 16) ⋅ (5 : d); г) (а ⋅ 32) : (х – у).', '<p>\na) b + 8 ⋅ n;<br/>\nб) d : 5 – p;<br/>\nв) (р + 16) ⋅ (5 : d);<br/>\nг) (а ⋅ 32) : (х – у).\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

