    VALUES (v_textbook_id, 82, '5', 2, 'Прочитай числа: 3 000 070, 3 000 700, 3 007 000, 3 070 000, 3 000 007, 3 700 000. Расположи их в порядке возрастания.', '</p>\n\n<p class="text">Прочитай числа: 3 000 070, 3 000 700, 3 007 000, 3 070 000, 3 000 007, 3 700 000. Расположи их в порядке возрастания.\n</p>', '3 000 070 – три миллиона семьдесят; 3 000 700 – три миллиона семьсот; 3 007 000 – три миллиона семь тысяч; 3 070 000 – три миллиона семьдесят тысяч; 3 000 007 – три миллиона семь; 3 700 000 – три миллиона семьсот тысяч; В порядке возрастания: 3 000 007, 3 000 070, 3 000 700, 3 007 000, 3 070 000, 3 700 000.', '<p>\n3 000 070 – три миллиона семьдесят;<br/>\n3 000 700 – три миллиона семьсот;<br/>\n3 007 000 – три миллиона семь тысяч;<br/>\n3 070 000 – три миллиона семьдесят тысяч;<br/>\n3 000 007 – три миллиона семь;<br/>\n3 700 000 – три миллиона семьсот тысяч;<br/>\nВ порядке возрастания: 3 000 007, 3 000 070, 3 000 700, 3 007 000, 3 070 000, 3 700 000.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

