    VALUES (v_textbook_id, 82, '6', 3, 'Запиши цифрами числа: А) семнадцать тысяч триста пять; Б) двести сорок семь тысяч девять; В) восемьдесят тысяч сто двадцать три; Г) девяносто тысяч четыре; Д) шесть миллионов двести; Е) пятьсот семьдесят миллионов сто тридцать девять тысяч семьсот сорок два; Ж) два миллиарда семь миллионов девятьсот тысяч один.', '</p>\n\n<p class="text">Запиши цифрами числа: <br/>\nА) семнадцать тысяч триста пять; <br/>\nБ) двести сорок семь тысяч девять; <br/>\nВ) восемьдесят тысяч сто двадцать три; <br/>\nГ) девяносто тысяч четыре; <br/>\nД) шесть миллионов двести; <br/>\nЕ) пятьсот семьдесят миллионов сто тридцать девять тысяч семьсот сорок два; <br/>\nЖ) два миллиарда семь миллионов девятьсот тысяч один.\n</p>', 'А) 17 305; Б) 247 010; В) 80 123; Г) 90 004; Д) 6 000 200; Е) 570 139 742; Ж) 2 007 900 001.', '<p>\nА) 17 305;<br/>\nБ) 247 010;<br/>\nВ) 80 123;<br/>\nГ) 90 004;<br/>\nД) 6 000 200;<br/>\nЕ) 570 139 742;<br/>\nЖ) 2 007 900 001.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

