    VALUES (v_textbook_id, 82, '8', 5, 'Выполни действия: А) 12 мин 23 с + 7 мин 52 с; Б) 6 ч 18 мин – 3 ч 49 мин; В) 2 сут 14 ч + 4 сут 15 ч; Г) 7 ч 36 мин + 4 ч 48 мин – 2 ч 39 мин; Д) 18 мин 16 с + 5 мин 4 с – 9 мин 52 с.', '</p>\n\n<p class="text">\nВыполни действия:<br/>\nА) 12 мин 23 с + 7 мин 52 с;<br/>\nБ) 6 ч 18 мин – 3 ч 49 мин;<br/>\nВ) 2 сут 14 ч + 4 сут 15 ч;<br/>\nГ) 7 ч 36 мин + 4 ч 48 мин – 2 ч 39 мин;<br/>\nД) 18 мин 16 с + 5 мин 4 с – 9 мин 52 с.\n</p>', 'А) 12 мин 23 с + 7 мин 52 с = 19 мин 75 с = 20 мин 15 с; Б) 6 ч 18 мин – 3 ч 49 мин = 5 ч 78 мин – 3 ч 49 мин = 2 ч 29 мин; В) 2 сут 14 ч + 4 сут 15 ч = 6 сут 29 ч = 7 сут 5 ч; Г) 7 ч 36 мин + 4 ч 48 мин – 2 ч 39 мин = 11 ч 84 мин – 2 ч 39 мин = 9 ч 45 мин; Д) 18 мин 16 с + 5 мин 4 с – 9 мин 52 с = 23 мин 20 с – 9 мин 52 с = 22 мин 80 с – 9 мин 52 с = 13 мин 28 с.', '<p>\nА) 12 мин 23 с + 7 мин 52 с = 19 мин 75 с = 20 мин 15 с;<br/>\nБ) 6 ч 18 мин – 3 ч 49 мин = 5 ч 78 мин – 3 ч 49 мин = 2 ч 29 мин;<br/>\nВ) 2 сут 14 ч + 4 сут 15 ч = 6 сут 29 ч = 7 сут 5 ч;<br/>\nГ) 7 ч 36 мин + 4 ч 48 мин – 2 ч 39 мин = 11 ч 84 мин – 2 ч 39 мин = 9 ч 45 мин;<br/>\nД) 18 мин 16 с + 5 мин 4 с – 9 мин 52 с = 23 мин 20 с – 9 мин 52 с = 22 мин 80 с – 9 мин 52 с = 13 мин 28 с.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'af85b0b66a509a493950df64989d5134b7c3042c11eb8a571e67a53d006c3b37', '2,3,4,5,6,7,9,12,14,15', NULL, 'выполни действия:а) 12 мин 23 с+7 мин 52 с; б) 6 ч 18 мин-3 ч 49 мин; в) 2 сут 14 ч+4 сут 15 ч; г) 7 ч 36 мин+4 ч 48 мин-2 ч 39 мин; д) 18 мин 16 с+5 мин 4 с-9 мин 52 с');

    VALUES (v_textbook_id, 82, '9', 6, 'Расположи стрелки часов так, чтобы они показывали: А) 9 ч 25 мин; Б) Половину второго; В) Без 10 минут шесть; Г) 20 минут девятого.', '</p>\n\n<p class="text">\nРасположи стрелки часов так, чтобы они показывали:<br/>\nА) 9 ч 25 мин;<br/>\nБ) Половину второго;<br/>\nВ) Без 10 минут шесть;<br/>\nГ) 20 минут девятого.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica82-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 82, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 82, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-82/')
