    VALUES (v_task_id, v_textbook_id, 3, '4ec30efa7e7923789200a841a1245cb87224639b6cda627bb1a9e7ce1af63f57', '9,10,20,25', NULL, 'расположи стрелки часов так, чтобы они показывали:а) 9 ч 25 мин; б) половину второго; в) без 10 минут шесть; г) 20 минут девятого');

    VALUES (v_textbook_id, 82, '10', 7, 'Напиши наименьшее и наибольшее пятизначное натуральное число, составленное из цифр 7, 9, 1, 3, 0 (цифры в записи числа не повторяются). Найди сумму и разность получившихся чисел.', '</p>\n\n<p class="text">\nНапиши наименьшее и наибольшее пятизначное натуральное число, составленное из цифр 7, 9, 1, 3, 0 (цифры в записи числа не повторяются). Найди сумму и разность получившихся чисел.\n</p>', 'Наибольшее пятизначное число – 97130; Наименьшее пятизначное число – 10379; 97 130 – 10 379 = 86 931; 97 130 + 10 379 = 107 689.', '<p>\nНаибольшее пятизначное число – 97130;<br/>\nНаименьшее пятизначное число – 10379;<br/>\n97 130 – 10 379 = 86 931;<br/>\n97 130 + 10 379 = 107 689.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '74948b5688e46640e3ceb63f910e4bae64b3959f94c8322b00dc786714cff254', '0,1,3,7,9', '["найди","разность","больше","меньше","раз"]'::jsonb, 'напиши наименьшее и наибольшее пятизначное натуральное число, составленное из цифр 7, 9, 1, 3, 0 (цифры в записи числа не повторяются). найди сумму и разность получившихся чисел');

    VALUES (v_textbook_id, 83, '1', 0, 'Сравни уравнения: m ⋅ 4 = 28 и (х – 5) ⋅ 4 = 28. Чем они похожи и чем отличаются? Реши их сделай вывод.', '</p>\n\n<p class="text">Сравни уравнения: m ⋅ 4 = 28 и (х – 5) ⋅ 4 = 28.<br/>\nЧем они похожи и чем отличаются? Реши их сделай вывод.\n</p>', 'Рассмотрев уравнения, можно заметить, что в первом уравнении сразу понятно, чем является компонент х и как его обнаружить. А во втором уравнении неизвестный компонент не отдельная переменная, а вся сумма в скобках. Для того, чтобы сравнить уравнения, нужно упростить второе уравнение: (х – 5) ⋅ 4 = 28; х – 5 = 28 : 4; х – 5 = 7; х = 5 + 7; х = 12; m ⋅ 4 = 28; m = 28 : 4; m = 7.', '<p>\nРассмотрев уравнения, можно заметить, что в первом уравнении сразу понятно, чем является компонент х и как его обнаружить. А во втором уравнении неизвестный компонент не отдельная переменная, а вся сумма в скобках.<br/>\n<br/>\nДля того, чтобы сравнить уравнения, нужно упростить второе уравнение:<br/>\n(х – 5) ⋅ 4 = 28;<br/>\nх – 5 = 28 : 4;<br/>\nх – 5 = 7;<br/>\nх = 5 + 7;<br/>\nх = 12;<br/>\n<br/>\nm ⋅ 4 = 28;<br/>\nm = 28 : 4;<br/>\nm = 7.\n</p>', 'Составные уравнения уравнения, решение которого сводится к решению цепочки простых уравнений, мы будем называть составным . Пример: Уравнение (х + 3) : 8 = 5 можно решать так: 1. Слева записано частное (последнее действие – деление). Неизвестно делимое х + 3. Чтобы найти неизвестное делимое, надо делитель умножить на частное. х + 3 = 8 ⋅ 5. 2. Упростим правую часть уравнения: х + 3 = 40. 3. Найдем неизвестное слагаемое: х = 40 – 3; х = 37. В более сложных составных уравнениях указанные шаги могут повторяться.', '<div class="recomended-block">\n<span class="title">Составные уравнения</span>\n<p>\nуравнения, решение которого сводится к решению цепочки простых уравнений, мы будем называть <b class="black">составным</b>.<br/>\n<br/>\nПример:<br/>\nУравнение (х + 3) : 8 = 5 можно решать так:<br/>\n1. Слева записано частное (последнее действие – деление). Неизвестно делимое х + 3. Чтобы найти неизвестное делимое, надо делитель умножить на частное.<br/>\nх + 3 = 8 ⋅ 5.<br/>\n2. Упростим правую часть уравнения:<br/>\nх + 3 = 40.<br/>\n3. Найдем неизвестное слагаемое:<br/>\nх = 40 – 3;<br/>\nх = 37.<br/>\nВ более сложных составных уравнениях указанные шаги могут повторяться.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-83/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd121b741a33746909d95266aa4544f3c82fd63b3081bec46d7025c04059fcd7e', '4,5,28', '["реши","сравни"]'::jsonb, 'сравни уравнения:m ⋅ 4=28 и (х-5) ⋅ 4=28. чем они похожи и чем отличаются? реши их сделай вывод');

    VALUES (v_textbook_id, 83, '2', 1, 'Реши уравнения с комментированием и сделай проверку: А) (у – 5) ⋅ 4 = 28; Б) 3 ⋅ а – 7 = 14; В) (24 + d) : 8 = 7; Г) k : 5 + 8 = 17; Д) 63 : (14 – х) = 7; Е) 32 – 16 : n = 30.', '</p>\n\n<p class="text">\nРеши уравнения с комментированием и сделай проверку:<br/>\nА) (у – 5) ⋅ 4 = 28;<br/>\nБ) 3 ⋅ а – 7 = 14;<br/>\nВ) (24 + d) : 8 = 7;<br/>\nГ) k : 5 + 8 = 17;<br/>\nД) 63 : (14 – х) = 7;<br/>\nЕ) 32 – 16 : n = 30.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica83-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 83, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 83, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-83/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica83-nomer2.jpg', 'peterson/3/part2/page83/task2_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'fb6cc673cd0fd4784192912c0dfd5ffe6fca0e2a210318307447453d7549f5cc', '3,4,5,7,8,14,16,17,24,28', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:а) (у-5) ⋅ 4=28; б) 3 ⋅ а-7=14; в) (24+d):8=7; г) k:5+8=17; д) 63:(14-х)=7; е) 32-16:n=30');

    VALUES (v_textbook_id, 83, '3', 2, 'Реши уравнения: (4 ⋅ b – 16) : 2 = 10; (2 + х : 7) ⋅ 8 = 72; 35 : (15 – у : 8) = 5.', '</p>\n\n<p class="text">\nРеши уравнения:<br/>\n(4 ⋅ b – 16) : 2 = 10;<br/>\n(2 + х : 7) ⋅ 8 = 72;<br/>\n35 : (15 – у : 8) = 5.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica83-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 83, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 83, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-83/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica83-nomer3.jpg', 'peterson/3/part2/page83/task3_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '6dd6b4fd86ab49cabd583cf6c3ad67f642c897f5876acb05828db1d5f37f6b22', '2,4,5,7,8,10,15,16,35,72', '["реши"]'::jsonb, 'реши уравнения:(4 ⋅ b-16):2=10; (2+х:7) ⋅ 8=72; 35:(15-у:8)=5');

    VALUES (v_textbook_id, 83, '4', 3, 'Запиши число, которое в n раз больше суммы чисел b и 6. Найди это число, если n = 7, b = 9.', '</p>\n\n<p class="text">\nЗапиши число, которое в n раз больше суммы чисел b и 6. Найди это число, если n = 7, b = 9.\n</p>', '(b + 6) ⋅ n; При n = 7, b = 9; (9 + 6) ⋅ 7 = 15 ⋅ 7 = 105; Ответ: при n = 7 и b = 9, число, которое в n раз больше суммы чисел b и 6 – 105.', '<p>\n(b + 6) ⋅ n;<br/>\nПри n = 7, b = 9;<br/>\n(9 + 6) ⋅ 7 = 15 ⋅ 7 = 105;<br/>\nОтвет: при n = 7 и b = 9, число, которое в n раз больше суммы чисел b и 6 – 105.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-83/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '8d38f2e7acbd3bf6a5c7c786dfa17d28a8731b63ebf113759135fcdddf589c71', '6,7,9', '["найди","больше","раз"]'::jsonb, 'запиши число, которое в n раз больше суммы чисел b и 6. найди это число, если n=7, b=9');

    VALUES (v_textbook_id, 83, '5', 4, 'Запиши число, которое: А) в 8 раз больше разности чисел а и 7; Б) в 5 раз меньше суммы чисел а и 18; В) на 4 больше, чем частное чисел а и 12; Г) на 9 меньше удвоенного числа а. Найди это число, если а = 12.', '</p>\n\n<p class="text">\nЗапиши число, которое:<br/>\nА) в 8 раз больше разности чисел а и 7;<br/>\nБ) в 5 раз меньше суммы чисел а и 18;<br/>\nВ) на 4 больше, чем частное чисел а и 12;<br/>\nГ) на 9 меньше удвоенного числа а.<br/>\nНайди это число, если а = 12.\n</p>', 'А) (а + 7) ⋅ 8, где а = 12: (12 + 7) ⋅ 8 = 19 ⋅ 8 = 162; Б) (а + 18) : 5, где а = 12: (12 + 18) : 5 = 30 : 5 = 6; В) а : 12 + 4, где а = 12: 12 : 12 + 4 = 1 + 4 = 5; Г) а ⋅ 2 – 9, где а = 12: 12 ⋅ 2 – 9 = 24 – 9 = 15.', '<p>\nА) (а + 7) ⋅ 8, где а = 12: (12 + 7) ⋅ 8 = 19 ⋅ 8 = 162;<br/>\nБ) (а + 18) : 5, где а = 12: (12 + 18) : 5 = 30 : 5 = 6;<br/>\nВ) а : 12 + 4, где а = 12: 12 : 12 + 4 = 1 + 4 = 5;<br/>\nГ) а ⋅ 2 – 9, где а = 12: 12 ⋅ 2 – 9 = 24 – 9 = 15.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-83/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '0aa037b03eec790eaa89517885a7ab39f39bdcd9c366284e6b0dcc1ca0589c5c', '4,5,7,8,9,12,18', '["найди","частное","больше","меньше","раз"]'::jsonb, 'запиши число, которое:а) в 8 раз больше разности чисел а и 7; б) в 5 раз меньше суммы чисел а и 18; в) на 4 больше, чем частное чисел а и 12; г) на 9 меньше удвоенного числа а. найди это число, если а=12');

    VALUES (v_textbook_id, 84, '6', 0, 'Самолёт пролетел 1840 км за 2 ч. За первый час он пролетел на 28 км больше, чем за второй. Сколько километров пролетел этот самолет за второй час?', '</p>\n\n<p class="text">Самолёт пролетел 1840 км за 2 ч. За первый час он пролетел на 28 км больше, чем за второй. Сколько километров пролетел этот самолет за второй час?</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica84-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 84, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 84, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-84/')
    RETURNING id INTO v_task_id;

