    VALUES (v_task_id, v_textbook_id, 3, '1b961d632822733c194bf5e799fda291afd8f4313dabc5ec0807d8a97d66f8f4', '2,28,1840', '["больше"]'::jsonb, 'самолёт пролетел 1840 км за 2 ч. за первый час он пролетел на 28 км больше, чем за второй. сколько километров пролетел этот самолет за второй час');

    VALUES (v_textbook_id, 84, '7', 1, 'А) (544 710 : 6 + (210 280 – 630 ⋅ 40); Б) (5409 ⋅ 80 + 560 490 : 7) : 3 + 84 096.', '</p>\n\n<p class="text">\nА) (544 710 : 6 + (210 280 – 630 ⋅ 40);<br/>\nБ) (5409 ⋅ 80 + 560 490 : 7) : 3 + 84 096.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica84-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 84, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 84, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-84/')
