    VALUES (v_task_id, v_textbook_id, 3, '89cd1784e3bb3a15e7cb406520c8d9414b106cb7ef44d2de94ffab1331c4b94c', '3,6,7,40,80,84,096,210,280,490', NULL, 'а) (544 710:6+(210 280-630 ⋅ 40); б) (5409 ⋅ 80+560 490:7):3+84 096');

    VALUES (v_textbook_id, 84, '8', 2, 'БЛИЦ турнир. А) У Коли а слив, а у Миши b слив. Они сложили их и поделили поровну. Сколько слив оказалось у каждого? Б) У Сергея а орехов, у Пети b орехов, а у Андрея с орехов. Они сложили их и поделили поровну. Сколько орехов оказалось у каждого? В) Одна дыня весит а кг, а другая на b кг легче. Сколько весят обе дыни вместе? Г) Три арбуза весят вместе а кг. Первый арбуз весит b кг, а второй на с кг тяжелее первого. Сколько весит третий арбуз? Д) Две тыквы весят а кг. Первая тыква весит b кг. Во сколько раз вторая тыква тяжелее первой?', '</p>\n\n<p class="text">\nБЛИЦ турнир.<br/>\nА) У Коли а слив, а у Миши b слив. Они сложили их и поделили поровну. Сколько слив оказалось у каждого?<br/>\nБ) У Сергея а орехов, у Пети b орехов, а у Андрея с орехов. Они сложили их и поделили поровну. Сколько орехов оказалось у каждого?<br/>\nВ) Одна дыня весит а кг, а другая на b кг легче. Сколько весят обе дыни вместе?<br/>\nГ) Три арбуза весят вместе а кг. Первый арбуз весит b кг, а второй на с кг тяжелее первого. Сколько весит третий арбуз?<br/>\nД) Две тыквы весят а кг. Первая тыква весит b кг. Во сколько раз вторая тыква тяжелее первой?\n</p>', 'А) (а + b) : 2; Б) (а + b + с) : 3; В) а + (а – b); Г) а – (b + (b – c)); Д) (а – b) : b.', '<p>\nА) (а + b) : 2;<br/>\nБ) (а + b + с) : 3;<br/>\nВ) а + (а – b);<br/>\nГ) а – (b + (b – c));<br/>\nД) (а – b) : b.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-84/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1c633d25778a43cfce05851fb3fe00f8d2c4aacd5f3d5ce58a4e5c3d0ff9bb1f', NULL, '["сложи","раз"]'::jsonb, 'блиц турнир. а) у коли а слив, а у миши b слив. они сложили их и поделили поровну. сколько слив оказалось у каждого? б) у сергея а орехов, у пети b орехов, а у андрея с орехов. они сложили их и поделили поровну. сколько орехов оказалось у каждого? в) одна дыня весит а кг, а другая на b кг легче. сколько весят обе дыни вместе? г) три арбуза весят вместе а кг. первый арбуз весит b кг, а второй на с кг тяжелее первого. сколько весит третий арбуз? д) две тыквы весят а кг. первая тыква весит b кг. во сколько раз вторая тыква тяжелее первой');

    VALUES (v_textbook_id, 84, '9', 3, 'Какие свойства арифметических действий выражают указанные равенства? Назови эти свойства. Что они означают? А + b = b + а; a ⋅ b = b ⋅ a; (a + b) + c = a + (b + c); (a ⋅ b) ⋅ c = a ⋅ (b ⋅ c); (a + b) ⋅ c = a ⋅ c + b ⋅ c; (a – b) ⋅ c = a ⋅ c – b ⋅ c.', '</p>\n\n<p class="text">\nКакие свойства арифметических действий выражают указанные равенства? Назови эти свойства. Что они означают?<br/>\nА + b = b + а;<br/>\na ⋅ b = b ⋅ a;<br/>\n(a + b) + c = a + (b + c);<br/>\n(a ⋅ b) ⋅ c = a ⋅ (b ⋅ c);<br/>\n(a + b) ⋅ c = a ⋅ c + b ⋅ c;<br/>\n(a – b) ⋅ c = a ⋅ c – b ⋅ c.\n</p>', 'a + b = b + а – от перестановки мест слагаемых значение суммы не меняется (переместительное свойство сложения); a ⋅ b = b ⋅ a – от перестановки мест множителей значение произведения не меняется (переместительное свойство умножения); (a + b) + c = a + (b + c) – чтобы к сумме прибавить число, можно это число прибавить к любому из слагаемых, а затем прибавить оставшееся слагаемое (сочетательное свойство сложения); (a ⋅ b) ⋅ c = a ⋅ (b ⋅ c) – при умножении произведения на число, можно на это число умножить любой множитель, а потом оставшийся множитель (сочетательное свойство умножения); (a + b) ⋅ c = a ⋅ c + b ⋅ c – чтобы суммы умножить на число, нужно это число умножить на каждое слагаемое, а полученные значения сложить (распределительное свойство умножения относительно сложения); (a – b) ⋅ c = a ⋅ c – b ⋅ c – при умножении разности на число, можно каждый из компонентов вычитания умножить на это число, а затем вычесть произведения друг из друга (распределительное свойство умножения относительно вычитания).', '<p>\na + b = b + а – от перестановки мест слагаемых значение суммы не меняется (переместительное свойство сложения);<br/>\na ⋅ b = b ⋅ a – от перестановки мест множителей значение произведения не меняется (переместительное свойство умножения);<br/>\n(a + b) + c = a + (b + c) – чтобы к сумме прибавить число, можно это число прибавить к любому из слагаемых, а затем прибавить оставшееся слагаемое (сочетательное свойство сложения);<br/>\n(a ⋅ b) ⋅ c = a ⋅ (b ⋅ c) – при умножении произведения на число, можно на это число умножить любой множитель, а потом оставшийся множитель (сочетательное свойство умножения);<br/>\n(a + b) ⋅ c = a ⋅ c + b ⋅ c – чтобы суммы умножить на число, нужно это число умножить на каждое слагаемое, а полученные значения сложить (распределительное свойство умножения относительно сложения);<br/>\n(a – b) ⋅ c = a ⋅ c – b ⋅ c – при умножении разности на число, можно каждый из компонентов вычитания умножить на это число, а затем вычесть произведения друг из друга (распределительное свойство умножения относительно вычитания).\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-84/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '0a21c4beaea80c18c3b35187aee61004a51270f76a6188a0a22206f660cc6b0f', NULL, NULL, 'какие свойства арифметических действий выражают указанные равенства? назови эти свойства. что они означают? а+b=b+а; a ⋅ b=b ⋅ a; (a+b)+c=a+(b+c); (a ⋅ b) ⋅ c=a ⋅ (b ⋅ c); (a+b) ⋅ c=a ⋅ c+b ⋅ c; (a-b) ⋅ c=a ⋅ c-b ⋅ c');

    VALUES (v_textbook_id, 84, '10', 4, 'Вычисли устно наиболее удобным способом. Обоснуй свой ответ. А) 56 + 56 + 56 + 56 + 56 + 56 + 56 + 56 + 56 + 56; Б) 398 + 7864 + 602 + 2136; В) 498 + 499 + 500 + 501 + 502; Г) 2 ⋅ (3794 ⋅ 5); Д) 879 ⋅ 7 + 879 ⋅ 3.', '</p>\n\n<p class="text">\nВычисли устно наиболее удобным способом. Обоснуй свой ответ.<br/>\nА) 56 + 56 + 56 + 56 + 56 + 56 + 56 + 56 + 56 + 56;<br/>\nБ) 398 + 7864 + 602 + 2136;<br/>\nВ) 498 + 499 + 500 + 501 + 502;<br/>\nГ) 2 ⋅ (3794 ⋅ 5);<br/>\nД) 879 ⋅ 7 + 879 ⋅ 3.\n</p>', 'А) 56 + 56 + 56 + 56 + 56 + 56 + 56 + 56 + 56 + 56 = 56 ⋅ 10 = 560, потому что сложение одинаковых слагаемых можно заменить умножением; Б) 398 + 7864 + 602 + 2136 = (398 + 602) + (2136 + 7864) = 1000 + 10 000 = 11 000 – по сочетательному свойству сложения; В) 498 + 499 + 500 + 501 + 502 = (498 + 502) + (499 + 501) + 500 = 1000 + 1000 + 500 = 2 500 – по сочетательному свойству сложения; Г) 2 ⋅ (3794 ⋅ 5) = (2 ⋅ 5) ⋅ 3794 = 10 ⋅ 3794 = 37 940 – по сочетательному свойству умножения.', '<p>\nА) 56 + 56 + 56 + 56 + 56 + 56 + 56 + 56 + 56 + 56 = 56 ⋅ 10 = 560, потому что сложение одинаковых слагаемых можно заменить умножением;<br/>\nБ) 398 + 7864 + 602 + 2136 = (398 + 602) + (2136 + 7864) = 1000 + 10 000 = 11 000 – по сочетательному свойству сложения;<br/>\nВ) 498 + 499 + 500 + 501 + 502 = (498 + 502) + (499 + 501) + 500 = 1000 + 1000 + 500 = 2 500 – по сочетательному свойству сложения;<br/>\nГ) 2 ⋅ (3794 ⋅ 5) = (2 ⋅ 5) ⋅ 3794 = 10 ⋅ 3794 = 37 940 – по сочетательному свойству умножения.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-84/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ae747dd336fb5aebecbfece54d3bc0bcbcb9a723d2da5f54d01ce94e5dad0ca3', '2,3,5,7,56,398,498,499,500,501', '["вычисли"]'::jsonb, 'вычисли устно наиболее удобным способом. обоснуй свой ответ. а) 56+56+56+56+56+56+56+56+56+56; б) 398+7864+602+2136; в) 498+499+500+501+502; г) 2 ⋅ (3794 ⋅ 5); д) 879 ⋅ 7+879 ⋅ 3');

    VALUES (v_textbook_id, 84, '11', 5, 'Для Вани, Толи и Миши есть три пирога: с рисом, капустой и яблоками. Миша не любит пироги с яблоками и не ест с капустой. Ваня не любит пироги с капустой, а Толя любит все пироги. Как им выбрать пироги, чтобы каждый получил пирог, который он любит?', '</p>\n\n<p class="text">\nДля Вани, Толи и Миши есть три пирога: с рисом, капустой и яблоками. Миша не любит пироги с яблоками и не ест с капустой. Ваня не любит пироги с капустой, а Толя любит все пироги. Как им выбрать пироги, чтобы каждый получил пирог, который он любит?\n</p>', 'Перечислим все условия: 1) Миша не любит пироги с яблоками и капустой; 2) Ваня не любит пироги с капустой; 3) Толя ест всё. По первому условию делаем вывод о том, что Миша ест пирог с рисом. По второму условию делаем вывод о том, что Ваня ест пирог с яблоком, потому что с капустой не любит, а с рисом ест Миша. По третьему условию делаем вывод о том, что Толя ест оставшийся пирог – я капустой. Ответ: Ваня – яблоки, Толя – с капустой, Миша – с рисом.', '<p>\nПеречислим все условия:<br/>\n1) Миша не любит пироги с яблоками и капустой;<br/>\n2) Ваня не любит пироги с капустой;<br/>\n3) Толя ест всё.<br/>\nПо первому условию делаем вывод о том, что Миша ест пирог с рисом.<br/>\nПо второму условию делаем вывод о том, что Ваня ест пирог с яблоком, потому что с капустой не любит, а с рисом ест Миша.<br/>\nПо третьему условию делаем вывод о том, что Толя ест оставшийся пирог – я капустой.<br/>\nОтвет: Ваня – яблоки, Толя – с капустой, Миша – с рисом.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-84/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '819ebb05b50b315df22edf2557add3efde8f5641f8fbe9f7d80a3c8428a70075', NULL, NULL, 'для вани, толи и миши есть три пирога:с рисом, капустой и яблоками. миша не любит пироги с яблоками и не ест с капустой. ваня не любит пироги с капустой, а толя любит все пироги. как им выбрать пироги, чтобы каждый получил пирог, который он любит');

    VALUES (v_textbook_id, 85, '1', 0, 'Составь 4 равенства из чисел: А) 7, 5, 12; Б) 9, 8 и 72. Построй для каждого случая графическую модель.', '</p>\n\n<p class="text">\nСоставь 4 равенства из чисел: <br/>\nА) 7, 5, 12; <br/>\nБ) 9, 8 и 72. <br/>\nПострой для каждого случая графическую модель.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica85-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 85, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 85, номер 1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-85/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica85-nomer1.jpg', 'peterson/3/part2/page85/task1_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '0e9d5adcf8580a57f19884c4c101810fca54067e0c29cc0a207cadf9118eb367', '4,5,7,8,9,12,72', NULL, 'составь 4 равенства из чисел:а) 7, 5, 12; б) 9, 8 и 72. построй для каждого случая графическую модель');

    VALUES (v_textbook_id, 85, '2', 1, 'Найди х в равенствах по образцу: 14 – х = а; x ⋅ 8 = с; x : b = 7; x + 3 = d; x – d = k; s : х = t. Образец: m : х = 25; х = m : 25.', '</p>\n\n<p class="text">\nНайди х в равенствах по образцу:<br/>\n14 – х = а;<br/>\nx ⋅ 8 = с;<br/>\nx : b = 7;<br/>\nx + 3 = d;<br/>\nx – d = k;<br/>\ns : х = t.<br/>\n<br/>\nОбразец: <br/>\nm : х = 25;<br/>\nх = m : 25.\n</p>', '14 – х = а; х = 14 – а; x ⋅ 8 = с; х = с : 8; x : b = 7; х = 7 ⋅ b; x + 3 = d; x = d – 3; x – d = k; x = d + k; s : х = t; x = s : t.', '<p>\n14 – х = а;<br/>\nх = 14 – а;<br/>\n<br/>\nx ⋅ 8 = с;<br/>\nх = с : 8;<br/>\n<br/>\nx : b = 7;<br/>\nх = 7 ⋅ b;<br/>\n<br/>\nx + 3 = d;<br/>\nx = d – 3;<br/>\n<br/>\nx – d = k;<br/>\nx = d + k;<br/>\n<br/>\ns : х = t;<br/>\nx = s : t.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-85/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'bae01d6b743100378c6a4ef11c561d40a914e0210daa2d59f03fc21f67973022', '3,7,8,14,25', '["найди","раз"]'::jsonb, 'найди х в равенствах по образцу:14-х=а; x ⋅ 8=с; x:b=7; x+3=d; x-d=k; s:х=t. образец:m:х=25; х=m:25');

    VALUES (v_textbook_id, 85, '3', 2, 'Реши уравнения и сделай проверку: а) (х ⋅ 3 + 5) : 4 = 8; б) 9 + 4 ⋅ (х – 2) = 21; в) 360 : (12 – х) – 15 = 25; г) 480 : (34 – х : 7 = 16.', '</p>\n\n<p class="text">\nРеши уравнения и сделай проверку:<br/>\nа) (х ⋅ 3 + 5) : 4 = 8;<br/>\nб) 9 + 4 ⋅ (х – 2) = 21;<br/>\nв) 360 : (12 – х) – 15 = 25;<br/>\nг) 480 : (34 – х : 7 = 16.\n</p>', '', '<div class="img-wrapper-460">\n<img width="650" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica85-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 85, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 85, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-85/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica85-nomer3.jpg', 'peterson/3/part2/page85/task3_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '4be7d155bbfd61702b2ee28ced94a5b2ec254a38f71ed0d44541a969e93b9305', '2,3,4,5,7,8,9,12,15,16', '["реши"]'::jsonb, 'реши уравнения и сделай проверку:а) (х ⋅ 3+5):4=8; б) 9+4 ⋅ (х-2)=21; в) 360:(12-х)-15=25; г) 480:(34-х:7=16');

    VALUES (v_textbook_id, 85, '4', 3, 'А) Солнце взошло в 5 ч 52 мин, а зашло в 18 ч 10 мин. Какова долгота дня? Б) Поезд был в пути 12 ч 38 мин. На станцию назначения он прибыл в 21 ч того же дня. В котором часу он вышел со станции отправления? В) Солдат встал на пост в 10 ч 45 мин и простоял на посту 1 ч 30 мин. В котором часу его сменили на посту?', '</p>\n\n<p class="text">\nА) Солнце взошло в 5 ч 52 мин, а зашло в 18 ч 10 мин. Какова долгота дня?<br/>\nБ) Поезд был в пути 12 ч 38 мин. На станцию назначения он прибыл в 21 ч того же дня. В котором часу он вышел со станции отправления?<br/>\nВ) Солдат встал на пост в 10 ч 45 мин и простоял на посту 1 ч 30 мин. В котором часу его сменили на посту?\n</p>', 'А) 18 ч 10 мин – 5 ч 52 мин = 17 ч 70 мин – 5 ч 52 мин = 12 ч 18 мин – долгота дня; Б) 21 ч 00 мин – 12 ч 38 мин = 20 ч 60 мин – 12 ч 38 мин = 8 ч 22 мин – он вышел со станции отправления; В) 10 ч 45 мин + 1 ч 30 мин = 11 ч 75 мин = 12 ч 15 мин – его сменили на посту.', '<p>\nА) 18 ч 10 мин – 5 ч 52 мин = 17 ч 70 мин – 5 ч 52 мин = 12 ч 18 мин – долгота дня;<br/>\nБ) 21 ч 00 мин – 12 ч 38 мин = 20 ч 60 мин – 12 ч 38 мин = 8 ч 22 мин – он вышел со станции отправления;<br/>\nВ) 10 ч 45 мин + 1 ч 30 мин = 11 ч 75 мин = 12 ч 15 мин – его сменили на посту.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-85/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '098b53624e7eb4e1504801b8d7f2cc64a51ff14201edf9f98fc4ab75f60c4c27', '1,5,10,12,18,21,30,38,45,52', NULL, 'а) солнце взошло в 5 ч 52 мин, а зашло в 18 ч 10 мин. какова долгота дня? б) поезд был в пути 12 ч 38 мин. на станцию назначения он прибыл в 21 ч того же дня. в котором часу он вышел со станции отправления? в) солдат встал на пост в 10 ч 45 мин и простоял на посту 1 ч 30 мин. в котором часу его сменили на посту');

    VALUES (v_textbook_id, 85, '5', 4, 'Вырази в указанных единицах измерения: 420 мин = … ч; 5 мин 24 с = … с; 9 ч 16 мин = … мин; 3 сут 18 ч = … ч; 1 ч 15 мин 54 с = … с; 6 сут 9 ч 20 мин = … мин.', '</p>\n\n<p class="text">\nВырази в указанных единицах измерения:<br/>\n420 мин = … ч;<br/>\n5 мин 24 с = … с;<br/>\n9 ч 16 мин = … мин;<br/>\n3 сут 18 ч = … ч;<br/>\n1 ч 15 мин 54 с = … с;<br/>\n6 сут 9 ч 20 мин = … мин.\n</p>', '420 мин = 7 ч, потому что 420 : 60 = 7; 5 мин 24 с = 60 ⋅ 5 + 24 = 324 с; 9 ч 16 мин = 9 ⋅ 60 + 16 = 540 + 16 = 556 мин; 3 сут 18 ч = 24 ⋅ 3 + 18 = 72 + 18 = 90 ч; 1 ч 15 мин 54 с = 60 ⋅ 60 + 15 ⋅ 60 + 54 = 3600 с + 900 с + 54 с = 4 554 с; 6 сут 9 ч 20 мин = 24 ⋅ 6 ⋅ 60 + 9 ⋅ 60 + 20 = 8 640 мин + 540 мин + 20 мин = 9 200 мин.', '<p>\n420 мин = 7 ч, потому что 420 : 60 = 7;<br/>\n5 мин 24 с = 60 ⋅ 5 + 24 = 324 с;<br/>\n9 ч 16 мин = 9 ⋅ 60 + 16 = 540 + 16 = 556 мин;<br/>\n3 сут 18 ч = 24 ⋅ 3 + 18 = 72 + 18 = 90 ч;<br/>\n1 ч 15 мин 54 с = 60 ⋅ 60 + 15 ⋅ 60 + 54 = 3600 с + 900 с + 54 с = 4 554 с;<br/>\n6 сут 9 ч 20 мин = 24 ⋅ 6 ⋅ 60 + 9 ⋅ 60 + 20 = 8 640 мин + 540 мин + 20 мин = 9 200 мин.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-85/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '308e8213d119cef03cca0557c1450fb77e053b90454654f16033ef70e98a9a9e', '1,3,5,6,9,15,16,18,20,24', '["раз"]'::jsonb, 'вырази в указанных единицах измерения:420 мин=... ч; 5 мин 24 с=... с; 9 ч 16 мин=... мин; 3 сут 18 ч=... ч; 1 ч 15 мин 54 с=... с; 6 сут 9 ч 20 мин=... мин');

    VALUES (v_textbook_id, 85, '6', 5, 'Составь программу действий и вычисли: А) 48 156 : 6 ⋅ 50 – (319 255 + 392 210 : 7); Б) 290 070 – (5026 + 2 018 400 : 400) ⋅ 8.', '</p>\n\n<p class="text">\nСоставь программу действий и вычисли:<br/>\nА) 48 156 : 6 ⋅ 50 – (319 255 + 392 210 : 7);<br/>\nБ) 290 070 – (5026 + 2 018 400 : 400) ⋅ 8.\n</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica85-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 85, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 85, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-85/')
    RETURNING id INTO v_task_id;

