    VALUES (v_textbook_id, 85, '7', 6, 'Из Лидова в кузьминки можно проехать на автобусе с пересадкой в Марьине или Сергеевке. Время движения автобуса между этими поселками указано на схеме. В Марьине приходится ждать автобуса 5 мин, а в Сергеевке – 15 мин. По какому пути быстрее проехать из Лидова в Кузьминки?', '</p>\n\n<p class="text">\nИз Лидова в кузьминки можно проехать на автобусе с пересадкой в Марьине или Сергеевке. Время движения автобуса между этими поселками указано на схеме.<br/>\nВ Марьине приходится ждать автобуса 5 мин, а в Сергеевке – 15 мин. По какому пути быстрее проехать из Лидова в Кузьминки?\n</p>', 'Чтобы попасть из Лидово в Кузьминки есть два пути: 1 путь: Лидово – Марьино – Кузьминки; Тогда, 1 ч 48 мин + 5 мин + 1 ч 15 мин = 1 ч 48 мин + 1 ч 20 мин = 2 ч 68 мин = 3 ч 8 мин. 2 путь: Лидово – Сергеевка – Кузьминки; Тогда, 1 ч 25 мин + 15 мин + 1 ч 35 мин = 1 ч 40 мин + 1 ч 35 мин = 2 ч 75 мин = 3 ч 15 мин. Вывод: быстрее проехать по пути 1 через Марьино.', '<p>\nЧтобы попасть из Лидово в Кузьминки есть два пути:<br/>\n1 путь: Лидово – Марьино – Кузьминки;<br/>\nТогда, 1 ч 48 мин + 5 мин + 1 ч 15 мин = 1 ч 48 мин + 1 ч 20 мин = 2 ч 68 мин = 3 ч 8 мин.<br/>\n2 путь: Лидово – Сергеевка – Кузьминки;<br/>\nТогда, 1 ч 25 мин + 15 мин + 1 ч 35 мин = 1 ч 40 мин + 1 ч 35 мин = 2 ч 75 мин = 3 ч 15 мин.<br/>\nВывод: быстрее проехать по пути 1 через Марьино.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-85/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '3d1d10247babce96d3e15bfaf343ac84a864f362908258a0f65c2afc4c502158', '5,15', NULL, 'из лидова в кузьминки можно проехать на автобусе с пересадкой в марьине или сергеевке. время движения автобуса между этими поселками указано на схеме. в марьине приходится ждать автобуса 5 мин, а в сергеевке-15 мин. по какому пути быстрее проехать из лидова в кузьминки');

    VALUES (v_textbook_id, 86, '8', 0, 'А) перенеси в тетрадь и заполни таблицу: Определи по таблице множество Е значений выражения 63 000 : а при данных значениях а. Б) Принадлежит ли множеству Е числа 9, 90 000? Сделай записи с помощью знаков.', '</p>\n\n<p class="text">\nА) перенеси в тетрадь  и заполни таблицу:\n</p>\n\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica86-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 86, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 86, номер 8, год 2022."/>\n</div>\n\n<p class="text">\nОпредели по таблице множество Е значений выражения 63 000 : а при данных значениях а.<br/>\nБ) Принадлежит ли множеству Е числа 9, 90 000? Сделай записи с помощью знаков.\n</p>', 'А)', '<p>\nА) \n</p>\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica86-nomer8-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 86, номер 8-1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 86, номер 8-1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-86/')
