    VALUES (v_textbook_id, 86, '9', 1, 'Составь выражение с переменной k: «Игорь решил 8 примеров, а Лёна – в k раз меньше. На сколько больше примеров решил Игорь, чем Лёня?». Запиши множество значений, которые может принимать k.', '</p>\n\n<p class="text">Составь выражение с переменной k:<br/>\n«Игорь решил 8 примеров, а Лёна – в k раз меньше. На сколько больше примеров решил Игорь, чем Лёня?».<br/> Запиши множество значений, которые может принимать k.\n</p>', '8 – 8 : k; k: {2, 4, 8}.', '<p>\n8 – 8 : k;<br/>\nk: {2, 4, 8}.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-86/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7c8035f686b7d77f6e0632f192f5ea662aefa0a7383813ec9a3f9bc01ffeda3c', '8', '["реши","больше","меньше","раз"]'::jsonb, 'составь выражение с переменной k:"игорь решил 8 примеров, а лёна-в k раз меньше. на сколько больше примеров решил игорь, чем лёня?". запиши множество значений, которые может принимать k');

    VALUES (v_textbook_id, 86, '10', 2, 'А) Какие значения может принимать переменная х в выражении 32 – 8 ⋅ х? Б) Какие значения может принимать переменная у в выражении 60 : (4 – у)?', '</p>\n\n<p class="text">\nА) Какие значения может принимать переменная х в выражении 32 – 8 ⋅ х?<br/>\nБ) Какие значения может принимать переменная у в выражении 60 : (4 – у)?\n</p>', 'А) 32 – 8 ⋅ х, где х: {0, 1, 2, 3, 4}; Б) 60 : (4 – у), где у: {0, 1, 2, 3}.', '<p>\nА) 32 – 8 ⋅ х, где х: {0, 1, 2, 3, 4};<br/>\nБ) 60 : (4 – у), где у: {0, 1, 2, 3}.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-86/')
    RETURNING id INTO v_task_id;

