    VALUES (v_task_id, v_textbook_id, 3, '4d5c760cf3db01a7e8f1bcdd8f6e7b1f7054091c67377cd12411053fcef68b66', '4,7', '["найди","реши","сравни","периметр","сторона"]'::jsonb, 'реши задачу:"сторона квадрата равна 7 дм. найди его периметр". проанализируй, какое правило используется здесь для решения? сравни его с равенством:р=а ⋅ 4. что могут обозначать переменные а, р? придумай свою задачу с этими же переменными');

