    VALUES (v_textbook_id, 88, '6', 2, 'А) Напиши формулы периметра и площади квадрата со стороной k; Б) Найди периметр и площадь квадрата со стороной 30 см; В) Найди площадь квадрата, периметр которого равен 36 дм.', '</p>\n\n<p class="text">\nА) Напиши формулы периметра и площади квадрата со стороной k;<br/>\nБ) Найди периметр и площадь квадрата со стороной 30 см;<br/>\nВ) Найди площадь квадрата, периметр которого равен 36 дм.\n</p>', 'А) Р = k ⋅ 4, S = k ⋅ k; Б) Р = 30 ⋅ 4 = 120 см, S = 30 ⋅ 30 = 900 см 2 ; В) Р = 36 дм, Р = а ⋅ 4, значит, а = 36 : 4 = 9 дм; S = 9 дм ⋅ 9 дм = 81 дм 2 .', '<p>\nА) Р = k ⋅ 4, S = k ⋅ k;<br/>\nБ) Р = 30 ⋅ 4 = 120 см, S = 30 ⋅ 30 = 900 см<sup>2</sup>;<br/>\nВ) Р = 36 дм, Р = а ⋅ 4, значит, а = 36 : 4 = 9 дм; S = 9 дм ⋅ 9 дм = 81 дм<sup>2</sup>.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-88/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'a2b10390d1dd214b7787d9a62460fef4e00f9488e967e204b9894e7f438ab5de', '30,36', '["найди","периметр","площадь"]'::jsonb, 'а) напиши формулы периметра и площади квадрата со стороной k; б) найди периметр и площадь квадрата со стороной 30 см; в) найди площадь квадрата, периметр которого равен 36 дм');

    VALUES (v_textbook_id, 88, '7', 3, 'Пусть сыну с лет, а отцу р лет. Отец старше сына на 21 год. Заполни в тетради таблицу. Как связаны между собой возраст отца р и возраст сына с? Составь формулу зависимости р от с. Во сколько раз отец старше сына, если отцу исполнилось 22 года, 24 года, 28 лет, 42 года?', '</p>\n\n<p class="text">Пусть сыну с лет, а отцу р лет. Отец старше сына на 21 год. Заполни в тетради таблицу. Как связаны между собой возраст отца р и возраст сына с? Составь формулу зависимости р от с.\n</p>\n\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica88-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 88, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 88, номер 7, год 2022."/>\n\n</div>\n<p class="text">\nВо сколько раз отец старше сына, если отцу исполнилось 22 года, 24 года, 28 лет, 42 года?\n</p>', 'с – возраст сына; р – возраст отца; с + 21 = р, потому что отец на 21 год старше сына; с = р – 21.', '<p>\nс – возраст сына;<br/>\nр – возраст отца;<br/>\nс + 21 = р, потому что отец на 21 год старше сына;<br/>\nс = р – 21.\n</p>\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica88-nomer7-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 88, номер 7-1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 88, номер 7-1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-88/')
    RETURNING id INTO v_task_id;

