    VALUES (v_task_id, v_textbook_id, 3, '2f165dfee49ac135cc65318ba4a390185928decb07dd5a1652fee196556492dc', '21,22,24,28,42', '["заполни","раз"]'::jsonb, 'пусть сыну с лет, а отцу р лет. отец старше сына на 21 год. заполни в тетради таблицу. как связаны между собой возраст отца р и возраст сына с? составь формулу зависимости р от с. во сколько раз отец старше сына, если отцу исполнилось 22 года, 24 года, 28 лет, 42 года');

    VALUES (v_textbook_id, 88, '8', 4, 'Рассмотри таблицы. Как связаны между собой переменные х и у? Составь формулу, выражающую у через х.', '</p>\n\n<p class="text">Рассмотри таблицы. Как связаны между собой переменные х и у? Составь формулу, выражающую у через х.</p>\n\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica88-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 88, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 88, номер 8, год 2022."/>\n</div>', 'А) х + 8 = у; 1 + 8 = 9; 2 + 8 = 10 и т.д. Б) х ⋅ 6 = у; 1 ⋅ 6 = 6; 2 ⋅ 6 = 12 и т.д.', '<p>\nА) х + 8 = у;<br/>\n1 + 8 = 9;<br/>\n2 + 8 = 10 и т.д.<br/>\n<br/>\nБ) х ⋅ 6 = у;<br/>\n1 ⋅ 6 = 6;<br/>\n2 ⋅ 6 = 12 и т.д.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-88/')
    RETURNING id INTO v_task_id;

