    VALUES (v_textbook_id, 88, '9', 5, 'Реши уравнения с комментированием и сделай проверку: А) 3 ⋅ (6 + а) = 45; Б) 12 – 40 : k = 4; В) (30 – n) : 2 = 9; Г) 7 ⋅ b – 15 = 6; Д) 20 : (х : 9) – 4 = 0; Е) (9 ⋅ t + 37) : 8 = 8.', '</p>\n\n<p class="text">\nРеши уравнения с комментированием и сделай проверку:<br/>\nА) 3 ⋅ (6 + а) = 45;<br/>\nБ) 12 – 40 : k = 4;<br/>\nВ) (30 – n) : 2 = 9;<br/>\nГ) 7 ⋅ b – 15 = 6;<br/>\nД) 20 : (х : 9) – 4 = 0;<br/>\nЕ) (9 ⋅ t + 37) : 8 = 8.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica88-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 88, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 88, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-88/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica88-nomer9.jpg', 'peterson/3/part2/page88/task9_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'e1781c36e2170a5424348b24d9b1ddbfb85f87931ec6a577cd8bf0b3cd3866d5', '0,2,3,4,6,7,8,9,12,15', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:а) 3 ⋅ (6+а)=45; б) 12-40:k=4; в) (30-n):2=9; г) 7 ⋅ b-15=6; д) 20:(х:9)-4=0; е) (9 ⋅ t+37):8=8');

    VALUES (v_textbook_id, 88, '10', 6, 'Выполни действия. Проверь результаты с помощью калькулятора. А) 326 714 – 250 ⋅ 3 + 25 946; Б) (38 056 – 5948) : 4 + 907 ⋅ 5', '</p>\n\n<p class="text">\nВыполни действия. Проверь результаты с помощью калькулятора.<br/>\nА) 326 714 – 250 ⋅ 3 + 25 946;<br/>\nБ) (38 056 – 5948) : 4 + 907 ⋅ 5\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica88-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 88, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 88, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-88/')
