    VALUES (v_textbook_id, 88, '11', 7, 'Найди в окружающей обстановке предметы формы куба. Сколько граней у куба? Сколько рёбер? Сколько вершин? Является ли куб прямоугольным параллелепипедом?', '</p>\n\n<p class="text">\nНайди в окружающей обстановке предметы формы куба. Сколько граней у куба? Сколько рёбер? Сколько вершин? Является ли куб прямоугольным параллелепипедом?\n</p>', 'Кубик из игры-ходилки, коробка с наклейками учителя, кубик лего. У куба 6 граней, 12 ребер и 8 вершин. Куб является прямоугольным параллелепипедом. Просто всего его грани равны, как и ребра.', '<p>\nКубик из игры-ходилки, коробка с наклейками учителя, кубик лего.<br/>\nУ куба 6 граней, 12 ребер и 8 вершин.<br/>\nКуб является прямоугольным параллелепипедом. Просто всего его грани равны, как и ребра.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-88/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'c072268f018ed78d92f0143f174e3bb24f6bc8c0ad82fa6a0cad2b8bda2559a8', NULL, '["найди"]'::jsonb, 'найди в окружающей обстановке предметы формы куба. сколько граней у куба? сколько рёбер? сколько вершин? является ли куб прямоугольным параллелепипедом');

    VALUES (v_textbook_id, 88, '12', 8, 'Из водопроводного крана надо набрать 4 л воды. Как это сделать, если имеются лишь два сосуда объемом 7 л и 5 л?', '</p>\n\n<p class="text">\nИз водопроводного крана надо набрать 4 л воды. Как это сделать, если имеются лишь два сосуда объемом 7 л и 5 л?\n</p>', '1) Налить сосуд в 7 литров; 2) Вылить в сосуд 5 литров; 3) Вылить воду из пятилитрового сосуда; 4) Оставшиеся 2 литра перелить в пятилитровый сосуд; 5) Набрать воду в семилитровый сосуд; 6) Перелить воду в сосуд 5 л. Тогда, в сосуде 7 литров останется 4 литра, потому что 7 – 3 = 4 л.', '<p>\n1) Налить сосуд в 7 литров;<br/>\n2) Вылить в сосуд 5 литров;<br/>\n3) Вылить воду из пятилитрового сосуда;<br/>\n4) Оставшиеся 2 литра перелить в пятилитровый сосуд;<br/>\n5) Набрать воду в семилитровый сосуд;<br/>\n6) Перелить воду в сосуд 5 л.<br/>\nТогда, в сосуде 7 литров останется 4 литра, потому что 7 – 3 = 4 л.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-88/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '0157ecf5ac56e258b314a8c75feeb0d54083d6478e1915cb40ab081f3d69a3c9', '4,5,7', NULL, 'из водопроводного крана надо набрать 4 л воды. как это сделать, если имеются лишь два сосуда объемом 7 л и 5 л');

    VALUES (v_textbook_id, 89, '1', 0, 'Реши задачи и напиши для них формулы: А) Длина коробки равна 4 дм, ширина – 3 дм, а высота – 5 дм. Чему равен объем этой коробки? Б) Алик склеил куб с ребром 9 см. Чему равен объем этого куба?', '</p>\n\n<p class="text">\nРеши задачи и напиши для них формулы:<br/>\nА) Длина коробки равна 4 дм, ширина – 3 дм, а высота – 5 дм. Чему равен объем этой коробки?<br/>\nБ) Алик склеил куб с ребром 9 см. Чему равен объем этого куба?\n</p>', 'А) V = a ⋅ b ⋅ c; V = 4 ⋅ 3 ⋅ 5 = 60 (дм 3 ) – объем прямоугольного параллелепипеда; Б) V = a ⋅ a ⋅ a; V = 9 ⋅ 9 ⋅ 9 = 81 ⋅ 9 = 729 (см 3 ) – объем куба.', '<p>\nА) V = a ⋅ b ⋅ c;<br/>\nV = 4 ⋅ 3 ⋅ 5 = 60 (дм<sup>3</sup>) – объем прямоугольного параллелепипеда;<br/>\nБ) V = a ⋅ a ⋅ a;<br/>\nV = 9 ⋅ 9 ⋅ 9 = 81 ⋅ 9 = 729 (см<sup>3</sup>) – объем куба.\n</p>', 'Формула объема прямоугольного параллелепипеда Форму прямоугольного параллелепипеда имеют многие предметы окружающей обстановки: коробки, кубики, шкаф и т.д. У прямоугольного параллелепипеда имеется 6 граней, 8 вершин и 12 рёбер. Но разную длину могут иметь лишь 3 ребра. Их называют измерениями прямоугольного параллелепипеда – длиной, шириной и высотой. Остальные рёбра равны либо длине, либо ширине, либо высоте (по 4 равных ребра для каждого измерения). Обозначим стороны основания прямоугольного параллелепипеда а и b, а высоту – с. Тогда на основание можно выставить а ⋅ b единичных кубиков, а по высоте выложить с таких слоёв. Значит, его объем V вычисляется по формуле: V = (a ⋅ b) ⋅ c или V = a ⋅ b ⋅ c. Объем прямоугольного параллелепипеда равен произведению трёх его измерений (длины, ширины и высоты). Прямоугольный параллелепипед, у которого все три измерения равны. Называется кубом. Объем куба вычисляются по формуле: V = a ⋅ a ⋅ a.', '<div class="recomended-block">\n<span class="title">Формула объема прямоугольного параллелепипеда</span>\n<p>\nФорму <b class="black">прямоугольного параллелепипеда</b> имеют многие предметы окружающей обстановки: коробки, кубики, шкаф и т.д.<br/>\nУ прямоугольного параллелепипеда имеется 6 граней, 8 вершин и 12 рёбер. Но разную длину могут иметь лишь 3 ребра. Их называют <b class="black">измерениями</b> прямоугольного параллелепипеда – длиной, шириной и высотой. Остальные рёбра равны либо длине, либо ширине, либо высоте (по 4 равных ребра для каждого измерения).<br/>\nОбозначим стороны основания прямоугольного параллелепипеда а и b, а высоту – с. Тогда на основание можно выставить а ⋅ b единичных кубиков, а по высоте выложить с таких слоёв. Значит, его объем V вычисляется по формуле:<br/>\nV = (a ⋅ b) ⋅ c или V = a ⋅ b ⋅ c.<br/>\n<b class="black">Объем прямоугольного параллелепипеда равен произведению трёх его измерений (длины, ширины и высоты).</b><br/>\nПрямоугольный параллелепипед, у которого все три измерения равны. Называется кубом. Объем куба вычисляются по формуле:<br/>\nV = a ⋅ a ⋅ a.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-89/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'f1f5267e1ac7421c20f4a480c250b4e80443f296d52151268fe7027ce1440f9e', '3,4,5,9', '["реши"]'::jsonb, 'реши задачи и напиши для них формулы:а) длина коробки равна 4 дм, ширина-3 дм, а высота-5 дм. чему равен объем этой коробки? б) алик склеил куб с ребром 9 см. чему равен объем этого куба');

    VALUES (v_textbook_id, 89, '2', 1, 'На модели прямоугольного параллелепипеда покажи грани, рёбра, вершины. Сколько граней, рёбер и вершин? Имеются ли равные рёбра, грани? Покажи их и сосчитай.', '</p>\n\n<p class="text">На модели прямоугольного параллелепипеда покажи грани, рёбра, вершины. Сколько граней, рёбер и вершин? Имеются ли равные рёбра, грани? Покажи их и сосчитай.</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica89-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 89, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 89, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-89/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica89-nomer2.jpg', 'peterson/3/part2/page89/task2_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '85a164d2a3e0d8d741bdee128386973c7453a0c9657af116397bfbaf20ebf911', NULL, NULL, 'на модели прямоугольного параллелепипеда покажи грани, рёбра, вершины. сколько граней, рёбер и вершин? имеются ли равные рёбра, грани? покажи их и сосчитай');

    VALUES (v_textbook_id, 89, '3', 2, 'По рисунку прямоугольного параллелепипеда назови: А) верхнюю и правую грани; Б) рёбра, равные ребру АМ; В) вершины, принадлежащие задней грани; Г) грань, равную ABCD.', '</p>\n\n<p class="text">По рисунку прямоугольного параллелепипеда назови: <br/>\nА) верхнюю и правую грани; <br/>\nБ) рёбра, равные ребру АМ; <br/>\nВ) вершины, принадлежащие задней грани; <br/>\nГ) грань, равную ABCD.\n</p>', 'А) Верхняя – MNPK, права – KPCD; Б) АМ = KD = PC = NB; В) N, P, C, B; Г) ABCD = MNPK.', '<p>\nА) Верхняя – MNPK, права – KPCD;<br/>\nБ) АМ = KD = PC = NB;<br/>\nВ) N, P, C, B;<br/>\nГ) ABCD = MNPK.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-89/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'bb1985eb022b265b7eaf01e6dca42382dcb7d2ef5ac53c785ae9049f5ab4bd72', NULL, NULL, 'по рисунку прямоугольного параллелепипеда назови:а) верхнюю и правую грани; б) рёбра, равные ребру ам; в) вершины, принадлежащие задней грани; г) грань, равную abcd');

    VALUES (v_textbook_id, 90, '4', 0, 'Найди по формуле объем прямоугольного параллелепипеда, если его измерения равны: А) а = 8 см, b = 10 см, с = 9 см; Б) а = 30 м, b = 20 м, с = 70 м; В) а = 2 дм, b = 70 см, с = 50 см. (Обрати внимание на единицы измерения.)', '</p>\n\n<p class="text">\nНайди по формуле объем прямоугольного параллелепипеда, если его измерения равны:<br/>\nА) а = 8 см, b = 10 см, с = 9 см;<br/>\nБ) а = 30 м, b = 20 м, с = 70 м;<br/>\nВ) а = 2 дм, b = 70 см, с = 50 см.<br/>\n(Обрати внимание на единицы измерения.)\n</p>', 'V = a ⋅ b ⋅ c. А) 8 ⋅ 10 ⋅ 9 = 720 см3; Б) 30 ⋅ 20 ⋅ 70 = 42 000 см3; В) 20 см ⋅ 70 см ⋅ 50 см = 70 см ⋅ 1000 см2 = 70 000 см3.', '<p>\nV = a ⋅ b ⋅ c.<br/>\nА) 8 ⋅ 10 ⋅ 9 = 720 см3;<br/>\nБ) 30 ⋅ 20 ⋅ 70 = 42 000 см3;<br/>\nВ) 20 см ⋅ 70 см ⋅ 50 см = 70 см ⋅ 1000 см2 = 70 000 см3.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-90/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'e96605b03726b7fa08316a1b59063926e0cf558e9809c69b1a7303a98b87809f', '2,8,9,10,20,30,50,70', '["найди"]'::jsonb, 'найди по формуле объем прямоугольного параллелепипеда, если его измерения равны:а) а=8 см, b=10 см, с=9 см; б) а=30 м, b=20 м, с=70 м; в) а=2 дм, b=70 см, с=50 см. (обрати внимание на единицы измерения.)');

    VALUES (v_textbook_id, 90, '5', 1, 'Каркас прямоугольного параллелепипеда сделан из проволоки. Его размеры указаны на рисунке. Сколько проволоки для него потребовалось?', '</p>\n\n<p class="text">\nКаркас прямоугольного параллелепипеда сделан из проволоки. Его размеры указаны на рисунке. Сколько проволоки для него потребовалось?\n</p>', 'Всего ребер 12 штук. 8 рёбер по 3 см. 4 ребра по 12 см. Тогда: 3 см ⋅ 8 + 12 см ⋅ 4 = 24 см + 48 см = 72 см.', '<p>\nВсего ребер 12 штук.<br/>\n8 рёбер по 3 см.<br/>\n4 ребра по 12 см.<br/>\nТогда: 3 см ⋅ 8 + 12 см ⋅ 4 = 24 см + 48 см = 72 см.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-90/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1ce057377a80cf7d4bcc7028e35dcfcdb34fd2a7785a914be667b2545e02fa87', NULL, '["раз"]'::jsonb, 'каркас прямоугольного параллелепипеда сделан из проволоки. его размеры указаны на рисунке. сколько проволоки для него потребовалось');

    VALUES (v_textbook_id, 90, '6', 2, 'Напиши формулу объема куба со стороной а. найди объем куба, если: 1) а = 4 см; 2) а = 60 м; 3) а = 900 см.', '</p>\n\n<p class="text">Напиши формулу объема куба со стороной а. найди объем куба, если: <br/>\n1) а = 4 см; <br/>\n2) а = 60 м; <br/>\n3) а = 900 см.\n</p>', 'V = a ⋅ a ⋅ a. 1) а = 4 см, V = 4 ⋅ 4 ⋅ 4 = 64 см3; 2) а = 60 см, V = 60 ⋅ 60 ⋅ 60 = 216 000 см3; 3) а = 900 см, V = 900 ⋅ 900 ⋅ 900 = 729 000 000 см3.', '<p>\nV = a ⋅ a ⋅ a.<br/>\n1) а = 4 см, V = 4 ⋅ 4 ⋅ 4 = 64 см3;<br/>\n2) а = 60 см, V = 60 ⋅ 60 ⋅ 60 = 216 000 см3;<br/>\n3) а = 900 см, V = 900 ⋅ 900 ⋅ 900 = 729 000 000 см3.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-90/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '913ef6a44cefb2d5ebb0f02a909637dcc65b4314e65da23cf9f26d5983ce1916', '1,2,3,4,60,900', '["найди"]'::jsonb, 'напиши формулу объема куба со стороной а. найди объем куба, если:1) а=4 см; 2) а=60 м; 3) а=900 см');

    VALUES (v_textbook_id, 90, '7', 3, 'Комната имеет форму прямоугольного параллелепипеда. Её высота равна 3 м, ширина 4 м, а длина 7 м. Чему равен объем этой комнаты? Найди площадь её пола, потолка, стен.', '</p>\n\n<p class="text">Комната имеет форму прямоугольного параллелепипеда. Её высота равна 3 м, ширина 4 м, а длина 7 м. Чему равен объем этой комнаты? Найди площадь её пола, потолка, стен.</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica90-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 90, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 90, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-90/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica90-nomer7.jpg', 'peterson/3/part2/page90/task7_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '12f38c2737a42fda8c339d8df29905450e4a9a513fd6fb923bcc432014a61be7', '3,4,7', '["найди","площадь"]'::jsonb, 'комната имеет форму прямоугольного параллелепипеда. её высота равна 3 м, ширина 4 м, а длина 7 м. чему равен объем этой комнаты? найди площадь её пола, потолка, стен');

    VALUES (v_textbook_id, 90, '8', 4, 'А) Найди сумму площадей всех граней прямоугольного параллелепипеда, если его измерения равны 5 см, 2 см и 3 см; Б) Напиши формулу площади поверхности прямоугольного параллелепипеда с измерениями a, b и с; В) Напиши формулу площади поверхности куба со стороной а.', '</p>\n\n<p class="text">\nА) Найди сумму площадей всех граней прямоугольного параллелепипеда, если его измерения равны 5 см, 2 см и 3 см;<br/>\nБ) Напиши формулу площади поверхности прямоугольного параллелепипеда с измерениями a, b и с;<br/>\nВ) Напиши формулу площади поверхности куба со стороной а.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica90-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 90, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 90, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-90/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica90-nomer8.jpg', 'peterson/3/part2/page90/task8_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '955bbd5cf1841979b39b79001ac81b00493eee67c792606e554db78380b14b04', '2,3,5', '["найди"]'::jsonb, 'а) найди сумму площадей всех граней прямоугольного параллелепипеда, если его измерения равны 5 см, 2 см и 3 см; б) напиши формулу площади поверхности прямоугольного параллелепипеда с измерениями a, b и с; в) напиши формулу площади поверхности куба со стороной а');

    VALUES (v_textbook_id, 90, '9', 5, 'Реши уравнения с комментированием и сделай проверку: 35 : у + 6 = 11; (4 + х) : 8 = 9; (9 ⋅ t – 14) : 4 = 10.', '</p>\n\n<p class="text">\nРеши уравнения с комментированием и сделай проверку:<br/>\n35 : у + 6 = 11;<br/>\n(4 + х) : 8 = 9;<br/>\n(9 ⋅ t – 14) : 4 = 10.\n</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica90-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 90, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 90, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-90/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica90-nomer9.jpg', 'peterson/3/part2/page90/task9_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '2e416b4d4c7e4fc26addb4ba2e76eb6a15705e2e480c653bd07dc7f889331fc2', '4,6,8,9,10,11,14,35', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:35:у+6=11; (4+х):8=9; (9 ⋅ t-14):4=10');

    VALUES (v_textbook_id, 90, '10', 6, 'При каких значениях а верны равенства? Объясни их смысл. а + 0 = 0 + а = а; а – 0 = а; а – а = 0; а : 1 = а; а : а = 1; 0 : а = 0; а ⋅ 1 = 1 ⋅ а = а; а ⋅ 0 = 0 ⋅ а = 0.', '</p>\n\n<p class="text">\nПри каких значениях а верны равенства? Объясни их смысл.<br/>\nа + 0 = 0 + а = а;<br/>\nа – 0 = а;<br/>\nа – а = 0;<br/>\n<br/>\nа : 1 = а;<br/>\nа : а = 1;<br/>\n0 : а = 0;<br/>\n<br/>\nа ⋅ 1 = 1 ⋅ а = а;<br/>\nа ⋅ 0 = 0 ⋅ а = 0.\n</p>', 'а + 0 = 0 + а = а – при любых значениях а, потому что если к числу прибавить ноль, то получится это же число; а – 0 = а – при любых значениях а, потому что если любое число уменьшить на 0, то получится это же число; а – а = 0 – при любых значениях а, потому что при вычитании числа из самого себя всегда получается ноль; а : 1 = а – при любых значениях а, потому что при делении любого числ анна единицу получается это же число; а : а = 1 – при любых значениях а, потому что при делении любого числа на само себя получается единица; 0 : а = 0 – при любых значениях а кроме нуля, потому что на ноль делить нельзя; а ⋅ 1 = 1 ⋅ а = а – при любых значениях а, потому что при умножении любого числа на единицу, получается это же число; а ⋅ 0 = 0 ⋅ а = 0 – при любых значениях а, потому что при умножении любого числа на ноль получается ноль.', '<p>\nа + 0 = 0 + а = а – при любых значениях а, потому что если к числу прибавить ноль, то получится это же число;<br/>\nа – 0 = а – при любых значениях а, потому что если любое число уменьшить на 0, то получится это же число;<br/>\nа – а = 0 – при любых значениях а, потому что при вычитании числа из самого себя всегда получается ноль;<br/>\n<br/>\nа : 1 = а – при любых значениях а, потому что при делении любого числ анна единицу получается это же число;<br/>\nа : а = 1 – при любых значениях а, потому что при делении любого числа на само себя получается единица;<br/>\n0 : а = 0 – при любых значениях а кроме нуля, потому что на ноль делить нельзя;<br/>\n<br/>\nа ⋅ 1 = 1 ⋅ а = а – при любых значениях а, потому что при умножении любого числа на единицу, получается это же число;<br/>\nа ⋅ 0 = 0 ⋅ а = 0 – при любых значениях а, потому что при умножении любого числа на ноль получается ноль.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-90/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'db9429f0db93e5eb8da97ae7950a18264403cd1a9832edbc1fd4844ff0e2421d', '0,1', NULL, 'при каких значениях а верны равенства? объясни их смысл. а+0=0+а=а; а-0=а; а-а=0; а:1=а; а:а=1; 0:а=0; а ⋅ 1=1 ⋅ а=а; а ⋅ 0=0 ⋅ а=0');

    VALUES (v_textbook_id, 90, '11', 7, 'Найди значения выражений: А) 375 ⋅ 0 + 294 : 294 – (16 – 16) : 2; Б) 7 : (15 : 15) – (21 – 21) ⋅ 5 + 1 ⋅ 9.', '</p>\n\n<p class="text">\nНайди значения выражений:<br/>\nА) 375 ⋅ 0 + 294 : 294 – (16 – 16) : 2;<br/>\nБ) 7 : (15 : 15) – (21 – 21) ⋅ 5 + 1 ⋅ 9.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica90-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 90, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 90, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-90/')
    RETURNING id INTO v_task_id;

