    VALUES (v_task_id, v_textbook_id, 3, 'e5e7724cc72caa6438226c7c58ab05cb2aa0cc0cf45d7f4db201f13f82a5f285', '0,1,2,5,7,9,15,16,21,294', '["найди"]'::jsonb, 'найди значения выражений:а) 375 ⋅ 0+294:294-(16-16):2; б) 7:(15:15)-(21-21) ⋅ 5+1 ⋅ 9');

    VALUES (v_textbook_id, 90, '12', 8, 'Повару надо зажарить 6 котлет, а на сковородке умещаются только 4 котлеты. Каждую котлету надо жарить 5 мин на одной стороне и 5 мин на другой. За какое минимальное время повар может зажарить все котлеты?', '</p>\n\n<p class="text">Повару надо зажарить 6 котлет, а на сковородке умещаются только 4 котлеты. Каждую котлету надо жарить 5 мин на одной стороне и 5 мин на другой. За какое минимальное время повар может зажарить все котлеты?\n</p>', '1. Сначала жарим 5 минут 4 котлеты на одной стороне (2 котлеты будут пожарены на одной стороне, а 2 переворачиваем). 2. 2 котлеты переворачиваем и дожариваем и добавляем еще 2 котлеты на 5 минут. 3. Снимаем 2 готовые котлеты и добавляем котлеты, которые были готовы наполовину. Тогда, 5 + 5 + 5 = 15 минут нужно, чтобы пожарить 6 котлет.', '<p>\n1. Сначала жарим 5 минут 4 котлеты на одной стороне (2 котлеты будут пожарены на одной стороне, а 2 переворачиваем).<br/>\n2. 2 котлеты переворачиваем и дожариваем и добавляем еще 2 котлеты на 5 минут.<br/>\n3. Снимаем 2 готовые котлеты и добавляем котлеты, которые были готовы наполовину. <br/>\nТогда, 5 + 5 + 5 = 15 минут нужно, чтобы пожарить 6 котлет.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-90/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4be80fa785b42b3bbb42c527f0be35e682445d04ecfc6d94f87c8a8225f7be68', '4,5,6', NULL, 'повару надо зажарить 6 котлет, а на сковородке умещаются только 4 котлеты. каждую котлету надо жарить 5 мин на одной стороне и 5 мин на другой. за какое минимальное время повар может зажарить все котлеты');

    VALUES (v_textbook_id, 91, '1', 0, 'Прочитай и назови формулы. Проверь свой ответ по учебнику. Зачем нужны формулы и как их устанавливают? S = a ⋅ b; P = (a + b) ⋅ 2; S = a ⋅ a; P = a ⋅ 4; V = a ⋅ a ⋅ a.', '</p>\n\n<p class="text">Прочитай и назови формулы. Проверь свой ответ по учебнику. Зачем нужны формулы и как их устанавливают?<br/>\nS = a ⋅ b;<br/>\nP = (a + b) ⋅ 2;<br/>\nS = a ⋅ a;<br/>\nP = a ⋅ 4;<br/>\nV = a ⋅ a ⋅ a.\n</p>', 'S = a ⋅ b – площадь прямоугольника; P = (a + b) ⋅ 2 – периметр прямоугольника; S = a ⋅ a – площадь квадрата; P = a ⋅ 4 – периметр квадрата; V = a ⋅ a ⋅ a – объем куба. Формулы нужны для того, чтобы проще обнаруживать неизвестное по заданию. Их устанавливают так, что между разными величинами обнаруживают взаимосвязи и закрепляют.', '<p>\nS = a ⋅ b – площадь прямоугольника;<br/>\nP = (a + b) ⋅ 2 – периметр прямоугольника;<br/>\nS = a ⋅ a – площадь квадрата;<br/>\nP = a ⋅ 4 – периметр квадрата;<br/>\nV = a ⋅ a ⋅ a – объем куба.<br/>\nФормулы нужны для того, чтобы проще обнаруживать неизвестное по заданию.<br/>\nИх устанавливают так, что между разными величинами обнаруживают взаимосвязи и закрепляют.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-91/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ff576e409f8bc82dfb131564e2f0e2e792cca02303a58b7eb07237cf1109ffa9', '2,4', NULL, 'прочитай и назови формулы. проверь свой ответ по учебнику. зачем нужны формулы и как их устанавливают? s=a ⋅ b; p=(a+b) ⋅ 2; s=a ⋅ a; p=a ⋅ 4; v=a ⋅ a ⋅ a');

    VALUES (v_textbook_id, 91, '2', 1, 'Перенеси в тетрадь таблицу. Заполни её, пользуясь формулами периметра и площади прямоугольника:', '</p>\n\n<p class="text">Перенеси в тетрадь таблицу. Заполни её, пользуясь формулами периметра и площади прямоугольника:</p>\n\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica91-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 91, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 91, номер 2, год 2022."/>\n</div>', 'S = a ⋅ b; P =(a + b) ⋅ 2.', '<p>\nS = a ⋅ b;<br/>\nP =(a + b) ⋅ 2.\n</p>\n<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica91-nomer2-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 91, номер 2-1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 91, номер 2-1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-91/')
    RETURNING id INTO v_task_id;

