    VALUES (v_textbook_id, 91, '3', 2, 'А) Бассейн имеет форму прямоугольного параллелепипеда. Его длина равна 15 м, ширина – 9 м, а глубина – 4 м. Чему равна площадь дна этого бассейна? Сколько кубических метров воды в него вмещается? Б) комната имеет форму прямоугольного параллелепипеда. Длина комнаты равна 7 м, ширина – 6м, а высота – 3 м. Чему равен объем этой комнаты и площадь её пола?', '</p>\n\n<p class="text">\nА) Бассейн имеет форму прямоугольного параллелепипеда. Его длина равна 15 м, ширина – 9 м, а глубина – 4 м. Чему равна площадь дна этого бассейна? Сколько кубических метров воды в него вмещается? <br/>\nБ) комната имеет форму прямоугольного параллелепипеда. Длина комнаты равна 7 м, ширина – 6м, а высота – 3 м. Чему равен объем этой комнаты и площадь её пола?\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica91-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 91, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 91, номер 3, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-91/')
    RETURNING id INTO v_task_id;

