    VALUES (v_task_id, v_textbook_id, 3, '1217855f0669024fba4d470d0894e161795f1b7e6731c3e7a407f13a8de0736c', '3,4,6,7,9,15', '["площадь"]'::jsonb, 'а) бассейн имеет форму прямоугольного параллелепипеда. его длина равна 15 м, ширина-9 м, а глубина-4 м. чему равна площадь дна этого бассейна? сколько кубических метров воды в него вмещается? б) комната имеет форму прямоугольного параллелепипеда. длина комнаты равна 7 м, ширина-6м, а высота-3 м. чему равен объем этой комнаты и площадь её пола');

    VALUES (v_textbook_id, 91, '4', 3, 'Площадь прямоугольника равна 1600 см2, а одна из сторон – 40 см. Найди его вторую сторону и периметр. Как называется такой прямоугольник?', '</p>\n\n<p class="text">Площадь прямоугольника равна 1600 см2, а одна из сторон – 40 см. Найди его вторую сторону и периметр. Как называется такой прямоугольник?</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica91-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 91, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 91, номер 4, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-91/')
