    VALUES (v_task_id, v_textbook_id, 3, 'ff2aa359abb846e96b385d6fa9366cfff5232708c6bec30816b370b6e6e50538', '2,40,1600', '["найди","периметр","площадь"]'::jsonb, 'площадь прямоугольника равна 1600 см2, а одна из сторон-40 см. найди его вторую сторону и периметр. как называется такой прямоугольник');

    VALUES (v_textbook_id, 91, '5', 4, 'Игорь решил примеры на деление с остатком и записал их так: 53 : 7 = 6 (ост. 11); 420 : 80 = 5 (ост. 2). Найди ошибки и реши примеры правильно.', '</p>\n\n<p class="text">\nИгорь решил примеры на деление с остатком и записал их так:<br/>\n53 : 7 = 6 (ост. 11);<br/>\n420 : 80 = 5 (ост. 2).<br/>\nНайди ошибки и реши примеры правильно.\n</p>', '53 : 7 = 6 (ост. 11) – выполнено неверно, потому что остаток больше делителя, а такого быть не может. Тогда, 53 : 7 = 7 (ост. 4). 420 : 80 = 5 (ост. 2) – выполнено неверно, потому что 5 * 80 + 2 = 402, а не 420. Тогда, 420 : 80 = 5 (ост. 20).', '<p>\n53 : 7 = 6 (ост. 11) – выполнено неверно, потому что остаток больше делителя, а такого быть не может.<br/>\nТогда, 53 : 7 = 7 (ост. 4).<br/>\n<br/>\n420 : 80 = 5 (ост. 2) – выполнено неверно, потому что 5 * 80 + 2 = 402, а не 420.<br/>\nТогда, 420 : 80 = 5 (ост. 20).\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-91/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '99a21b377d9bfd49b51c66726a5284b190e01c1d9b08582d85acef4f0bfa359e', '2,5,6,7,11,53,80,420', '["найди","реши"]'::jsonb, 'игорь решил примеры на деление с остатком и записал их так:53:7=6 (ост. 11); 420:80=5 (ост. 2). найди ошибки и реши примеры правильно');

    VALUES (v_textbook_id, 91, '6', 5, 'Найди частное и остаток при делении чисел. Сделай проверку. А) 45 : 6; Б) 78 : 14; В) 81 580 : 9; Г) 672 043 : 8; Д) 402 600 : 500; Е) 1 218 460 : 60.', '</p>\n\n<p class="text">\nНайди частное и остаток при делении чисел. Сделай проверку. <br/>\nА) 45 : 6;<br/>\nБ) 78 : 14;<br/>\nВ) 81 580 : 9;<br/>\nГ) 672 043 : 8;<br/>\nД) 402 600 : 500;<br/>\nЕ) 1 218 460 : 60.\n</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica91-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 91, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 91, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-91/')
