    VALUES (v_task_id, v_textbook_id, 3, '2756d92efe3c179c8265cf874d7c64f440ec7d27e2472b2d950d2ae132223b4b', '1,6,8,9,14,043,45,60,78,81', '["найди","частное","остаток"]'::jsonb, 'найди частное и остаток при делении чисел. сделай проверку. а) 45:6; б) 78:14; в) 81 580:9; г) 672 043:8; д) 402 600:500; е) 1 218 460:60');

    VALUES (v_textbook_id, 91, '7', 6, 'А) Оля сказала, что никто из мальчиков не знает стихи А.С.Пушкина. Как доказать, что это не так? Б) Юра сказал, что все попугаи живут в Африке. Петя сказал, что это не так. Кто из них прав? Почему? Докажи.', '</p>\n\n<p class="text">\nА) Оля сказала, что никто из мальчиков не знает стихи А.С.Пушкина. Как доказать, что это не так?<br/>\nБ) Юра сказал, что все попугаи живут в Африке. Петя сказал, что это не так. Кто из них прав? Почему? Докажи.\n</p>', 'А) Нужно попросить хотя бы одного мальчика рассказать его стихотворение. Возможно, хотя бы один мальчик сможет, и тогда высказывание будет ложным. Б) Петя прав, а Юра – нет, ведь у мена дома живет попугай, хотя я живу не в Африке, а в России.', '<p>\nА) Нужно попросить хотя бы одного мальчика рассказать его стихотворение. Возможно, хотя бы один мальчик сможет, и тогда высказывание будет ложным.<br/>\nБ) Петя прав, а Юра – нет, ведь у мена дома живет попугай, хотя я живу не в Африке, а в России.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-91/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '9a2643b2b7ee6ba6c24d374a7ada1715da2b1d22c2d4c76ac823a3f6075d1dd9', NULL, NULL, 'а) оля сказала, что никто из мальчиков не знает стихи а.с.пушкина. как доказать, что это не так? б) юра сказал, что все попугаи живут в африке. петя сказал, что это не так. кто из них прав? почему? докажи');

    VALUES (v_textbook_id, 91, '8', 7, 'А) Верно ли, что некоторые числа удовлетворяются равенству х ⋅ х + 8 = 12? Как это доказать? Б) Верно ли, что неравенство b < 8 верно для всех чисел? Обоснуй свой ответ.', '</p>\n\n<p class="text">\nА) Верно ли, что некоторые числа удовлетворяются равенству х ⋅ х + 8 = 12? Как это доказать?<br/>\nБ) Верно ли, что неравенство b &lt; 8 верно для всех чисел? Обоснуй свой ответ.\n</p>', 'А) х ⋅ х + 8 = 12 – чтобы доказать это, нужно найти хотя бы одно значение х, которое обращает высказывание в верное равенство. 2 ⋅ 2 + 8 = 12, т.е. 4 + 8 = 12. Б) b < 8 для всех чисел неверно – доказать это можно, если обнаружить такое значение b, при котором неравенство становится ложным, например, 9 < 8 – неверно, значит, не для любых чисел.', '<p>\nА) х ⋅ х + 8 = 12 – чтобы доказать это, нужно найти хотя бы одно значение х, которое обращает высказывание в верное равенство.<br/>\n2 ⋅ 2 + 8 = 12, т.е. 4 + 8 = 12.<br/>\n<br/>\nБ) b &lt; 8 для всех чисел неверно – доказать это можно, если обнаружить такое значение b, при котором неравенство становится ложным, например, 9 &lt; 8 – неверно, значит, не для любых чисел.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-91/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'a47b5928ef138ce8ac6d70bb160b83e3e244e0ac27e385089e3486aa8d0fe964', '8,12', NULL, 'а) верно ли, что некоторые числа удовлетворяются равенству х ⋅ х+8=12? как это доказать? б) верно ли, что неравенство b<8 верно для всех чисел? обоснуй свой ответ');

    VALUES (v_textbook_id, 92, '9', 0, 'Реши уравнения с комментированием и сделай проверку: 50 – 9 ⋅ а = 23; (m : 5 + 3) ⋅ 6 = 48; 56 : (36 : k – 2) = 8.', '</p>\n\n<p class="text">\nРеши уравнения с комментированием и сделай проверку:<br/>\n50 – 9 ⋅ а = 23;<br/>\n(m : 5 + 3) ⋅ 6 = 48;<br/>\n56 : (36 : k – 2) = 8.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica92-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 92, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 92, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-92/')
    RETURNING id INTO v_task_id;

