    VALUES (v_task_id, v_textbook_id, 3, 'c02275c75c4fb80148b2cd4e9d34fa7b5007ce619a22c4238d5f5a4dceb1d698', '2,3,5,6,8,9,23,36,48,50', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:50-9 ⋅ а=23; (m:5+3) ⋅ 6=48; 56:(36:k-2)=8');

    VALUES (v_textbook_id, 92, '10', 1, 'Найди значение выражения 80 – х, если х = 9, 18, 27, 36, 45. Составь таблицу.', '</p>\n\n<p class="text">\nНайди значение выражения 80 – х, если х = 9, 18, 27, 36, 45. Составь таблицу.\n</p>', '80 – х; При х = 9, 80 – 9 = 71; При х = 18, 80 – 18 = 62; При х = 27, 80 – 27 = 53; При х = 36, 80 – 36 = 44; При х = 45, 80 – 45 = 35.', '<p>\n80 – х;<br/>\nПри х = 9, 80 – 9 = 71;<br/>\nПри х = 18, 80 – 18 = 62;<br/>\nПри х = 27, 80 – 27 = 53;<br/>\nПри х = 36, 80 – 36 = 44;<br/>\nПри х = 45, 80 – 45 = 35.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-92/')
    RETURNING id INTO v_task_id;

