    VALUES (v_textbook_id, 92, '11', 2, 'Рассмотри таблицы. Как связаны между собой переменные х и у? Составь формулу, выражающую у через х.', '</p>\n\n<p class="text">Рассмотри таблицы. Как связаны между собой переменные х и у? Составь формулу, выражающую у через х.</p>\n\n<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica92-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 92, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 92, номер 11, год 2022."/>\n</div>', 'А) х ⋅ 5 = у; Б) х ⋅ х = у.', '<p>\nА) х ⋅ 5 = у;<br/>\nБ) х ⋅ х = у.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-92/')
    RETURNING id INTO v_task_id;

