    VALUES (v_textbook_id, 92, '12', 3, 'Назови число, которое предшествует при счёте числу: 1 000 000; 8 700 000; 43 060 000; 105 250 000.', '</p>\n\n<p class="text">\nНазови число, которое предшествует при счёте числу:<br/>\n1 000 000;<br/>\n8 700 000;<br/>\n43 060 000;<br/>\n105 250 000.\n</p>', '1 000 000 – 999 999 – девятьсот девяносто девять тысяч девятьсот девяносто девять; 8 700 000 – 8 699 999 – восемь миллионов шестьсот девяносто девять девятьсот девяносто девять; 43 060 000 – 43 059 999 – сорок три миллиона пятьдесят девять тысяч девятьсот девяносто девять; 105 250 000 – 105 249 999 – сто пять тысяч двести сорок девять девятьсот девяносто девять.', '<p>\n1 000 000 – 999 999 – девятьсот девяносто девять тысяч девятьсот девяносто девять;<br/>\n8 700 000 – 8 699 999 – восемь миллионов шестьсот девяносто девять девятьсот девяносто девять;<br/>\n43 060 000 – 43 059 999 – сорок три миллиона пятьдесят девять тысяч девятьсот девяносто девять;<br/>\n105 250 000 – 105 249 999 – сто пять тысяч двести сорок девять девятьсот девяносто девять.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-92/')
    RETURNING id INTO v_task_id;

