    VALUES (v_textbook_id, 92, '13', 4, 'Назови число, которое следует в натуральном ряду за числом: 87 999; 417 099; 65 045 079; 203 100 049 999.', '</p>\n\n<p class="text">\nНазови число, которое следует в натуральном ряду за числом:<br/>\n87 999;<br/>\n417 099;<br/>\n65 045 079;<br/>\n203 100 049 999.\n</p>', '87 999 – 88 000 – восемьдесят восемь тысяч; 417 099 – 417 100 – четыреста семнадцать тысяч; 65 045 079 – 65 045 080 – шестьдесят пять миллионов сорок пять тысяч восемьдесят; 203 100 049 999 – 203 100 050 000 – двести три миллиарда сто миллионов пятьдесят тысяч.', '<p>\n87 999 – 88 000 – восемьдесят восемь тысяч;<br/>\n417 099 – 417 100 – четыреста семнадцать тысяч;<br/>\n65 045 079 – 65 045 080 – шестьдесят пять миллионов сорок пять тысяч восемьдесят;<br/>\n203 100 049 999 – 203 100 050 000 – двести три миллиарда сто миллионов пятьдесят тысяч.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-92/')
