    VALUES (v_textbook_id, 92, '15', 6, 'Назови фигуры, изображенные на чертеже. Определи, какой фигурой является их пересечение. Найди другие случаи пересечения треугольника и четырехугольника. Нарисуй их в тетради и покажи пересечение цветом.', '</p>\n\n<p class="text">\nНазови фигуры, изображенные на чертеже. Определи, какой фигурой является их пересечение.<br/>\nНайди другие случаи пересечения треугольника и четырехугольника. Нарисуй их в тетради и покажи пересечение цветом.\n</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica92-nomer15.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 92, номер 15, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 92, номер 15, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-92/')
