    VALUES (v_textbook_id, 92, '16', 7, 'Найди на рисунке кубик, у которого три данные грани точно такие же, как у кубика М. Решение можно проверить на модели куба.', '</p>\n\n<p class="text">Найди на рисунке кубик, у которого три данные грани точно такие же, как у кубика М.<br/>\nРешение можно проверить на модели куба.\n</p>', 'Это кубик Е.', '<p>\nЭто кубик Е.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-92/')
    RETURNING id INTO v_task_id;

