    VALUES (v_textbook_id, 93, '2', 1, 'Найди по рисунку делимое, делитель, частное и остаток. Запиши в тетради соответствующее числовое равенство. 20 = … ⋅ … + …', '</p>\n\n<p class="text">Найди по рисунку делимое, делитель, частное и остаток. Запиши в тетради соответствующее числовое равенство.<br/>\n20 = … ⋅ … + …\n</p>', '20 = 6 ⋅ 3 + 2. Делимое – 20. Делитель – 3. Частное – 6. Остаток – 2.', '<p>\n20 = 6 ⋅ 3 + 2.<br/>\nДелимое – 20.<br/>\nДелитель – 3.<br/>\nЧастное – 6.<br/>\nОстаток – 2.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-93/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4bec98c53abf0faf229edfbad5df9adec766dbf5e597ec371c6287a05570dcec', '20', '["найди","частное","делитель","делимое","остаток"]'::jsonb, 'найди по рисунку делимое, делитель, частное и остаток. запиши в тетради соответствующее числовое равенство. 20=... ⋅ ...+');

    VALUES (v_textbook_id, 93, '3', 2, 'А) Проверь равенства, выражающие связь между компонентами деления с остатков: 11 = 4 ⋅ 2 + 3; 17 = 6 ⋅ 2 + 5; 19 = 5 ⋅ 3 + 4. Сделай чертежи. Назови делимое, делитель, частное и остаток. Б) Запиши все три равенства одной буквенной формулой, обозначая делимое а, делитель b, частное с и остаток r. А = … ⋅ … + …, r … b. Сравни значение остатка r и делителя b. Сделай вывод.', '</p>\n\n<p class="text">\nА) Проверь равенства, выражающие связь между компонентами деления с остатков:<br/>\n11 = 4 ⋅ 2 + 3;<br/>\n17 = 6 ⋅ 2 + 5;<br/>\n19 = 5 ⋅ 3 + 4.<br/>\nСделай чертежи. Назови делимое, делитель, частное и остаток.<br/>\nБ) Запиши все три равенства одной буквенной формулой, обозначая делимое а, делитель b, частное с и остаток r.<br/>\nА = … ⋅ … + …, r … b.<br/>\nСравни значение остатка r и делителя b. Сделай вывод.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica93-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 93, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 93, номер 3, год 2022."/>', 'Формула деления с остатком При делении числа а на число b устанавливают, сколько раз по b содержится в а: Если получилось с откладываний и осталось r единиц (r < b), то а = b ⋅ c + r. Это равенство называют формулой деления с остатком . В ней показана взаимосвязь между делимым, делителем, неполным частным и остатком: а = b ⋅ c + r, r < b. Итак, при делении с остатком делимое равно произведению делителя и неполного частного плюс остаток. При этом остаток всегда меньше делителя .', '<div class="recomended-block">\n<span class="title">Формула деления с остатком</span>\n<p>\nПри делении числа а на число b устанавливают, сколько раз по b  содержится в а:<br/>\nЕсли получилось с откладываний и осталось r единиц (r &lt; b), то а = b ⋅ c + r. Это равенство называют <b class="black">формулой деления с остатком</b>. В ней показана взаимосвязь между делимым, делителем, неполным частным и остатком: <br/>\nа = b ⋅ c + r, r &lt; b.<br/>\nИтак, при делении с остатком <b class="black">делимое равно произведению делителя и неполного частного плюс остаток. При этом остаток всегда меньше делителя</b>.\n</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-93/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica93-nomer3.jpg', 'peterson/3/part2/page93/task3_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'f1f834c1732df89ec51b44ca160bece80b720dea77df0029b4c75c076d26d558', '2,3,4,5,6,11,17,19', '["сравни","частное","делитель","делимое","остаток"]'::jsonb, 'а) проверь равенства, выражающие связь между компонентами деления с остатков:11=4 ⋅ 2+3; 17=6 ⋅ 2+5; 19=5 ⋅ 3+4. сделай чертежи. назови делимое, делитель, частное и остаток. б) запиши все три равенства одной буквенной формулой, обозначая делимое а, делитель b, частное с и остаток r. а=... ⋅ ...+..., r ... b. сравни значение остатка r и делителя b. сделай вывод');

    VALUES (v_textbook_id, 94, '4', 0, 'Запиши формулу деления с остатком. Пользуясь этой формулой, найди делимое а, если: 1) b = 7, c = 4, r = 1; 2) b = 12, c = 6, r = 3.', '</p>\n\n<p class="text">\nЗапиши формулу деления с остатком. Пользуясь этой формулой, найди делимое а, если:<br/>\n1) b = 7, c = 4,  r = 1;<br/>\n2) b = 12, c = 6, r = 3.\n</p>', 'а = b ⋅ c + r, где Делимое – а; Делитель – b; Частное – c; Остаток – r < b. 1) a = 7 ⋅ 4 + 1 = 29; 2) a = 12 ⋅ 6 + 3 = 75.', '<p>\nа = b ⋅ c + r, где<br/>\nДелимое – а;<br/>\nДелитель – b;<br/>\nЧастное – c;<br/>\nОстаток – r &lt; b.<br/>\n<br/>\n1) a = 7 ⋅ 4 + 1 = 29;<br/>\n2) a = 12 ⋅ 6 + 3 = 75.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-94/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'dffe5de8b93a2a464dc989499d488e162a1550fc613bdec579afc2bf279ad3bb', '1,2,3,4,6,7,12', '["найди","делимое"]'::jsonb, 'запиши формулу деления с остатком. пользуясь этой формулой, найди делимое а, если:1) b=7, c=4, r=1; 2) b=12, c=6, r=3');

