    VALUES (v_textbook_id, 94, '8', 3, 'Запиши формулу деления с остатком для случая, когда остаток равен 0. Как можно назвать в этом случае числа a, b и с?', '</p>\n\n<p class="text">\nЗапиши формулу деления с остатком для случая, когда остаток равен 0. Как можно назвать в этом случае числа a, b и с?\n</p>', 'а = b ⋅ c, где а – делимое, b – делитель, с – частное.', '<p>\nа = b ⋅ c, где а – делимое, b – делитель, с – частное.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-94/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '02ab60e94a9a58c3c17f288fadec4b35fd8bfb7c54a917d7ebba59c53dd786af', '0', '["остаток"]'::jsonb, 'запиши формулу деления с остатком для случая, когда остаток равен 0. как можно назвать в этом случае числа a, b и с');

    VALUES (v_textbook_id, 94, '9', 4, 'Рассмотри решение примера: 600 : 70 = 60 д. : 7 д. = 8 (ост. 4 д.) = 8 (ост. 40). Почему при делении с остатком круглых чисел в остатке надо приписать отброшенное число нулей? Вычисли и сделай проверку: А) 160 : 30; Б) 290 : 60; В) 430 : 40; Г) 920 : 50; Д) 3800 : 900; Е) 6700 : 200; Ж) 21 400 : 70; З) 576 200 : 800.', '</p>\n\n<p class="text">\nРассмотри решение примера:<br/>\n600 : 70 = 60 д. : 7 д. = 8 (ост. 4 д.) = 8 (ост. 40).<br/>\nПочему при делении с остатком круглых чисел в остатке надо приписать отброшенное число нулей? Вычисли и сделай проверку:<br/>\nА) 160 : 30;<br/>\nБ) 290 : 60;<br/>\nВ) 430 : 40;<br/>\nГ) 920 : 50;<br/>\nД) 3800 : 900;<br/>\nЕ) 6700 : 200;<br/>\nЖ) 21 400 : 70;<br/>\nЗ) 576 200 : 800.\n</p>', 'При делении с остатков круглых чисел в остатке надо приписать отброшенное число нулей, потому что в делимом и делителе их одинаковое количество отбрасывают, а затем нужно вернуть. А) 160 : 30 = 16 дес. : 3 дес. = 5 (ост. 1 дес.) = 5 (ост. 10); Проверка: 5 ⋅ 30 + 10 = 160; Б) 290 : 60 = 29 дес. : 6 дес. = 4 (ост. 5 дес.) = 4 (ост. 50); Проверка: 4 ⋅ 60 + 50 = 290; В) 430 : 40 = 43 дес. : 4 дес. = 10 (отс. 3 дес.) = 10 (ост. 30); Проверка: 10 ⋅ 40 + 30 = 430; Г) 920 : 50 = 92 дес. : 5 дес. = 18 (ост. 2 дес.) = 18 (ост. 20); Проверка: 18 ⋅ 50 + 20 = 920; Д) 3800 : 900 = 38 сот. : 9 сот. = 4 (ост. 2 сот.) = 4 (ост. 200); Проверка: 4 ⋅ 900 + 200 = 3800; Е) 6700 : 200 = 67 сот. : 2 сот. = 33 (ост. 1 сот.) = 33 (ост. 100); Проверка: 33 ⋅ 200 + 100 = 6700; Ж) 21 400 : 70 = 2140 дес. : 7 дес. = 305 (ост. 5 дес.) = 305 (ост. 50); Проверка: 305 ⋅ 70 + 50 = 21 400; З) 576 200 : 800 = 5762 сот. : 8 сот. = 720 (ост. 2 сот.) = 720 (ост. 200); Проверка: 720 ⋅ 800 + 200 = 576 200.', '<p>\nПри делении с остатков круглых чисел в остатке надо приписать отброшенное число нулей, потому что в делимом и делителе их одинаковое количество отбрасывают, а затем нужно вернуть.<br/>\nА) 160 : 30 = 16 дес. : 3 дес. = 5 (ост. 1 дес.) = 5 (ост. 10);<br/>\nПроверка: 5 ⋅ 30 + 10 = 160;<br/>\n<br/>\nБ) 290 : 60 = 29 дес. : 6 дес. = 4 (ост. 5 дес.) = 4 (ост. 50);<br/>\nПроверка: 4 ⋅ 60 + 50 = 290;<br/>\n<br/>\nВ) 430 : 40 = 43 дес. : 4 дес. = 10 (отс. 3 дес.) = 10 (ост. 30);<br/>\nПроверка: 10 ⋅ 40 + 30 = 430;<br/>\n<br/>\nГ) 920 : 50 = 92 дес. : 5 дес. = 18 (ост. 2 дес.) = 18 (ост. 20);<br/>\nПроверка: 18 ⋅ 50 + 20 = 920;<br/>\n<br/>\nД) 3800 : 900 = 38 сот. : 9 сот. = 4 (ост. 2 сот.) = 4 (ост. 200);<br/>\nПроверка: 4 ⋅ 900 + 200 = 3800;<br/>\n<br/>\nЕ) 6700 : 200 = 67 сот. : 2 сот. = 33 (ост. 1 сот.) = 33 (ост. 100);<br/>\nПроверка: 33 ⋅ 200 + 100 = 6700;<br/>\n<br/>\nЖ) 21 400 : 70 = 2140 дес. : 7 дес. = 305 (ост. 5 дес.) = 305 (ост. 50);<br/>\nПроверка: 305 ⋅ 70 + 50 = 21 400;<br/>\n<br/>\nЗ) 576 200 : 800 = 5762 сот. : 8 сот. = 720 (ост. 2 сот.) = 720 (ост. 200);<br/>\nПроверка: 720 ⋅ 800 + 200 = 576 200.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-94/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '41460b7c79855d4575a5e8361cb3511749bdc052ff63e5f736ef7b4fd838f64f', '4,7,8,21,30,40,50,60,70,160', '["вычисли"]'::jsonb, 'рассмотри решение примера:600:70=60 д.:7 д.=8 (ост. 4 д.)=8 (ост. 40). почему при делении с остатком круглых чисел в остатке надо приписать отброшенное число нулей? вычисли и сделай проверку:а) 160:30; б) 290:60; в) 430:40; г) 920:50; д) 3800:900; е) 6700:200; ж) 21 400:70; з) 576 200:800');

    VALUES (v_textbook_id, 94, '10', 5, 'Прочитай числа: 75 994 608; 75 994 600 315; 70 000 031; 712 021; 99 999. Расположи эти числа в порядке возрастания.', '</p>\n\n<p class="text">\nПрочитай числа:<br/>\n75 994 608;<br/>\n75 994 600 315;<br/>\n70 000 031;<br/>\n712 021;<br/>\n99 999.<br/>\nРасположи эти числа в порядке возрастания.\n</p>', '99 999 – девяносто девять тысяч девятьсот девяносто девять; 712 021 – семьсот двенадцать тысяч двадцать один; 70 000 031 – семьдесят миллионов тридцать один; 75 994 608 – семьдесят пять миллионов девятьсот девяносто четыре тысячи шестьсот восемь; 75 994 600 315 – семьдесят пять миллиардов девятьсот девяносто четыре миллиона шестьсот тысяч триста пятнадцать.', '<p>\n99 999 – девяносто девять тысяч девятьсот девяносто девять;<br/>\n712 021 – семьсот двенадцать тысяч двадцать один;<br/>\n70 000 031 – семьдесят миллионов тридцать один;<br/>\n75 994 608 – семьдесят пять миллионов девятьсот девяносто четыре тысячи шестьсот восемь;<br/>\n75 994 600 315 – семьдесят пять миллиардов девятьсот девяносто четыре миллиона шестьсот тысяч триста пятнадцать.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-94/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '88b85d1a94af331a08fb9bd2a918f44c0ebf7d76c2505eec9e496aa0ec5dedaf', '000,021,031,70,75,99,315,600,608,712', NULL, 'прочитай числа:75 994 608; 75 994 600 315; 70 000 031; 712 021; 99 999. расположи эти числа в порядке возрастания');

    VALUES (v_textbook_id, 94, '11', 6, 'Реши уравнения с комментированием по компонентам действий: 14 – 81 : х = 5; (у – 3) : 5 = 30; (m ⋅ 4 + 6) : 9 = 2.', '</p>\n\n<p class="text">\nРеши уравнения с комментированием по компонентам действий:<br/>\n14 – 81 : х = 5;<br/>\n(у – 3) : 5 = 30;<br/>\n(m ⋅ 4 + 6) : 9 = 2.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica94-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 94, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 94, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-94/')
    RETURNING id INTO v_task_id;

