    VALUES (v_textbook_id, 94, '14', 9, 'Половина половины числа равна 10. Какое это число?', '</p>\n\n<p class="text">\nПоловина половины числа равна 10. Какое это число?\n</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica94-nomer14.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 94, номер 14, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 94, номер 14, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-94/')
    RETURNING id INTO v_task_id;

