    VALUES (v_task_id, v_textbook_id, 3, '450fba49488e935f9fa07fd96afc3002781e5b0575d0bce3af12ff5457776eda', '10', NULL, 'половина половины числа равна 10. какое это число');

    VALUES (v_textbook_id, 95, '1', 0, 'Запиши формулы: А) площади прямоугольника; Б) периметра прямоугольника; В) периметра квадрата; Г) объема прямоугольного параллелепипеда; Д) объема куба; Е) деления с остатком.', '</p>\n\n<p class="text">Запиши формулы: <br/>\nА) площади прямоугольника; <br/>\nБ) периметра прямоугольника; <br/>\nВ) периметра квадрата; <br/>\nГ) объема прямоугольного параллелепипеда; <br/>\nД) объема куба; <br/>\nЕ) деления с остатком.\n</p>', 'А) S = a ⋅ b; Б) Р = (a + b) ⋅ 2; В) Р = a ⋅ 4; Г) V = a ⋅ b ⋅ c; Д) V = a ⋅ a ⋅ a; Е) a = b ⋅ c + r.', '<p>\nА) S = a ⋅ b;<br/>\nБ) Р = (a + b) ⋅ 2;<br/>\nВ) Р = a ⋅ 4;<br/>\nГ) V = a ⋅ b ⋅ c;<br/>\nД) V = a ⋅ a ⋅ a;<br/>\nЕ) a = b ⋅ c + r.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '2943c50c06c57ad841ff5df3eaa6fb8e63618e05e68050ea79c4d00672ba94b7', NULL, '["периметр"]'::jsonb, 'запиши формулы:а) площади прямоугольника; б) периметра прямоугольника; в) периметра квадрата; г) объема прямоугольного параллелепипеда; д) объема куба; е) деления с остатком');

    VALUES (v_textbook_id, 95, '2', 1, 'Пользуясь формулой а = b ⋅ c + r, найди: 1) а, если b = 6, с = 8, r = 4; 2) b, если а = 29, с = 3, r = 2; 3) c, если а = 38, b = 7, r = 3; 4) b, если а = 59, с = 6, r = 5.', '</p>\n\n<p class="text">\nПользуясь формулой а = b ⋅ c + r, найди:<br/>\n1) а, если b = 6, с = 8, r = 4;<br/>\n2) b, если а = 29, с = 3, r = 2;<br/>\n3) c, если а = 38, b = 7, r = 3;<br/>\n4) b, если а = 59, с = 6, r = 5.\n</p>', '1) а = 6 ⋅ 8 + 4 = 48 + 4 = 52; 2) 29 = b ⋅ 3 + 2; b ⋅ 3 = 27; b = 27 : 3 = 9; 3) 38 = 7 ⋅ с + 3; 7 ⋅ с = 35; С = 35 : 7 = 5; 4) 59 = b ⋅ 6 + 5; b ⋅ 6 = 54; b = 54 : 6 = 9. Ответ: 1) 52; 2) 9; 3) 5; 4) 9.', '<p>\n1) а = 6 ⋅ 8 + 4 = 48 + 4 = 52;<br/>\n<br/>\n2) 29 = b ⋅ 3 + 2;<br/>\nb ⋅ 3 = 27;<br/>\nb = 27 : 3 = 9;<br/>\n<br/>\n3) 38 = 7 ⋅ с + 3;<br/>\n7 ⋅ с = 35;<br/>\nС = 35 : 7 = 5;<br/>\n<br/>\n4) 59 = b ⋅ 6 + 5;<br/>\nb ⋅ 6 = 54;<br/>\nb = 54 : 6 = 9.<br/>\n<br/>\nОтвет: 1) 52; 2) 9; 3) 5; 4) 9.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '3fa1ba2384abcf985492d289c182cf0f3d35140defd69ff4623ac6a1002e9200', '1,2,3,4,5,6,7,8,29,38', '["найди"]'::jsonb, 'пользуясь формулой а=b ⋅ c+r, найди:1) а, если b=6, с=8, r=4; 2) b, если а=29, с=3, r=2; 3) c, если а=38, b=7, r=3; 4) b, если а=59, с=6, r=5');

    VALUES (v_textbook_id, 95, '3', 2, 'Запиши формулу деления с остатком. Пользуясь ею, заполни в тетради таблицу:', '</p>\n\n<p class="text">Запиши формулу деления с остатком. Пользуясь ею, заполни в тетради таблицу:</p>\n\n<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica95-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 95, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 95, номер 3, год 2022."/>\n</div>', 'а = b ⋅ c + r.', '<p>\nа = b ⋅ c + r.\n</p>\n<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica95-nomer3-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 95, номер 3-1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 95, номер 3-1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica95-nomer3.jpg', 'peterson/3/part2/page95/task3_condition_0.jpg', '');

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica95-nomer3-1.jpg', 'peterson/3/part2/page95/task3_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '67163adfb44a95835f26f4f1331c8c24ec0e637c9ef5b5d44195ba94a6c9fdb5', NULL, '["заполни"]'::jsonb, 'запиши формулу деления с остатком. пользуясь ею, заполни в тетради таблицу');

    VALUES (v_textbook_id, 95, '4', 3, 'А) Найди ошибку в вычислении: 43 000 : 8 000 = 5 (ост. 3). Б) Вычисли и сделай проверку: 370 : 40; 6800 : 700; 44 000 : 6 000; 512 000 : 9 000.', '</p>\n\n<p class="text">\nА) Найди ошибку в вычислении:<br/>\n43 000 : 8 000 = 5 (ост. 3).<br/>\n<br/>\nБ) Вычисли и сделай проверку:<br/>\n370 : 40;<br/>\n6800 : 700;<br/>\n44 000 : 6 000;<br/>\n512 000 : 9 000.\n</p>', 'А) 43 000 : 8 000 = 43 тыс. : 8 тыс. = 5 (ост. 3 тыс.) = 5 (ост. 3000). Б) 370 : 40 = 37 дес. : 4 дес. = 9 (ост. 1 дес. ) = 9 (ост. 10). Проверка: 9 ⋅ 40 + 10 = 370. 6800 : 700 = 68 сот. : 7 сот. = 9 (ост. 5 сот.) = 9 (ост. 500). Проверка: 9 ⋅ 700 + 500 = 6800. 44 000 : 6000 = 44 тыс. : 6 тыс. = 7 (ост. 2 тыс.) = 7 (ост. 2 000). Проверка: 7 ⋅ 6000 + 2000 = 44 000. 512 000 : 9 000 = 512 тыс. : 9 тыс. = 56 (ост. 8 тыс.) = 56 (ост. 8 000). Проверка: 56 ⋅ 9 000 + 8 000 = 512 000.', '<p>\nА) <br/>\n43 000 : 8 000 = 43 тыс. : 8 тыс. = 5 (ост. 3 тыс.) = 5 (ост. 3000).<br/>\n<br/>\nБ) <br/>\n370 : 40 = 37 дес. : 4 дес. = 9 (ост. 1 дес. ) = 9 (ост. 10).<br/>\nПроверка: 9 ⋅ 40 + 10 = 370.<br/>\n<br/>\n6800 : 700 = 68 сот. : 7 сот. = 9 (ост. 5 сот.) = 9 (ост. 500).<br/>\nПроверка: 9 ⋅ 700 + 500 = 6800.<br/>\n<br/>\n44 000 : 6000 = 44 тыс. : 6 тыс. = 7 (ост. 2 тыс.) = 7 (ост. 2 000).<br/>\nПроверка: 7 ⋅ 6000 + 2000 = 44 000.<br/>\n<br/>\n512 000 : 9 000 = 512 тыс. : 9 тыс. = 56 (ост. 8 тыс.) = 56 (ост. 8 000).<br/>\nПроверка: 56 ⋅ 9 000 + 8 000 = 512 000.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '56850bfce89a7b485a2f3e4ce8ec71e55c20cdb85bffec7da5c9af0fa829dfc9', '000,3,5,6,8,9,40,43,44,370', '["вычисли","найди"]'::jsonb, 'а) найди ошибку в вычислении:43 000:8 000=5 (ост. 3). б) вычисли и сделай проверку:370:40; 6800:700; 44 000:6 000; 512 000:9 000');

    VALUES (v_textbook_id, 95, '5', 4, 'Периметр прямоугольника равен 48 см, а его ширина – 6 см. Найди длину этого прямоугольника.', '</p>\n\n<p class="text">Периметр прямоугольника равен 48 см, а его ширина – 6 см. Найди длину этого прямоугольника.</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica95-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 95, номер 5, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 95, номер 5, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica95-nomer5.jpg', 'peterson/3/part2/page95/task5_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '585dfffa6c64de01700e3df4996b1b7b1cc30ee3f3f06b489d0a8496ed8e6048', '6,48', '["найди","периметр"]'::jsonb, 'периметр прямоугольника равен 48 см, а его ширина-6 см. найди длину этого прямоугольника');

    VALUES (v_textbook_id, 95, '6', 5, 'Найди высоту прямоугольного параллелепипеда, если его объем равен 240 см 3 , а сторона основания – 5 см и 8 см.', '</p>\n\n<p class="text">Найди высоту прямоугольного параллелепипеда, если его объем равен 240 см<sup>3</sup>, а сторона основания – 5 см и 8 см.</p>', '', '<div class="img-wrapper-460">\n<img width="600" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica95-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 95, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 95, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica95-nomer6.jpg', 'peterson/3/part2/page95/task6_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'ef6800c0e948e86bddf0dee4f778c70156a1ac934a4cec527002e0ed0b1d1168', '3,5,8,240', '["найди","сторона"]'::jsonb, 'найди высоту прямоугольного параллелепипеда, если его объем равен 240 см 3 , а сторона основания-5 см и 8 см');

    VALUES (v_textbook_id, 95, '7', 6, 'Реши примеры. Объясни прием вычислений в каждом столбике: 78 ⋅ 3; 4 ⋅ 26; 56 : 4; 75 : 5; 87 : 29; 90 : 18; 500 ⋅ 90; 80 ⋅ 7000; 42 000 : 600; 320 000 : 800.', '</p>\n\n<p class="text">\nРеши примеры. Объясни прием вычислений в каждом столбике:<br/>\n78 ⋅ 3;<br/>\n4 ⋅ 26;<br/>\n<br/>\n56 : 4;<br/>\n75 : 5;<br/>\n<br/>\n87 : 29;<br/>\n90 : 18;<br/>\n<br/>\n500 ⋅ 90;<br/>\n80 ⋅ 7000;<br/>\n<br/>\n42 000 : 600;<br/>\n320 000 : 800.\n</p>', '78 ⋅ 3 = (70 + 8) ⋅ 3 = 70 ⋅ 3 + 8 ⋅ 3 = 210 + 24 = 234; 4 ⋅ 26 = 4 ⋅ (20 + 6) = (4 ⋅ 20) + (4 ⋅ 6) = 80 + 24 = 104; 56 : 4 = (40 + 16) : 4 = 40 : 4 + 16 : 4 = 10 + 4 = 14; 75 : 5 = (50 + 25) : 5 = 50 : 5 + 25 : 5 = 10 + 5 = 15; 87 : 29 = 3; 90 : 18 = 5; 500 ⋅ 90 = 45 000; 80 ⋅ 7000 = 560 000; 42 000 : 600 = 420 сот : 6 сот = 70; 320 000 : 800 = 3200 сот : 8 сот = 400', '<p>\n78 ⋅ 3 = (70 + 8) ⋅ 3 = 70 ⋅ 3 + 8 ⋅ 3 = 210 + 24 = 234;<br/>\n4 ⋅ 26 = 4 ⋅ (20 + 6) = (4 ⋅ 20) + (4 ⋅ 6) = 80 + 24 = 104;<br/>\n<br/>\n56 : 4 = (40 + 16) : 4 = 40 : 4 + 16 : 4 = 10 + 4 = 14;<br/>\n75 : 5 = (50 + 25) : 5 = 50 : 5 + 25 : 5 = 10 + 5 = 15;<br/>\n<br/>\n87 : 29 = 3;<br/>\n90 : 18 = 5;<br/>\n<br/>\n500 ⋅ 90 = 45 000;<br/>\n80 ⋅ 7000 = 560 000;<br/>\n<br/>\n42 000 : 600 = 420 сот : 6 сот = 70;<br/>\n320 000 : 800 = 3200 сот : 8 сот = 400\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '12c8e58745f963fb0adb2eb867438fcd71b8cfb5f6dfdedc3ef7f80c807082a4', '000,3,4,5,18,26,29,42,56,75', '["реши","столбик"]'::jsonb, 'реши примеры. объясни прием вычислений в каждом столбике:78 ⋅ 3; 4 ⋅ 26; 56:4; 75:5; 87:29; 90:18; 500 ⋅ 90; 80 ⋅ 7000; 42 000:600; 320 000:800');

    VALUES (v_textbook_id, 95, '8', 7, 'Реши уравнения с комментированием и сделай проверку: (48 : t + 7) ⋅ 6 = 90; 100 – (b ⋅ 8 – 50) = 30; 9600 : (540 : d – 4) = 600.', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:<br/>\n(48 : t + 7) ⋅ 6 = 90;<br/>\n100 – (b ⋅ 8 – 50) = 30;<br/>\n9600 : (540 : d – 4) = 600.\n</p>', '', '<div class="img-wrapper-460">\n<img width="550" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica95-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 2, станица 95, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 2, станица 95, номер 8, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast2/stranica95-nomer8.jpg', 'peterson/3/part2/page95/task8_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'ba66f5fdda39a3322f0aecaf20058cacf5ba4e32ad0cc26e8c7f16bc3654a3ca', '4,6,7,8,30,48,50,90,100,540', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:(48:t+7) ⋅ 6=90; 100-(b ⋅ 8-50)=30; 9600:(540:d-4)=600');

    VALUES (v_textbook_id, 95, '9', 8, 'На какое число нужно разделить число 46, чтобы получить частное 3 и остаток 10?', '</p>\n\n<p class="text">На какое число нужно разделить число 46, чтобы получить частное 3 и остаток 10?\n</p>', '46 – делимое; х – делитель; 3 – частное; 10 – остаток. Тогда – 46 : х = 3 (ост. 10); 46 = (х ⋅ 3) + 10; 46 – 10 = х ⋅ 3; 36 = х ⋅ 3; x = 12, т.е. число нужно разделить на 12. Ответ: число 46 нужно разделить на 12.', '<p>\n46 – делимое;<br/>\nх – делитель;<br/>\n3 – частное;<br/>\n10 – остаток.<br/>\nТогда – 46 : х = 3 (ост. 10);<br/>\n46 = (х ⋅ 3) + 10;<br/>\n46 – 10 = х ⋅ 3;<br/>\n36 = х ⋅ 3;<br/>\nx = 12, т.е. число нужно разделить на 12.<br/>\nОтвет: число 46 нужно разделить на 12.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd25abf16e4ef11ae1bdd9871f54424eb514bbe48ed3ca5ac199c6123402693cd', '3,10,46', '["раздели","частное","раз","остаток"]'::jsonb, 'на какое число нужно разделить число 46, чтобы получить частное 3 и остаток 10');

    VALUES (v_textbook_id, 95, '10', 9, 'Подбери корни уравнений: А) х ⋅ х + х = 20; Б) (х – 1) ⋅ (х + 1) = 63.', '</p>\n\n<p class="text">Подбери корни уравнений:<br/>\nА) х ⋅ х + х = 20;<br/>\nБ) (х – 1) ⋅ (х + 1) = 63.\n</p>', 'А) 4 ⋅ 4 + 4 = 20, потому что 16 + 4 = 20. Б) (х – 1) ⋅ (х + 1) = 63. Чтобы найти х, нужно вспомнить, какие два числа при умножении образуют 63. Это числа 7 и 9. 7 = 8 – 1 и 9 = 8 + 1. Значит, х – 8. (8 – 1) ⋅ (8 + 1) = 63, потому что 7 ⋅ 9 = 63.', '<p>\nА) 4 ⋅ 4 + 4 = 20, потому что 16 + 4 = 20.<br/>\nБ) (х – 1) ⋅ (х + 1) = 63.<br/>\nЧтобы найти х, нужно вспомнить, какие два числа при умножении образуют 63.<br/>\nЭто числа 7 и 9.<br/>\n7 = 8 – 1 и 9 = 8 + 1.<br/>\nЗначит,  х – 8.<br/>\n(8 – 1) ⋅ (8 + 1) = 63, потому что 7 ⋅ 9 = 63.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7e90de4b15b718360ce825edd66d5f89cf612f0890ee6e47142d7036adc1c3a3', '1,20,63', NULL, 'подбери корни уравнений:а) х ⋅ х+х=20; б) (х-1) ⋅ (х+1)=63');

    VALUES (v_textbook_id, 95, '11', 10, 'Найди закономерность и продолжи ряд на 2 числа. 8, 789, 678 910 …', '</p>\n\n<p class="text">Найди закономерность и продолжи ряд на 2 числа.<br/>\n8, 789, 678 910 …\n</p>', '8 – 7 8 9 – 6 789 10 – 5 678910 11 – 4 567891011 12. Каждое следующее число увеличивается за счет количества знаков так, что слева появляется дополнительный знак на единицу меньше данного, а справа – на единицу больше предыдущего.', '<p>\n8 – 7<b class="black">8</b>9 – 6<b class="black">789</b>10 – 5<b class="black">678910</b>11 – 4<b class="black">567891011</b>12.<br/>\nКаждое следующее число увеличивается за счет количества знаков так, что слева появляется дополнительный знак на единицу меньше данного, а справа – на единицу больше предыдущего.\n</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/2-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'f7d1105d0d11f56c3a888ed819affc8e9add06e09c0367b8d7287e00181cb825', '2,8,678,789,910', '["найди"]'::jsonb, 'найди закономерность и продолжи ряд на 2 числа. 8, 789, 678 910');

